import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Mail, Lock, LogIn, Loader2, AlertCircle, ArrowLeft } from 'lucide-react';
import { UserRole } from '../types';

interface LoginViewProps {
  onLoginSuccess: (user: any) => void;
  onBack: () => void;
}

const LoginView: React.FC<LoginViewProps> = ({ onLoginSuccess, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
        email, password,
      });
      if (authError) throw authError;

      const { data: empData } = await supabase
        .from('employees')
        .select('*')
        .eq('email', email)
        .single();

      const userData = {
        id: authData.user?.id,
        name: empData?.name || authData.user?.email?.split('@')[0],
        email: authData.user?.email,
        role: empData?.role || UserRole.EMPLOYEE,
        avatar: empData?.avatar || `https://picsum.photos/seed/${authData.user?.id}/100`,
      };

      onLoginSuccess(userData);
    } catch (err: any) {
      setError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4 animate-in fade-in duration-500">
      <div className="bg-white rounded-[4rem] shadow-2xl p-10 md:p-16 max-w-md w-full border border-slate-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>

        <div className="text-center mb-10">
          <div className="w-24 h-24 bg-blue-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-blue-500/30 p-4">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" alt="Monte Logo" className="w-full h-full object-contain brightness-0 invert" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">MONTE HUB</h2>
          <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2 px-4 py-1 bg-slate-50 rounded-full inline-block">Sincronização Cloud Ativa</p>
        </div>

        {error && (
          <div className="mb-6 bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-center gap-3 text-red-700 text-xs font-bold animate-shake">
            <AlertCircle size={18} /> {error}
          </div>
        )}

        <form onSubmit={handleSignIn} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Staff</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required type="email" value={email} onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-12 pr-4 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm"
                placeholder="nome@monte-imobiliaria.com"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave de Segurança</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required type="password" value={password} onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-12 pr-4 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm"
                placeholder="••••••••"
              />
            </div>
          </div>

          <button 
            disabled={loading} type="submit" 
            className={`w-full py-6 bg-blue-600 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20 active:scale-95 ${loading ? 'animate-pulse opacity-90 cursor-wait' : ''}`}
          >
            {loading ? <Loader2 className="animate-spin" size={20} /> : <><LogIn size={20} /> Aceder ao ERP</>}
          </button>
        </form>

        <div className="mt-10 text-center">
          <button onClick={onBack} className="text-slate-400 hover:text-blue-600 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-colors">
            <ArrowLeft size={14} /> Voltar ao Portal Público
          </button>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect, useRef } from 'react';
import { MOCK_PROPERTIES } from '../constants';
import { 
  MapPin, BedDouble, Bath, Ruler, ArrowLeft, Share2, Heart, 
  ShieldCheck, ChevronRight, ChevronLeft, MessageSquare, Phone, Mail, 
  Maximize2, Send, Loader2, User, Bot, Sparkles, ZoomIn
} from 'lucide-react';
import { supabase } from '../supabaseClient';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'agent';
  timestamp: Date;
}

interface PropertyDetailViewProps {
  propertyId: string | null;
  onBack: () => void;
}

const PropertyDetailView: React.FC<PropertyDetailViewProps> = ({ propertyId, onBack }) => {
  const property = MOCK_PROPERTIES.find(p => p.id === propertyId);

  const images = property ? [property.image, ...property.gallery] : [];
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const thumbnailRefs = useRef<(HTMLButtonElement | null)[]>([]);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  // Chat States
  const [messages, setMessages] = useState<Message[]>([
    { id: '1', text: 'Olá! Como posso ajudar com este imóvel?', sender: 'agent', timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  // Navegação via Teclado
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight') nextImage();
      if (e.key === 'ArrowLeft') prevImage();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentIndex]);

  // Scroll automático para miniatura ativa
  useEffect(() => {
    if (thumbnailRefs.current[currentIndex] && scrollContainerRef.current) {
      thumbnailRefs.current[currentIndex]?.scrollIntoView({
        behavior: 'smooth',
        block: 'nearest',
        inline: 'center'
      });
    }
  }, [currentIndex]);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  if (!property) return (
    <div className="py-20 text-center">
      <p>Imóvel não encontrado.</p>
      <button onClick={onBack} className="text-blue-600 font-bold mt-4">Voltar</button>
    </div>
  );

  const nextImage = () => {
    triggerTransition();
    setCurrentIndex((prev) => (prev + 1) % images.length);
  };

  const prevImage = () => {
    triggerTransition();
    setCurrentIndex((prev) => (prev - 1 + images.length) % images.length);
  };

  const triggerTransition = () => {
    setIsTransitioning(true);
    setTimeout(() => setIsTransitioning(false), 300);
  };

  const handleSendMessage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      text: inputText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsSending(true);

    try {
      await supabase.from('contact_requests').insert([{
        name: 'Interessado (Chat)',
        email: 'chat@web.user',
        subject: `Dúvida Imóvel: ${property.title}`,
        message: inputText,
        created_at: new Date().toISOString()
      }]);

      setIsTyping(true);
      setTimeout(() => {
        const agentMsg: Message = {
          id: (Date.now() + 1).toString(),
          text: 'Recebemos a sua mensagem! Um dos nossos consultores irá analisar o seu pedido e responder via WhatsApp ou Email brevemente. Posso ajudar com mais alguma coisa?',
          sender: 'agent',
          timestamp: new Date()
        };
        setMessages(prev => [...prev, agentMsg]);
        setIsTyping(false);
      }, 1500);

    } catch (err) {
      console.error("Chat error:", err);
    } finally {
      setIsSending(false);
    }
  };

  return (
    <div className="max-w-7xl mx-auto py-12 px-4 md:px-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Breadcrumbs & Actions */}
      <div className="flex items-center justify-between mb-8">
        <button onClick={onBack} className="flex items-center gap-2 text-slate-500 hover:text-blue-600 font-bold text-sm transition-all group">
          <ArrowLeft size={18} className="group-hover:-translate-x-1 transition-transform" /> Voltar ao Catálogo
        </button>
        <div className="flex gap-2">
           <button className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:text-blue-600 transition-all" title="Partilhar"><Share2 size={18} /></button>
           <button className="p-2.5 bg-white border border-slate-200 rounded-xl text-slate-500 hover:text-red-500 transition-all" title="Favoritos"><Heart size={18} /></button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">
        {/* Main Content (Images & Info) */}
        <div className="lg:col-span-2 space-y-10">
          {/* Gallery Section */}
          <div className="space-y-6">
            <div className="relative group aspect-video rounded-[2.5rem] overflow-hidden shadow-2xl bg-slate-100">
              <img 
                src={images[currentIndex]} 
                alt={`${property.title} - Imagem ${currentIndex + 1}`} 
                className={`w-full h-full object-cover transition-all duration-500 transform ${isTransitioning ? 'opacity-0 scale-105' : 'opacity-100 scale-100'}`}
              />

              <div className="absolute inset-0 flex items-center justify-between px-6 opacity-0 group-hover:opacity-100 transition-opacity z-20">
                <button 
                  onClick={prevImage}
                  className="p-4 bg-white/90 backdrop-blur-md text-slate-900 rounded-full shadow-lg hover:bg-blue-600 hover:text-white transition-all transform hover:scale-110 active:scale-90"
                >
                  <ChevronLeft size={28} />
                </button>
                <button 
                  onClick={nextImage}
                  className="p-4 bg-white/90 backdrop-blur-md text-slate-900 rounded-full shadow-lg hover:bg-blue-600 hover:text-white transition-all transform hover:scale-110 active:scale-90"
                >
                  <ChevronRight size={28} />
                </button>
              </div>

              <div className="absolute top-6 left-6 flex gap-3 z-20">
                <div className="bg-blue-600 text-white px-5 py-2 rounded-full font-black text-xs uppercase tracking-widest shadow-lg flex items-center gap-2">
                   <ShieldCheck size={14} /> {property.dealType}
                </div>
                <div className="bg-white/90 backdrop-blur-md text-slate-900 px-5 py-2 rounded-full font-black text-xs uppercase tracking-widest shadow-lg flex items-center gap-2">
                  <Maximize2 size={14} /> {currentIndex + 1} / {images.length}
                </div>
              </div>

              <div className="absolute bottom-6 right-6 z-20">
                <button className="p-4 bg-white/20 backdrop-blur-lg hover:bg-white/40 text-white rounded-2xl transition-all border border-white/30 group/btn">
                  <ZoomIn size={24} className="group-hover/btn:scale-125 transition-transform" />
                </button>
              </div>
            </div>

            {/* Thumbnail Carousel */}
            <div 
              ref={scrollContainerRef}
              className="flex gap-4 overflow-x-auto pb-4 scrollbar-hide px-1"
            >
              {images.map((img, i) => (
                <button 
                  key={i} 
                  ref={el => thumbnailRefs.current[i] = el}
                  onClick={() => {
                    triggerTransition();
                    setCurrentIndex(i);
                  }}
                  className={`relative shrink-0 w-36 aspect-[4/3] rounded-2xl overflow-hidden border-4 transition-all duration-300 ${
                    currentIndex === i 
                    ? 'border-blue-600 ring-4 ring-blue-100 scale-95 opacity-100 shadow-xl' 
                    : 'border-transparent opacity-60 hover:opacity-100 grayscale hover:grayscale-0'
                  }`}
                >
                  <img src={img} className="w-full h-full object-cover" alt={`Miniatura ${i + 1}`} />
                  {currentIndex === i && (
                    <div className="absolute inset-0 bg-blue-600/10 flex items-center justify-center">
                      <div className="w-2 h-2 bg-blue-600 rounded-full animate-ping"></div>
                    </div>
                  )}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-white p-8 md:p-12 rounded-[2.5rem] border border-slate-100 shadow-sm">
             <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10">
                <div>
                  <h1 className="text-4xl font-black text-slate-900 mb-3 tracking-tight">{property.title}</h1>
                  <p className="flex items-center gap-2 text-slate-500 font-medium text-lg">
                    <MapPin size={22} className="text-blue-600" /> {property.location}, Moçambique
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Valor de {property.dealType === 'Venda' ? 'Venda' : 'Renda'}</p>
                  <p className="text-5xl font-black text-blue-600 tracking-tighter">
                    {property.price.toLocaleString('pt-MZ', { style: 'currency', currency: 'MZN', minimumFractionDigits: 0 })}
                  </p>
                </div>
             </div>

             <div className="grid grid-cols-2 md:grid-cols-4 gap-4 py-10 border-y border-slate-50">
                {[
                  { icon: <BedDouble size={28} />, label: 'Quartos', value: property.beds },
                  { icon: <Bath size={28} />, label: 'Banheiros', value: property.baths },
                  { icon: <Ruler size={28} />, label: 'Área Total', value: `${property.area} m²` },
                  { icon: <ShieldCheck size={28} />, label: 'Vigilância', value: 'Disponível' },
                ].map((stat, i) => (
                  <div key={i} className="flex flex-col items-center text-center p-6 bg-slate-50 rounded-[2rem] hover:bg-blue-50 transition-all duration-300 cursor-default group">
                    <div className="text-blue-600 mb-3 group-hover:scale-110 transition-transform">{stat.icon}</div>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{stat.label}</span>
                    <span className="text-lg font-black text-slate-900">{stat.value}</span>
                  </div>
                ))}
             </div>

             <div className="mt-10 space-y-8">
                <div className="flex items-center gap-3">
                  <div className="w-1.5 h-8 bg-blue-600 rounded-full"></div>
                  <h2 className="text-2xl font-black text-slate-900">Sobre este Imóvel</h2>
                </div>
                <div className="prose prose-slate max-w-none">
                  <p className="text-slate-600 leading-relaxed font-medium text-lg">
                    {property.description}
                  </p>
                </div>
             </div>
          </div>
        </div>

        {/* Sidebar with Chat */}
        <aside className="space-y-8">
           <div className="bg-white rounded-[3rem] border border-slate-100 shadow-xl overflow-hidden flex flex-col h-[650px] sticky top-24">
              {/* Agent Header */}
              <div className="p-8 bg-slate-900 text-white flex items-center gap-4">
                <div className="relative">
                  <img src={`https://picsum.photos/seed/agent_${property.id}/100`} className="w-14 h-14 rounded-2xl object-cover ring-2 ring-blue-500" alt="Consultor" />
                  <span className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-2 border-slate-900 rounded-full animate-pulse"></span>
                </div>
                <div>
                  <p className="text-base font-black text-white leading-none mb-1">Equipa Comercial</p>
                  <p className="text-[10px] font-bold text-blue-400 uppercase tracking-widest">Online Agora</p>
                </div>
              </div>

              {/* Chat Body */}
              <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar bg-slate-50/50">
                {messages.map((msg) => (
                  <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-${msg.sender === 'user' ? 'right' : 'left'}-2`}>
                    <div className={`max-w-[85%] p-4 rounded-2xl text-sm font-medium shadow-sm ${
                      msg.sender === 'user' 
                        ? 'bg-blue-600 text-white rounded-tr-none' 
                        : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'
                    }`}>
                      {msg.text}
                      <p className={`text-[9px] mt-1 opacity-60 ${msg.sender === 'user' ? 'text-blue-100' : 'text-slate-400'}`}>
                        {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                      </p>
                    </div>
                  </div>
                ))}
                {isTyping && (
                  <div className="flex justify-start animate-pulse">
                    <div className="bg-white border border-slate-100 p-3 rounded-2xl rounded-tl-none flex gap-1 shadow-sm">
                      <span className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce"></span>
                      <span className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.2s]"></span>
                      <span className="w-1.5 h-1.5 bg-slate-300 rounded-full animate-bounce [animation-delay:0.4s]"></span>
                    </div>
                  </div>
                )}
                <div ref={chatEndRef} />
              </div>

              {/* Chat Input */}
              <div className="p-6 bg-white border-t border-slate-100">
                <form onSubmit={handleSendMessage} className="flex items-center gap-2 mb-4">
                  <input 
                    type="text"
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                    placeholder="Tire suas dúvidas..."
                    className="flex-1 bg-slate-50 border-none rounded-xl px-4 py-4 text-sm font-bold focus:ring-2 focus:ring-blue-600 transition-all outline-none"
                  />
                  <button 
                    type="submit"
                    disabled={!inputText.trim() || isSending}
                    className="p-4 bg-blue-600 text-white rounded-xl hover:bg-blue-700 disabled:opacity-50 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
                  >
                    {isSending ? <Loader2 size={20} className="animate-spin" /> : <Send size={20} />}
                  </button>
                </form>
                <div className="flex flex-wrap gap-2">
                   {[
                     { text: 'Valor final?', icon: <Sparkles size={10}/> },
                     { text: 'Financiamento?', icon: <ShieldCheck size={10}/> },
                     { text: 'Visitar agora!', icon: <MapPin size={10}/> }
                   ].map((btn, i) => (
                     <button 
                       key={i}
                       type="button"
                       onClick={() => setInputText(btn.text)}
                       className="text-[9px] font-black uppercase text-slate-500 bg-slate-50 px-3 py-2 rounded-lg hover:text-blue-600 hover:bg-blue-50 transition-all border border-slate-100 flex items-center gap-1.5"
                     >
                       {btn.icon} {btn.text}
                     </button>
                   ))}
                </div>
              </div>
           </div>

           <div className="grid grid-cols-2 gap-4">
              <a href="tel:+258875018283" className="flex items-center justify-center gap-3 py-5 bg-slate-900 text-white rounded-2xl font-black text-xs hover:bg-slate-800 transition-all shadow-lg active:scale-95"><Phone size={16}/> Ligar</a>
              <a href={`mailto:monteimobiliario@gmail.com?subject=Interesse: ${property.title}`} className="flex items-center justify-center gap-3 py-5 bg-white border border-slate-200 text-slate-900 rounded-2xl font-black text-xs hover:bg-slate-50 transition-all shadow-sm active:scale-95"><Mail size={16}/> Email</a>
           </div>
        </aside>
      </div>
    </div>
  );
};

