import React, { useState, useEffect, useRef } from 'react';
import { User, Property } from '../types';
import { Bell, Search, LogOut, Menu, Loader2, Home, MapPin, ChevronRight, X } from 'lucide-react';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  user: User;
  onLogout: () => void;
  onOpenSidebar: () => void;
  onViewProperty: (id: string) => void;
}

const Header: React.FC<HeaderProps> = ({ user, onLogout, onOpenSidebar, onViewProperty }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Property[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const searchRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim().length < 2) {
        setResults([]);
        setIsSearching(false);
        return;
      }

      setIsSearching(true);
      try {
        const { data, error } = await supabase
          .from('properties')
          .select('*')
          .or(`title.ilike.%${query}%,location.ilike.%${query}%`)
          .limit(5);

        if (!error && data) {
          setResults(data);
        }
      } catch (err) {
        console.error("Search error:", err);
      } finally {
        setIsSearching(false);
        setShowResults(true);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  const handleSelectResult = (id: string) => {
    onViewProperty(id);
    setQuery('');
    setShowResults(false);
  };

  return (
    <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-4 md:px-8 shrink-0 relative z-[60]">
      <div className="flex items-center gap-4 flex-1">
        <button onClick={onOpenSidebar} className="md:hidden text-slate-500 p-2 hover:bg-slate-100 rounded-lg">
          <Menu size={24} />
        </button>

        {/* Global Search Bar */}
        <div ref={searchRef} className="hidden sm:flex relative max-w-xs md:max-w-md w-full">
          <span className="absolute inset-y-0 left-3 flex items-center text-slate-400">
            {isSearching ? <Loader2 size={18} className="animate-spin text-blue-600" /> : <Search size={18} />}
          </span>
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => query.length >= 2 && setShowResults(true)}
            placeholder="Pesquisar imóveis (Título ou Local)..."
            className="w-full pl-10 pr-10 py-2.5 bg-slate-50 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent text-sm font-medium transition-all"
          />
          {query && (
            <button 
              onClick={() => {setQuery(''); setResults([]);}} 
              className="absolute inset-y-0 right-3 flex items-center text-slate-400 hover:text-slate-600"
            >
              <X size={16} />
            </button>
          )}

          {/* Search Results Panel */}
          {showResults && (query.length >= 2) && (
            <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-2xl border border-slate-100 overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
              <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Resultados Cloud</span>
                {results.length > 0 && <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">{results.length} encontrados</span>}
              </div>

              <div className="max-h-[350px] overflow-y-auto custom-scrollbar">
                {results.length > 0 ? (
                  results.map((prop) => (
                    <button
                      key={prop.id}
                      onClick={() => handleSelectResult(prop.id)}
                      className="w-full flex items-center gap-4 p-4 hover:bg-slate-50 transition-colors text-left border-b border-slate-50 last:border-0 group"
                    >
                      <img 
                        src={prop.image} 
                        alt="" 
                        className="w-12 h-12 rounded-lg object-cover shadow-sm group-hover:scale-105 transition-transform"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-sm font-bold text-slate-900 truncate group-hover:text-blue-600 transition-colors">{prop.title}</p>
                        <div className="flex items-center gap-2 text-[10px] text-slate-500 font-medium">
                          <MapPin size={10} className="text-blue-500" />
                          <span className="truncate">{prop.location}</span>
                        </div>
                      </div>
                      <div className="text-right shrink-0">
                        <p className="text-xs font-black text-blue-600">{prop.price.toLocaleString()} MT</p>
                        <ChevronRight size={14} className="text-slate-300 ml-auto mt-1 group-hover:translate-x-1 transition-transform" />
                      </div>
                    </button>
                  ))
                ) : !isSearching ? (
                  <div className="p-8 text-center">
                    <Home size={32} className="mx-auto text-slate-200 mb-2" />
                    <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Nenhum imóvel encontrado</p>
                  </div>
                ) : (
                  <div className="p-8 text-center flex flex-col items-center gap-2">
                    <Loader2 size={24} className="animate-spin text-blue-500" />
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Buscando na Cloud...</p>
                  </div>
                )}
              </div>

              {results.length > 0 && (
                <div className="p-3 bg-slate-50 text-center border-t border-slate-100">
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Use as setas para navegar e Enter para selecionar</span>
                </div>
              )}
            </div>
          )}
        </div>
      </div>

      <div className="flex items-center gap-4 md:gap-6">
        <button className="relative p-2 text-slate-500 hover:bg-slate-50 rounded-full">
          <Bell size={20} />
          <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 border-2 border-white rounded-full"></span>
        </button>

        <div className="h-8 w-px bg-slate-200"></div>

        <div className="flex items-center gap-3">
          <div className="text-right hidden sm:block">
            <p className="text-sm font-semibold text-slate-900 leading-none">{user.name}</p>
            <p className="text-xs text-slate-500 mt-1">{user.role}</p>
          </div>
          <img src={user.avatar} alt={user.name} className="w-10 h-10 rounded-xl object-cover ring-2 ring-slate-100" />
          <button 
            onClick={onLogout}
            className="ml-2 p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
            title="Sair do sistema"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>
    </header>
  );
};

