  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  const sqlSchema = `-- MONTE HUB CLOUD INFRASTRUCTURE SCRIPT v4.1
-- Execute este script no SQL Editor do Supabase para inicializar o banco de dados.

-- 1. Gestão de Cargos (Com Soft Delete)
CREATE TABLE IF NOT EXISTS public.roles (
