      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[]) => {
    if (!editingUser) return;
    const currentPerms = editingUser.permissions || [];
    const idsInCategory = permsInCategory.map(p => p.id);
    const allSelected = idsInCategory.every(id => currentPerms.includes(id));
    const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const filteredRoles = useMemo(() => {
    return roles.filter(r => r.is_deleted === showDeletedRoles);
  }, [roles, showDeletedRoles]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Monitorização e governança de privilégios cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowRolesModal(true)} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <Award size={16} className="text-blue-600" /> Gerir Cargos
           </button>
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Histórico Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-4 mb-6"><Database size={24} className="text-indigo-400" /><h3 className="text-xl font-black">Infraestrutura Supabase Cloud</h3></div>
        <p className="text-xs text-slate-400 mb-4 font-medium leading-relaxed">Se estiver a receber erro de tabela não encontrada, copie o script abaixo, vá ao **SQL Editor** do Supabase e clique em **Run**. Isto criará todas as tabelas (incluindo Recrutamento, Leads e Tarefas).</p>
        <pre className="bg-slate-800 p-6 rounded-2xl text-[10px] text-indigo-200 font-mono overflow-x-auto mb-6 max-h-80 custom-scrollbar border border-white/5 selection:bg-indigo-500">{sqlSchema}</pre>
        <button onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="flex items-center gap-2 px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-xl shadow-indigo-500/20 active:scale-95">
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado para o Clipboard!' : 'Copiar Script de Reparação SQL'}
        </button>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar utilizador..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Acesso Granular</th>
                <th className="px-10 py-6 text-right">Acção</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8"><div className="flex items-center gap-5"><img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover" alt="" /><div><p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p><span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span></div></div></td>
                  <td className="px-10 py-8"><div className="flex flex-wrap justify-center gap-1.5">{user.permissions?.length ? user.permissions.slice(0, 3).map(p => (<span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>)) : <span className="text-[9px] font-black text-slate-300 italic uppercase">Padrão</span>}</div></td>
                  <td className="px-10 py-8 text-right"><button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100"><UserCog size={22} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10"><img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover shadow-lg" alt="" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Sincronização Cloud de Privilégios</p></div></div>
            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Atribuição de Cargo</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-indigo-600">
                  {roles.filter(r => !r.is_deleted).map(r => <option key={r.name} value={r.name}>{r.name}</option>)}
                </select>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2"><h3 className="text-xs font-black uppercase text-slate-900">{category}</h3><button type="button" onClick={() => toggleCategory(category, perms)} className="text-[9px] font-black uppercase text-indigo-600 bg-indigo-50 px-4 py-1.5 rounded-full">Alternar Grupo</button></div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">{perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (<button key={p.id} type="button" onClick={() => togglePermission(p.id)} className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all ${isActive ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'}`}><div className="flex items-center justify-between mb-3"><div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div></div><span className="text-[11px] font-black uppercase mb-1">{p.label}</span><span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span></button>);
                        })}</div>
                    </div>
                ))}
              </div>
              <button disabled={saving} type="submit" className="w-full py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3">
                {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Sincronizar Permissões</>}
              </button>
            </form>
          </div>
        </div>
      )}

      {showRolesModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-2xl w-full shadow-2xl relative flex flex-col max-h-[90vh]">
            <button onClick={() => { setShowRolesModal(false); setShowDeletedRoles(false); }} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center justify-between mb-10">
              <div className="flex items-center gap-4">
                <Award size={24} className="text-blue-600" />
                <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{showDeletedRoles ? 'Reciclagem de Cargos' : 'Gestão de Cargos'}</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Hierarquia Monte Imobiliária</p>
                </div>
              </div>

              <button 
                onClick={() => setShowDeletedRoles(!showDeletedRoles)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${showDeletedRoles ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}
              >
                {showDeletedRoles ? <Eye size={14} /> : <EyeOff size={14} />}
                {showDeletedRoles ? 'Ver Ativos' : 'Ver Eliminados'}
              </button>
            </div>

            {!showDeletedRoles && (
              <div className="mb-8 space-y-4">
                <div className="flex gap-4">
                  <input 
                    value={newRoleName} 
                    onChange={e => setNewRoleName(e.target.value)}
                    placeholder="Novo Cargo (Ex: Analista de Dados)" 
                    className="flex-1 bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-blue-600"
                  />
                  <button 
                    onClick={handleAddRole}
                    disabled={rolesLoading || !newRoleName.trim()}
                    className="px-8 py-5 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-700 disabled:opacity-50 transition-all"
                  >
                    {rolesLoading ? <Loader2 className="animate-spin" /> : 'Adicionar'}
                  </button>
                </div>
              </div>
            )}

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-3">
              {filteredRoles.length === 0 ? (
                <div className="py-20 text-center flex flex-col items-center gap-3 opacity-30">
                  <Award size={48} />
                  <p className="text-xs font-black uppercase tracking-widest">Nenhum cargo {showDeletedRoles ? 'eliminado' : 'ativo'}</p>
                </div>
              ) : filteredRoles.map((role) => (
                <div key={role.name} className={`p-5 rounded-[1.5rem] border flex items-center justify-between group transition-all ${role.is_deleted ? 'bg-slate-50 border-slate-100 opacity-60' : 'bg-white border-slate-100 shadow-sm'}`}>
                  {editingRoleName?.old === role.name ? (
                    <div className="flex-1 flex gap-3">
                      <input 
                        autoFocus
                        value={editingRoleName.new}
                        onChange={e => setEditingRoleName({...editingRoleName, new: e.target.value})}
                        className="flex-1 bg-white rounded-xl px-4 py-2 font-bold text-sm outline-none ring-2 ring-blue-500"
                      />
                      <button onClick={handleUpdateRole} className="p-2 bg-blue-600 text-white rounded-xl"><Check size={16} /></button>
                      <button onClick={() => setEditingRoleName(null)} className="p-2 bg-slate-200 text-slate-500 rounded-xl"><X size={16} /></button>
                    </div>
                  ) : (
                    <>
                      <div className="flex items-center gap-3">
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-black text-xs ${role.is_deleted ? 'bg-slate-200 text-slate-400' : 'bg-blue-100 text-blue-600'}`}>
                          {role.name.charAt(0)}
                        </div>
                        <span className={`font-bold text-sm ${role.is_deleted ? 'text-slate-400' : 'text-slate-900'}`}>{role.name}</span>
                      </div>
                      <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        {role.is_deleted ? (
                          <button 
                            onClick={() => handleReactivateRole(role.name)} 
                            className="flex items-center gap-3 px-4 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-[10px] font-black uppercase tracking-tighter hover:bg-emerald-100 transition-all shadow-sm"
                            title="Reativar Cargo"
                          >
                            <RotateCcw size={14} /> Reativar
                          </button>
                        ) : (
                          <>
                            <button onClick={() => setEditingRoleName({old: role.name, new: role.name})} className="p-2 text-slate-400 hover:text-blue-600"><Edit size={16} /></button>
                            <button onClick={() => handleDeleteRole(role.name)} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 size={16} /></button>
                          </>
                        )}
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
            <div className="mt-8 pt-8 border-t border-slate-100 text-center">
              <button onClick={() => { setShowRolesModal(false); setShowDeletedRoles(false); }} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all">Concluído</button>
            </div>
          </div>
        </div>
      )}

      {showAuditModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-5xl w-full shadow-2xl relative flex flex-col max-h-[90vh]">
            <button onClick={() => setShowAuditModal(false)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10"><Activity size={24} className="text-indigo-600" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">Auditoria Cloud</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Rastreabilidade total do sistema</p></div></div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
              {loadingLogs ? <div className="py-20 flex justify-center"><Loader2 className="animate-spin text-indigo-600" size={32} /></div> : auditLogs.map((log) => (
                <div key={log.id} className="p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100"><div className="flex justify-between gap-4 mb-4"><div className="flex items-center gap-3"><div className="px-3 py-1 bg-indigo-600 text-white rounded-lg text-[9px] font-black uppercase">{log.action_type}</div><div className="text-slate-900 font-bold text-sm">Por: {log.admin_name} -> {log.target_user_name}</div></div><div className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{new Date(log.created_at).toLocaleString('pt-MZ')}</div></div><div className="p-4 bg-white rounded-2xl border border-slate-100 text-[11px] text-slate-600 leading-relaxed italic">{log.change_details}</div></div>
              ))}
            </div>
            <div className="mt-8 pt-8 border-t border-slate-100 text-center"><button onClick={() => setShowAuditModal(false)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase hover:bg-indigo-600 transition-all">Fechar Histórico</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  ChevronUp, 
  AlertCircle,
  LayoutList,
  Search
} from 'lucide-react';
import { Task } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        // Mock data if table doesn't exist yet
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada para o lote 45.', completed: false, priority: 'Alta' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza dos filtros no 2º andar.', completed: true, priority: 'Média' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;

    const newTask = {
      title: newTaskTitle,
      description: '',
      completed: false,
      priority: 'Média' as const
    };

    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setExpandedId(data[0].id); // Expand new task by default
      } else {
        // Local only fallback
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) {
      console.error(e);
    }
  };

  const toggleComplete = async (task: Task) => {
    try {
      const { error } = await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      if (!error) {
        setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
      }
    } catch (e) {
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    try {
      await supabase.from('tasks').update({ description }).eq('id', id);
    } catch (e) {}
  };

  const deleteTask = async (id: string) => {
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', id);
      if (!error) {
        setTasks(tasks.filter(t => t.id !== id));
      }
    } catch (e) {
      setTasks(tasks.filter(t => t.id !== id));
    }
  };

  const filteredTasks = tasks.filter(task => 
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full">
      <div className="p-8 border-b border-slate-50 flex items-center justify-between">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Tarefas Diárias
        </h3>
        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1 rounded-full">
          {tasks.filter(t => !t.completed).length} pendentes
        </span>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/30 space-y-4">
        <form onSubmit={handleAddTask} className="flex gap-2">
          <input 
            type="text" 
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="O que precisa ser feito hoje?"
            className="flex-1 bg-white rounded-xl px-4 py-3 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm"
          />
          <button 
            type="submit"
            className="p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
          >
            <Plus size={20} />
          </button>
        </form>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input 
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Procurar nas tarefas..."
            className="w-full pl-10 pr-4 py-2.5 text-xs font-bold bg-white rounded-xl border border-slate-100 focus:ring-2 focus:ring-blue-100 outline-none transition-all"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
        {filteredTasks.map((task) => (
          <div 
            key={task.id} 
            className={`group bg-white border rounded-2xl transition-all duration-300 ${
              expandedId === task.id ? 'border-blue-200 shadow-lg' : 'border-slate-100 hover:border-blue-100'
            }`}
          >
            <div className="p-4 flex items-center gap-4">
              <button 
                onClick={() => toggleComplete(task)}
                className={`transition-colors ${task.completed ? 'text-emerald-500' : 'text-slate-300 hover:text-blue-500'}`}
              >
                {task.completed ? <CheckCircle2 size={22} /> : <Circle size={22} />}
              </button>

              <div className="flex-1 min-w-0" onClick={() => setExpandedId(expandedId === task.id ? null : task.id)}>
                <p className={`text-sm font-bold truncate transition-all ${
                  task.completed ? 'text-slate-400 line-through italic' : 'text-slate-900'
                }`}>
                  {task.title}
                </p>
              </div>

              <div className="flex items-center gap-2">
                <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded ${
                  task.priority === 'Alta' ? 'bg-rose-50 text-rose-600' : 
                  task.priority === 'Média' ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-400'
                }`}>
                  {task.priority}
                </span>
                <button 
                  onClick={() => setExpandedId(expandedId === task.id ? null : task.id)}
                  className="p-1.5 text-slate-300 hover:text-blue-600 transition-all"
                >
                  {expandedId === task.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                </button>
                <button 
                  onClick={() => deleteTask(task.id)}
                  className="p-1.5 text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>

            {expandedId === task.id && (
              <div className="px-12 pb-5 pt-0 animate-in slide-in-from-top-2 duration-300">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                    <AlertCircle size={10} className="text-blue-500" /> Detalhes da Tarefa
                  </label>
                  <textarea 
                    value={task.description}
                    onChange={(e) => updateDescription(task.id, e.target.value)}
                    rows={3}
                    className="w-full bg-slate-50 rounded-xl p-4 text-[13px] font-medium text-slate-600 border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none custom-scrollbar"
                    placeholder="Adicione uma descrição detalhada aqui..."
                  />
                </div>
              </div>
            )}
          </div>
        ))}

        {filteredTasks.length === 0 && (
          <div className="py-20 text-center flex flex-col items-center gap-3 opacity-30">
            <Search size={48} />
            <p className="text-xs font-black uppercase tracking-widest">Nenhuma tarefa encontrada</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Shield, Key, UserCog, Save, 
  CheckCircle2, Loader2, Search,
  Fingerprint, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Users as UsersIcon, Terminal, Plus, Settings2,
  ChevronRight, History, Activity, Calendar, Award,
  RotateCcw, EyeOff, ShieldAlert, Lock
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee, User } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

interface AuditLog {
  id: string;
  admin_name: string;
  target_user_name: string;
  action_type: string;
  change_details: string;
  created_at: string;
}

interface RoleRecord {
  id: string;
  name: string;
  is_deleted: boolean;
  permissions: string[];
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  { id: 'finance.view', label: 'Ver Finanças', category: 'Financeiro', description: 'Consultar relatórios e saldos.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Criar Lançamentos', category: 'Financeiro', description: 'Adicionar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Remover Registos', category: 'Financeiro', description: 'Eliminar transações do fluxo.', icon: <Trash2 size={14} /> },
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista e status de contratos.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Controlar projetos e orçamentos.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Gerir imóveis e portfólio.', icon: <LayoutGrid size={14} /> },
  { id: 'admin.access', label: 'Full TI Admin', category: 'Sistema', description: 'Acesso total às ferramentas TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Logs Auditoria', category: 'Sistema', description: 'Rastrear todas as mudanças.', icon: <Terminal size={14} /> },
];

interface AdminViewProps {
  currentUser: User | null;
}

const AdminView: React.FC<AdminViewProps> = ({ currentUser }) => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<RoleRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [originalUserState, setOriginalUserState] = useState<Employee | null>(null);

  const [showRolesModal, setShowRolesModal] = useState(false);
  const [showDeletedRoles, setShowDeletedRoles] = useState(false);
  const [newRoleName, setNewRoleName] = useState('');
  const [editingRoleName, setEditingRoleName] = useState<{old: string, new: string} | null>(null);
  const [editingRolePermissions, setEditingRolePermissions] = useState<RoleRecord | null>(null);
  const [rolesLoading, setRolesLoading] = useState(false);

  const [showAuditModal, setShowAuditModal] = useState(false);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  const sqlSchema = `-- MONTE HUB FULL INFRASTRUCTURE SETUP v4.7
-- COPIE E EXECUTE ESTE SCRIPT NO "SQL EDITOR" DO SUPABASE

-- 1. Tabela de Cargos (Suporte a Permissões Granulares)
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    is_deleted boolean DEFAULT false,
    permissions text[] DEFAULT '{}',
    created_at timestamptz DEFAULT now()
);

-- Garantir que a coluna permissions existe (caso a tabela já tenha sido criada)
DO $$ 
BEGIN 
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name='roles' AND column_name='permissions') THEN
        ALTER TABLE public.roles ADD COLUMN permissions text[] DEFAULT '{}';
    END IF;
END $$;

-- 2. Tabela de Colaboradores (ERP CORE)
CREATE TABLE IF NOT EXISTS public.employees (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text NOT NULL,
    email text UNIQUE NOT NULL,
    role text NOT NULL,
    department text,
    salary numeric DEFAULT 0,
    status text DEFAULT 'Ativo',
    avatar text,
    phone text,
    permissions text[] DEFAULT '{}',
    document_type text,
    document_number text,
    document_expiry date,
    payment_method text,
    contract_start date,
    created_at timestamptz DEFAULT now()
);

-- (Restante das tabelas omitido para brevidade no SQL Editor, mas mantido na base de dados)
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    setRolesLoading(true);
    try {
      const { data, error } = await supabase.from('roles').select('*').order('name');
      if (!error && data) {
        setRoles(data);
      } else {
        const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
        setRoles(fallbackRoles);
      }
    } catch (e) { 
      const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
      setRoles(fallbackRoles);
    } finally {
      setRolesLoading(false);
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) { console.warn("Error fetching users"); }
    finally { setLoading(false); }
  }

  async function fetchAuditLogs() {
    setLoadingLogs(true);
    try {
      const { data, error } = await supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);
      if (!error) setAuditLogs(data || []);
    } catch (e) { console.warn("Error fetching logs"); }
    finally { setLoadingLogs(false); }
  }

  const handleAddRole = async () => {
    if (!newRoleName.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase.from('roles').insert([{ name: newRoleName.trim(), is_deleted: false, permissions: [] }]);
      if (error) throw error;
      setNewRoleName('');
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao adicionar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateRole = async () => {
    if (!editingRoleName || !editingRoleName.new.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ name: editingRoleName.new.trim() })
        .eq('name', editingRoleName.old);
      if (error) throw error;
      setEditingRoleName(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao atualizar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleSaveRolePermissions = async () => {
    if (!editingRolePermissions) return;
    setSaving(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ permissions: editingRolePermissions.permissions })
        .eq('id', editingRolePermissions.id);
      if (error) throw error;

      if (currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_name: `Cargo: ${editingRolePermissions.name}`,
          action_type: 'CARGO_PRIVILEGIOS',
          change_details: `Template de permissões atualizado para o cargo ${editingRolePermissions.name}`
        }]);
      }

      setEditingRolePermissions(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao salvar permissões do cargo: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteRole = async (name: string) => {
    if (!confirm(`Deseja desativar o cargo "${name}"? Ele será movido para a reciclagem.`)) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: true })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao desativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleReactivateRole = async (name: string) => {
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: false })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao reativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateUserPermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser || !originalUserState) return;
    setSaving(true);
    const changes = [];
    if (editingUser.role !== originalUserState.role) changes.push(`Cargo: [${originalUserState.role}] -> [${editingUser.role}]`);
    const oldPerms = originalUserState.permissions || [];
    const newPerms = editingUser.permissions || [];
    const added = newPerms.filter(p => !oldPerms.includes(p));
    const removed = oldPerms.filter(p => !newPerms.includes(p));
    if (added.length > 0) changes.push(`+ Permissões: ${added.join(', ')}`);
    if (removed.length > 0) changes.push(`- Permissões: ${removed.join(', ')}`);

    try {
      const { error } = await supabase.from('employees').update({ role: editingUser.role, permissions: editingUser.permissions || [] }).eq('id', editingUser.id);
      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const toggleUserPermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleRolePermission = (permId: string) => {
    if (!editingRolePermissions) return;
    const current = editingRolePermissions.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[], target: 'user' | 'role') => {
    const idsInCategory = permsInCategory.map(p => p.id);

    if (target === 'user' && editingUser) {
      const currentPerms = editingUser.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingUser({ ...editingUser, permissions: newPerms });
    } else if (target === 'role' && editingRolePermissions) {
      const currentPerms = editingRolePermissions.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
    }
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const filteredRoles = useMemo(() => {
    return roles.filter(r => r.is_deleted === showDeletedRoles);
  }, [roles, showDeletedRoles]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Monitorização e governança de privilégios cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowRolesModal(true)} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <Award size={16} className="text-blue-600" /> Gerir Cargos
           </button>
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Histórico Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-4 mb-6"><Database size={24} className="text-indigo-400" /><h3 className="text-xl font-black">Infraestrutura Supabase Cloud</h3></div>
        <p className="text-xs text-slate-400 mb-4 font-medium leading-relaxed">Se estiver a receber erro de tabela não encontrada ou coluna ausente, copie o script abaixo, vá ao **SQL Editor** do Supabase e clique em **Run**.</p>
        <pre className="bg-slate-800 p-6 rounded-2xl text-[10px] text-indigo-200 font-mono overflow-x-auto mb-6 max-h-80 custom-scrollbar border border-white/5 selection:bg-indigo-500">{sqlSchema}</pre>
        <button onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="flex items-center gap-2 px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all shadow-xl shadow-indigo-500/20 active:scale-95">
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado para o Clipboard!' : 'Copiar Script de Reparação SQL'}
        </button>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar utilizador..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Acesso Granular</th>
                <th className="px-10 py-6 text-right">Acção</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8"><div className="flex items-center gap-5"><img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover" alt="" /><div><p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p><span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span></div></div></td>
                  <td className="px-10 py-8"><div className="flex flex-wrap justify-center gap-1.5">{user.permissions?.length ? user.permissions.slice(0, 3).map(p => (<span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>)) : <span className="text-[9px] font-black text-slate-300 italic uppercase">Padrão</span>}</div></td>
                  <td className="px-10 py-8 text-right"><button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100"><UserCog size={22} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10"><img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover shadow-lg" alt="" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Sincronização Cloud de Privilégios</p></div></div>
            <form onSubmit={handleUpdateUserPermissions} className="space-y-12">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Atribuição de Cargo</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-indigo-600">
                  {roles.filter(r => !r.is_deleted).map(r => <option key={r.name} value={r.name}>{r.name}</option>)}
                </select>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2"><h3 className="text-xs font-black uppercase text-slate-900">{category}</h3><button type="button" onClick={() => toggleCategory(category, perms, 'user')} className="text-[9px] font-black uppercase text-indigo-600 bg-indigo-50 px-4 py-1.5 rounded-full">Alternar Grupo</button></div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">{perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (<button key={p.id} type="button" onClick={() => toggleUserPermission(p.id)} className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all ${isActive ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'}`}><div className="flex items-center justify-between mb-3"><div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div></div><span className="text-[11px] font-black uppercase mb-1">{p.label}</span><span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span></button>);
                        })}</div>
                    </div>
                ))}
              </div>
              <button disabled={saving} type="submit" className="w-full py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3">
                {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Sincronizar Permissões</>}
              </button>
            </form>
          </div>
