                         <Edit3 size={14} />
                       </button>
                       <button 
                        onClick={() => deleteTestimonial(t.id)}
                        className="p-2 bg-white text-slate-400 hover:text-rose-600 rounded-lg shadow-sm"
                       >
                         <Trash2 size={14} />
                       </button>
                    </div>
                 </div>
               ))}
               {testimonials.length === 0 && (
                 <div className="col-span-full py-10 text-center opacity-30 italic text-sm">Ainda sem opiniões registadas.</div>
               )}
            </div>
          </div>
        </div>

        {/* Sidebar Content */}
        <div className="space-y-8">
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-2">
