               </div>
               <button disabled={savingTestimonial} type="submit" className="w-full py-6 bg-slate-900 text-white font-black rounded-[2rem] hover:bg-amber-600 transition-all active:scale-95 flex items-center justify-center gap-3">
                  {savingTestimonial ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Guardar Opinião</>}
               </button>
            </form>
          </div>
        </div>
      )}

      {/* Quick Transaction Modal */}
      {showQuickTransaction && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-md w-full shadow-2xl relative">
            <button onClick={() => setShowQuickTransaction(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900"><CloseIcon size={28} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3"><Wallet className="text-blue-600" /> Movimento Rápido</h2>
            <form onSubmit={handleQuickTx} className="space-y-6">
               <div className="flex p-1.5 bg-slate-100 rounded-2xl">
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'RECEITA'})} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-xl transition-all ${txForm.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Receita</button>
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'DESPESA'})} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-xl transition-all ${txForm.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Despesa</button>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Descrição</label>
                  <input required value={txForm.description} onChange={e => setTxForm({...txForm, description: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-2 focus:ring-blue-600" placeholder="Ex: Material de Escritório" />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Valor (MT)</label>
                  <input required type="number" value={txForm.amount} onChange={e => setTxForm({...txForm, amount: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-black text-xl border-none outline-none focus:ring-2 focus:ring-blue-600" placeholder="0.00" />
               </div>
               <button disabled={savingTx} type="submit" className="w-full py-6 bg-slate-900 text-white font-black rounded-[2rem] hover:bg-blue-600 transition-all active:scale-95 flex items-center justify-center gap-3">
                  {savingTx ? <Loader2 className="animate-spin" /> : <><Plus size={20} /> Registar Transação</>}
               </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;

import React, { useState, useEffect } from 'react';
import { Search, MapPin, Building2, ThumbsUp, ArrowRight, Star, MessageCircle, Loader2, ShieldCheck, Sparkles } from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Property } from '../types';

interface HomeViewProps {
  onNavigate: (path: string) => void;
  onViewProperty: (id: string) => void;
}

const HERO_IMAGES = [
  // Engenheira Negra Liderando - Representação de Competência e Diversidade
  'https://images.unsplash.com/photo-1581092160607-ee22621dd758?auto=format&fit=crop&q=80&w=1600',
  // Arquitetura Moderna de Luxo
  'https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&q=80&w=1600',
  // Planeamento e Visão Técnica
  'https://images.unsplash.com/photo-1503387762-592dea58ef23?auto=format&fit=crop&q=80&w=1600',
  // Interior Sofisticado
  'https://images.unsplash.com/photo-1600566753190-17f0bcd2a6c4?auto=format&fit=crop&q=80&w=1600',
  // Paisagem Urbana/Beira Moderna
  'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80&w=1600'
];

const HomeView: React.FC<HomeViewProps> = ({ onNavigate, onViewProperty }) => {
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [featuredProperties, setFeaturedProperties] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImageIndex((prev) => (prev + 1) % HERO_IMAGES.length);
    }, 6000); // Ligeiramente mais lento para apreciar as imagens
    fetchFeatured();
    return () => clearInterval(interval);
  }, []);

  async function fetchFeatured() {
    const { data, error } = await supabase
      .from('properties')
      .select('*')
      .eq('featured', true)
      .limit(6);
    if (!error) setFeaturedProperties(data || []);
    setLoading(false);
  }

  return (
    <div className="animate-in fade-in duration-500">
      {/* Hero Section Master */}
      <section className="relative h-[600px] md:h-[750px] flex items-center justify-center overflow-hidden">
        <div className="absolute inset-0 z-0">
          {HERO_IMAGES.map((img, idx) => (
            <div 
              key={idx}
              className={`absolute inset-0 transition-all duration-1000 transform ${idx === currentImageIndex ? 'opacity-100 scale-100' : 'opacity-0 scale-110'}`}
            >
              <img 
                src={img} 
                className="w-full h-full object-cover"
                alt={`Slide ${idx + 1}`}
              />
              <div className="absolute inset-0 bg-gradient-to-b from-slate-900/60 via-slate-900/40 to-slate-900/70 backdrop-blur-[1px]"></div>
            </div>
          ))}
        </div>

        <div className="relative z-10 max-w-6xl mx-auto px-6 text-center">
          <div className="inline-flex items-center gap-2 bg-blue-600/20 backdrop-blur-xl border border-blue-400/30 px-4 py-2 rounded-full text-blue-400 text-[10px] font-black uppercase tracking-[0.2em] mb-8 animate-in slide-in-from-top-4 duration-700">
            <Sparkles size={14} /> Líder em Moçambique
          </div>

          <h1 className="text-4xl md:text-7xl font-black text-white mb-8 leading-[1.1] tracking-tighter">
            Excelência Imobiliária <br />
            com a <span className="text-blue-500 drop-shadow-sm">Monte Imobiliária</span>
          </h1>

          <p className="text-slate-200 text-lg md:text-2xl font-medium max-w-3xl mx-auto mb-12 leading-relaxed opacity-90">
            Sua visão, nossa engenharia. Transformamos o mercado da Beira com transparência, tecnologia e solidez.
          </p>

          <div className="bg-white/95 backdrop-blur-md p-3 rounded-[2rem] md:rounded-full shadow-2xl flex flex-col md:flex-row gap-3 max-w-3xl mx-auto ring-1 ring-white/20 animate-in slide-in-from-bottom-8 duration-1000">
            <div className="flex-1 flex items-center px-6 py-4 gap-4 border-b md:border-b-0 md:border-r border-slate-100">
              <MapPin size={22} className="text-blue-600" />
              <div className="text-left flex-1">
                <label className="block text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Localização</label>
                <input type="text" placeholder="Qual bairro procura na Beira?" className="w-full bg-transparent outline-none text-slate-800 font-black text-sm placeholder:text-slate-300" />
              </div>
            </div>
            <button 
              onClick={() => onNavigate('imoveis')} 
              className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-5 rounded-[1.5rem] md:rounded-full font-black flex items-center justify-center gap-3 transition-all shadow-xl shadow-blue-600/30 hover:scale-105 active:scale-95"
            >
              <Search size={20} /> <span className="uppercase text-xs tracking-widest">Explorar Catálogo</span>
            </button>
          </div>

          <div className="mt-16 flex flex-wrap justify-center gap-8 md:gap-16 opacity-70">
            {[
              { label: 'Projetos Concluídos', value: '500+' },
              { label: 'Clientes Felizes', value: '2k+' },
              { label: 'Anos de Mercado', value: '15+' },
            ].map((stat, i) => (
              <div key={i} className="text-center">
                <p className="text-2xl font-black text-white">{stat.value}</p>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{stat.label}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Featured Properties Section */}
      <section className="py-24 px-4 md:px-8 bg-white relative">
        <div className="max-w-7xl mx-auto">
          <div className="flex flex-col md:flex-row justify-between items-end mb-16 gap-6">
            <div>
              <div className="flex items-center gap-2 text-blue-600 font-black text-[10px] uppercase tracking-widest mb-3">
                <ShieldCheck size={16} /> Verificação Monte Hub
              </div>
              <h2 className="text-4xl font-black text-slate-900 tracking-tight">Imóveis em Destaque</h2>
              <p className="text-slate-500 font-medium text-lg mt-2">Fotos reais, dados verificados e transparência total.</p>
            </div>
            <button 
              onClick={() => onNavigate('imoveis')} 
              className="group px-8 py-4 bg-slate-50 text-slate-900 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3 hover:bg-blue-600 hover:text-white transition-all shadow-sm"
            >
              Ver Todos os Imóveis <ArrowRight size={18} className="group-hover:translate-x-2 transition-transform" />
            </button>
          </div>

          {loading ? (
            <div className="flex flex-col items-center justify-center py-32 gap-4">
              <Loader2 className="animate-spin text-blue-600" size={48} />
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">A carregar destaques cloud...</p>
            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
              {featuredProperties.map((property, idx) => (
                <div 
                  key={property.id} 
                  onClick={() => onViewProperty(property.id)} 
                  className="group cursor-pointer bg-white rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all duration-500 overflow-hidden animate-in fade-in slide-in-from-bottom-8"
                  style={{ animationDelay: `${idx * 100}ms`, animationFillMode: 'backwards' }}
                >
                  <div className="h-64 overflow-hidden relative">
                    <img 
                      src={property.image} 
                      className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" 
                      alt={property.title}
                    />
                    <div className="absolute top-5 left-5 flex gap-2">
                       <div className="bg-blue-600 text-white text-[9px] font-black uppercase px-4 py-1.5 rounded-full shadow-lg backdrop-blur-md">
                         {property.deal_type || property.dealType}
                       </div>
                       {property.featured && (
                         <div className="bg-amber-500 text-white text-[9px] font-black uppercase px-4 py-1.5 rounded-full shadow-lg">
                           Destaque
                         </div>
                       )}
                    </div>
                  </div>
                  <div className="p-10">
                    <div className="flex items-center justify-between mb-4">
                      <p className="text-blue-600 font-black text-2xl tracking-tighter">{property.price.toLocaleString()} MT</p>
                      <div className="flex gap-1">
                        {[1, 2, 3, 4, 5].map(s => <Star key={s} size={10} className="fill-amber-400 text-amber-400" />)}
