                  <img src="https://images.unsplash.com/photo-1573497019940-1c28c88b4f3e?auto=format&fit=crop&q=80&w=800" alt="Equipa Técnica Monte" className="w-full h-full object-cover" />
               </div>
               <div className="absolute -bottom-10 -right-10 w-64 h-64 bg-blue-600 rounded-[3rem] p-8 text-white shadow-2xl z-20 hidden md:block animate-bounce-slow">
                  <ThumbsUp size={48} className="mb-4" />
                  <p className="text-2xl font-black leading-tight tracking-tight">Qualidade <br />Garantida</p>
                  <p className="text-xs font-medium text-blue-100 mt-2">Nossa equipa de engenharia valida cada detalhe.</p>
               </div>
            </div>
            <div className="lg:w-1/2 space-y-8">
               <h2 className="text-4xl md:text-6xl font-black text-slate-900 leading-tight tracking-tighter">
                 Liderando com <br /><span className="text-blue-600">Conhecimento Técnico</span>
               </h2>
               <p className="text-lg text-slate-500 font-medium leading-relaxed">
                 Na Monte Imobiliária, não apenas vendemos casas. Oferecemos a segurança de uma equipa técnica multidisciplinar liderada por engenheiros e arquitetos experientes.
               </p>
               <div className="space-y-6">
                  {[
                    'Avaliação Técnica Rigorosa',
                    'Regularização Documental Garantida',
                    'Suporte em Reformas e Manutenção',
                    'Transparência Total no Processo'
                  ].map((item, i) => (
                    <div key={i} className="flex items-center gap-4">
                      <div className="w-6 h-6 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center"><CheckCircle2 size={16} /></div>
                      <span className="font-black text-sm text-slate-700 uppercase tracking-widest">{item}</span>
                    </div>
                  ))}
               </div>
               <button onClick={() => onNavigate('sobre')} className="px-10 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-sm uppercase tracking-widest hover:bg-blue-600 transition-all shadow-xl active:scale-95">
                 Conheça Nossa Visão
               </button>
            </div>
         </div>
      </section>
    </div>
  );
};

export default HomeView;

