        rating: testimonialForm.rating,
        status: testimonialForm.status
      };

      let res;
      if (editingTestimonialId) {
        res = await supabase.from('testimonials').update(payload).eq('id', editingTestimonialId);
      } else {
        res = await supabase.from('testimonials').insert([payload]);
