  ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property, Testimonial } from '../types';
import { getStrategicInsight } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ revenue: 0, expenses: 0, employees: 0, properties: 0, contacts: 0 });
  const [recentContacts, setRecentContacts] = useState<any[]>([]);
  const [recentStaff, setRecentStaff] = useState<Employee[]>([]);
  const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Analisando pulso da empresa...');
  const [showQuickTransaction, setShowQuickTransaction] = useState(false);
  const [showTestimonialModal, setShowTestimonialModal] = useState(false);
  const [savingTx, setSavingTx] = useState(false);
  const [savingTestimonial, setSavingTestimonial] = useState(false);

  const [txForm, setTxForm] = useState({ description: '', amount: '', type: 'DESPESA' as 'RECEITA' | 'DESPESA' });
  const [testimonialForm, setTestimonialForm] = useState<Partial<Testimonial>>({ 
    client_name: '', client_avatar: '', comment: '', rating: 5, status: 'Aprovado' 
  });
  const [editingTestimonialId, setEditingTestimonialId] = useState<string | null>(null);

  useEffect(() => {
    fetchGlobalStats();
    fetchTestimonials();
  }, []);

  async function fetchTestimonials() {
    try {
      const { data, error } = await supabase
        .from('testimonials')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error) setTestimonials(data || []);
    } catch (e) { console.error(e); }
  }

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*').limit(5).order('created_at', { ascending: false }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').limit(5).order('created_at', { ascending: false })
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        revenue: rev,
        expenses: exp,
        employees: (await supabase.from('employees').select('*', { count: 'exact', head: true })).count || 0,
        properties: propRes.count || 0,
        contacts: (await supabase.from('contact_requests').select('*', { count: 'exact', head: true })).count || 0
      });

      setRecentStaff(empRes.data || []);
      setRecentContacts(contactRes.data || []);

      const insight = await getStrategicInsight(`Receitas: ${rev}MT, Despesas: ${exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.data?.length}`);
      setAiInsight(insight);

    } catch (error) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleQuickTx = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTx(true);
    try {
      const { error } = await supabase.from('transactions').insert([{
        description: txForm.description,
        amount: Number(txForm.amount),
        type: txForm.type,
        category: 'Geral',
        date: new Date().toISOString().split('T')[0]
      }]);
      if (!error) {
        setShowQuickTransaction(false);
        setTxForm({ description: '', amount: '', type: 'DESPESA' });
        fetchGlobalStats();
      }
    } finally {
      setSavingTx(false);
    }
  };

  const handleSaveTestimonial = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTestimonial(true);
    try {
      const payload = {
        client_name: testimonialForm.client_name,
        client_avatar: testimonialForm.client_avatar || `https://picsum.photos/seed/${testimonialForm.client_name}/100`,
        comment: testimonialForm.comment,
        rating: testimonialForm.rating,
        status: testimonialForm.status
      };

      let res;
      if (editingTestimonialId) {
        res = await supabase.from('testimonials').update(payload).eq('id', editingTestimonialId);
      } else {
        res = await supabase.from('testimonials').insert([payload]);
      }

      if (!res.error) {
        setShowTestimonialModal(false);
        setTestimonialForm({ client_name: '', client_avatar: '', comment: '', rating: 5, status: 'Aprovado' });
        setEditingTestimonialId(null);
        fetchTestimonials();
      }
    } finally {
      setSavingTestimonial(false);
    }
  };

  const deleteTestimonial = async (id: string) => {
    if (!confirm("Remover opinião do cliente?")) return;
    try {
      await supabase.from('testimonials').delete().eq('id', id);
      fetchTestimonials();
    } catch (e) { console.error(e); }
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#10b981' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  const barData = useMemo(() => [
    { name: 'Financeiro', receitas: stats.revenue, despesas: stats.expenses }
  ], [stats]);

  if (loading) return (
    <div className="h-full flex items-center justify-center py-20">
      <div className="flex flex-col items-center gap-4">
        <Loader2 className="animate-spin text-blue-600" size={48} />
        <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Sincronizando Monte Cloud...</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* System Status Banner */}
      <div className="flex items-center justify-between bg-white px-8 py-4 rounded-[2rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-3">
           <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]"></div>
           <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-2">
             <ShieldCheck size={14} className="text-blue-600" /> Monte Hub v5.0 - Sincronização Estável
           </span>
        </div>
        <div className="flex items-center gap-6">
           <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase">
              <Activity size={12} className="text-indigo-400" /> Latência: 12ms
           </div>
           <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase">
              <Cloud size={12} className="text-blue-400" /> Cloud Node: Mozambique South
           </div>
           <div className="flex items-center gap-2 text-[9px] font-bold text-slate-400 uppercase">
              <Globe size={12} className="text-emerald-400" /> Rede Activa
           </div>
        </div>
      </div>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Fluxo Cloud', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-blue-600" />, trend: 'Performance em Tempo Real', color: 'blue' },
          { label: 'Portfólio Ativo', value: stats.properties, icon: <Home className="text-indigo-600" />, trend: 'Imóveis Registados', color: 'indigo' },
          { label: 'Staff Total', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores Activos', color: 'emerald' },
          { label: 'Solicitações', value: stats.contacts, icon: <MessageSquare className="text-amber-600" />, trend: 'Pedidos Pendentes', color: 'amber' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group overflow-hidden relative">
            <div className={`absolute top-0 right-0 w-24 h-24 bg-${kpi.color}-50 rounded-full translate-x-12 -translate-y-12 group-hover:scale-110 transition-transform`}></div>
            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-4">
                <div className={`p-3 bg-${kpi.color}-50 rounded-2xl`}>{kpi.icon}</div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{kpi.label}</span>
              </div>
              <h3 className="text-3xl font-black text-slate-900 tracking-tight mb-1">{kpi.value}</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase">{kpi.trend}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-8">
          {/* AI Strategic Box */}
          <div className="bg-slate-900 rounded-[3.5rem] p-12 text-white relative overflow-hidden shadow-2xl group border border-white/5">
             <div className="absolute top-0 right-0 w-80 h-80 bg-blue-600/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
             <div className="relative z-10">
                <div className="flex items-center gap-3 mb-8">
                   <div className="p-4 bg-blue-600 rounded-[1.5rem] text-white animate-pulse shadow-lg shadow-blue-500/40"><Sparkles size={24} /></div>
                   <div>
                     <h3 className="text-2xl font-black tracking-tight">Análise Preditiva Monte</h3>
                     <p className="text-[10px] font-black text-blue-400 uppercase tracking-widest mt-1">Intelligence v5.0 Deep Cloud</p>
                   </div>
                </div>
                <p className="text-2xl font-medium text-slate-200 leading-relaxed italic mb-10 max-w-2xl">"{aiInsight}"</p>
                <div className="flex items-center gap-6">
                   <div className="flex items-center gap-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">
                     <Activity size={14} className="text-emerald-500" /> Redes Neurais Ativas
                   </div>
                   <div className="px-4 py-2 bg-white/5 rounded-full text-[9px] font-black text-blue-300 uppercase">Contexto: Financeiro + RH</div>
                </div>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
             <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm flex flex-col">
                <div className="flex items-center justify-between mb-10">
                  <div>
                    <h3 className="text-xl font-black text-slate-900">Fluxo de Caixa</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Controlo de Entradas e Saídas</p>
                  </div>
                </div>
                <div className="h-[250px] w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={barData} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" hide />
                      <YAxis hide />
                      <Tooltip 
                        contentStyle={{ borderRadius: '1.5rem', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }}
                      />
                      <Bar dataKey="receitas" fill="#10b981" radius={[12, 12, 0, 0]} barSize={45} />
                      <Bar dataKey="despesas" fill="#f43f5e" radius={[12, 12, 0, 0]} barSize={45} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
             </div>

             <div className="h-[400px]">
                <TodoList />
             </div>
          </div>

          {/* Testimonials Management Section Refined */}
          <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm overflow-hidden relative">
            <div className="absolute top-0 right-0 p-12 opacity-5 pointer-events-none">
               <Quote size={120} />
            </div>
            <div className="flex items-center justify-between mb-12 relative z-10">
               <div className="flex items-center gap-4">
                 <div className="p-4 bg-amber-100 text-amber-600 rounded-[1.5rem]"><Star size={24} className="fill-current" /></div>
                 <div>
                   <h3 className="text-2xl font-black text-slate-900 tracking-tight">Mural de Prestígio</h3>
                   <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Feedback e Prova Social Monte</p>
                 </div>
               </div>
               <button 
                onClick={() => { setEditingTestimonialId(null); setTestimonialForm({ client_name: '', client_avatar: '', comment: '', rating: 5, status: 'Aprovado' }); setShowTestimonialModal(true); }}
                className="px-8 py-4 bg-slate-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-600 transition-all shadow-xl active:scale-95 flex items-center gap-3"
               >
                 <Plus size={16} /> Registar Opinião
               </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6 relative z-10">
               {testimonials.slice(0, 4).map(t => (
                 <div key={t.id} className="p-8 bg-slate-50/50 rounded-[3rem] relative group border border-slate-100 hover:border-amber-200 hover:bg-white transition-all duration-500 shadow-sm hover:shadow-xl">
                    <div className="flex items-center justify-between mb-6">
                      <div className="flex items-center gap-4">
                        <img src={t.client_avatar} className="w-14 h-14 rounded-2xl object-cover shadow-md ring-4 ring-white" alt="" />
                        <div>
                          <p className="text-base font-black text-slate-900 leading-none mb-2">{t.client_name}</p>
                          <div className="flex gap-1">
                            {[...Array(5)].map((_, i) => (
                              <Star key={i} size={12} className={i < t.rating ? 'fill-amber-400 text-amber-400' : 'text-slate-200'} />
                            ))}
                          </div>
                        </div>
                      </div>
                      <Quote className="text-slate-100 group-hover:text-amber-100 transition-colors" size={32} />
                    </div>
                    <p className="text-sm text-slate-600 italic mb-8 leading-relaxed font-medium">"{t.comment}"</p>
                    <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all translate-y-2 group-hover:translate-y-0">
                       <button 
                        onClick={() => { setEditingTestimonialId(t.id); setTestimonialForm(t); setShowTestimonialModal(true); }}
                        className="p-3 bg-white text-slate-400 hover:text-blue-600 rounded-xl shadow-md border border-slate-100 transition-all"
                       >
                         <Edit3 size={16} />
                       </button>
                       <button 
                        onClick={() => deleteTestimonial(t.id)}
                        className="p-3 bg-white text-slate-400 hover:text-rose-600 rounded-xl shadow-md border border-slate-100 transition-all"
                       >
                         <Trash2 size={16} />
                       </button>
                    </div>
                 </div>
               ))}
               {testimonials.length === 0 && (
                 <div className="col-span-full py-20 text-center flex flex-col items-center gap-4 opacity-40">
                   <MessageSquare size={48} className="text-slate-200" />
                   <p className="text-sm font-black uppercase tracking-[0.2em] text-slate-400">Aguardando Prova Social Cloud</p>
                 </div>
               )}
            </div>
          </div>
        </div>

        {/* Sidebar Content */}
        <div className="space-y-8">
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-2">
              <TrendingUp className="text-blue-600" size={20} /> Equilíbrio de Capital
            </h3>
            <div className="h-64 w-full mb-6">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={chartData}
                    cx="50%"
                    cy="50%"
                    innerRadius={70}
                    outerRadius={90}
                    paddingAngle={8}
                    dataKey="value"
                  >
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '1.5rem', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }}
                    formatter={(value: any) => [`${Number(value).toLocaleString()} MT`, 'Volume']}
                  />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="space-y-4">
              <div className="p-6 bg-emerald-50 rounded-[2.5rem] flex justify-between items-center group hover:scale-105 transition-all shadow-sm">
                <div>
                  <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">Receitas</p>
                  <p className="text-2xl font-black text-slate-900">{stats.revenue.toLocaleString()} MT</p>
                </div>
                <div className="p-3 bg-white rounded-2xl shadow-sm text-emerald-600"><ArrowUpRight size={20} /></div>
              </div>
              <div className="p-6 bg-rose-50 rounded-[2.5rem] flex justify-between items-center group hover:scale-105 transition-all shadow-sm">
                <div>
                  <p className="text-[10px] font-black text-rose-600 uppercase tracking-widest mb-1">Despesas</p>
                  <p className="text-2xl font-black text-slate-900">{stats.expenses.toLocaleString()} MT</p>
                </div>
                <div className="p-3 bg-white rounded-2xl shadow-sm text-rose-600"><ArrowDownRight size={20} /></div>
              </div>
              <button onClick={() => setShowQuickTransaction(true)} className="w-full py-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] hover:border-blue-600 hover:text-blue-600 transition-all flex items-center justify-center gap-3 mt-4">
                <Plus size={16} /> Lançamento Rápido
              </button>
            </div>
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h3 className="text-xl font-black text-slate-900">Talentos Recentes</h3>
                <p className="text-[10px] font-black text-slate-400 uppercase mt-1">Onboarding Staff</p>
              </div>
              <Users className="text-blue-600" size={24} />
            </div>
            <div className="space-y-6">
              {recentStaff.map(s => (
                <div key={s.id} className="flex items-center gap-5 group cursor-pointer">
                  <div className="relative">
                    <img src={s.avatar} className="w-14 h-14 rounded-2xl object-cover ring-4 ring-slate-50 shadow-md group-hover:ring-blue-100 transition-all" alt="" />
                    <span className="absolute -bottom-1 -right-1 w-4 h-4 bg-emerald-500 border-4 border-white rounded-full"></span>
                  </div>
                  <div className="flex-1">
                    <p className="text-base font-black text-slate-900 leading-none mb-1.5 group-hover:text-blue-600 transition-colors">{s.name}</p>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{s.role}</p>
                  </div>
                  <ChevronRight size={16} className="text-slate-200 group-hover:text-blue-600 group-hover:translate-x-1 transition-all" />
                </div>
              ))}
              <button className="w-full py-5 bg-slate-50 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] rounded-2xl hover:bg-slate-900 hover:text-white transition-all mt-4">Gestão de Equipa</button>
            </div>
          </div>
        </div>
      </div>

      {/* Testimonial Modal Refined */}
      {showTestimonialModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-lg w-full shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2 bg-amber-500"></div>
            <button onClick={() => setShowTestimonialModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><CloseIcon size={24} /></button>

            <div className="flex items-center gap-4 mb-10">
               <div className="w-12 h-12 bg-amber-50 text-amber-600 rounded-2xl flex items-center justify-center"><Star size={24} className="fill-current" /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">Registar Opinião</h2>
            </div>

            <form onSubmit={handleSaveTestimonial} className="space-y-8">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Cliente</label>
                  <input required value={testimonialForm.client_name} onChange={e => setTestimonialForm({...testimonialForm, client_name: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-amber-100 transition-all" placeholder="Ex: Maria Santos" />
               </div>

               <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nível de Satisfação</label>
                  <div className="flex gap-4 justify-center bg-slate-50 p-6 rounded-3xl border border-slate-100 shadow-inner">
                    {[1, 2, 3, 4, 5].map(star => (
                      <button type="button" key={star} onClick={() => setTestimonialForm({...testimonialForm, rating: star})} className="transition-all transform hover:scale-125 active:scale-90">
                        <Star size={32} className={star <= (testimonialForm.rating || 0) ? 'fill-amber-400 text-amber-400 drop-shadow-sm' : 'text-slate-200'} />
                      </button>
                    ))}
                  </div>
               </div>

               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">O Depoimento</label>
                  <textarea required value={testimonialForm.comment} onChange={e => setTestimonialForm({...testimonialForm, comment: e.target.value})} className="w-full bg-slate-50 p-6 rounded-[2.5rem] font-medium border-none outline-none focus:ring-4 focus:ring-amber-100 resize-none transition-all shadow-inner" rows={4} placeholder="O que o cliente disse sobre a excelência Monte..." />
               </div>

               <div className="flex gap-4">
                 <button disabled={savingTestimonial} type="submit" className="flex-1 py-7 bg-slate-900 text-white font-black rounded-[2.5rem] hover:bg-amber-600 transition-all active:scale-95 flex items-center justify-center gap-4 shadow-2xl">
                    {savingTestimonial ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Guardar Mural</>}
                 </button>
                 <button type="button" onClick={() => setShowTestimonialModal(false)} className="px-10 py-7 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Sair</button>
               </div>
            </form>
          </div>
        </div>
      )}

      {/* Quick Transaction Modal Refined */}
      {showQuickTransaction && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-lg w-full shadow-2xl relative border-t-8 border-blue-600">
            <button onClick={() => setShowQuickTransaction(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><CloseIcon size={24} /></button>

            <div className="flex items-center gap-4 mb-10">
               <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center"><Wallet size={24} /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">Movimento Flash</h2>
            </div>

            <form onSubmit={handleQuickTx} className="space-y-8">
               <div className="flex p-2 bg-slate-100 rounded-[2rem] shadow-inner">
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'RECEITA'})} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest rounded-[1.5rem] transition-all ${txForm.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Entrada</button>
