                           onChange={(e) => updateApplicationStatus(app.id, e.target.value)}
                           className={`text-[9px] font-black uppercase tracking-widest p-2 rounded-xl outline-none border-none cursor-pointer transition-colors ${
                             app.status === 'Pendente' ? 'bg-amber-50 text-amber-600' :
                             app.status === 'Em Análise' ? 'bg-blue-50 text-blue-600' :
                             app.status === 'Aceite' ? 'bg-emerald-50 text-emerald-600' :
                             'bg-slate-100 text-slate-400'
                           }`}
                         >
                            <option>Pendente</option>
                            <option>Em Análise</option>
                            <option>Entrevistado</option>
                            <option>Aceite</option>
                            <option>Rejeitado</option>
                         </select>
                      </td>
                      <td className="px-10 py-8 text-[11px] font-bold text-slate-400">
                         {new Date(app.created_at).toLocaleDateString()}
                      </td>
                      <td className="px-10 py-8 text-right">
                         <div className="flex items-center justify-end gap-2">
                            {app.applicant_linkedin && (
                               <a href={app.applicant_linkedin} target="_blank" rel="noreferrer" className="p-2.5 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl transition-all border border-slate-100"><LinkIcon size={16} /></a>
                            )}
                            <button className="p-2.5 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-500/20 hover:scale-110 transition-all"><ChevronRight size={16} /></button>
                         </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </div>
