                  <div className="md:col-span-2 space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><Camera size={14} className="text-blue-500" /> URL da Imagem de Capa</label><input value={vacancyForm.image} onChange={e => setVacancyForm({...vacancyForm, image: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100 transition-all" placeholder="https://images.unsplash.com/..." /></div>
               </div>
               <div className="space-y-2"><div className="flex items-center justify-between px-1"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2"><AlignLeft size={14} className="text-blue-500" /> Descrição da Vaga</label><div className="flex gap-2"><button type="button" onClick={() => setVacancyForm({...vacancyForm, description: ''})} className="text-[9px] font-black uppercase text-slate-400 hover:text-slate-600 flex items-center gap-1 bg-slate-50 px-3 py-1.5 rounded-full transition-all"><RefreshCcw size={10} /> Limpar</button><button type="button" onClick={handleAiOptimize} disabled={isAiLoading} className="text-[10px] font-black uppercase text-indigo-600 flex items-center gap-1.5 bg-indigo-50 px-4 py-1.5 rounded-full hover:bg-indigo-100 transition-all disabled:opacity-50 shadow-sm">{isAiLoading ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />} Gerar Descrição IA</button></div></div><textarea value={vacancyForm.description} onChange={e => setVacancyForm({...vacancyForm, description: e.target.value})} rows={10} className="w-full bg-slate-50 p-8 rounded-[2.5rem] font-medium border-none outline-none focus:ring-4 focus:ring-blue-100 text-sm leading-relaxed custom-scrollbar" placeholder="Clique em 'Gerar Descrição IA'..." /></div>
               <div className="flex gap-4 pt-4"><button type="submit" disabled={saving || isAiLoading} className="flex-1 py-6 bg-blue-600 text-white rounded-[2rem] font-black shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50">{saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> {editingVacancyId ? 'Guardar Alterações' : 'Publicar Vaga Agora'}</>}</button><button type="button" onClick={() => setShowVacancyModal(false)} className="px-10 py-6 bg-slate-100 text-slate-500 rounded-[2rem] font-black hover:bg-slate-200 transition-all">Cancelar</button></div>
            </form>
          </div>
        </div>
      )}

      {showAddModal && (
