        setNewTaskTitle('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) {
      console.error(e);
