                    className={`p-1.5 rounded-lg transition-all ${expandedId === task.id ? 'bg-blue-50 text-blue-600' : 'text-slate-300 hover:text-blue-600'}`}
                  >
                    {expandedId === task.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                  </button>
                  <button 
                    onClick={() => deleteTask(task.id)}
                    className="p-1.5 text-slate-300 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>

              {expandedId === task.id && (
                <div className="px-12 pb-5 pt-0 animate-in slide-in-from-top-2 duration-300 space-y-5">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                        <Calendar size={10} className="text-blue-500" /> Data de Vencimento
                      </label>
                      <div className="flex gap-2">
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={(e) => updateDueDate(task.id, e.target.value)}
                          className="flex-1 bg-slate-50 rounded-xl px-4 py-2.5 text-xs font-bold border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all cursor-pointer"
                        />
                        {task.due_date && (
                          <button 
                            onClick={() => updateDueDate(task.id, null)}
                            className="px-3 bg-slate-50 text-slate-400 hover:text-rose-500 rounded-xl transition-all border border-transparent hover:border-rose-100"
                            title="Remover Prazo"
                          >
                            <XCircle size={16} />
                          </button>
                        )}
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                        <AlertCircle size={10} className="text-blue-500" /> Prioridade
                      </label>
                      <div className="flex gap-2">
                        {(['Baixa', 'Média', 'Alta'] as const).map((p) => (
                          <button
                            key={p}
                            onClick={() => updatePriority(task.id, p)}
                            className={`flex-1 py-2 text-[9px] font-black uppercase rounded-lg border transition-all ${
                              task.priority === p 
                                ? 'bg-white border-blue-200 text-blue-600 shadow-sm' 
                                : 'bg-slate-50 border-transparent text-slate-400 hover:bg-slate-100'
                            }`}
                          >
                            {p}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-2 relative">
                    <div className="flex items-center justify-between">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-1.5">
                        <FileText size={10} className="text-blue-500" /> Descrição Detalhada
                      </label>
                      {isSyncing === task.id && (
                        <div className="flex items-center gap-1.5 text-blue-500 animate-pulse">
                          <CloudUpload size={10} />
                          <span className="text-[8px] font-black uppercase">Sincronizando...</span>
                        </div>
                      )}
                      {!isSyncing && hasDescription && expandedId === task.id && (
                        <div className="flex items-center gap-1 text-emerald-500">
                          <Check size={10} />
                          <span className="text-[8px] font-black uppercase">Guardado na Cloud</span>
                        </div>
                      )}
                    </div>
                    <textarea 
                      autoFocus={task.description === ''}
                      value={task.description}
                      onChange={(e) => updateDescription(task.id, e.target.value)}
                      rows={4}
                      className="w-full bg-slate-50/50 rounded-2xl p-5 text-[13px] font-medium text-slate-600 border border-slate-100 outline-none focus:ring-2 focus:ring-blue-100 focus:bg-white transition-all resize-none custom-scrollbar shadow-inner"
                      placeholder="Adicione detalhes, observações técnicas ou instruções específicas para esta tarefa..."
                    />
                    <div className="absolute bottom-3 right-4 text-[9px] font-bold text-slate-300">
                      {task.description?.length || 0} caracteres
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}

        {filteredTasks.length === 0 && (
          <div className="py-20 text-center flex flex-col items-center gap-3 opacity-30">
            <Search size={48} className="text-slate-200" />
            <p className="text-xs font-black uppercase tracking-widest">Nenhuma tarefa encontrada</p>
          </div>
        )}
      </div>

      <div className="p-4 bg-slate-50/30 border-t border-slate-50 text-center">
         <p className="text-[8px] font-black text-slate-300 uppercase tracking-[0.2em]">Monte Hub Task Infrastructure v2.0</p>
      </div>
    </div>
  );
};

