                role="listitem"
              >
                <div 
                  className={`p-8 flex flex-col md:flex-row md:items-center justify-between gap-6 cursor-pointer select-none transition-colors ${expandedId === job.id ? 'bg-blue-50/30' : 'hover:bg-slate-50/50'}`}
                  onClick={() => toggleExpand(job.id)}
