                                >
                                  Candidatar-se Agora <ArrowRight size={18} />
                                </button>
                                <p className="text-[9px] text-center text-slate-400 mt-4 font-medium uppercase tracking-tighter">
                                   Processo gerido via Monte Cloud Recruitment
                                </p>
                             </div>
                          </div>
                       </div>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* Candidatura Espontânea */}
          <div className="mt-20 bg-slate-900 p-12 md:p-20 rounded-[4rem] text-center text-white relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/20 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 transition-transform duration-700 group-hover:scale-150"></div>
            <div className="relative z-10 max-w-2xl mx-auto">
              <h3 className="text-3xl font-black mb-6">Candidatura Espontânea</h3>
