            {applyStatus === 'success' ? (
              <div className="py-10 text-center animate-in zoom-in duration-500">
                <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-[1.5rem] flex items-center justify-center mx-auto mb-6">
                  <CheckCircle2 size={40} />
                </div>
                <h2 className="text-2xl font-black text-slate-900 mb-3 tracking-tight">Enviado com Sucesso!</h2>
                <p className="text-slate-500 font-medium text-base leading-relaxed mb-8">
