                        placeholder="João da Silva" 
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail</label>
                      <input 
                        required 
                        type="email"
                        value={applyForm.email}
                        onChange={e => setApplyForm({...applyForm, email: e.target.value})}
                        className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl font-bold text-sm outline-none focus:ring-2 focus:ring-blue-100 transition-all" 
                        placeholder="exemplo@email.com" 
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                        <Phone size={10} className="text-blue-500" /> Telemóvel
                      </label>
                      <input 
                        required 
                        value={applyForm.phone}
                        onChange={e => setApplyForm({...applyForm, phone: e.target.value})}
                        className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl font-bold text-sm outline-none focus:ring-2 focus:ring-blue-100 transition-all" 
                        placeholder="+258 8X..." 
                      />
                    </div>
                    <div className="space-y-1.5">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                        <LinkIcon size={10} className="text-blue-500" /> LinkedIn (URL)
                      </label>
                      <input 
                        value={applyForm.linkedin}
                        onChange={e => setApplyForm({...applyForm, linkedin: e.target.value})}
                        className="w-full bg-slate-50 border border-slate-100 p-4 rounded-xl font-bold text-sm outline-none focus:ring-2 focus:ring-blue-100 transition-all" 
                        placeholder="https://linkedin.com/..." 
                      />
                    </div>
                  </div>

                  <div className="space-y-1.5">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Breve Resumo</label>
                    <textarea 
                      required
                      value={applyForm.message}
                      onChange={e => setApplyForm({...applyForm, message: e.target.value})}
                      rows={3}
                      className="w-full bg-slate-50 border border-slate-100 p-5 rounded-2xl font-medium outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none text-xs" 
                      placeholder="Fale um pouco sobre a sua experiência..."
                    />
                  </div>

                  <div className="p-5 bg-blue-50 rounded-2xl border border-blue-100 space-y-3">
                     <div className="flex items-start gap-3">
                        <div className="pt-0.5">
                          <input 
                            required
                            type="checkbox" 
                            id="consent-checkbox"
                            checked={hasConsent}
                            onChange={(e) => setHasConsent(e.target.checked)}
                            className="w-4 h-4 rounded border-blue-300 text-blue-600 focus:ring-blue-500 cursor-pointer"
                          />
                        </div>
                        <label htmlFor="consent-checkbox" className="text-[10px] text-slate-700 font-medium leading-relaxed cursor-pointer select-none">
                           Aceite Legal: <span className="text-blue-700 font-bold">Ao enviar, concorda com o processamento dos seus dados</span> para fins de recrutamento exclusivo da Monte Imobiliária.
                        </label>
                     </div>
                  </div>

                  <button 
                    disabled={isApplying || !hasConsent}
                    type="submit"
                    className="w-full py-5 bg-blue-600 text-white font-black rounded-xl shadow-xl hover:bg-slate-900 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50 text-xs"
                  >
                    {isApplying ? <Loader2 className="animate-spin" /> : <><Send size={18} /> Enviar Candidatura</>}
                  </button>

                  <div className="flex items-center justify-center gap-2 text-[8px] text-slate-400 font-black uppercase tracking-widest">
                     <ShieldCheck size={10} className="text-blue-500" /> Privacidade Monte Hub
                  </div>
                </form>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default CareerView;

