import React, { useState, useEffect } from 'react';
import { Briefcase, MapPin, ArrowRight, UserPlus, Mail, Loader2, Info, ChevronDown, ChevronUp, Image as ImageIcon, X, Send, CheckCircle2, Globe, Link as LinkIcon, Phone, ShieldCheck, HelpCircle } from 'lucide-react';
import { supabase } from '../supabaseClient';
import { JobVacancy } from '../types';

const CareerView: React.FC = () => {
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // States para Candidatura
  const [showApplyModal, setShowApplyModal] = useState(false);
  const [selectedJob, setSelectedJob] = useState<JobVacancy | null>(null);
  const [isApplying, setIsApplying] = useState(false);
  const [applyStatus, setApplyStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [hasConsent, setHasConsent] = useState(false);
  const [applyForm, setApplyForm] = useState({
    name: '',
    email: '',
    phone: '',
    linkedin: '',
    message: ''
  });

  useEffect(() => {
    fetchVacancies();
  }, []);

  async function fetchVacancies() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('job_vacancies')
        .select('*')
        .eq('status', 'Open')
        .order('created_at', { ascending: false });

      if (!error) setVacancies(data || []);
    } catch (err) {
      console.error("Error fetching jobs:", err);
    } finally {
      setLoading(false);
    }
  }

  const toggleExpand = (id: string) => {
    setExpandedId(expandedId === id ? null : id);
  };

  const handleOpenApply = (job: JobVacancy) => {
    setSelectedJob(job);
    setApplyStatus('idle');
    setHasConsent(false);
    setApplyForm({ name: '', email: '', phone: '', linkedin: '', message: '' });
    setShowApplyModal(true);
  };

  const handleApplySubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasConsent) return;

    setIsApplying(true);

    try {
      const { error } = await supabase.from('job_applications').insert([{
        job_id: selectedJob?.id,
        job_title: selectedJob?.title,
        applicant_name: applyForm.name,
        applicant_email: applyForm.email,
        applicant_phone: applyForm.phone,
        applicant_linkedin: applyForm.linkedin,
        message: applyForm.message,
        status: 'Pendente',
        consent_given: true,
        consent_timestamp: new Date().toISOString(),
        created_at: new Date().toISOString()
      }]);

      if (error) throw error;
      setApplyStatus('success');
    } catch (err) {
      console.error("Apply error:", err);
      setApplyStatus('error');
    } finally {
      setIsApplying(false);
    }
  };

  return (
    <div className="animate-in fade-in duration-700" role="main">
      {/* Hero Section - Reduzido 10% (h-[400px]) */}
      <section className="relative h-[400px] flex items-center justify-center text-center text-white overflow-hidden" aria-labelledby="careers-hero-title">
        <div className="absolute inset-0 z-0">
          <img 
            src="https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&q=80&w=1200" 
            alt="Equipa profissional Monte Imobiliária" 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-slate-900/70 backdrop-blur-[2px]"></div>
        </div>

        <div className="relative z-10 max-w-3xl px-4">
          <h1 id="careers-hero-title" className="text-3xl md:text-5xl font-black mb-4 leading-tight">
            Construa o seu futuro na <br /><span className="text-blue-400">Monte Imobiliária</span>
          </h1>
          <p className="text-blue-100 text-base md:text-lg font-medium max-w-xl mx-auto mb-8">
            Faça parte de uma equipa dinâmica que valoriza o talento e a inovação no mercado Moçambicano.
          </p>
          <div className="flex justify-center">
            <a href="#vagas" className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3.5 rounded-2xl font-black text-sm transition-all shadow-xl shadow-blue-500/30">
              Explorar Vagas
            </a>
          </div>
        </div>
      </section>

      {/* Vagas Abertas Section */}
      <section id="vagas" className="py-20 px-4 md:px-8 bg-slate-50" aria-labelledby="vagas-disponiveis-title">
        <div className="max-w-6xl mx-auto">
          <div className="flex items-center justify-between mb-10">
            <div className="flex items-center gap-3">
              <div className="p-2.5 bg-blue-600 rounded-xl text-white">
                <UserPlus size={20} aria-hidden="true" />
              </div>
              <h2 id="vagas-disponiveis-title" className="text-2xl font-black text-slate-900">Oportunidades</h2>
            </div>
            {!loading && (
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest" aria-live="polite">
                {vacancies.length} Abertas
              </span>
            )}
          </div>

          <div className="space-y-5" role="list">
            {loading ? (
              <div className="py-16 flex flex-col items-center gap-4">
                 <Loader2 className="animate-spin text-blue-600" size={32} />
                 <p className="text-slate-400 font-bold uppercase tracking-widest text-[9px]">A carregar oportunidades...</p>
              </div>
            ) : vacancies.length === 0 ? (
              <div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 text-center space-y-4">
                 <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto">
                    <Info size={28} />
                 </div>
                 <h3 className="text-lg font-black text-slate-900">Nenhuma vaga aberta</h3>
                 <p className="text-slate-500 font-medium italic text-sm">Siga-nos para atualizações ou envie uma candidatura espontânea.</p>
              </div>
            ) : vacancies.map((job) => (
              <div 
                key={job.id} 
                className={`group bg-white rounded-[2rem] border border-slate-100 shadow-sm transition-all duration-500 overflow-hidden ${expandedId === job.id ? 'shadow-2xl ring-2 ring-blue-500/10' : 'hover:shadow-md'}`}
                role="listitem"
              >
                <div 
                  className={`p-6 flex flex-col md:flex-row md:items-center justify-between gap-4 cursor-pointer select-none transition-colors ${expandedId === job.id ? 'bg-blue-50/30' : 'hover:bg-slate-50/50'}`}
                  onClick={() => toggleExpand(job.id)}
                >
                  <div className="flex-1">
                    <h3 className="text-lg font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-1">{job.title}</h3>
                    <div className="flex flex-wrap items-center gap-3 text-[10px] font-bold">
                       <span className="flex items-center gap-1.5 text-slate-500"><Briefcase size={12} className="text-blue-500" /> {job.area}</span>
                       <span className="flex items-center gap-1.5 text-slate-500"><MapPin size={12} className="text-blue-500" /> {job.location}</span>
                       <span className="bg-white border border-blue-100 text-blue-600 px-2.5 py-0.5 rounded-full">{job.type}</span>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                     <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${expandedId === job.id ? 'bg-blue-600 text-white rotate-180' : 'bg-slate-100 text-slate-400'}`}>
                        <ChevronDown size={16} />
                     </div>
                  </div>
