import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  ChevronUp, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  XCircle,
  AlertTriangle,
  FileText,
  CloudUpload,
  Check,
  Clock,
  RotateCcw
} from 'lucide-react';
import { Task } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        // Fallback robusto caso a tabela não exista
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada para o lote 45.', completed: false, priority: 'Alta', due_date: '2024-05-01' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza dos filtros no 2º andar.', completed: true, priority: 'Média', due_date: '2024-05-30' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;

    const newTask = {
      title: newTaskTitle,
      description: '',
      completed: false,
      priority: 'Média' as const,
      due_date: null
    };

    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) {
      console.error(e);
    }
  };

  const toggleComplete = async (task: Task) => {
    try {
      const { error } = await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      if (!error) {
        setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
      }
    } catch (e) {
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);
    syncTimeoutRef.current = setTimeout(async () => {
      try {
        await supabase.from('tasks').update({ description }).eq('id', id);
        setTimeout(() => setIsSyncing(null), 1000);
      } catch (e) {
        setIsSyncing(null);
      }
    }, 1000);
  };

  const updateDueDate = async (id: string, due_date: string | null) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: due_date || undefined } : t));
    try {
      await supabase.from('tasks').update({ due_date }).eq('id', id);
    } catch (e) {}
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try {
      await supabase.from('tasks').update({ priority }).eq('id', id);
    } catch (e) {}
  };

  const deleteTask = async (id: string) => {
    if (!window.confirm('Deseja eliminar esta tarefa permanentemente?')) return;
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', id);
      if (!error) setTasks(tasks.filter(t => t.id !== id));
    } catch (e) {
      setTasks(tasks.filter(t => t.id !== id));
    }
  };

  const isOverdue = (dateStr?: string) => {
    if (!dateStr) return false;
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const due = new Date(dateStr);
    return due < today;
  };

  const getPriorityColorClass = (priority: string, isOverdue: boolean, isCompleted: boolean) => {
    if (isOverdue && !isCompleted) return 'bg-rose-500 animate-pulse ring-4 ring-rose-500/20';
    switch (priority) {
      case 'Alta': return 'bg-rose-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-300';
      default: return 'bg-blue-500';
    }
  };

  const filteredTasks = tasks.filter(task => 
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  return (
    <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full">
      {/* Header Fixo */}
      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Lista de Afazeres
        </h3>
        <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
          <RotateCcw size={16} className={loading ? 'animate-spin' : ''} />
        </button>
      </div>

      {/* Input de Nova Tarefa e Pesquisa */}
      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="flex gap-2">
          <input 
            type="text" 
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="Adicionar nova tarefa..."
            className="flex-1 bg-white rounded-xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none transition-all shadow-sm"
          />
          <button 
            type="submit"
            className="p-4 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all shadow-lg shadow-blue-500/20 active:scale-95"
          >
            <Plus size={24} />
          </button>
        </form>

        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input 
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Pesquisar em títulos ou descrições..."
            className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-xl border border-slate-100 focus:ring-2 focus:ring-blue-100 outline-none transition-all"
          />
        </div>
      </div>

      {/* Lista de Itens */}
      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {filteredTasks.length === 0 ? (
          <div className="py-20 text-center flex flex-col items-center gap-3 opacity-30">
            <Search size={48} className="text-slate-200" />
            <p className="text-xs font-black uppercase tracking-widest">Sem resultados</p>
          </div>
        ) : filteredTasks.map((task) => {
          const overdue = isOverdue(task.due_date) && !task.completed;
          const isExpanded = expandedId === task.id;

          return (
            <div 
              key={task.id} 
              className={`group bg-white border rounded-[1.75rem] transition-all duration-500 relative overflow-hidden ${
                isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : 
                overdue ? 'border-rose-400 bg-rose-50/40 shadow-md ring-1 ring-rose-200' : 'border-slate-100 hover:border-blue-100'
              }`}
            >
              {/* Barra Lateral de Prioridade */}
              <div className={`absolute left-0 top-0 bottom-0 w-2 ${getPriorityColorClass(task.priority, overdue, task.completed)} transition-all duration-500`}></div>

              <div className="p-5 pl-7 flex items-center gap-4">
                <button 
                  onClick={() => toggleComplete(task)}
                  className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : overdue ? 'text-rose-500' : 'text-slate-300 hover:text-blue-500'}`}
                >
                  {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                </button>

                <div className="flex-1 min-w-0 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                  <div className="flex items-center gap-3">
                    {/* Indicador Visual de Status (Ícone) */}
                    <div className="shrink-0">
                      {task.completed ? (
                        <CheckCircle2 size={14} className="text-emerald-500" />
                      ) : overdue ? (
                        <AlertTriangle size={14} className="text-rose-500 animate-pulse" />
                      ) : task.priority === 'Alta' ? (
                        <AlertCircle size={14} className="text-amber-500" />
                      ) : (
                        <div className="w-1.5 h-1.5 rounded-full bg-blue-400" />
                      )}
                    </div>

                    <p className={`text-sm font-black truncate transition-all ${
                      task.completed ? 'text-slate-400 line-through italic' : overdue ? 'text-rose-900' : 'text-slate-900'
                    }`}>
                      {task.title}
                    </p>
                    {overdue && (
                      <span className="bg-rose-600 text-white text-[8px] font-black uppercase px-2 py-0.5 rounded-full animate-pulse shadow-lg shadow-rose-200">Expirado</span>
                    )}
                  </div>

                  <div className="flex items-center gap-4 mt-1.5">
                    {task.due_date && (
                      <div className="flex items-center gap-1.5 animate-in fade-in">
                        {overdue ? <AlertTriangle size={12} className="text-rose-500" /> : <Calendar size={12} className="text-blue-400" />}
                        <span className={`text-[10px] font-black uppercase tracking-tighter ${overdue ? 'text-rose-600' : 'text-slate-400'}`}>
                          {overdue ? 'Venceu em: ' : 'Prazo: '}
                          {new Date(task.due_date).toLocaleDateString('pt-MZ')}
                        </span>
                      </div>
                    )}
                    {task.description && !isExpanded && (
                       <div className="flex items-center gap-1 text-slate-300">
                          <FileText size={10} />
                          <span className="text-[10px] font-bold italic truncate max-w-[120px]">{task.description}</span>
                       </div>
                    )}
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-lg ${
                    task.priority === 'Alta' ? 'bg-rose-100 text-rose-600' : 
                    task.priority === 'Média' ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'
                  }`}>
                    {task.priority}
                  </span>
                  <button 
                    onClick={() => setExpandedId(isExpanded ? null : task.id)}
                    className={`p-2 rounded-xl transition-all ${isExpanded ? 'bg-blue-100 text-blue-600 rotate-180' : 'bg-slate-50 text-slate-400 hover:text-blue-600'}`}
                  >
                    <ChevronDown size={18} />
                  </button>
                  <button 
                    onClick={() => deleteTask(task.id)}
                    className="p-2 text-slate-200 hover:text-rose-600 opacity-0 group-hover:opacity-100 transition-all transform hover:scale-110"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              </div>

              {/* Área Expandida - Detalhes & Descrição Longa */}
              {isExpanded && (
                <div className="px-14 pb-8 pt-2 animate-in slide-in-from-top-4 duration-500 space-y-8">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Prazo */}
                    <div className="space-y-3">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                        <Clock size={12} className={overdue ? 'text-rose-500' : 'text-blue-500'} /> 
                        Alterar Prazo de Entrega
                      </label>
                      <div className="flex gap-2">
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={(e) => updateDueDate(task.id, e.target.value)}
                          className={`flex-1 rounded-2xl px-5 py-3.5 text-xs font-bold border-none outline-none focus:ring-4 transition-all cursor-pointer shadow-inner ${
                            overdue ? 'bg-rose-100 text-rose-800 focus:ring-rose-200' : 'bg-slate-100 text-slate-700 focus:ring-blue-100'
                          }`}
                        />
                        {task.due_date && (
                          <button 
                            onClick={() => updateDueDate(task.id, null)}
                            className="px-4 bg-slate-100 text-slate-400 hover:text-rose-600 rounded-2xl transition-all hover:bg-rose-50"
                            title="Limpar Prazo"
                          >
                            <XCircle size={18} />
                          </button>
                        )}
                      </div>
                    </div>

                    {/* Prioridade */}
                    <div className="space-y-3">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                        <AlertCircle size={12} className="text-blue-500" /> Nível de Prioridade Cloud
                      </label>
                      <div className="flex gap-2 bg-slate-100 p-1.5 rounded-2xl">
                        {(['Baixa', 'Média', 'Alta'] as const).map((p) => (
                          <button
                            key={p}
                            onClick={() => updatePriority(task.id, p)}
                            className={`flex-1 py-2.5 text-[9px] font-black uppercase rounded-xl transition-all ${
                              task.priority === p 
                                ? 'bg-white text-blue-600 shadow-md transform scale-[1.02]' 
                                : 'text-slate-400 hover:text-slate-600'
                            }`}
                          >
                            {p}
                          </button>
                        ))}
                      </div>
                    </div>
                  </div>

                  {/* Campo de Descrição Detalhada - NOVO */}
                  <div className="space-y-3 relative">
                    <div className="flex items-center justify-between px-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                        <FileText size={12} className="text-blue-500" /> Notas Detalhadas e Planeamento
                      </label>

                      {/* Indicadores de Sincronização */}
                      <div className="h-5 flex items-center">
                        {isSyncing === task.id ? (
                          <div className="flex items-center gap-2 text-blue-600 animate-pulse">
                            <CloudUpload size={12} />
                            <span className="text-[8px] font-black uppercase">Sincronizando p/ Cloud...</span>
                          </div>
                        ) : task.description && (
                          <div className="flex items-center gap-1.5 text-emerald-500 animate-in fade-in">
                            <Check size={12} />
                            <span className="text-[8px] font-black uppercase">Alterações Guardadas</span>
                          </div>
                        )}
                      </div>
                    </div>

                    <div className="relative group/text">
                      <textarea 
                        value={task.description}
                        onChange={(e) => updateDescription(task.id, e.target.value)}
                        rows={6}
                        className="w-full bg-slate-50 rounded-[2rem] p-8 text-sm font-medium text-slate-600 border-2 border-transparent outline-none focus:border-blue-100 focus:bg-white transition-all resize-none shadow-inner leading-relaxed"
                        placeholder="Descreva aqui o passo-a-passo para a execução desta tarefa..."
                      />
                      <div className="absolute bottom-6 right-6 flex items-center gap-2">
                        <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest bg-slate-50/80 backdrop-blur-sm px-3 py-1 rounded-full border border-slate-100 group-focus-within/text:opacity-0 transition-opacity">
                          {task.description?.length || 0} Caracteres
                        </span>
                      </div>
                    </div>
                    <p className="text-[9px] text-slate-400 italic px-2">A descrição é atualizada em tempo real no Monte Hub enquanto digita.</p>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Footer Informacional */}
      <div className="p-5 bg-slate-50/50 border-t border-slate-50 text-center">
         <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">Monte Cloud Task Engine v3.0</p>
      </div>
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle, Briefcase, 
  Search, MapPin, DollarSign, LayoutList, Sparkles, AlignLeft, RefreshCcw,
  CheckCircle2, Camera, Link as LinkIcon, UserPlus, MessageSquare, ChevronRight, Fingerprint,
  BellRing,
  ExternalLink,
  Info,
  Calendar,
  CreditCard,
  Wrench,
  FileBadge,
  Building2,
  Trophy
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole, JobVacancy, JobApplication } from '../types';
import { generateJobDescription } from '../geminiService';

const SUGGESTED_ROLES = [
  'Estagiário de Digitador de Dados',
  'Gerente de Produção',
  'Agente de Campo',
  'Marketing',
  'Gerente de Campo',
  'Revisor de Dados',
  'Consultor Imobiliário',
  'Motorista Profissional'
];

const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies' | 'applications'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [viewingEmp, setViewingEmp] = useState<Employee | null>(null);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [editingVacancyId, setEditingVacancyId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [realtimeNotification, setRealtimeNotification] = useState<{name: string, job: string} | null>(null);
  const [saving, setSaving] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [recentAppIds, setRecentAppIds] = useState<Set<string>>(new Set());

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '+258 ',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Operações & Campo', type: 'Full-time', location: 'Beira', salary: '', status: 'Open', description: '', image: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchData();
    fetchVacancies();
    fetchApplications();

    const channel = supabase
      .channel('hr_realtime_dashboard')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, (payload) => {
        const newApp = payload.new as JobApplication;
        setApplications(prev => [newApp, ...prev]);
        if (audioRef.current) audioRef.current.play().catch(e => {});
        setRealtimeNotification({ name: newApp.applicant_name, job: newApp.job_title });
        setRecentAppIds(prev => new Set(prev).add(newApp.id));
        setTimeout(() => setRealtimeNotification(null), 8000);
        setTimeout(() => setRecentAppIds(prev => { const next = new Set(prev); next.delete(newApp.id); return next; }), 15000);
      })
      .on('postgres_changes', { event: 'UPDATE', table: 'job_applications' }, (payload) => {
        const updated = payload.new as JobApplication;
        setApplications(prev => prev.map(a => a.id === updated.id ? updated : a));
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data, error: sbError } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (!sbError) setVacancies(data || []);
    } catch (err) {}
  }

  async function fetchApplications() {
    try {
      const { data, error: sbError } = await supabase.from('job_applications').select('*').order('created_at', { ascending: false });
      if (!sbError) setApplications(data || []);
    } catch (err) {}
  }

  const updateApplicationStatus = async (id: string, newStatus: string) => {
    try {
      const { error } = await supabase.from('job_applications').update({ status: newStatus }).eq('id', id);
      if (!error) setApplications(applications.map(app => app.id === id ? { ...app, status: newStatus as any } : app));
    } catch (err) {}
  };

  const handleAiOptimize = async () => {
    if (!vacancyForm.title) {
      setError("Por favor, digite o Cargo primeiro para a IA trabalhar.");
      setTimeout(() => setError(null), 3000);
      return;
    }
    setIsAiLoading(true);
    try {
      const optimizedText = await generateJobDescription(vacancyForm.title || '', vacancyForm.area || '', vacancyForm.location || '');
      setVacancyForm(prev => ({ ...prev, description: optimizedText }));
    } finally { setIsAiLoading(false); }
  };

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!vacancyForm.title?.trim() || !vacancyForm.description?.trim()) {
      setError("Título e Descrição são obrigatórios para publicar.");
      return;
    }
    setSaving(true);
    try {
      const payload = { 
        title: vacancyForm.title.trim(), area: vacancyForm.area, type: vacancyForm.type,
        location: vacancyForm.location?.trim() || 'Beira', salary: vacancyForm.salary?.trim() || 'A Negociar',
        description: vacancyForm.description.trim(), image: vacancyForm.image?.trim() || '', status: vacancyForm.status || 'Open'
      };
      let res;
      if (editingVacancyId) res = await supabase.from('job_vacancies').update(payload).eq('id', editingVacancyId);
      else res = await supabase.from('job_vacancies').insert([payload]);
      if (res.error) throw res.error;
      setShowVacancyModal(false);
      setEditingVacancyId(null);
      setVacancyForm(initialVacancyState);
      fetchVacancies();
    } catch (err: any) { setError("Erro ao processar: " + err.message); } 
    finally { setSaving(false); }
  };

  const handleEditVacancy = (vacancy: JobVacancy) => {
    setError(null);
    setEditingVacancyId(vacancy.id);
    setVacancyForm(vacancy);
    setShowVacancyModal(true);
  };

  const deleteVacancy = async (id: string) => {
    if (confirm('Deseja remover esta vaga permanentemente?')) {
      const { error } = await supabase.from('job_vacancies').delete().eq('id', id);
      if (!error) fetchVacancies();
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);
    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!formState.name || formState.name.trim().length < 3) { setError("Por favor, insira um nome completo válido."); return; }
    if (!formState.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formState.email)) { setError("Por favor, insira um e-mail corporativo válido."); return; }
    setSaving(true);
    try {
      const payload = { ...formState, salary: Number(formState.salary), status: formState.status || 'Ativo', avatar: `https://picsum.photos/seed/${formState.name}/100` };
      if (editingEmpId) await supabase.from('employees').update(payload).eq('id', editingEmpId);
      else await supabase.from('employees').insert([payload]);
      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { setError(err.message); } 
    finally { setSaving(false); }
  };

  const openViewModal = (emp: Employee) => {
    setViewingEmp(emp);
    setShowViewModal(true);
  };

  if (loading) return <div className="flex justify-center py-24"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20 relative">

      {/* Realtime Toast Notification */}
      {realtimeNotification && (
        <div className="fixed top-24 right-8 z-[200] bg-slate-900 text-white p-6 rounded-[2.5rem] shadow-2xl flex items-center gap-5 animate-in slide-in-from-right-10 duration-700 border border-emerald-500/30 backdrop-blur-xl">
           <div className="relative">
              <div className="w-14 h-14 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-500/20 animate-bounce">
                <BellRing size={28} className="text-white" />
              </div>
              <span className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-400 rounded-full animate-ping"></span>
           </div>
           <div>
              <p className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.2em] mb-1">Nova Candidatura Cloud</p>
              <h4 className="text-base font-black tracking-tight leading-none mb-1">{realtimeNotification.name}</h4>
              <p className="text-xs text-slate-400 font-medium italic">Pretende: {realtimeNotification.job}</p>
           </div>
           <button onClick={() => setRealtimeNotification(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors ml-4 text-slate-500"><X size={18} /></button>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Talentos</h1>
             <p className="text-slate-500 font-medium">Controle de staff e recrutamento em tempo real.</p>
           </div>
        </div>
        <div className="flex gap-3">
          {activeTab === 'employees' ? (
            <button onClick={() => { setError(null); setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Novo Colaborador
            </button>
          ) : activeTab === 'vacancies' ? (
            <button onClick={() => { setError(null); setEditingVacancyId(null); setVacancyForm(initialVacancyState); setShowVacancyModal(true); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Criar Nova Vaga
            </button>
          ) : (
            <button onClick={fetchApplications} className="px-8 py-4 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-sm shadow-sm hover:bg-slate-200 transition-all active:scale-95 flex items-center gap-2">
              <RefreshCcw size={18} /> Forçar Sincronização
            </button>
          )}
        </div>
      </div>

      <div className="flex p-1.5 bg-slate-100 rounded-[2rem] w-full max-w-lg mx-auto border border-slate-200 shadow-inner">
        <button onClick={() => setActiveTab('employees')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-indigo-400'}`}><Users size={16} /> Staff</button>
        <button onClick={() => setActiveTab('vacancies')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-blue-400'}`}><Briefcase size={16} /> Vagas</button>
        <button onClick={() => setActiveTab('applications')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all relative ${activeTab === 'applications' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500 hover:text-emerald-400'}`}>
          <UserPlus size={16} /> Candidatos 
          {applications.filter(a => a.status === 'Pendente').length > 0 && <span className={`w-5 h-5 bg-rose-500 text-white text-[9px] rounded-full flex items-center justify-center border-2 border-white ml-1 ${recentAppIds.size > 0 ? 'animate-bounce' : ''}`}>{applications.filter(a => a.status === 'Pendente').length}</span>}
        </button>
      </div>

      {activeTab === 'employees' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.map((emp, index) => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div 
                key={emp.id} 
                onClick={() => openViewModal(emp)}
                className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500 animate-in fade-in slide-in-from-bottom-4 duration-700 cursor-pointer"
                style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'backwards' }}
              >
                <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>
                <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-20">
                  <button onClick={(e) => { e.stopPropagation(); setError(null); setEditingEmpId(emp.id); setFormState(emp); setShowAddModal(true); }} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-100 transition-all"><Edit3 size={18} /></button>
                </div>
                <div className="mt-8 flex flex-col items-center">
                  <div className="relative mb-5">
                    <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-8 ring-slate-50 shadow-inner group-hover:scale-105 transition-transform duration-500" alt={emp.name} />
                    <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-4 border-white ${emp.status === 'Ativo' ? 'bg-green-500' : 'bg-amber-500'}`}></div>
                  </div>
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                </div>
                <div className="pt-6 border-t border-slate-50 flex justify-between items-center text-[11px] font-medium text-slate-500">
                  <div className="flex items-center gap-1.5"><Mail size={12} className="text-slate-300" /> {emp.email.split('@')[0]}...</div>
                  <div className="flex items-center gap-1.5"><Phone size={12} className="text-slate-300" /> {emp.phone}</div>
                </div>
              </div>
            );
          })}
        </div>
      ) : activeTab === 'vacancies' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {vacancies.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border border-dashed border-slate-200 animate-in fade-in duration-700">
               <Briefcase size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Sem vagas publicadas</p>
            </div>
          ) : vacancies.map((v, index) => (
            <div key={v.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all relative overflow-hidden flex flex-col group animate-in fade-in slide-in-from-bottom-4 duration-700" style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'backwards' }}>
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><Briefcase size={20} className={v.status === 'Open' ? 'text-blue-600' : 'text-slate-300'} /></div>
                <div className="flex gap-2">
                  <button onClick={() => handleEditVacancy(v)} className="p-2 text-slate-300 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                  <button onClick={() => deleteVacancy(v.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">{v.title}</h3>
              <div className="space-y-2 mb-6">
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><MapPin size={14} className="text-blue-500" /> {v.location}</div>
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><LayoutList size={14} className="text-blue-500" /> {v.area}</div>
                <div className="flex items-center gap-2 text-xs font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg w-fit mt-3"><Mail size={12} /> monteimobiliario@gmail.com</div>
              </div>
              <div className="mt-auto pt-6 border-t border-slate-50 flex items-center justify-between">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${v.status === 'Open' ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-400'}`}>{v.status === 'Open' ? v.type : 'Fechada'}</span>
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(v.created_at).toLocaleDateString()}</span>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in duration-700">
           <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
              <div className="flex items-center gap-4">
                 <div className="p-3 bg-emerald-100 text-emerald-600 rounded-2xl"><UserPlus size={24} /></div>
                 <div>
                    <h3 className="text-xl font-black text-slate-900">Portal de Candidatos</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Sincronização Cloud Realtime Ativa</p>
                 </div>
              </div>
              <div className="flex gap-4">
                 <div className="px-4 py-2 bg-white rounded-xl border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <Sparkles size={12} className="text-emerald-500 animate-pulse" /> Cloud Live
                 </div>
              </div>
           </div>
           <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                    <th className="px-10 py-6">Candidato / Perfil</th>
