               <h2 className="text-2xl font-black text-slate-900 tracking-tight mb-2">{viewingEmp.name}</h2>
               <p className="text-xs font-black text-indigo-600 uppercase tracking-[0.2em] bg-indigo-50 px-4 py-1.5 rounded-xl mb-8">{viewingEmp.role}</p>
               <div className="w-full space-y-4">
                  <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4 text-left">
                     <div className="p-3 bg-blue-50 text-blue-600 rounded-xl"><Mail size={20} /></div>
                     <div className="min-w-0 flex-1">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1.5">Email Cloud</p>
                        <p className="text-sm font-bold text-slate-700 truncate">{viewingEmp.email}</p>
                     </div>
                  </div>
                  <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4 text-left">
                     <div className="p-3 bg-emerald-50 text-emerald-600 rounded-xl"><Phone size={20} /></div>
                     <div className="flex-1">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1.5">Contacto Direto</p>
                        <p className="text-sm font-bold text-slate-700">{viewingEmp.phone}</p>
                     </div>
                  </div>
               </div>
            </div>
            {/* Painel Informação Direita */}
            <div className="flex-1 p-12 overflow-y-auto custom-scrollbar space-y-12">
               <section>
                  <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mb-6 flex items-center gap-3">
                     <FileBadge size={16} className="text-indigo-600" /> Detalhes Contratuais Monte Cloud
                  </h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                     <div className="p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100">
                        <div className="flex items-center gap-3 mb-4"><DollarSign size={18} className="text-emerald-500" /><span className="text-xs font-black text-slate-900 uppercase">Vencimento Base</span></div>
                        <p className="text-3xl font-black text-slate-900 tracking-tighter">{viewingEmp.salary.toLocaleString()} <span className="text-sm text-slate-400">MT/Mês</span></p>
                     </div>
                     <div className="p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100">
                        <div className="flex items-center gap-3 mb-4"><CreditCard size={18} className="text-blue-500" /><span className="text-xs font-black text-slate-900 uppercase">Método de Pagamento</span></div>
                        <p className="text-2xl font-black text-blue-600">{viewingEmp.payment_method || 'M-Pesa'}</p>
                     </div>
                  </div>
               </section>
               <section>
                  <div className="flex items-center justify-between mb-6">
                     <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center gap-3"><Wrench size={16} className="text-blue-600" /> Histórico Operacional</h3>
                     <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg">Sincronizado Monte Cloud: OK</span>
                  </div>
                  <div className="bg-indigo-900 p-8 rounded-[3.5rem] relative overflow-hidden group">
                     <div className="absolute top-0 right-0 p-8 opacity-10"><Trophy size={80} className="text-white" /></div>
                     <div className="relative z-10">
                        <h4 className="text-lg font-black text-white mb-2">Monte Intelligence v5.0 Performance</h4>
                        <p className="text-xs text-indigo-200 font-medium mb-6 leading-relaxed">Avaliação estratégica baseada em conformidade técnica e agilidade operacional.</p>
                        <button className="px-6 py-2 bg-white text-indigo-900 rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-blue-400 hover:text-white transition-all">Relatório Analítico</button>
                     </div>
                  </div>
               </section>
            </div>
          </div>
        </div>
      )}

      {/* Modal Novo Colaborador */}
      {showAddModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-8 border-indigo-600">
            <button onClick={() => { setShowAddModal(false); setEditingEmpId(null); }} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10">
               <div className="w-14 h-14 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><UserPlus size={28} /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingEmpId ? 'Editar Staff' : 'Registar Novo Talento'}</h2>
            </div>
            <form onSubmit={handleSaveEmployee} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                  <input required value={formState.name} onChange={e => setFormState({...formState, name: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Email Profissional</label>
                  <input required type="email" value={formState.email} onChange={e => setFormState({...formState, email: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                </div>
              </div>
              <div className="pt-8 border-t border-slate-100 flex gap-4">
                 <button disabled={saving} type="submit" className="flex-1 py-7 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-2xl hover:bg-slate-900 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50">
                    {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Sincronizar Staff Cloud</>}
                 </button>
                 <button type="button" onClick={() => { setShowAddModal(false); setEditingEmpId(null); }} className="px-10 py-7 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Sair</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Publicar Vaga */}
      {showVacancyModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 md:p-14 max-w-5xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-8 border-blue-600">
            <button onClick={() => setShowVacancyModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-6">
               <div className="w-14 h-14 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center shadow-inner"><Briefcase size={28} /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingVacancyId ? 'Editar Vaga' : 'Publicar Oportunidade'}</h2>
            </div>
            <div className="bg-blue-50 border border-blue-100 p-4 rounded-[2.5rem] mb-8 flex items-center gap-3">
               <Info size={20} className="text-blue-600" />
               <p className="text-[10px] font-bold text-blue-800 uppercase tracking-widest">Canais de Apoio Monte: <span className="font-black">monteimobiliario@gmail.com</span> | <span className="font-black">+258 87 501 8283</span></p>
            </div>
            <form onSubmit={handleSaveVacancy} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Título do Cargo</label>
                  <input required value={vacancyForm.title} onChange={e => setVacancyForm({...vacancyForm, title: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all" />
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Área</label>
                   <select value={vacancyForm.area} onChange={e => setVacancyForm({...vacancyForm, area: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all cursor-pointer">
                      <option>Vendas</option><option>Operações</option><option>Tecnologia</option><option>Administrativo</option>
                   </select>
                </div>
              </div>
              <div className="space-y-4">
                 <div className="flex items-center justify-between">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição Estratégica (Markdown)</label>
                    <button type="button" onClick={handleAiOptimize} disabled={isAiLoading} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-blue-600 transition-all flex items-center gap-2 shadow-lg active:scale-95 disabled:opacity-50">
                       {isAiLoading ? <Loader2 className="animate-spin" size={14} /> : <Sparkles size={14} className="text-blue-400" />} Otimizar: Monte Intelligence v5.0
                    </button>
                 </div>
                 <textarea required value={vacancyForm.description} onChange={e => setVacancyForm({...vacancyForm, description: e.target.value})} rows={8} className="w-full bg-slate-50 border-none rounded-[3.5rem] p-10 font-medium text-sm outline-none focus:ring-4 focus:ring-blue-100 transition-all resize-none shadow-inner" placeholder="O que o candidato ideal precisa de saber..." />
              </div>
              <div className="pt-8 border-t border-slate-100 flex gap-4">
                 <button disabled={saving} type="submit" className="flex-1 py-7 bg-blue-600 text-white font-black rounded-[2.5rem] shadow-2xl hover:bg-slate-900 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50">
                    {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Publicar na Monte Cloud</>}
                 </button>
                 <button type="button" onClick={() => setShowVacancyModal(false)} className="px-10 py-7 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Voltar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HRView;

import React, { useState, useEffect } from 'react';
import { Briefcase, MapPin, ArrowRight, UserPlus, Mail, Loader2, Info, ChevronDown, ChevronUp, Image as ImageIcon, X, Send, CheckCircle2, Globe, Link as LinkIcon, Phone, ShieldCheck, HelpCircle } from 'lucide-react';
import { supabase } from '../supabaseClient';
import { JobVacancy } from '../types';

const CareerView: React.FC = () => {
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // States para Candidatura
  const [showApplyModal, setShowApplyModal] = useState(false);
  const [selectedJob, setSelectedJob] = useState<JobVacancy | null>(null);
  const [isApplying, setIsApplying] = useState(false);
  const [applyStatus, setApplyStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [hasConsent, setHasConsent] = useState(false);
  const [applyForm, setApplyForm] = useState({ name: '', email: '', phone: '', linkedin: '', message: '' });

  useEffect(() => {
    fetchVacancies();
  }, []);

  async function fetchVacancies() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('job_vacancies')
        .select('*')
        .eq('status', 'Open')
        .order('created_at', { ascending: false });
      if (!error) setVacancies(data || []);
    } catch (err) {
      console.error("Error fetching jobs:", err);
    } finally {
      setLoading(false);
    }
  }

  const handleOpenApply = (job: JobVacancy) => {
    setSelectedJob(job);
    setApplyStatus('idle');
    setHasConsent(false);
    setApplyForm({ name: '', email: '', phone: '', linkedin: '', message: '' });
    setShowApplyModal(true);
  };

  const handleApplySubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasConsent) return;
    setIsApplying(true);
    try {
      const { error } = await supabase.from('job_applications').insert([{
        job_id: selectedJob?.id, job_title: selectedJob?.title, applicant_name: applyForm.name,
        applicant_email: applyForm.email, applicant_phone: applyForm.phone, applicant_linkedin: applyForm.linkedin,
        message: applyForm.message, status: 'Pendente', consent_given: true, created_at: new Date().toISOString()
      }]);
      if (error) throw error;
      setApplyStatus('success');
    } catch (err) {
      setApplyStatus('error');
    } finally {
      setIsApplying(false);
    }
  };

  if (loading) return (
    <div className="py-32 flex flex-col items-center gap-4 bg-white min-h-[60vh]">
       <Loader2 className="animate-spin text-blue-600" size={48} />
       <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando com a Monte Cloud...</p>
    </div>
  );

  return (
    <div className="animate-in fade-in duration-700" role="main">
      <section className="relative h-[450px] flex items-center justify-center text-center text-white overflow-hidden">
        <div className="absolute inset-0 z-0">
          <img src="https://images.unsplash.com/photo-1522071820081-009f0129c71c?auto=format&fit=crop&q=80&w=1200" alt="Team" className="w-full h-full object-cover" />
          <div className="absolute inset-0 bg-slate-900/75 backdrop-blur-[1px]"></div>
        </div>
        <div className="relative z-10 max-w-4xl px-4">
          <h1 className="text-4xl md:text-6xl font-black mb-6 leading-tight tracking-tighter">
            Trabalhe na <span className="text-blue-400">Monte Cloud</span>
          </h1>
          <p className="text-slate-300 text-lg md:text-xl font-medium max-w-2xl mx-auto mb-10 leading-relaxed italic">
            Canal Oficial: <span className="text-white font-bold">monteimobiliario@gmail.com</span> | <span className="text-white font-bold">+258 87 501 8283</span>
          </p>
          <a href="#vagas" className="bg-blue-600 hover:bg-blue-700 text-white px-12 py-5 rounded-[2.5rem] font-black text-xs uppercase tracking-widest transition-all shadow-2xl">Explorar Oportunidades</a>
        </div>
      </section>

      <section id="vagas" className="py-20 px-4 md:px-8 bg-slate-50">
        <div className="max-w-6xl mx-auto">
          <div className="flex items-center justify-between mb-12">
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Vagas em Destaque</h2>
            <div className="flex items-center gap-2 px-4 py-2 bg-white rounded-full border border-slate-200 text-[10px] font-black text-slate-400 uppercase tracking-widest">
               <ShieldCheck size={14} className="text-blue-600" /> Vagas Auditadas
            </div>
          </div>

          <div className="space-y-6">
            {vacancies.map((job) => (
              <div key={job.id} className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden transition-all hover:shadow-2xl hover:scale-[1.005]">
                <div className="p-8 flex flex-col md:flex-row md:items-center justify-between gap-6 cursor-pointer" onClick={() => setExpandedId(expandedId === job.id ? null : job.id)}>
                   <div className="flex-1">
                      <h3 className="text-2xl font-black text-slate-900 mb-2">{job.title}</h3>
                      <div className="flex flex-wrap gap-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                         <span className="flex items-center gap-1.5"><MapPin size={12} className="text-blue-600" /> {job.location}</span>
                         <span className="flex items-center gap-1.5"><Briefcase size={12} className="text-blue-600" /> {job.area}</span>
                      </div>
                   </div>
                   <div className="flex items-center gap-4">
                      <button onClick={() => handleOpenApply(job)} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-[10px] uppercase tracking-widest hover:bg-slate-900 transition-all">Candidatar-se</button>
                      <div className={`p-3 rounded-full bg-slate-50 text-slate-400 transition-transform ${expandedId === job.id ? 'rotate-180' : ''}`}><ChevronDown size={20} /></div>
                   </div>
                </div>
                {expandedId === job.id && (
                  <div className="px-10 pb-12 pt-4 border-t border-slate-50 animate-in slide-in-from-top-4 duration-500">
                     <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                        <div className="lg:col-span-8">
                           <div className="prose prose-slate max-w-none text-slate-600 font-medium whitespace-pre-line leading-relaxed text-sm bg-slate-50 p-10 rounded-[3.5rem] border border-slate-100">
                              {job.description || "Descrição em sincronização técnica."}
                           </div>
                        </div>
                        <div className="lg:col-span-4 space-y-6">
                           <div className="p-8 bg-white border border-slate-100 rounded-[3.5rem] shadow-xl">
                              <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6 border-b border-slate-50 pb-4">Suporte ao Candidato</h4>
                              <div className="space-y-4">
                                 <div className="flex items-center gap-3 text-xs font-bold text-slate-700"><Mail size={16} className="text-blue-600" /> monteimobiliario@gmail.com</div>
                                 <div className="flex items-center gap-3 text-xs font-bold text-slate-700"><Phone size={16} className="text-blue-600" /> +258 87 501 8283</div>
                              </div>
                              <div className="mt-8 pt-6 border-t border-slate-50 flex items-center gap-3">
                                 <HelpCircle size={18} className="text-amber-500" />
                                 <p className="text-[9px] text-slate-400 font-medium leading-tight italic">Problemas no formulário? Entre em contacto direto pelos canais acima.</p>
                              </div>
                           </div>
                        </div>
                     </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* Modal Candidatura */}
      {showApplyModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 md:p-14 max-w-2xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] border-t-8 border-blue-600">
            <button onClick={() => setShowApplyModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            {applyStatus === 'success' ? (
              <div className="py-20 text-center animate-in zoom-in">
                <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8"><CheckCircle2 size={64} /></div>
                <h2 className="text-3xl font-black text-slate-900 mb-2">Enviado para a Cloud!</h2>
                <p className="text-slate-500 font-medium mb-10">Analisaremos o seu perfil em tempo real. Boa sorte!</p>
                <button onClick={() => setShowApplyModal(false)} className="px-12 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all">Concluído</button>
              </div>
            ) : (
              <>
                <div className="mb-10">
                   <span className="bg-blue-50 text-blue-600 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest mb-3 inline-block">Monte Digital Recruiter</span>
                   <h2 className="text-3xl font-black text-slate-900">Candidatura: {selectedJob?.title}</h2>
                </div>
                <form onSubmit={handleApplySubmit} className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <input required value={applyForm.name} onChange={e => setApplyForm({...applyForm, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50" placeholder="Nome Completo" />
                    <input required type="email" value={applyForm.email} onChange={e => setApplyForm({...applyForm, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50" placeholder="E-mail de Contacto" />
                    <input required value={applyForm.phone} onChange={e => setApplyForm({...applyForm, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50" placeholder="Telemóvel (+258...)" />
                    <input value={applyForm.linkedin} onChange={e => setApplyForm({...applyForm, linkedin: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold outline-none border-none focus:ring-4 focus:ring-blue-50" placeholder="Link LinkedIn (Opcional)" />
                  </div>
                  <textarea required value={applyForm.message} onChange={e => setApplyForm({...applyForm, message: e.target.value})} rows={4} className="w-full bg-slate-50 rounded-[2.5rem] p-8 text-xs font-medium outline-none border-none focus:ring-4 focus:ring-blue-50 resize-none shadow-inner" placeholder="Por que quer trabalhar connosco? Conte brevemente a sua história..." />
                  <div className="flex items-start gap-4 p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                    <input required type="checkbox" checked={hasConsent} onChange={e => setHasConsent(e.target.checked)} className="mt-1 w-5 h-5 rounded text-blue-600 cursor-pointer" />
                    <label className="text-[10px] text-slate-500 font-medium leading-relaxed italic">Concordo com o processamento dos meus dados para fins exclusivos de recrutamento na Monte Imobiliária. Proteção total via Monte Hub.</label>
                  </div>
                  <button disabled={isApplying || !hasConsent} type="submit" className="w-full py-7 bg-blue-600 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-slate-900 transition-all flex items-center justify-center gap-3 disabled:opacity-50">
                    {isApplying ? <Loader2 className="animate-spin" /> : <><Send size={18} /> Submeter Candidatura Cloud</>}
                  </button>
                  <p className="text-center text-[9px] font-black text-slate-300 uppercase tracking-widest">Suporte: +258 87 501 8283</p>
                </form>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default CareerView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUp, TrendingDown, Users, Home, 
  Plus, MessageSquare, Briefcase, 
  Loader2, Wallet, ChevronRight,
  ArrowUpRight, ArrowDownRight, Activity,
  Sparkles, Star, Quote, Trash2, Edit3, Save, X as CloseIcon, 
  Cloud, ShieldCheck, Globe
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, 
  ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property, Testimonial } from '../types';
import { getStrategicInsight } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ revenue: 0, expenses: 0, employees: 0, properties: 0, contacts: 0 });
  const [recentStaff, setRecentStaff] = useState<Employee[]>([]);
  const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Analisando pulso da empresa...');
  const [showQuickTransaction, setShowQuickTransaction] = useState(false);
  const [showTestimonialModal, setShowTestimonialModal] = useState(false);
  const [savingTx, setSavingTx] = useState(false);
  const [savingTestimonial, setSavingTestimonial] = useState(false);

  const [txForm, setTxForm] = useState({ description: '', amount: '', type: 'DESPESA' as 'RECEITA' | 'DESPESA' });
  const [testimonialForm, setTestimonialForm] = useState<Partial<Testimonial>>({ 
    client_name: '', client_avatar: '', comment: '', rating: 5, status: 'Aprovado' 
  });
  const [editingTestimonialId, setEditingTestimonialId] = useState<string | null>(null);

  useEffect(() => {
    fetchGlobalStats();
    fetchTestimonials();
  }, []);

  async function fetchTestimonials() {
    try {
      const { data, error } = await supabase.from('testimonials').select('*').order('created_at', { ascending: false });
      if (!error) setTestimonials(data || []);
    } catch (e) {}
  }

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*').limit(5).order('created_at', { ascending: false }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true })
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        revenue: rev, expenses: exp,
        employees: (await supabase.from('employees').select('*', { count: 'exact', head: true })).count || 0,
        properties: propRes.count || 0, contacts: contactRes.count || 0
      });

      setRecentStaff(empRes.data || []);
      const insight = await getStrategicInsight(`Receitas: ${rev}MT, Despesas: ${exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.data?.length}`);
      setAiInsight(insight);
    } catch (error) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleQuickTx = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTx(true);
    try {
      const { error } = await supabase.from('transactions').insert([{
        description: txForm.description, amount: Number(txForm.amount), type: txForm.type, category: 'Geral',
        date: new Date().toISOString().split('T')[0]
      }]);
      if (!error) { setShowQuickTransaction(false); setTxForm({ description: '', amount: '', type: 'DESPESA' }); fetchGlobalStats(); }
    } finally { setSavingTx(false); }
  };

  const handleSaveTestimonial = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTestimonial(true);
    try {
      const payload = { client_name: testimonialForm.client_name, client_avatar: testimonialForm.client_avatar || `https://picsum.photos/seed/${testimonialForm.client_name}/100`, comment: testimonialForm.comment, rating: testimonialForm.rating, status: testimonialForm.status };
      let res;
      if (editingTestimonialId) res = await supabase.from('testimonials').update(payload).eq('id', editingTestimonialId);
      else res = await supabase.from('testimonials').insert([payload]);
      if (!res.error) { setShowTestimonialModal(false); setEditingTestimonialId(null); fetchTestimonials(); }
    } finally { setSavingTestimonial(false); }
  };

  const deleteTestimonial = async (id: string) => {
    if (confirm("Remover?")) { await supabase.from('testimonials').delete().eq('id', id); fetchTestimonials(); }
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#10b981' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  const barData = useMemo(() => [{ name: 'Financeiro', receitas: stats.revenue, despesas: stats.expenses }], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <Loader2 className="animate-spin text-blue-600" size={56} />
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando com a Monte Cloud...</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* Status Bar */}
      <div className="flex items-center justify-between bg-white px-10 py-5 rounded-[4rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-4">
           <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_12px_rgba(16,185,129,0.7)]"></div>
           <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
             <ShieldCheck size={18} className="text-blue-600" /> Monte Hub v7.0 Full Sync
           </span>
        </div>
        <div className="hidden md:flex items-center gap-8">
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Activity size={14} className="text-indigo-500" /> Latência Cloud: 18ms</div>
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Globe size={14} className="text-emerald-500" /> Rede Activa: Beira Node</div>
        </div>
      </div>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Fluxo Cloud', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-blue-600" />, trend: 'Saldo Disponível', color: 'blue' },
          { label: 'Portfólio', value: stats.properties, icon: <Home className="text-indigo-600" />, trend: 'Imóveis Ativos', color: 'indigo' },
          { label: 'Staff Monte', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores', color: 'emerald' },
          { label: 'Leads Ativos', value: stats.contacts, icon: <MessageSquare className="text-amber-600" />, trend: 'Candidaturas/Pedidos', color: 'amber' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all group overflow-hidden relative">
            <div className={`absolute top-0 right-0 w-32 h-32 bg-${kpi.color}-50 rounded-full translate-x-12 -translate-y-12 group-hover:scale-110 transition-transform`}></div>
            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-6">
                <div className={`p-4 bg-${kpi.color}-50 rounded-2xl`}>{kpi.icon}</div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{kpi.label}</span>
              </div>
              <h3 className="text-4xl font-black text-slate-900 tracking-tight mb-2">{kpi.value}</h3>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{kpi.trend}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-10">
        <div className="xl:col-span-2 space-y-10">
          {/* AI Strategic Box */}
          <div className="bg-slate-900 rounded-[4rem] p-16 text-white relative overflow-hidden shadow-2xl group border border-white/5">
             <div className="absolute top-0 right-0 w-[450px] h-[450px] bg-blue-600/10 rounded-full blur-[120px] -translate-y-1/2 translate-x-1/2"></div>
             <div className="relative z-10">
                <div className="flex items-center gap-4 mb-10">
                   <div className="p-5 bg-blue-600 rounded-[2rem] text-white animate-pulse shadow-2xl shadow-blue-500/40"><Sparkles size={32} /></div>
                   <div>
                     <h3 className="text-3xl font-black tracking-tight">Monte Intelligence v5.0</h3>
                     <p className="text-[10px] font-black text-blue-400 uppercase tracking-[0.3em] mt-2">Deep Learning Strategy Engine</p>
                   </div>
                </div>
                <p className="text-3xl font-medium text-slate-200 leading-relaxed italic mb-12 max-w-3xl">"{aiInsight}"</p>
                <div className="flex items-center gap-8">
                   <div className="flex items-center gap-3 text-[11px] font-black uppercase tracking-[0.3em] text-slate-500">
                     <Activity size={18} className="text-emerald-500" /> Analisando Contexto Global
                   </div>
                   <div className="px-6 py-2 bg-white/5 rounded-full text-[10px] font-black text-blue-300 uppercase border border-white/5">Sincronizado: OK</div>
                </div>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
             <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm flex flex-col min-h-[450px]">
                <div className="flex items-center justify-between mb-12">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900">Performance Fiscal</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Balanço de Capital Monte Cloud</p>
                  </div>
                </div>
                <div className="flex-1 w-full">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={barData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" hide />
                      <YAxis hide />
                      <Tooltip contentStyle={{ borderRadius: '2rem', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.1)' }} />
                      <Bar dataKey="receitas" fill="#10b981" radius={[15, 15, 0, 0]} barSize={55} />
                      <Bar dataKey="despesas" fill="#f43f5e" radius={[15, 15, 0, 0]} barSize={55} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
             </div>
             <div className="h-[450px]"><TodoList /></div>
          </div>
        </div>

        {/* Sidebar */}
        <div className="space-y-10">
          <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm">
            <h3 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-3">
              <TrendingUp className="text-blue-600" size={24} /> Balanço Cloud
            </h3>
            <div className="h-72 w-full mb-10">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie data={chartData} cx="50%" cy="50%" innerRadius={85} outerRadius={110} paddingAngle={10} dataKey="value">
                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                  </Pie>
                  <Tooltip contentStyle={{ borderRadius: '2rem', border: 'none' }} formatter={(v: any) => `${Number(v).toLocaleString()} MT`} />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="space-y-4">
              <div className="p-8 bg-emerald-50 rounded-[3rem] flex justify-between items-center group transition-all shadow-sm">
                <div><p className="text-[11px] font-black text-emerald-600 uppercase tracking-widest mb-1">Receitas</p><p className="text-2xl font-black text-slate-900">{stats.revenue.toLocaleString()} MT</p></div>
                <div className="p-4 bg-white rounded-2xl shadow-sm text-emerald-600 group-hover:scale-110 transition-all"><ArrowUpRight size={24} /></div>
              </div>
              <div className="p-8 bg-rose-50 rounded-[3rem] flex justify-between items-center group transition-all shadow-sm">
                <div><p className="text-[11px] font-black text-rose-600 uppercase tracking-widest mb-1">Despesas</p><p className="text-2xl font-black text-slate-900">{stats.expenses.toLocaleString()} MT</p></div>
                <div className="p-4 bg-white rounded-2xl shadow-sm text-rose-600 group-hover:scale-110 transition-all"><ArrowDownRight size={24} /></div>
              </div>
              <button onClick={() => setShowQuickTransaction(true)} className="w-full py-7 border-2 border-dashed border-slate-200 rounded-[3rem] text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] hover:border-blue-600 hover:text-blue-600 transition-all flex items-center justify-center gap-3 mt-4">
                <Plus size={20} /> Novo Lançamento
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Quick Transaction Modal */}
      {showQuickTransaction && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-16 max-w-lg w-full shadow-2xl relative border-t-8 border-blue-600">
            <button onClick={() => setShowQuickTransaction(false)} className="absolute top-12 right-12 text-slate-400 hover:text-slate-900 transition-colors"><CloseIcon size={32} /></button>
            <div className="flex items-center gap-4 mb-12">
               <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center shadow-inner"><Wallet size={32} /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">Movimento Cloud</h2>
            </div>
            <form onSubmit={handleQuickTx} className="space-y-10">
               <div className="flex p-2 bg-slate-100 rounded-[3rem] shadow-inner">
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'RECEITA'})} className={`flex-1 py-5 text-[11px] font-black uppercase tracking-widest rounded-[2.5rem] transition-all ${txForm.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Entrada</button>
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'DESPESA'})} className={`flex-1 py-5 text-[11px] font-black uppercase tracking-widest rounded-[2.5rem] transition-all ${txForm.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Saída</button>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Motivo / Categoria</label>
                  <input required value={txForm.description} onChange={e => setTxForm({...txForm, description: e.target.value})} className="w-full bg-slate-50 p-6 rounded-3xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100 transition-all" placeholder="Ex: Manutenção Elétrica Sede" />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Valor (MZN)</label>
                  <input required type="number" value={txForm.amount} onChange={e => setTxForm({...txForm, amount: e.target.value})} className="w-full bg-slate-50 p-8 rounded-3xl font-black text-4xl border-none outline-none focus:ring-4 focus:ring-blue-100 shadow-inner" placeholder="0.00" />
               </div>
               <button disabled={savingTx} type="submit" className="w-full py-8 bg-blue-600 text-white font-black rounded-[3rem] hover:bg-slate-900 transition-all active:scale-95 flex items-center justify-center gap-4 shadow-2xl shadow-blue-600/20">
                  {savingTx ? <Loader2 className="animate-spin" /> : <><Plus size={24} /> Confirmar Registo</>}
               </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Shield, Key, UserCog, Save, 
  CheckCircle2, Loader2, Search,
  Fingerprint, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Users as UsersIcon, Terminal, Plus, Settings2,
  ChevronRight, History, Activity, Calendar, Award,
  RotateCcw, EyeOff, ShieldAlert, Lock, Zap,
  AlertTriangle,
  ArrowRight
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee, User } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

interface AuditLog {
  id: string;
  admin_name: string;
  target_user_name: string;
  action_type: string;
  change_details: string;
  created_at: string;
}

interface RoleRecord {
  id: string;
  name: string;
  is_deleted: boolean;
  permissions: string[];
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  { id: 'finance.view', label: 'Ver Finanças', category: 'Financeiro', description: 'Consultar relatórios e saldos.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Criar Lançamentos', category: 'Financeiro', description: 'Adicionar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Remover Registos', category: 'Financeiro', description: 'Eliminar transações do fluxo.', icon: <Trash2 size={14} /> },
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista e status de contratos.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Controlar projetos e orçamentos.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Gerir imóveis e portfólio.', icon: <LayoutGrid size={14} /> },
  { id: 'admin.access', label: 'Full TI Admin', category: 'Sistema', description: 'Acesso total às ferramentas TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Logs Auditoria', category: 'Sistema', description: 'Rastrear todas as mudanças.', icon: <Terminal size={14} /> },
];

interface AdminViewProps {
  currentUser: User | null;
}

const AdminView: React.FC<AdminViewProps> = ({ currentUser }) => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<RoleRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [originalUserState, setOriginalUserState] = useState<Employee | null>(null);

  const [showRolesModal, setShowRolesModal] = useState(false);
  const [showDeletedRoles, setShowDeletedRoles] = useState(false);
  const [newRoleName, setNewRoleName] = useState('');
  const [editingRoleName, setEditingRoleName] = useState<{old: string, new: string} | null>(null);
  const [editingRolePermissions, setEditingRolePermissions] = useState<RoleRecord | null>(null);
  const [rolesLoading, setRolesLoading] = useState(false);

  const [showAuditModal, setShowAuditModal] = useState(false);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  const sqlSchema = `-- MONTE HUB FULL INFRASTRUCTURE SETUP v7.0
-- 1. Tabela de Cargos
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    is_deleted boolean DEFAULT false,
    permissions text[] DEFAULT '{}',
    created_at timestamptz DEFAULT now()
);
-- Adicionar as outras tabelas e configurações conforme necessário...`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    setRolesLoading(true);
    try {
      const { data, error } = await supabase.from('roles').select('*').order('name');
      if (!error && data) {
        setRoles(data);
      } else {
        const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
        setRoles(fallbackRoles);
      }
    } catch (e) { 
      const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
      setRoles(fallbackRoles);
    } finally {
      setRolesLoading(false);
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) { console.warn("Error fetching users"); }
    finally { setLoading(false); }
  }

  async function fetchAuditLogs() {
    setLoadingLogs(true);
    try {
      const { data, error } = await supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);
      if (!error) setAuditLogs(data || []);
    } catch (e) { console.warn("Error fetching logs"); }
    finally { setLoadingLogs(false); }
  }

  const handleAddRole = async () => {
    if (!newRoleName.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase.from('roles').insert([{ name: newRoleName.trim(), is_deleted: false, permissions: [] }]);
      if (error) throw error;
      setNewRoleName('');
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao adicionar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateRole = async () => {
    if (!editingRoleName || !editingRoleName.new.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ name: editingRoleName.new.trim() })
        .eq('name', editingRoleName.old);
      if (error) throw error;
      setEditingRoleName(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao atualizar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleSaveRolePermissions = async () => {
    if (!editingRolePermissions) return;
    setSaving(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ permissions: editingRolePermissions.permissions })
        .eq('id', editingRolePermissions.id);
      if (error) throw error;

      if (currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_name: `Cargo: ${editingRolePermissions.name}`,
          action_type: 'CARGO_MATRIZ_SYNC',
          change_details: `Template de privilégios redefinido para o cargo: ${editingRolePermissions.name}. Total: ${editingRolePermissions.permissions.length} perms.`
        }]);
      }

      setEditingRolePermissions(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao salvar permissões do cargo: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteRole = async (name: string) => {
    if (!confirm(`Deseja desativar o cargo "${name}"? Ele será movido para a reciclagem.`)) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: true })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao desativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleReactivateRole = async (name: string) => {
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: false })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao reativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateUserPermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser || !originalUserState) return;
    setSaving(true);
    const changes = [];
    if (editingUser.role !== originalUserState.role) changes.push(`Cargo: [${originalUserState.role}] -> [${editingUser.role}]`);
    const oldPerms = originalUserState.permissions || [];
    const newPerms = editingUser.permissions || [];
    const added = newPerms.filter(p => !oldPerms.includes(p));
    const removed = oldPerms.filter(p => !newPerms.includes(p));
    if (added.length > 0) changes.push(`+ Permissões: ${added.join(', ')}`);
    if (removed.length > 0) changes.push(`- Permissões: ${removed.join(', ')}`);

    try {
      const { error } = await supabase.from('employees').update({ role: editingUser.role, permissions: editingUser.permissions || [] }).eq('id', editingUser.id);
      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const toggleUserPermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleRolePermission = (permId: string) => {
    if (!editingRolePermissions) return;
    const current = editingRolePermissions.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[], target: 'user' | 'role') => {
    const idsInCategory = permsInCategory.map(p => p.id);

    if (target === 'user' && editingUser) {
      const currentPerms = editingUser.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingUser({ ...editingUser, permissions: newPerms });
    } else if (target === 'role' && editingRolePermissions) {
      const currentPerms = editingRolePermissions.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
    }
  };

  const applyRoleTemplateToUser = () => {
    if (!editingUser) return;
    const roleTemplate = roles.find(r => r.name === editingUser.role);
    if (roleTemplate) {
      setEditingUser({ ...editingUser, permissions: [...roleTemplate.permissions] });
    }
  };

  const getSecurityLevel = (permsCount: number) => {
    if (permsCount >= 8) return { label: 'Crítico', color: 'bg-rose-500', text: 'text-rose-600' };
    if (permsCount >= 5) return { label: 'Elevado', color: 'bg-amber-500', text: 'text-amber-600' };
    if (permsCount >= 3) return { label: 'Médio', color: 'bg-blue-500', text: 'text-blue-600' };
    return { label: 'Baixo', color: 'bg-emerald-500', text: 'text-emerald-600' };
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const filteredRoles = useMemo(() => {
    return roles.filter(r => r.is_deleted === showDeletedRoles);
  }, [roles, showDeletedRoles]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Governança estratégica de matrizes de privilégios.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowRolesModal(true)} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <Settings2 size={16} className="text-blue-600" /> Configurar Matriz de Cargos
           </button>
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Histórico Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-4 mb-6"><Database size={24} className="text-indigo-400" /><h3 className="text-xl font-black">Infraestrutura Cloud Matriz v7.0</h3></div>
        <p className="text-xs text-slate-400 mb-4 font-medium leading-relaxed max-w-2xl">Módulo de sincronização de permissões por cargo. Reduza o overhead de gestão de TI aplicando templates de acesso a grupos inteiros de colaboradores.</p>
        <div className="flex gap-4">
           <button onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="flex items-center gap-2 px-8 py-4 bg-white/10 hover:bg-white/20 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all border border-white/5 selection:bg-indigo-500">
             {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Script SQL de Reparação'}
           </button>
           <div className="px-6 py-4 bg-emerald-500/10 border border-emerald-500/20 rounded-xl flex items-center gap-3 text-emerald-400">
              <CheckCircle2 size={16} />
              <span className="text-[10px] font-black uppercase tracking-widest">Servidor Online & Sincronizado</span>
           </div>
        </div>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar colaborador ou cargo..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Permissões Específicas (Overrides)</th>
                <th className="px-10 py-6 text-right">Controlo</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase()) || u.role.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover ring-4 ring-slate-50" alt="" />
                      <div>
                        <p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p>
                        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap justify-center gap-1.5">
                      {user.permissions?.length ? user.permissions.map(p => (
                        <span key={p} className="text-[8px] font-black bg-white border border-slate-100 text-slate-400 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>
                      )) : <span className="text-[9px] font-black text-slate-300 italic uppercase tracking-tighter">Utilizando Matriz do Cargo</span>}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100 shadow-sm transition-all group-hover:scale-105">
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-[12px] border-indigo-600">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <div className="relative">
                 <img src={editingUser.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover shadow-2xl ring-4 ring-white" alt="" />
                 <div className="absolute -bottom-2 -right-2 p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><UserCog size={16}/></div>
               </div>
               <div>
