import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  XCircle,
  AlertTriangle,
  FileText,
  CloudUpload,
  Check,
  Clock,
  RotateCcw,
  Loader2,
  X
} from 'lucide-react';
import { Task } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada para o lote 45.', completed: false, priority: 'Alta', due_date: '2024-05-01' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza dos filtros no 2º andar.', completed: true, priority: 'Média', due_date: '2024-05-30' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { title: newTaskTitle, description: '', completed: false, priority: 'Média' as const, due_date: null };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, due_date: string | null) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: due_date || undefined } : t));
    try { await supabase.from('tasks').update({ due_date }).eq('id', id); } catch (e) {}
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);
    syncTimeoutRef.current = setTimeout(async () => {
      try { await supabase.from('tasks').update({ description }).eq('id', id); setTimeout(() => setIsSyncing(null), 1000); } catch (e) { setIsSyncing(null); }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId) return;
    try {
      await supabase.from('tasks').delete().eq('id', deletingTaskId);
      setTasks(tasks.filter(t => t.id !== deletingTaskId));
      setDeletingTaskId(null);
    } catch (e) {
      setDeletingTaskId(null);
    }
  };

  const isOverdue = (dateStr?: string) => {
