          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : overdue ? 'border-rose-400 bg-rose-50/40' : 'border-slate-100 hover:border-blue-100'}`}>
