} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property, Testimonial } from '../types';
import { getStrategicInsight } from '../geminiService';
import TodoList from '../components/TodoList';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ revenue: 0, expenses: 0, employees: 0, properties: 0, contacts: 0 });
  const [recentStaff, setRecentStaff] = useState<Employee[]>([]);
  const [testimonials, setTestimonials] = useState<Testimonial[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Analisando pulso da empresa...');
  const [showQuickTransaction, setShowQuickTransaction] = useState(false);
  const [showTestimonialModal, setShowTestimonialModal] = useState(false);
  const [savingTx, setSavingTx] = useState(false);
  const [savingTestimonial, setSavingTestimonial] = useState(false);

  const [txForm, setTxForm] = useState({ description: '', amount: '', type: 'DESPESA' as 'RECEITA' | 'DESPESA' });
  const [testimonialForm, setTestimonialForm] = useState<Partial<Testimonial>>({ 
    client_name: '', client_avatar: '', comment: '', rating: 5, status: 'Aprovado' 
  });
  const [editingTestimonialId, setEditingTestimonialId] = useState<string | null>(null);

  useEffect(() => {
    fetchGlobalStats();
    fetchTestimonials();
  }, []);

  async function fetchTestimonials() {
    try {
      const { data, error } = await supabase.from('testimonials').select('*').order('created_at', { ascending: false });
      if (!error) setTestimonials(data || []);
    } catch (e) {}
  }

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*').limit(5).order('created_at', { ascending: false }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true })
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        revenue: rev, expenses: exp,
        employees: (await supabase.from('employees').select('*', { count: 'exact', head: true })).count || 0,
        properties: propRes.count || 0, contacts: contactRes.count || 0
      });

      setRecentStaff(empRes.data || []);
      const insight = await getStrategicInsight(`Receitas: ${rev}MT, Despesas: ${exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.data?.length}`);
      setAiInsight(insight);
    } catch (error) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleQuickTx = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTx(true);
    try {
      const { error } = await supabase.from('transactions').insert([{
        description: txForm.description, amount: Number(txForm.amount), type: txForm.type, category: 'Geral',
        date: new Date().toISOString().split('T')[0]
      }]);
      if (!error) { setShowQuickTransaction(false); setTxForm({ description: '', amount: '', type: 'DESPESA' }); fetchGlobalStats(); }
    } finally { setSavingTx(false); }
  };

  const handleSaveTestimonial = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTestimonial(true);
    try {
      const payload = { client_name: testimonialForm.client_name, client_avatar: testimonialForm.client_avatar || `https://picsum.photos/seed/${testimonialForm.client_name}/100`, comment: testimonialForm.comment, rating: testimonialForm.rating, status: testimonialForm.status };
      let res;
      if (editingTestimonialId) res = await supabase.from('testimonials').update(payload).eq('id', editingTestimonialId);
      else res = await supabase.from('testimonials').insert([payload]);
      if (!res.error) { setShowTestimonialModal(false); setEditingTestimonialId(null); fetchTestimonials(); }
    } finally { setSavingTestimonial(false); }
  };

  const deleteTestimonial = async (id: string) => {
    if (confirm("Remover?")) { await supabase.from('testimonials').delete().eq('id', id); fetchTestimonials(); }
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#10b981' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  const barData = useMemo(() => [{ name: 'Financeiro', receitas: stats.revenue, despesas: stats.expenses }], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <Loader2 className="animate-spin text-blue-600" size={56} />
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* Status Bar */}
      <div className="flex items-center justify-between bg-white px-10 py-5 rounded-[4rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-4">
           <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_12px_rgba(16,185,129,0.7)]"></div>
           <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
             <ShieldCheck size={18} className="text-blue-600" /> Monte Imobiliária Hub Sync
           </span>
        </div>
        <div className="hidden md:flex items-center gap-8">
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Activity size={14} className="text-indigo-500" /> Latência Cloud: 18ms</div>
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Globe size={14} className="text-emerald-500" /> Rede Activa: Beira Node</div>
        </div>
      </div>

      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Fluxo Monte', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-blue-600" />, trend: 'Saldo Disponível', color: 'blue' },
          { label: 'Portfólio', value: stats.properties, icon: <Home className="text-indigo-600" />, trend: 'Imóveis Ativos', color: 'indigo' },
