             <div className="relative z-10">
                <div className="flex items-center gap-4 mb-10">
                   <div className="p-5 bg-blue-600 rounded-[2rem] text-white animate-pulse shadow-2xl shadow-blue-500/40"><Sparkles size={32} /></div>
