import React, { useState, useEffect, useMemo } from 'react';
import { ArrowUpCircle, ArrowDownCircle, Plus, DollarSign, X, Loader2, BarChart3, TrendingUp } from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction } from '../types';

const FinanceView: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newLaunch, setNewLaunch] = useState({
    description: '',
    category: 'Vendas',
    amount: '',
    type: 'DESPESA' as 'RECEITA' | 'DESPESA',
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  async function fetchTransactions() {
    setLoading(true);
    const { data, error } = await supabase.from('transactions').select('*').order('date', { ascending: false });
    if (!error) setTransactions(data || []);
    setLoading(false);
  }

  const handleLaunch = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      description: newLaunch.description,
      category: newLaunch.category,
      amount: Number(newLaunch.amount),
      type: newLaunch.type,
      date: new Date().toISOString().split('T')[0]
    };

    const { error } = await supabase.from('transactions').insert([payload]);
    if (!error) {
      setShowModal(false);
      setNewLaunch({ description: '', category: 'Vendas', amount: '', type: 'DESPESA' });
      fetchTransactions();
    }
  };

  const totals = transactions.reduce((acc, curr) => {
    if (curr.type === 'RECEITA') acc.receita += Number(curr.amount);
    else acc.despesa += Number(curr.amount);
    return acc;
  }, { receita: 0, despesa: 0 });

  // Processamento de dados para o gráfico (Últimos 6 meses)
  const chartData = useMemo(() => {
    const months = [];
    const date = new Date();

    // Gerar chaves para os últimos 6 meses
    for (let i = 5; i >= 0; i--) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthName = d.toLocaleString('pt-BR', { month: 'short' });
      months.push({
        key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`,
        name: monthName.charAt(0).toUpperCase() + monthName.slice(1),
        receita: 0,
        despesa: 0
      });
    }

    // Distribuir transações nos meses correspondentes
    transactions.forEach(t => {
      const tMonth = t.date.substring(0, 7); // yyyy-mm
      const monthObj = months.find(m => m.key === tMonth);
      if (monthObj) {
        if (t.type === 'RECEITA') monthObj.receita += Number(t.amount);
        else monthObj.despesa += Number(t.amount);
      }
    });

    return months;
  }, [transactions]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-emerald-500/20">
            <BarChart3 size={24} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Fluxo Financeiro</h1>
            <p className="text-slate-500 font-medium">Balanço corporativo Monte Imobiliária.</p>
          </div>
        </div>
        <button onClick={() => setShowModal(true)} className="flex items-center gap-2 px-8 py-4 bg-emerald-600 text-white rounded-[2rem] font-black text-sm shadow-xl shadow-emerald-500/20 hover:scale-105 transition-all">
          <Plus size={20} /> Novo Lançamento
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <>
          {/* Cards de Resumo */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Receitas Acumuladas</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-emerald-600">{totals.receita.toLocaleString()} MT</p>
                <ArrowUpCircle className="text-emerald-500" size={24} />
              </div>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Despesas Acumuladas</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-rose-600">{totals.despesa.toLocaleString()} MT</p>
                <ArrowDownCircle className="text-rose-500" size={24} />
              </div>
            </div>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl group-hover:bg-white/10 transition-all"></div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Saldo em Caixa</p>
              <p className="text-3xl font-black text-white">{(totals.receita - totals.despesa).toLocaleString()} MT</p>
            </div>
          </div>

          {/* Gráfico de Barras Mensal */}
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h3 className="text-xl font-black text-slate-900">Histórico de Performance</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Gestão Monte Imobiliária</p>
              </div>
              <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest">
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 bg-emerald-500 rounded-full"></span> Receitas
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 bg-rose-500 rounded-full"></span> Despesas
                </div>
              </div>
            </div>

            <div className="w-full" style={{ height: '350px' }}>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis 
                    dataKey="name" 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 700 }}
                    dy={10}
                  />
                  <YAxis 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 700 }}
                    tickFormatter={(value) => `${value / 1000}k`}
                  />
                  <Tooltip 
                    cursor={{ fill: '#f8fafc' }}
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: 'bold' }}
                    formatter={(value: any) => [`${value.toLocaleString()} MT`]}
                  />
                  <Bar 
                    dataKey="receita" 
                    name="Receitas" 
                    fill="#10b981" 
                    radius={[10, 10, 0, 0]} 
                    barSize={40}
                  />
                  <Bar 
                    dataKey="despesa" 
                    name="Despesas" 
                    fill="#f43f5e" 
                    radius={[10, 10, 0, 0]} 
                    barSize={40}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Tabela de Transações */}
          <div className="bg-white rounded-[3.5rem] border border-slate-100 overflow-hidden shadow-sm">
            <div className="px-10 py-6 border-b border-slate-50 flex items-center justify-between">
              <h3 className="text-lg font-black text-slate-900">Extrato Recente</h3>
              <div className="flex gap-2">
                <span className="text-[10px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase">Sincronizado</span>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <th className="px-10 py-5">Descrição</th>
                    <th className="px-10 py-5">Categoria</th>
                    <th className="px-10 py-5">Data</th>
                    <th className="px-10 py-5 text-right">Valor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {transactions.length === 0 ? (
                    <tr>
                      <td colSpan={4} className="px-10 py-20 text-center text-slate-400 font-medium italic">
                        Nenhuma transação registada até ao momento.
                      </td>
                    </tr>
                  ) : (
                    transactions.map((t) => (
                      <tr key={t.id} className="hover:bg-slate-50/50 transition-all group">
                        <td className="px-10 py-6 font-bold text-slate-900">{t.description}</td>
                        <td className="px-10 py-6">
                          <span className="text-[10px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-lg uppercase tracking-wider">{t.category}</span>
                        </td>
                        <td className="px-10 py-6 text-sm text-slate-500 font-medium">{t.date}</td>
                        <td className={`px-10 py-6 text-right font-black ${t.type === 'RECEITA' ? 'text-emerald-600' : 'text-rose-600'}`}>
                          {t.type === 'RECEITA' ? '+' : '-'} {t.amount.toLocaleString()} MT
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-lg w-full shadow-2xl relative">
            <button onClick={() => setShowModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900 transition-colors"><X size={28} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3">
              <DollarSign className="text-emerald-600" /> Novo Lançamento
            </h2>
            <form onSubmit={handleLaunch} className="space-y-6">
              <div className="flex p-1.5 bg-slate-100 rounded-[1.5rem]">
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'RECEITA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Receita</button>
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'DESPESA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Despesa</button>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input required placeholder="Ex: Pagamento Fornecedor AC" value={newLaunch.description} onChange={e => setNewLaunch({...newLaunch, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 transition-all" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                <select value={newLaunch.category} onChange={e => setNewLaunch({...newLaunch, category: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer">
                  <option>Vendas</option><option>Aluguel</option><option>Manutenção</option><option>Salários</option><option>Marketing</option><option>TI</option><option>Logística</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montante (MT)</label>
                <input required type="number" placeholder="0.00" value={newLaunch.amount} onChange={e => setNewLaunch({...newLaunch, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-black outline-none border-none text-2xl focus:ring-2 focus:ring-emerald-500 transition-all" />
              </div>
              <button type="submit" className="w-full py-6 bg-emerald-600 text-white font-black rounded-[2rem] shadow-xl shadow-emerald-500/20 hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-3">
                <Plus size={20} /> Confirmar Lançamento Monte
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default FinanceView;

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  XCircle,
  AlertTriangle,
  FileText,
  CloudUpload,
  Check,
  Clock,
  RotateCcw,
  Loader2,
  X
} from 'lucide-react';
import { Task } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada para o lote 45.', completed: false, priority: 'Alta', due_date: '2024-05-01' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza dos filtros no 2º andar.', completed: true, priority: 'Média', due_date: '2024-05-30' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { title: newTaskTitle, description: '', completed: false, priority: 'Média' as const, due_date: null };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, due_date: string | null) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: due_date || undefined } : t));
    try { await supabase.from('tasks').update({ due_date }).eq('id', id); } catch (e) {}
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);
    syncTimeoutRef.current = setTimeout(async () => {
      try { await supabase.from('tasks').update({ description }).eq('id', id); setTimeout(() => setIsSyncing(null), 1000); } catch (e) { setIsSyncing(null); }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId) return;
    try {
      await supabase.from('tasks').delete().eq('id', deletingTaskId);
      setTasks(tasks.filter(t => t.id !== deletingTaskId));
      setDeletingTaskId(null);
    } catch (e) {
      setDeletingTaskId(null);
    }
  };

  const isOverdue = (dateStr?: string) => {
    if (!dateStr) return false;
    const today = new Date(); today.setHours(0,0,0,0);
    return new Date(dateStr) < today;
  };

  const getPriorityColorClass = (priority: string, overdue: boolean, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    if (overdue) return 'bg-red-600 animate-pulse';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-gray-400';
      default: return 'bg-blue-500';
    }
  };

  const filteredTasks = tasks.filter(task => 
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  if (loading) return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm p-20 flex flex-col items-center gap-4">
      <Loader2 className="animate-spin text-blue-600" size={32} />
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Lista de Afazeres
        </h3>
        <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
          <RotateCcw size={16} />
        </button>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="flex gap-2">
          <input 
            type="text" 
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="Adicionar nova tarefa..."
            className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none transition-all"
          />
          <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20"><Plus size={24} /></button>
        </form>
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Pesquisar afazeres..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 focus:ring-2 focus:ring-blue-100 outline-none" />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {filteredTasks.map((task) => {
          const overdue = isOverdue(task.due_date) && !task.completed;
          const isExpanded = expandedId === task.id;
          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : overdue ? 'border-red-400 bg-red-50/40' : 'border-slate-100 hover:border-blue-100'}`}>
              {/* Barra Lateral de Prioridade */}
              <div className={`absolute left-0 top-0 bottom-0 w-1 ${getPriorityColorClass(task.priority, overdue, task.completed)} transition-all duration-500 shadow-sm`}></div>

              <div className="p-5 pl-7 flex items-center gap-4">
                <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : overdue ? 'text-red-500' : 'text-slate-300 hover:text-blue-500'}`}>
                  {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                </button>
                <div className="flex-1 min-w-0 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                  <div className="flex items-center gap-3">
                    {/* Ponto Colorido de Prioridade */}
                    <div className="shrink-0">
                      {task.completed ? (
                        <CheckCircle2 size={14} className="text-emerald-500" />
                      ) : overdue ? (
                        <AlertTriangle size={14} className="text-red-600 animate-pulse" />
                      ) : (
                        <div className={`w-3 h-3 rounded-full ${
                          task.priority === 'Alta' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' :
                          task.priority === 'Média' ? 'bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]' : 
                          'bg-gray-400'
                        }`} />
                      )}
                    </div>
                    <p className={`text-sm font-black truncate ${task.completed ? 'text-slate-400 line-through' : overdue ? 'text-red-900' : 'text-slate-900'}`}>{task.title}</p>
                  </div>
                  {task.due_date && <div className="flex items-center gap-1.5 mt-1.5"><Calendar size={12} className="text-blue-400" /><span className="text-[10px] font-black uppercase text-slate-400">{new Date(task.due_date).toLocaleDateString()}</span></div>}
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className="p-2 text-slate-400 hover:text-blue-600"><ChevronDown className={isExpanded ? 'rotate-180' : ''} size={18} /></button>
                  <button onClick={() => setDeletingTaskId(task.id)} className="p-2 text-slate-300 hover:text-red-600 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={18} /></button>
                </div>
              </div>
              {isExpanded && (
                <div className="px-14 pb-8 pt-2 animate-in slide-in-from-top-4 duration-500 space-y-6">
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prioridade</label>
                        <div className="flex gap-2 bg-slate-50 p-1 rounded-xl">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button key={p} onClick={() => updatePriority(task.id, p)} className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400'}`}>{p}</button>
                          ))}
                        </div>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prazo</label>
                        <input type="date" value={task.due_date || ''} onChange={e => updateDueDate(task.id, e.target.value)} className="w-full bg-slate-50 rounded-xl px-4 py-2 text-xs font-bold border-none outline-none focus:ring-2 focus:ring-blue-100" />
                      </div>
                   </div>
                   <div className="space-y-2">
                      <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Notas Internas</label>
                      <textarea value={task.description} onChange={e => updateDescription(task.id, e.target.value)} rows={4} className="w-full bg-slate-50 rounded-[2rem] p-6 text-xs font-medium border-none outline-none focus:bg-white focus:ring-2 focus:ring-blue-50 transition-all shadow-inner resize-none" placeholder="Detalhes da tarefa..." />
                   </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="p-5 bg-slate-50/50 border-t border-slate-50 text-center">
         <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">Monte Imobiliária Task Engine v5.0</p>
      </div>

      {deletingTaskId && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-10 max-w-sm w-full shadow-2xl text-center border-t-8 border-red-500 animate-in zoom-in-95 duration-500">
