import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  XCircle,
  AlertTriangle,
  FileText,
  CloudUpload,
  Check,
  Clock,
  RotateCcw,
  Loader2,
  X
} from 'lucide-react';
import { Task } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [lastSavedId, setLastSavedId] = useState<string | null>(null);
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const [isDeletingLoading, setIsDeletingLoading] = useState(false);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        // Fallback para dados de exemplo se a tabela não existir
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada para o lote 45.', completed: false, priority: 'Alta', due_date: '2024-05-01' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza dos filtros no 2º andar.', completed: true, priority: 'Média', due_date: '2024-05-30' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { title: newTaskTitle, description: '', completed: false, priority: 'Média' as const, due_date: null };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, due_date: string | null) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: due_date || undefined } : t));
    try { await supabase.from('tasks').update({ due_date }).eq('id', id); } catch (e) {}
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => setLastSavedId(null), 2000);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId) return;
    setIsDeletingLoading(true);
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) {
        setTasks(tasks.filter(t => t.id !== deletingTaskId));
      }
    } catch (e) {
      console.error("Erro ao eliminar tarefa:", e);
    } finally {
      setIsDeletingLoading(false);
      setDeletingTaskId(null);
    }
  };

  const isOverdue = (dateStr?: string) => {
    if (!dateStr) return false;
    const today = new Date(); today.setHours(0,0,0,0);
    return new Date(dateStr) < today;
  };

  const getPriorityColorClass = (priority: string, overdue: boolean, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    if (overdue) return 'bg-red-600 animate-pulse';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const getPriorityBadgeClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-50 text-emerald-600 border-emerald-100';
    switch (priority) {
      case 'Alta': return 'bg-red-50 text-red-600 border-red-100';
      case 'Média': return 'bg-blue-50 text-blue-600 border-blue-100';
      case 'Baixa': return 'bg-slate-50 text-slate-500 border-slate-200';
      default: return 'bg-blue-50 text-blue-600 border-blue-100';
    }
  };

  const filteredTasks = tasks.filter(task => 
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  if (loading) return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm p-20 flex flex-col items-center gap-4">
      <Loader2 className="animate-spin text-blue-600" size={32} />
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Lista de Afazeres
        </h3>
        <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
          <RotateCcw size={16} />
        </button>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="flex gap-2">
          <input 
            type="text" 
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="Adicionar nova tarefa..."
            className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none transition-all"
          />
          <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20"><Plus size={24} /></button>
        </form>
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Pesquisar afazeres..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 focus:ring-2 focus:ring-blue-100 outline-none" />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {filteredTasks.length === 0 ? (
          <div className="py-20 text-center text-slate-300 italic text-xs">Sem tarefas nesta vista.</div>
        ) : filteredTasks.map((task) => {
          const overdue = isOverdue(task.due_date) && !task.completed;
          const isExpanded = expandedId === task.id;
          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : overdue ? 'border-red-400 bg-red-50/40' : 'border-slate-100 hover:border-blue-100'}`}>
              {/* Barra Lateral de Prioridade Reforçada */}
              <div className={`absolute left-0 top-0 bottom-0 w-2 ${getPriorityColorClass(task.priority, overdue, task.completed)} transition-all duration-500 shadow-inner`}></div>

              <div className="p-5 pl-8 flex items-center gap-4">
                <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : overdue ? 'text-red-500' : 'text-slate-300 hover:text-blue-500'}`}>
                  {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                </button>
                <div className="flex-1 min-w-0 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                  <div className="flex items-center gap-3">
                    <div className="shrink-0">
                      {task.completed ? (
                        <CheckCircle2 size={14} className="text-emerald-500" />
                      ) : overdue ? (
                        <AlertTriangle size={14} className="text-red-600 animate-pulse" />
                      ) : (
                        <div className={`w-3 h-3 rounded-full ${
                          task.priority === 'Alta' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' :
                          task.priority === 'Média' ? 'bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]' : 
                          'bg-slate-400'
                        }`} />
                      )}
                    </div>
                    <p className={`text-sm font-black truncate ${task.completed ? 'text-slate-400 line-through' : overdue ? 'text-red-900' : 'text-slate-900'}`}>{task.title}</p>

                    {/* Badge de Prioridade Visual */}
                    <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full border transition-colors ${getPriorityBadgeClass(task.priority, task.completed)}`}>
                      {task.priority}
                    </span>
                  </div>
                  {task.due_date && <div className="flex items-center gap-1.5 mt-1.5"><Calendar size={12} className="text-blue-400" /><span className="text-[10px] font-black uppercase text-slate-400">{new Date(task.due_date).toLocaleDateString()}</span></div>}
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className="p-2 text-slate-400 hover:text-blue-600"><ChevronDown className={isExpanded ? 'rotate-180' : ''} size={18} /></button>
                  <button onClick={() => setDeletingTaskId(task.id)} className="p-2 text-slate-300 hover:text-red-600 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={18} /></button>
                </div>
              </div>
              {isExpanded && (
                <div className="px-14 pb-8 pt-2 animate-in slide-in-from-top-4 duration-500 space-y-6">
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Alterar Prioridade</label>
                        <div className="flex gap-2 bg-slate-50 p-1 rounded-xl">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button key={p} onClick={() => updatePriority(task.id, p)} className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:bg-white/50'}`}>{p}</button>
                          ))}
                        </div>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prazo</label>
                        <input type="date" value={task.due_date || ''} onChange={e => updateDueDate(task.id, e.target.value)} className="w-full bg-slate-50 rounded-xl px-4 py-2 text-xs font-bold border-none outline-none focus:ring-2 focus:ring-blue-100" />
                      </div>
                   </div>
                   <div className="space-y-2">
                      <div className="flex items-center justify-between">
                         <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Notas Internas</label>

                         {/* Indicador Visual de Sincronização Aprimorado */}
                         <div className="flex items-center gap-2">
                           {isSyncing === task.id ? (
                             <div className="flex items-center gap-1.5 text-blue-500 animate-pulse">
                               <CloudUpload size={10} />
                               <span className="text-[7px] font-black uppercase">A guardar na Cloud...</span>
                             </div>
                           ) : lastSavedId === task.id ? (
                             <div className="flex items-center gap-1.5 text-emerald-500 animate-in fade-in duration-300">
                               <Check size={10} />
                               <span className="text-[7px] font-black uppercase">Guardado com sucesso</span>
                             </div>
                           ) : null}
                         </div>
                      </div>
                      <textarea value={task.description} onChange={e => updateDescription(task.id, e.target.value)} rows={4} className="w-full bg-slate-50 rounded-[2rem] p-6 text-xs font-medium border-none outline-none focus:bg-white focus:ring-2 focus:ring-blue-50 transition-all shadow-inner resize-none" placeholder="Detalhes da tarefa..." />
                   </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="p-5 bg-slate-50/50 border-t border-slate-50 text-center">
         <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">Monte Imobiliária Task Engine v5.2</p>
      </div>

      {/* Modal de Confirmação de Exclusão */}
      {deletingTaskId && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-10 max-sm w-full shadow-2xl text-center border-t-8 border-red-500 animate-in zoom-in-95 duration-500">
              <div className="w-20 h-20 bg-red-50 text-red-500 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
                 <AlertTriangle size={40} className={isDeletingLoading ? 'animate-spin' : 'animate-pulse'} />
              </div>
              <h4 className="text-xl font-black text-slate-900 mb-2">Eliminar Tarefa?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">Esta acção removerá o registo permanentemente da Monte Imobiliária.</p>

              <div className="flex flex-col gap-3">
                 <button 
                   disabled={isDeletingLoading}
                   onClick={confirmDeletion}
                   className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20 hover:bg-red-600 transition-all active:scale-95 flex items-center justify-center gap-2"
                 >
                   {isDeletingLoading ? <Loader2 className="animate-spin" size={16} /> : "Sim, Eliminar Agora"}
                 </button>
                 <button 
                   disabled={isDeletingLoading}
                   onClick={() => setDeletingTaskId(null)}
                   className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all"
                 >
                   Cancelar
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect } from 'react';
import { 
  Calendar, Users, DollarSign, ArrowRight, Clock, 
  Loader2, Plus, X, Save, Edit3, Trash2, Camera, 
  CheckCircle2, AlertTriangle, Building, AlertCircle,
  UserPlus, TrendingUp, TrendingDown
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Project } from '../types';

const ProjectsView: React.FC = () => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const [formData, setFormData] = useState<Partial<Project>>({
    name: '',
    status: 'Planejado',
    budget: 0,
    spent: 0,
    deadline: '',
    image: '',
    team: []
  });

  const [teamInput, setTeamInput] = useState('');

  useEffect(() => {
    fetchProjects();
  }, []);

  async function fetchProjects() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('projects')
        .select('*')
        .order('created_at', { ascending: false });

      if (!error) setProjects(data || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleOpenModal = (project: Project | null = null) => {
    setMessage(null);
    if (project) {
      setEditingProject(project);
      setFormData(project);
      setTeamInput(project.team ? project.team.join(', ') : '');
    } else {
      setEditingProject(null);
      setFormData({
        name: '',
        status: 'Planejado',
        budget: 0,
        spent: 0,
        deadline: '',
        image: '',
        team: []
      });
      setTeamInput('');
    }
    setShowModal(true);
  };

  const handleSaveProject = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setMessage(null);

    const teamArray = teamInput.split(',').map(name => name.trim()).filter(name => name !== '');

    const payload = {
      ...formData,
      team: teamArray,
      image: formData.image || 'https://images.unsplash.com/photo-1503387762-592dea58ef23?auto=format&fit=crop&q=80&w=800'
    };

    try {
      const { error } = editingProject 
        ? await supabase.from('projects').update(payload).eq('id', editingProject.id)
        : await supabase.from('projects').insert([payload]);

      if (error) throw error;

      setMessage({ 
        type: 'success', 
        text: editingProject ? 'Projeto atualizado com sucesso!' : 'Obra iniciada com sucesso na Cloud.' 
      });
      setShowModal(false);
      fetchProjects();

      setTimeout(() => setMessage(null), 5000);
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Erro ao processar solicitação.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteProject = async (id: string) => {
    if (confirm('Tem certeza que deseja excluir este projeto?')) {
      const { error } = await supabase.from('projects').delete().eq('id', id);
      if (!error) {
        setMessage({ type: 'success', text: 'Projeto removido com sucesso.' });
        setTimeout(() => setMessage(null), 3000);
        fetchProjects();
      }
    }
  };

  // Função centralizada para estilos de progresso solicitada
  const getProgressStyles = (percent: number) => {
    if (percent >= 100) {
      return { 
        bar: 'bg-rose-500 shadow-[0_0_12px_rgba(244,63,94,0.4)]', 
        text: 'text-rose-600',
        label: 'Excedido' 
      };
    }
    if (percent >= 80) {
      return { 
        bar: 'bg-amber-500 shadow-[0_0_12px_rgba(245,158,11,0.3)]', 
        text: 'text-amber-600',
        label: 'Crítico' 
      };
    }
    return { 
      bar: 'bg-emerald-500 shadow-[0_0_12px_rgba(16,185,129,0.3)]', 
      text: 'text-emerald-600',
      label: 'Saudável' 
    };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
            <Building size={28} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Projetos & Obras</h1>
            <p className="text-slate-500 font-medium">Controle financeiro e execução em tempo real.</p>
          </div>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl shadow-blue-500/20 hover:bg-blue-700 transition-all hover:scale-105"
        >
          <Plus size={20} /> Iniciar Obra
        </button>
      </div>

      {message && (
        <div className={`p-5 rounded-[2rem] border-l-4 flex items-center justify-between gap-4 animate-in slide-in-from-top-4 ${
          message.type === 'success' ? 'bg-emerald-50 border-emerald-500 text-emerald-800' : 'bg-rose-50 border-rose-500 text-rose-800'
        }`}>
          <div className="flex items-center gap-4">
            {message.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
            <p className="text-sm font-black uppercase tracking-tight">{message.text}</p>
          </div>
          <button onClick={() => setMessage(null)} className="p-2 hover:bg-black/5 rounded-full transition-colors"><X size={18} /></button>
        </div>
      )}

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {projects.map((project) => {
            const spentPercent = project.budget > 0 ? Math.round((Number(project.spent) / Number(project.budget)) * 100) : 0;
            const remaining = Number(project.budget) - Number(project.spent);
            const isOverBudget = spentPercent >= 100;
            const styles = getProgressStyles(spentPercent);

            return (
              <div key={project.id} className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col hover:shadow-2xl transition-all duration-500 group">
                <div className="h-48 relative overflow-hidden">
                  <img src={project.image || 'https://images.unsplash.com/photo-1541888946425-d81bb19480c5?auto=format&fit=crop&q=80&w=800'} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={project.name} />
                  <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent"></div>
                  <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-4 py-1.5 rounded-xl text-[10px] font-black uppercase text-blue-600 shadow-sm">
                    {project.status}
                  </div>
                  <div className="absolute bottom-4 left-6 right-6 flex items-center justify-between text-white">
                    <div className="flex -space-x-2">
                      {project.team?.slice(0, 3).map((member, i) => (
                        <img key={i} src={`https://picsum.photos/seed/${member}/100`} className="w-8 h-8 rounded-full border-2 border-white object-cover" title={member} alt="" />
                      ))}
                      {project.team && project.team.length > 3 && (
                        <div className="w-8 h-8 rounded-full border-2 border-white bg-slate-800 flex items-center justify-center text-[10px] font-black">+{project.team.length - 3}</div>
                      )}
                    </div>
                    <div className="flex items-center gap-1.5 text-[10px] font-black uppercase">
                       <Calendar size={12} className="text-blue-400" /> {project.deadline}
                    </div>
                  </div>
                </div>

                <div className="p-8 flex-1 flex flex-col">
                  <div className="flex justify-between items-start mb-6">
                    <h3 className="text-xl font-black text-slate-900 line-clamp-1 flex-1">{project.name}</h3>
                    <div className="flex gap-1 ml-4 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={() => handleOpenModal(project)} className="p-2 text-slate-400 hover:text-blue-600 bg-slate-50 rounded-lg transition-all"><Edit3 size={16} /></button>
                      <button onClick={() => handleDeleteProject(project.id)} className="p-2 text-slate-400 hover:text-rose-600 bg-slate-50 rounded-lg transition-all"><Trash2 size={16} /></button>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4 mb-8">
                    <div className="p-4 bg-slate-50 rounded-2xl">
                      <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1 flex items-center gap-1">
                        <DollarSign size={10} className="text-blue-500" /> Orçamento
                      </p>
                      <p className="text-sm font-black text-slate-900">{Number(project.budget).toLocaleString()} MT</p>
                    </div>
                    <div className={`p-4 rounded-2xl ${isOverBudget ? 'bg-rose-50' : 'bg-blue-50'}`}>
                      <p className={`text-[9px] font-black uppercase tracking-widest mb-1 flex items-center gap-1 ${isOverBudget ? 'text-rose-600' : 'text-blue-600'}`}>
                        {isOverBudget ? <TrendingUp size={10} /> : <TrendingDown size={10} />} Saldo
                      </p>
                      <p className={`text-sm font-black ${isOverBudget ? 'text-rose-700' : 'text-blue-700'}`}>
                        {remaining.toLocaleString()} MT
                      </p>
                    </div>
                  </div>

                  <div className="mt-auto">
                    <div className="flex justify-between items-end mb-3">
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mb-1">Saúde Financeira</p>
                        <p className={`text-sm font-black ${styles.text} ${isOverBudget ? 'animate-pulse' : ''}`}>
                          {styles.label} ({spentPercent}%)
                        </p>
                      </div>
                      <div className={`text-xl font-black tracking-tighter ${styles.text}`}>
                        {spentPercent}%
                      </div>
                    </div>

                    <div className="w-full bg-slate-100 h-4 rounded-full overflow-hidden relative shadow-inner">
                      <div 
                        className={`h-full transition-all duration-1000 ease-out relative ${styles.bar}`} 
                        style={{ width: `${Math.min(spentPercent, 100)}%` }}
                      >
                        <div className="absolute inset-0 bg-white/20 blur-[1px]"></div>
                        <div className="absolute inset-y-0 right-0 w-8 bg-gradient-to-r from-transparent to-white/30 skew-x-[-20deg]"></div>
                      </div>
                    </div>

                    <div className="flex justify-between mt-3 text-[10px] font-bold">
                      <span className="text-slate-400 uppercase">Gasto: <span className="text-slate-900">{Number(project.spent).toLocaleString()} MT</span></span>
                      {isOverBudget && (
                        <span className="text-rose-600 flex items-center gap-1 uppercase font-black">
                          <AlertTriangle size={10}/> Risco Crítico
                        </span>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Project Modal */}
      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-2xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => setShowModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-3"><Building className="text-blue-600" /> {editingProject ? 'Editar Projeto' : 'Nova Obra Monte'}</h2>
            <form onSubmit={handleSaveProject} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Projeto</label>
                  <input required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" placeholder="Ex: Reforma Condomínio Mar" />
                </div>
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2"><UserPlus size={14} className="text-blue-600" /> Equipa (Nomes separados por vírgula)</label>
                  <input value={teamInput} onChange={e => setTeamInput(e.target.value)} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" placeholder="Ex: Ana Silva, Bruno Costa" />
                </div>
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">URL da Imagem da Obra</label>
                  <div className="relative">
                    <Camera className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input value={formData.image} onChange={e => setFormData({...formData, image: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 pl-14 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" placeholder="https://images.unsplash.com/..." />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Orçamento Total (MT)</label>
                  <input required type="number" value={formData.budget} onChange={e => setFormData({...formData, budget: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Gasto Atual (MT)</label>
                  <input required type="number" value={formData.spent} onChange={e => setFormData({...formData, spent: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status Atual</label>
                  <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-5 border-none font-bold outline-none cursor-pointer">
                    <option>Planejado</option><option>Em Andamento</option><option>Concluído</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Data de Entrega</label>
                  <input required type="date" value={formData.deadline} onChange={e => setFormData({...formData, deadline: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" />
                </div>
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full py-6 bg-blue-600 text-white font-black rounded-[2.5rem] shadow-2xl hover:bg-blue-700 transition-all flex items-center justify-center disabled:opacity-50">
                {isSubmitting ? <Loader2 className="animate-spin mr-2" /> : <Save size={20} className="mr-2" />}
                {editingProject ? 'Guardar Alterações' : 'Iniciar Projeto na Cloud'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProjectsView;

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  XCircle,
  AlertTriangle,
  FileText,
  CloudUpload,
  Check,
  Clock,
  RotateCcw,
  Loader2,
  X,
  RefreshCw
} from 'lucide-react';
import { Task } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [lastSavedId, setLastSavedId] = useState<string | null>(null);
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const [isDeletingLoading, setIsDeletingLoading] = useState(false);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
  }, []);

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        // Fallback para dados de exemplo se a tabela não existir
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada para o lote 45.', completed: false, priority: 'Alta', due_date: '2024-05-01' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza dos filtros no 2º andar.', completed: true, priority: 'Média', due_date: '2024-05-30' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { title: newTaskTitle, description: '', completed: false, priority: 'Média' as const, due_date: null };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, due_date: string | null) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: due_date || undefined } : t));
    try { await supabase.from('tasks').update({ due_date }).eq('id', id); } catch (e) {}
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => setLastSavedId(null), 2000);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId) return;
    setIsDeletingLoading(true);
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) {
        setTasks(tasks.filter(t => t.id !== deletingTaskId));
      }
    } catch (e) {
      console.error("Erro ao eliminar tarefa:", e);
    } finally {
      setIsDeletingLoading(false);
      setDeletingTaskId(null);
    }
  };

  const isOverdue = (dateStr?: string) => {
    if (!dateStr) return false;
    const today = new Date(); today.setHours(0,0,0,0);
    return new Date(dateStr) < today;
  };

  const getPriorityColorClass = (priority: string, overdue: boolean, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    if (overdue) return 'bg-red-600 animate-pulse';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const getPriorityBadgeClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-50 text-emerald-600 border-emerald-100';
    switch (priority) {
      case 'Alta': return 'bg-red-50 text-red-600 border-red-100';
      case 'Média': return 'bg-blue-50 text-blue-600 border-blue-100';
      case 'Baixa': return 'bg-slate-50 text-slate-500 border-slate-200';
      default: return 'bg-blue-50 text-blue-600 border-blue-100';
    }
  };

  const filteredTasks = tasks.filter(task => 
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
    (task.description && task.description.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  if (loading) return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm p-20 flex flex-col items-center gap-4">
      <Loader2 className="animate-spin text-blue-600" size={32} />
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Lista de Afazeres
        </h3>
        <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
          <RotateCcw size={16} />
        </button>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="flex gap-2">
          <input 
            type="text" 
            value={newTaskTitle}
            onChange={(e) => setNewTaskTitle(e.target.value)}
            placeholder="Adicionar nova tarefa..."
            className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none transition-all"
          />
          <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20"><Plus size={24} /></button>
        </form>
        <div className="relative">
          <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
          <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Pesquisar afazeres..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 focus:ring-2 focus:ring-blue-100 outline-none" />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {filteredTasks.length === 0 ? (
          <div className="py-20 text-center text-slate-300 italic text-xs">Sem tarefas nesta vista.</div>
        ) : filteredTasks.map((task) => {
          const overdue = isOverdue(task.due_date) && !task.completed;
          const isExpanded = expandedId === task.id;
          const isTaskSyncing = isSyncing === task.id;
          const isTaskSaved = lastSavedId === task.id;

          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : overdue ? 'border-red-400 bg-red-50/40' : 'border-slate-100 hover:border-blue-100'}`}>
              {/* Barra Lateral de Prioridade Reforçada */}
              <div className={`absolute left-0 top-0 bottom-0 w-2 ${getPriorityColorClass(task.priority, overdue, task.completed)} transition-all duration-500 shadow-inner`}></div>

              <div className="p-5 pl-8 flex items-center gap-4">
                <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : overdue ? 'text-red-500' : 'text-slate-300 hover:text-blue-500'}`}>
                  {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                </button>
                <div className="flex-1 min-w-0 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                  <div className="flex items-center gap-3">
                    <div className="shrink-0">
                      {task.completed ? (
                        <CheckCircle2 size={14} className="text-emerald-500" />
                      ) : overdue ? (
                        <AlertTriangle size={14} className="text-red-600 animate-pulse" />
                      ) : (
                        <div className={`w-3 h-3 rounded-full ${
                          task.priority === 'Alta' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.4)]' :
                          task.priority === 'Média' ? 'bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.3)]' : 
                          'bg-slate-400'
                        }`} />
                      )}
                    </div>
                    <p className={`text-sm font-black truncate ${task.completed ? 'text-slate-400 line-through' : overdue ? 'text-red-900' : 'text-slate-900'}`}>{task.title}</p>

                    {/* Badge de Prioridade Visual */}
                    <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full border transition-colors ${getPriorityBadgeClass(task.priority, task.completed)}`}>
                      {task.priority}
                    </span>
                  </div>
                  {task.due_date && <div className="flex items-center gap-1.5 mt-1.5"><Calendar size={12} className="text-blue-400" /><span className="text-[10px] font-black uppercase text-slate-400">{new Date(task.due_date).toLocaleDateString()}</span></div>}
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className="p-2 text-slate-400 hover:text-blue-600"><ChevronDown className={isExpanded ? 'rotate-180' : ''} size={18} /></button>
                  <button onClick={() => setDeletingTaskId(task.id)} className="p-2 text-slate-300 hover:text-red-600 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={18} /></button>
                </div>
              </div>
              {isExpanded && (
                <div className="px-14 pb-8 pt-2 animate-in slide-in-from-top-4 duration-500 space-y-6">
                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Alterar Prioridade</label>
                        <div className="flex gap-2 bg-slate-50 p-1 rounded-xl">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button key={p} onClick={() => updatePriority(task.id, p)} className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-400 hover:bg-white/50'}`}>{p}</button>
                          ))}
                        </div>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prazo</label>
                        <input type="date" value={task.due_date || ''} onChange={e => updateDueDate(task.id, e.target.value)} className="w-full bg-slate-50 rounded-xl px-4 py-2 text-xs font-bold border-none outline-none focus:ring-2 focus:ring-blue-100" />
                      </div>
                   </div>
                   <div className="space-y-2">
                      <div className="flex items-center justify-between">
                         <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Notas Internas</label>

                         {/* Indicador Visual de Sincronização Refinado */}
                         <div className="flex items-center gap-2 h-5">
                           {isTaskSyncing ? (
                             <div className="flex items-center gap-1.5 px-3 py-1 bg-blue-50 text-blue-600 rounded-full border border-blue-100 animate-pulse">
                               <RefreshCw size={10} className="animate-spin" />
                               <span className="text-[7px] font-black uppercase tracking-tighter">A guardar na Cloud...</span>
                             </div>
                           ) : isTaskSaved ? (
                             <div className="flex items-center gap-1.5 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full border border-emerald-100 animate-in fade-in slide-in-from-right-2 duration-300">
                               <CheckCircle2 size={10} className="animate-bounce" />
                               <span className="text-[7px] font-black uppercase tracking-tighter">Sincronizado</span>
                             </div>
                           ) : (
                             <div className="flex items-center gap-1 text-slate-300">
                               <CloudUpload size={10} />
                               <span className="text-[7px] font-black uppercase tracking-tighter">Cloud Ativa</span>
                             </div>
                           )}
                         </div>
                      </div>
                      <textarea 
                        value={task.description} 
                        onChange={e => updateDescription(task.id, e.target.value)} 
                        rows={4} 
                        className={`w-full bg-slate-50 rounded-[2rem] p-6 text-xs font-medium border-2 outline-none transition-all shadow-inner resize-none ${
                          isTaskSyncing ? 'border-blue-200 bg-blue-50/10 ring-4 ring-blue-50' : 
                          isTaskSaved ? 'border-emerald-200' : 
                          'border-transparent focus:bg-white focus:ring-2 focus:ring-blue-50'
                        }`} 
                        placeholder="Detalhes da tarefa..." 
                      />
                   </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      <div className="p-5 bg-slate-50/50 border-t border-slate-50 text-center">
         <p className="text-[9px] font-black text-slate-300 uppercase tracking-[0.3em]">Monte Imobiliária Task Engine v5.3</p>
      </div>

      {/* Modal de Confirmação de Exclusão */}
      {deletingTaskId && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-10 max-sm w-full shadow-2xl text-center border-t-8 border-red-500 animate-in zoom-in-95 duration-500">
              <div className="w-20 h-20 bg-red-50 text-red-500 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner">
                 <AlertTriangle size={40} className={isDeletingLoading ? 'animate-spin' : 'animate-pulse'} />
              </div>
              <h4 className="text-xl font-black text-slate-900 mb-2">Eliminar Tarefa?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">Esta acção removerá o registo permanentemente da Monte Imobiliária.</p>

              <div className="flex flex-col gap-3">
                 <button 
                   disabled={isDeletingLoading}
                   onClick={confirmDeletion}
                   className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20 hover:bg-red-600 transition-all active:scale-95 flex items-center justify-center gap-2"
                 >
                   {isDeletingLoading ? <Loader2 className="animate-spin" size={16} /> : "Sim, Eliminar Agora"}
                 </button>
                 <button 
                   disabled={isDeletingLoading}
                   onClick={() => setDeletingTaskId(null)}
                   className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all"
                 >
                   Cancelar
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

