                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'DESPESA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Saída</button>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Beneficiário (Responsável)</label>
                <div className="flex gap-2">
                  {isCreatingBeneficiary ? (
                    <div className="flex-1 flex gap-2 animate-in slide-in-from-top-2">
                      <input 
                        placeholder="Nome do Novo Agente/Digitador..." 
                        value={newBeneficiary.name}
                        onChange={e => setNewBeneficiary({...newBeneficiary, name: e.target.value})}
                        className="flex-1 bg-blue-50 border-blue-200 border rounded-2xl p-4 font-bold text-xs"
                      />
                      <select 
                        value={newBeneficiary.category}
                        onChange={e => setNewBeneficiary({...newBeneficiary, category: e.target.value as BeneficiaryCategory})}
                        className="bg-blue-50 border-blue-200 border rounded-2xl p-4 text-[10px] font-black uppercase"
                      >
                        <option>Agente de Campo</option><option>Supervisor</option><option>Digitador</option><option>Marketing</option>
                      </select>
                      <button type="button" onClick={handleCreateBeneficiary} className="p-4 bg-emerald-500 text-white rounded-2xl"><Plus size={20}/></button>
                      <button type="button" onClick={() => setIsCreatingBeneficiary(false)} className="p-4 bg-slate-200 text-slate-500 rounded-2xl"><X size={20}/></button>
                    </div>
                  ) : (
                    <div className="flex-1 flex gap-2">
                      <select 
                        value={newLaunch.beneficiary_id}
                        onChange={e => setNewLaunch({...newLaunch, beneficiary_id: e.target.value})}
                        className="flex-1 bg-slate-50 border-none rounded-2xl p-5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer"
                      >
                        <option value="">Geral / Sem Beneficiário</option>
                        {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name} ({b.category})</option>)}
                      </select>
                      <button type="button" onClick={() => setIsCreatingBeneficiary(true)} className="p-4 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-100"><UserPlus size={20}/></button>
                    </div>
                  )}
