              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input required placeholder="Ex: Pagamento por Digitadores de Dados" value={newLaunch.description} onChange={e => setNewLaunch({...newLaunch, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500" />
