               <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-xl shadow-indigo-500/20"><History size={28} /></div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Cofre de Auditoria Cloud</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Rastreabilidade integral de governação e segurança.</p>
               </div>
            </div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
              {loadingLogs ? <div className="py-20 flex justify-center"><Loader2 className="animate-spin text-indigo-600" size={32} /></div> : auditLogs.map((log) => (
                <div key={log.id} className="p-8 bg-slate-50 rounded-[3rem] border border-slate-100 hover:bg-white hover:shadow-xl hover:border-indigo-100 transition-all group">
                   <div className="flex justify-between items-start gap-4 mb-6">
                      <div className="flex items-center gap-4">
                         <div className="px-4 py-1.5 bg-indigo-600 text-white rounded-full text-[9px] font-black uppercase tracking-widest shadow-md">{log.action_type}</div>
                         <div className="flex items-center gap-2 text-slate-900 font-bold text-sm">
                            <span>{log.admin_name}</span>
                            <ArrowRight size={14} className="text-slate-300" />
                            <span className="text-indigo-600">{log.target_user_name}</span>
                         </div>
                      </div>
                      <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                         <Calendar size={12} />
                         {new Date(log.created_at).toLocaleString('pt-MZ')}
                      </div>
                   </div>
                   <div className="p-5 bg-white/50 rounded-2xl border border-slate-100 text-[11px] text-slate-600 leading-relaxed font-medium italic group-hover:text-slate-900 transition-colors">
                      {log.change_details}
                   </div>
                </div>
              ))}
            </div>
            <div className="mt-8 pt-8 border-t border-slate-100 text-center"><button onClick={() => setShowAuditModal(false)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-2xl">Fechar Relatório</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

export enum UserRole {
  ADMIN = 'Administrador de Sistema',
  CEO = 'Director Executivo (CEO)',
  MANAGER = 'Gestor Geral Operacional',
  FINANCE = 'Director Financeiro',
  HR = 'Gestor de Recursos Humanos',
  SALES_LEAD = 'Chefe de Vendas',
  SALES = 'Consultor Imobiliário',
  MAINTENANCE_LEAD = 'Supervisor de Manutenção',
  MAINTENANCE = 'Técnico Especializado',
  IT_MANAGER = 'Gestor de TI & Sistemas',
  MARKETING = 'Marketing & Comunicação',
  SECURITY_LEAD = 'Chefe de Segurança',
  RECEPTIONIST = 'Recepcionista / Front Desk',
  EMPLOYEE = 'Colaborador Geral'
}

