  id: string;
  name: string;
  category: BeneficiaryCategory;
  phone?: string;
  email?: string;
  created_at?: string;
}

export interface User {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  avatar: string;
  permissions: string[];
}

export interface Transaction {
  id: string;
  type: 'RECEITA' | 'DESPESA';
  category: string;
  amount: number;
  date: string;
  description: string;
  beneficiary_id?: string;
  beneficiary_name?: string; // Virtual para facilitar exibição
}

export interface Task {
  id: string;
  title: string;
  description: string;
  completed: boolean;
  priority: 'Baixa' | 'Média' | 'Alta';
  due_date?: string;
  beneficiary_id?: string;
}

