export interface Property {
  id: string;
  title: string;
  type: PropertyCategory;
  dealType: 'Venda' | 'Aluguel';
  price: number;
  location: string;
  beds: number;
  baths: number;
  area: number;
  image: string;
  gallery: string[];
  description: string;
  featured?: boolean;
}

export interface Project {
  id: string;
  name: string;
  status: 'Planejado' | 'Em Andamento' | 'Concluído';
  budget: number;
  spent: number;
  deadline: string;
  team: string[];
  image?: string;
}

export interface StrategicPlan {
  id: string;
  goal: string;
  kpi: string;
  progress: number;
  responsible: string;
  deadline: string;
}

export interface Employee {
  id: string;
  name: string;
  role: UserRole;
  department: string;
  salary: number;
  status: 'Ativo' | 'Férias' | 'Inativo' | 'Suspenso';
  avatar: string;
  email: string;
  phone: string;
  join_date: string;
  permissions: string[];
  document_type?: string;
