import { generateJobDescription } from '../geminiService';

const SUGGESTED_ROLES = [
  'Estagiário de Digitador de Dados',
  'Gerente de Produção',
  'Agente de Campo',
  'Marketing',
  'Gerente de Campo',
  'Revisor de Dados',
  'Consultor Imobiliário',
  'Motorista Profissional'
];

const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies' | 'applications'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [viewingEmp, setViewingEmp] = useState<Employee | null>(null);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [editingVacancyId, setEditingVacancyId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [realtimeNotification, setRealtimeNotification] = useState<{name: string, job: string} | null>(null);
  const [saving, setSaving] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [recentAppIds, setRecentAppIds] = useState<Set<string>>(new Set());

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '+258 ',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Operações & Campo', type: 'Full-time', location: 'Beira', salary: '', status: 'Open', description: '', image: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchData();
    fetchVacancies();
    fetchApplications();

    const channel = supabase
      .channel('hr_realtime_dashboard')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, (payload) => {
        const newApp = payload.new as JobApplication;
        setApplications(prev => [newApp, ...prev]);
        if (audioRef.current) audioRef.current.play().catch(e => {});
        setRealtimeNotification({ name: newApp.applicant_name, job: newApp.job_title });
        setRecentAppIds(prev => new Set(prev).add(newApp.id));
        setTimeout(() => setRealtimeNotification(null), 8000);
        setTimeout(() => setRecentAppIds(prev => { const next = new Set(prev); next.delete(newApp.id); return next; }), 15000);
      })
      .on('postgres_changes', { event: 'UPDATE', table: 'job_applications' }, (payload) => {
        const updated = payload.new as JobApplication;
        setApplications(prev => prev.map(a => a.id === updated.id ? updated : a));
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data, error: sbError } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (!sbError) setVacancies(data || []);
    } catch (err) {}
  }

  async function fetchApplications() {
    try {
      const { data, error: sbError } = await supabase.from('job_applications').select('*').order('created_at', { ascending: false });
      if (!sbError) setApplications(data || []);
    } catch (err) {}
  }

  const updateApplicationStatus = async (id: string, newStatus: string) => {
    try {
      const { error } = await supabase.from('job_applications').update({ status: newStatus }).eq('id', id);
      if (!error) setApplications(applications.map(app => app.id === id ? { ...app, status: newStatus as any } : app));
    } catch (err) {}
  };

  const handleAiOptimize = async () => {
    if (!vacancyForm.title) {
      setError("Por favor, digite o Cargo primeiro para a IA trabalhar.");
      setTimeout(() => setError(null), 3000);
      return;
    }
    setIsAiLoading(true);
    try {
      const optimizedText = await generateJobDescription(vacancyForm.title || '', vacancyForm.area || '', vacancyForm.location || '');
      setVacancyForm(prev => ({ ...prev, description: optimizedText }));
    } finally { setIsAiLoading(false); }
  };

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!vacancyForm.title?.trim() || !vacancyForm.description?.trim()) {
      setError("Título e Descrição são obrigatórios para publicar.");
      return;
    }
    setSaving(true);
    try {
      const payload = { 
        title: vacancyForm.title.trim(), area: vacancyForm.area, type: vacancyForm.type,
        location: vacancyForm.location?.trim() || 'Beira', salary: vacancyForm.salary?.trim() || 'A Negociar',
        description: vacancyForm.description.trim(), image: vacancyForm.image?.trim() || '', status: vacancyForm.status || 'Open'
      };
      let res;
      if (editingVacancyId) res = await supabase.from('job_vacancies').update(payload).eq('id', editingVacancyId);
      else res = await supabase.from('job_vacancies').insert([payload]);
      if (res.error) throw res.error;
      setShowVacancyModal(false);
      setEditingVacancyId(null);
      setVacancyForm(initialVacancyState);
      fetchVacancies();
    } catch (err: any) { setError("Erro ao processar: " + err.message); } 
    finally { setSaving(false); }
  };

  const handleEditVacancy = (vacancy: JobVacancy) => {
    setError(null);
    setEditingVacancyId(vacancy.id);
    setVacancyForm(vacancy);
    setShowVacancyModal(true);
  };

  const deleteVacancy = async (id: string) => {
    if (confirm('Deseja remover esta vaga permanentemente?')) {
      const { error } = await supabase.from('job_vacancies').delete().eq('id', id);
      if (!error) fetchVacancies();
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);
    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!formState.name || formState.name.trim().length < 3) { setError("Por favor, insira um nome completo válido."); return; }
    if (!formState.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formState.email)) { setError("Por favor, insira um e-mail corporativo válido."); return; }
    setSaving(true);
    try {
      const payload = { ...formState, salary: Number(formState.salary), status: formState.status || 'Ativo', avatar: `https://picsum.photos/seed/${formState.name}/100` };
      if (editingEmpId) await supabase.from('employees').update(payload).eq('id', editingEmpId);
      else await supabase.from('employees').insert([payload]);
      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { setError(err.message); } 
    finally { setSaving(false); }
  };

  const openViewModal = (emp: Employee) => {
    setViewingEmp(emp);
    setShowViewModal(true);
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-24 gap-4">
      <Loader2 className="animate-spin text-indigo-600" size={48} />
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20 relative">

      {/* Realtime Toast Notification */}
      {realtimeNotification && (
        <div className="fixed top-24 right-8 z-[200] bg-slate-900 text-white p-6 rounded-[2.5rem] shadow-2xl flex items-center gap-5 animate-in slide-in-from-right-10 duration-700 border border-emerald-500/30 backdrop-blur-xl">
           <div className="relative">
              <div className="w-14 h-14 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-500/20 animate-bounce">
                <BellRing size={28} className="text-white" />
              </div>
              <span className="absolute -top-1 -right-1 w-4 h-4 bg-emerald-400 rounded-full animate-ping"></span>
           </div>
           <div>
              <p className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.2em] mb-1">Nova Candidatura Monte</p>
              <h4 className="text-base font-black tracking-tight leading-none mb-1">{realtimeNotification.name}</h4>
              <p className="text-xs text-slate-400 font-medium italic">Pretende: {realtimeNotification.job}</p>
           </div>
           <button onClick={() => setRealtimeNotification(null)} className="p-2 hover:bg-white/10 rounded-full transition-colors ml-4 text-slate-500"><X size={18} /></button>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Talentos</h1>
             <p className="text-slate-500 font-medium">Controle de staff e recrutamento Monte Imobiliária.</p>
           </div>
        </div>
        <div className="flex gap-3">
          {activeTab === 'employees' ? (
            <button onClick={() => { setError(null); setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Novo Colaborador
            </button>
          ) : activeTab === 'vacancies' ? (
            <button onClick={() => { setError(null); setEditingVacancyId(null); setVacancyForm(initialVacancyState); setShowVacancyModal(true); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Criar Nova Vaga
            </button>
          ) : (
            <button onClick={fetchApplications} className="px-8 py-4 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-sm shadow-sm hover:bg-slate-200 transition-all active:scale-95 flex items-center gap-2">
              <RefreshCcw size={18} /> Forçar Sincronização
            </button>
          )}
        </div>
      </div>

      <div className="flex p-1.5 bg-slate-100 rounded-[2.5rem] w-full max-w-lg mx-auto border border-slate-200 shadow-inner">
        <button onClick={() => setActiveTab('employees')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-indigo-400'}`}><Users size={16} /> Staff</button>
        <button onClick={() => setActiveTab('vacancies')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500 hover:text-blue-400'}`}><Briefcase size={16} /> Vagas</button>
        <button onClick={() => setActiveTab('applications')} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all relative ${activeTab === 'applications' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500 hover:text-emerald-400'}`}>
          <UserPlus size={16} /> Candidatos 
          {applications.filter(a => a.status === 'Pendente').length > 0 && <span className={`w-5 h-5 bg-rose-500 text-white text-[9px] rounded-full flex items-center justify-center border-2 border-white ml-1 ${recentAppIds.size > 0 ? 'animate-bounce' : ''}`}>{applications.filter(a => a.status === 'Pendente').length}</span>}
        </button>
      </div>

      {activeTab === 'employees' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.map((emp, index) => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div 
                key={emp.id} 
                onClick={() => openViewModal(emp)}
                className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500 animate-in fade-in slide-in-from-bottom-4 duration-700 cursor-pointer"
                style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'backwards' }}
              >
                <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>
                <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity z-20">
                  <button onClick={(e) => { e.stopPropagation(); setError(null); setEditingEmpId(emp.id); setFormState(emp); setShowAddModal(true); }} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-100 transition-all"><Edit3 size={18} /></button>
                </div>
                <div className="mt-8 flex flex-col items-center">
                  <div className="relative mb-5">
                    <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-8 ring-slate-50 shadow-inner group-hover:scale-105 transition-transform duration-500" alt={emp.name} />
                    <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-4 border-white ${emp.status === 'Ativo' ? 'bg-green-500' : 'bg-amber-500'}`}></div>
                  </div>
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                </div>
                <div className="pt-6 border-t border-slate-50 flex justify-between items-center text-[11px] font-medium text-slate-500">
                  <div className="flex items-center gap-1.5"><Mail size={12} className="text-slate-300" /> {emp.email.split('@')[0]}...</div>
                  <div className="flex items-center gap-1.5"><Phone size={12} className="text-slate-300" /> {emp.phone}</div>
                </div>
              </div>
            );
          })}
        </div>
      ) : activeTab === 'vacancies' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {vacancies.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3.5rem] border border-dashed border-slate-200 animate-in fade-in duration-700">
               <Briefcase size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Sem vagas publicadas</p>
            </div>
          ) : vacancies.map((v, index) => (
            <div key={v.id} className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all relative overflow-hidden flex flex-col group animate-in fade-in slide-in-from-bottom-4 duration-700" style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'backwards' }}>
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><Briefcase size={20} className={v.status === 'Open' ? 'text-blue-600' : 'text-slate-300'} /></div>
                <div className="flex gap-2">
                  <button onClick={() => handleEditVacancy(v)} className="p-2 text-slate-300 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                  <button onClick={() => deleteVacancy(v.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">{v.title}</h3>
              <div className="space-y-2 mb-6">
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><MapPin size={14} className="text-blue-500" /> {v.location}</div>
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><LayoutList size={14} className="text-blue-500" /> {v.area}</div>
                <div className="flex flex-col gap-1 mt-3">
                   <div className="flex items-center gap-2 text-xs font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg w-fit"><Mail size={12} /> monteimobiliario@gmail.com</div>
                   <div className="flex items-center gap-2 text-[10px] font-black text-blue-500 px-3 py-1"><Phone size={12} /> +258 87 501 8283</div>
                </div>
              </div>
              <div className="mt-auto pt-6 border-t border-slate-50 flex items-center justify-between">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${v.status === 'Open' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>{v.status === 'Open' ? v.type : 'Fechada'}</span>
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(v.created_at).toLocaleDateString()}</span>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden animate-in fade-in duration-700">
           <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
              <div className="flex items-center gap-4">
                 <div className="p-3 bg-emerald-100 text-emerald-600 rounded-2xl"><UserPlus size={24} /></div>
                 <div>
                    <h3 className="text-xl font-black text-slate-900">Portal de Candidatos</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Sincronização Monte Imobiliária Ativa</p>
                 </div>
              </div>
              <div className="flex gap-4">
                 <div className="px-4 py-2 bg-white rounded-xl border border-slate-100 text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <Sparkles size={12} className="text-emerald-500 animate-pulse" /> Sincronizado
                 </div>
              </div>
           </div>
           <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                    <th className="px-10 py-6">Candidato / Perfil</th>
                    <th className="px-10 py-6">Vaga Pretendida</th>
                    <th className="px-10 py-6 text-center">Conformidade</th>
                    <th className="px-10 py-6">Status / Acção RH</th>
                    <th className="px-10 py-6 text-right">Acções</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {applications.length === 0 ? (
                    <tr>
                      <td colSpan={5} className="px-10 py-24 text-center">
                         <MessageSquare size={48} className="mx-auto text-slate-100 mb-4" />
                         <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Aguardando novas candidaturas Monte...</p>
                      </td>
                    </tr>
                  ) : applications.map((app) => {
                    const isNew = recentAppIds.has(app.id);
                    return (
                      <tr key={app.id} className={`hover:bg-slate-50/50 transition-all group relative ${isNew ? 'bg-emerald-50/30' : ''}`}>
                        {isNew && <div className="absolute left-0 top-0 bottom-0 w-1 bg-emerald-500 animate-pulse"></div>}
                        <td className="px-10 py-8">
                          <div className="flex items-center gap-4">
                             <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-slate-400 font-black relative overflow-hidden ${isNew ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100'}`}>{app.applicant_name.charAt(0)}{isNew && <div className="absolute top-0 right-0 p-1 bg-emerald-500 text-[6px] text-white font-black uppercase">Novo</div>}</div>
                             <div>
                                <div className="flex items-center gap-2">
                                  <p className="text-sm font-black text-slate-900 leading-none mb-1">{app.applicant_name}</p>
                                  {isNew && <span className="bg-emerald-500 text-white text-[8px] font-black px-1.5 py-0.5 rounded uppercase animate-pulse">Recém Chegado</span>}
                                </div>
                                <div className="flex items-center gap-2 text-[10px] text-slate-400 font-medium"><Mail size={10} /> {app.applicant_email}</div>
                             </div>
                          </div>
                        </td>
                        <td className="px-10 py-8"><span className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-lg uppercase tracking-wider">{app.job_title}</span></td>
                        <td className="px-10 py-8 text-center"><div className="inline-flex items-center gap-2 px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full border border-emerald-100"><Fingerprint size={12} /><span className="text-[9px] font-black uppercase tracking-tighter">LGPD Validada</span></div></td>
                        <td className="px-10 py-8">
                           <select value={app.status} onChange={(e) => updateApplicationStatus(app.id, e.target.value)} className={`text-[9px] font-black uppercase tracking-widest p-2 rounded-xl outline-none border-none cursor-pointer transition-colors ${app.status === 'Pendente' ? 'bg-amber-50 text-amber-600' : app.status === 'Em Análise' ? 'bg-blue-50 text-blue-600' : app.status === 'Aceite' ? 'bg-emerald-50 text-emerald-600' : 'bg-slate-100 text-slate-400'}`}>
                              <option>Pendente</option><option>Em Análise</option><option>Entrevistado</option><option>Aceite</option><option>Rejeitado</option>
                           </select>
                        </td>
                        <td className="px-10 py-8 text-right">
                           <div className="flex items-center justify-end gap-2">
                              {app.applicant_linkedin && <a href={app.applicant_linkedin} target="_blank" rel="noreferrer" className="p-2.5 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl transition-all border border-slate-100" title="Ver LinkedIn"><LinkIcon size={16} /></a>}
                              <button className="p-2.5 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-500/20 hover:scale-110 transition-all" title="Ver Detalhes"><ChevronRight size={16} /></button>
                           </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
           </div>
        </div>
      )}

      {/* Modal Visualizar Detalhes Colaborador (Dossiê Profissional) */}
      {showViewModal && viewingEmp && (
