                      <Tooltip contentStyle={{ borderRadius: '2rem', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.1)' }} />
                      <Bar dataKey="receitas" fill="#10b981" radius={[15, 15, 0, 0]} barSize={55} />
                      <Bar dataKey="despesas" fill="#f43f5e" radius={[15, 15, 0, 0]} barSize={55} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
             </div>
             <div className="h-[450px]"><TodoList /></div>
          </div>
        </div>

        <div className="space-y-10">
          <div className="bg-slate-900 rounded-[3.5rem] p-10 text-white shadow-xl relative overflow-hidden border border-white/5">
             <div className="relative z-10">
                <div className="flex items-center gap-3 mb-8">
                   <UserCheck className="text-emerald-400" size={24} />
                   <h3 className="text-lg font-black uppercase tracking-tight">Novos Talentos</h3>
