                  <input required value={vacancyForm.title} onChange={e => setVacancyForm({...vacancyForm, title: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all" />
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Área</label>
                   <select value={vacancyForm.area} onChange={e => setVacancyForm({...vacancyForm, area: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all cursor-pointer">
                      <option>Vendas</option><option>Operações</option><option>Tecnologia</option><option>Administrativo</option>
                   </select>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Estado da Vaga</label>
                   <select value={vacancyForm.status} onChange={e => setVacancyForm({...vacancyForm, status: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all cursor-pointer">
                      <option value="Open">Aberta (Publicada)</option>
                      <option value="Closed">Fechada (Encerrada)</option>
                   </select>
                </div>
                <div className="space-y-2">
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Localização</label>
                   <input value={vacancyForm.location} onChange={e => setVacancyForm({...vacancyForm, location: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all" placeholder="Ex: Beira, Macuti" />
                </div>
              </div>
              <div className="space-y-4">
                 <div className="flex items-center justify-between">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição Estratégica (Markdown)</label>
                    <button type="button" onClick={handleAiOptimize} disabled={isAiLoading} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-blue-600 transition-all flex items-center gap-2 shadow-lg active:scale-95 disabled:opacity-50">
                       {isAiLoading ? <Loader2 className="animate-spin" size={14} /> : <Sparkles size={14} className="text-blue-400" />} Otimizar: Monte Intelligence v5.0
                    </button>
                 </div>
                 <textarea required value={vacancyForm.description} onChange={e => setVacancyForm({...vacancyForm, description: e.target.value})} rows={8} className="w-full bg-slate-50 border-none rounded-[3.5rem] p-10 font-medium text-sm outline-none focus:ring-4 focus:ring-blue-100 transition-all resize-none shadow-inner" placeholder="O que o candidato ideal precisa de saber..." />
              </div>
              <div className="pt-8 border-t border-slate-100 flex gap-4">
                 <button disabled={saving} type="submit" className="flex-1 py-7 bg-blue-600 text-white font-black rounded-[2.5rem] shadow-2xl hover:bg-slate-900 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50">
                    {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Publicar na Monte Imobiliária</>}
                 </button>
                 <button type="button" onClick={() => setShowVacancyModal(false)} className="px-10 py-7 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Voltar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

