import React, { useState } from 'react';
import { 
  Truck, 
  MapPin, 
  User, 
  Settings, 
  Search, 
  Plus, 
  Fuel, 
  Gauge, 
  Calendar,
  CheckCircle2,
  AlertTriangle,
  History,
  MoreHorizontal,
  ShieldCheck,
  ShieldAlert,
  Shield
} from 'lucide-react';

interface Vehicle {
  id: string;
  plate: string;
  model: string;
  driver: string;
  status: 'Disponível' | 'Em Rota' | 'Manutenção' | 'Reserva';
  fuelLevel: number;
  lastMaintenance: string;
  mileage: string;
}

const MOCK_FLEET: Vehicle[] = [
  { id: '1', plate: 'ABC-123-MC', model: 'Toyota Hilux 2023', driver: 'António Muleva', status: 'Em Rota', fuelLevel: 75, lastMaintenance: '2024-04-15', mileage: '12.450 km' },
  { id: '2', plate: 'XYZ-888-MC', model: 'Isuzu D-Max', driver: 'Carlos Beira', status: 'Disponível', fuelLevel: 100, lastMaintenance: '2024-05-10', mileage: '45.200 km' },
  { id: '3', plate: 'MOZ-555-BE', model: 'Mitsubishi L200', driver: 'N/A', status: 'Manutenção', fuelLevel: 20, lastMaintenance: '2023-11-20', mileage: '88.120 km' },
  { id: '4', plate: 'AFR-777-MC', model: 'Ford Ranger XL', driver: 'Sérgio Maputo', status: 'Disponível', fuelLevel: 35, lastMaintenance: '2024-01-01', mileage: '22.300 km' },
];

const FleetView: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const stats = {
    total: MOCK_FLEET.length,
    active: MOCK_FLEET.filter(v => v.status === 'Em Rota').length,
    maintenance: MOCK_FLEET.filter(v => v.status === 'Manutenção').length,
    available: MOCK_FLEET.filter(v => v.status === 'Disponível').length,
  };

  const getSafetyStatus = (fuel: number, maintenanceDate: string) => {
    const today = new Date();
    const lastMaint = new Date(maintenanceDate);
    const diffTime = Math.abs(today.getTime() - lastMaint.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

    // Regras de Segurança
    if (fuel < 25 || diffDays > 180) {
      return { 
        label: 'Crítico', 
        color: 'text-rose-600 bg-rose-50', 
        icon: <ShieldAlert size={14} />,
        border: 'border-rose-100'
      };
    }
    if (fuel < 45 || diffDays > 90) {
      return { 
        label: 'Atenção', 
        color: 'text-amber-600 bg-amber-50', 
        icon: <Shield size={14} />,
        border: 'border-amber-100'
      };
    }
    return { 
      label: 'Seguro', 
      color: 'text-emerald-600 bg-emerald-50', 
      icon: <ShieldCheck size={14} />,
      border: 'border-emerald-100'
    };
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
            <Truck size={28} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Frota</h1>
            <p className="text-slate-500 font-medium italic">Controle operacional de veículos e motoristas.</p>
          </div>
        </div>
        <div className="flex gap-3">
           <button className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-blue-600" /> Histórico de Rotas
           </button>
           <button className="px-6 py-3 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-700 transition-all flex items-center gap-2 shadow-xl shadow-blue-500/20">
             <Plus size={16} /> Adicionar Veículo
           </button>
        </div>
      </div>

      {/* KPI Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Frota Total', value: stats.total, icon: <Truck size={20} />, bg: 'bg-slate-50', text: 'text-slate-600' },
          { label: 'Em Serviço', value: stats.active, icon: <MapPin size={20} />, bg: 'bg-blue-50', text: 'text-blue-600' },
          { label: 'Disponíveis', value: stats.available, icon: <CheckCircle2 size={20} />, bg: 'bg-emerald-50', text: 'text-emerald-600' },
          { label: 'Manutenção', value: stats.maintenance, icon: <AlertTriangle size={20} />, bg: 'bg-amber-50', text: 'text-amber-600' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
            <div className={`p-3 ${kpi.bg} ${kpi.text} rounded-2xl w-fit mb-4`}>
              {kpi.icon}
            </div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{kpi.label}</p>
            <h3 className="text-3xl font-black text-slate-900">{kpi.value}</h3>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
              placeholder="Pesquisar por matrícula ou motorista..." 
              className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-blue-50" 
            />
          </div>
          <div className="flex gap-2">
             <button className="p-4 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-2xl transition-all">
                <Settings size={20} />
             </button>
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Veículo / Matrícula</th>
                <th className="px-10 py-6">Status Operacional</th>
                <th className="px-10 py-6 text-center">Segurança</th>
                <th className="px-10 py-6">Motorista Atual</th>
                <th className="px-10 py-6">Combustível</th>
                <th className="px-10 py-6 text-right">Acção</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {MOCK_FLEET.filter(v => 
                v.plate.toLowerCase().includes(searchTerm.toLowerCase()) || 
                v.driver.toLowerCase().includes(searchTerm.toLowerCase())
              ).map((vehicle) => {
                const safety = getSafetyStatus(vehicle.fuelLevel, vehicle.lastMaintenance);

                // Definição dinâmica de estilos por status
                const getStatusStyles = (status: string) => {
                  switch (status) {
                    case 'Disponível':
                      return { bg: 'bg-emerald-50 text-emerald-600', dot: 'bg-emerald-600' };
                    case 'Em Rota':
                      return { bg: 'bg-blue-50 text-blue-600', dot: 'bg-blue-600 animate-pulse' };
                    case 'Manutenção':
                      return { bg: 'bg-amber-50 text-amber-600', dot: 'bg-amber-600' };
                    case 'Reserva':
                    default:
                      return { bg: 'bg-slate-100 text-slate-500', dot: 'bg-slate-400' };
                  }
                };

                const statusStyles = getStatusStyles(vehicle.status);

                return (
                  <tr key={vehicle.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-10 py-8">
                      <div className="flex items-center gap-5">
                        <div className="w-12 h-12 bg-slate-100 rounded-xl flex items-center justify-center text-slate-400">
                          <Truck size={24} />
                        </div>
                        <div>
                          <p className="text-base font-black text-slate-900 leading-none mb-1">{vehicle.model}</p>
                          <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded uppercase tracking-wider">{vehicle.plate}</span>
                        </div>
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${statusStyles.bg}`}>
                        <span className={`w-1.5 h-1.5 rounded-full ${statusStyles.dot}`}></span>
                        {vehicle.status}
                      </div>
                    </td>
                    <td className="px-10 py-8 text-center">
                      <div className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase border ${safety.color} ${safety.border} shadow-sm transition-transform group-hover:scale-105`}>
                        {safety.icon}
                        {safety.label}
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-400">
                          <User size={14} />
                        </div>
                        <span className="text-sm font-bold text-slate-700">{vehicle.driver}</span>
                      </div>
                    </td>
                    <td className="px-10 py-8">
                      <div className="w-full max-w-[120px]">
                        <div className="flex justify-between items-center mb-1 text-[10px] font-black">
                          <span className="text-slate-400 uppercase tracking-tighter">Nível</span>
                          <span className={vehicle.fuelLevel < 25 ? 'text-rose-600' : 'text-emerald-600'}>{vehicle.fuelLevel}%</span>
                        </div>
                        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                          <div 
                            className={`h-full transition-all duration-1000 ${vehicle.fuelLevel < 25 ? 'bg-rose-500' : 'bg-emerald-500'}`} 
                            style={{ width: `${vehicle.fuelLevel}%` }}
                          ></div>
                        </div>
                      </div>
                    </td>
                    <td className="px-10 py-8 text-right">
                      <button className="p-3 bg-white text-slate-300 hover:text-blue-600 rounded-xl border border-slate-100 shadow-sm transition-all group-hover:scale-105 active:scale-95">
                        <MoreHorizontal size={20} />
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Maintenance Alerts Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-black text-slate-900 flex items-center gap-3">
              <History className="text-blue-600" /> Manutenções Próximas
            </h3>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Este Mês</span>
          </div>
          <div className="space-y-4">
             {MOCK_FLEET.slice(0, 3).map(v => (
               <div key={v.id} className="p-5 bg-slate-50 rounded-2xl flex items-center justify-between group hover:bg-white hover:shadow-lg transition-all border border-transparent hover:border-blue-100">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-slate-400">
                       <Calendar size={18} />
                    </div>
                    <div>
                      <p className="text-sm font-black text-slate-900 leading-none mb-1">{v.model}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter">Última: {v.lastMaintenance}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-1">Quilometragem</p>
                    <p className="text-sm font-black text-slate-900">{v.mileage}</p>
                  </div>
               </div>
             ))}
          </div>
        </div>

        <div className="bg-slate-900 p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/2"></div>
          <div className="relative z-10 h-full flex flex-col justify-between">
            <div className="mb-8">
              <div className="p-3 bg-blue-600 rounded-2xl w-fit mb-6 text-white shadow-lg shadow-blue-500/20">
                <Fuel size={24} />
              </div>
              <h3 className="text-2xl font-black text-white tracking-tight mb-2">Relatório de Combustível</h3>
              <p className="text-slate-400 text-sm font-medium">Análise de consumo médio da frota para optimização de custos operacionais.</p>
            </div>
            <button className="w-full py-5 bg-white/10 hover:bg-white/20 text-white border border-white/10 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all">
              Gerar Relatório Cloud
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FleetView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ArrowUpCircle, 
  ArrowDownCircle, 
  Plus, 
  DollarSign, 
  X, 
  Loader2, 
  BarChart3, 
  TrendingUp, 
  User, 
  UserPlus, 
  Tag, 
  Edit3, 
  Trash2, 
  Phone, 
  Mail, 
  Users, 
  Check, 
  Save, 
  AlertTriangle,
  Search,
  Filter
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Beneficiary, BeneficiaryCategory } from '../types';

const FinanceView: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [beneficiaries, setBeneficiaries] = useState<Beneficiary[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showBeneficiaryModal, setShowBeneficiaryModal] = useState(false);
  const [beneficiarySearch, setBeneficiarySearch] = useState('');

  const [newLaunch, setNewLaunch] = useState({
    description: '',
    category: 'Vendas',
    amount: '',
    type: 'DESPESA' as 'RECEITA' | 'DESPESA',
    beneficiary_id: ''
  });

  const [beneficiaryForm, setBeneficiaryForm] = useState<Partial<Beneficiary>>({
    name: '',
    category: 'Agente de Campo',
    phone: '',
    email: ''
  });
  const [editingBeneficiaryId, setEditingBeneficiaryId] = useState<string | null>(null);

  useEffect(() => {
    fetchTransactions();
    fetchBeneficiaries();
  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTransactions() {
    setLoading(true);
    const { data, error } = await supabase
      .from('transactions')
      .select(`
        *,
        beneficiary:beneficiaries(name)
      `)
      .order('date', { ascending: false });

    if (!error) {
      const formatted = (data || []).map((t: any) => ({
        ...t,
        beneficiary_name: t.beneficiary?.name
      }));
      setTransactions(formatted);
    }
    setLoading(false);
  }

  const handleSaveBeneficiary = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!beneficiaryForm.name?.trim()) return;

    try {
      if (editingBeneficiaryId) {
        const { error } = await supabase
          .from('beneficiaries')
          .update(beneficiaryForm)
          .eq('id', editingBeneficiaryId);
        if (!error) {
          setBeneficiaries(beneficiaries.map(b => b.id === editingBeneficiaryId ? { ...b, ...beneficiaryForm } : b));
        }
      } else {
        const { data, error } = await supabase
          .from('beneficiaries')
          .insert([beneficiaryForm])
          .select();
        if (!error && data) {
          setBeneficiaries([...beneficiaries, data[0]]);
        }
      }
      setShowBeneficiaryModal(false);
      setEditingBeneficiaryId(null);
      setBeneficiaryForm({ name: '', category: 'Agente de Campo', phone: '', email: '' });
    } catch (e) {}
  };

  const handleDeleteBeneficiary = async (id: string) => {
    if (!confirm('Eliminar este beneficiário permanentemente? Isso não removerá transações antigas, mas o nome pode não aparecer mais vinculado.')) return;
    try {
      const { error } = await supabase.from('beneficiaries').delete().eq('id', id);
      if (!error) {
        setBeneficiaries(beneficiaries.filter(b => b.id !== id));
      }
    } catch (e) {}
  };

  const handleLaunch = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      description: newLaunch.description,
      category: newLaunch.category,
      amount: Number(newLaunch.amount),
      type: newLaunch.type,
      beneficiary_id: newLaunch.beneficiary_id || null,
      date: new Date().toISOString().split('T')[0]
    };

    const { error } = await supabase.from('transactions').insert([payload]);
    if (!error) {
      setShowModal(false);
      setNewLaunch({ description: '', category: 'Vendas', amount: '', type: 'DESPESA', beneficiary_id: '' });
      fetchTransactions();
    }
  };

  const totals = transactions.reduce((acc, curr) => {
    if (curr.type === 'RECEITA') acc.receita += Number(curr.amount);
    else acc.despesa += Number(curr.amount);
    return acc;
  }, { receita: 0, despesa: 0 });

  const chartData = useMemo(() => {
    const months = [];
    const date = new Date();
    for (let i = 5; i >= 0; i--) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthName = d.toLocaleString('pt-BR', { month: 'short' });
      months.push({
        key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`,
        name: monthName.charAt(0).toUpperCase() + monthName.slice(1),
        receita: 0,
        despesa: 0
      });
    }
    transactions.forEach(t => {
      const tMonth = t.date.substring(0, 7);
      const monthObj = months.find(m => m.key === tMonth);
      if (monthObj) {
        if (t.type === 'RECEITA') monthObj.receita += Number(t.amount);
        else monthObj.despesa += Number(t.amount);
      }
    });
    return months;
  }, [transactions]);

  const filteredBeneficiaries = beneficiaries.filter(b => 
    b.name.toLowerCase().includes(beneficiarySearch.toLowerCase()) ||
    b.category.toLowerCase().includes(beneficiarySearch.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-emerald-500/20">
            <BarChart3 size={24} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Fluxo Financeiro</h1>
            <p className="text-slate-500 font-medium">Balanço corporativo com rastreio de beneficiários.</p>
          </div>
        </div>
        <button onClick={() => setShowModal(true)} className="flex items-center gap-2 px-8 py-4 bg-emerald-600 text-white rounded-[2rem] font-black text-sm shadow-xl shadow-emerald-500/20 hover:scale-105 transition-all">
          <Plus size={20} /> Novo Lançamento
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Receitas Acumuladas</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-emerald-600">{totals.receita.toLocaleString()} MT</p>
                <ArrowUpCircle className="text-emerald-500" size={24} />
              </div>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Despesas Acumuladas</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-rose-600">{totals.despesa.toLocaleString()} MT</p>
                <ArrowDownCircle className="text-rose-500" size={24} />
              </div>
            </div>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl group-hover:bg-white/10 transition-all"></div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Saldo em Caixa</p>
              <p className="text-3xl font-black text-white">{(totals.receita - totals.despesa).toLocaleString()} MT</p>
            </div>
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-xl font-black text-slate-900">Histórico de Performance</h3>
              <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest text-slate-400">
                <div className="flex items-center gap-2"><span className="w-3 h-3 bg-emerald-500 rounded-full"></span> Entradas</div>
                <div className="flex items-center gap-2"><span className="w-3 h-3 bg-rose-500 rounded-full"></span> Saídas</div>
              </div>
            </div>
            <div className="w-full h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 700 }} />
                  <YAxis hide />
                  <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }} />
                  <Bar dataKey="receita" fill="#10b981" radius={[10, 10, 0, 0]} />
                  <Bar dataKey="despesa" fill="#f43f5e" radius={[10, 10, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* CRUD Gestão de Beneficiários */}
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm space-y-8">
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
              <div className="flex items-center gap-4">
                <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl shadow-inner">
                  <Users size={28} />
                </div>
                <div>
                  <h3 className="text-2xl font-black text-slate-900">Gestão de Beneficiários</h3>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Base de Dados de Agentes e Prestadores</p>
                </div>
              </div>

              <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-4">
                <div className="relative">
                  <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    type="text"
                    value={beneficiarySearch}
                    onChange={(e) => setBeneficiarySearch(e.target.value)}
                    placeholder="Procurar beneficiário..."
                    className="pl-12 pr-4 py-3 bg-slate-50 border-none rounded-xl text-sm font-bold w-full sm:w-64 outline-none focus:ring-2 focus:ring-blue-100"
                  />
                </div>
                <button 
                  onClick={() => {
                    setEditingBeneficiaryId(null);
                    setBeneficiaryForm({ name: '', category: 'Agente de Campo', phone: '', email: '' });
                    setShowBeneficiaryModal(true);
                  }} 
                  className="px-6 py-3.5 bg-blue-600 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-900 transition-all flex items-center justify-center gap-2 shadow-xl shadow-blue-500/10 active:scale-95"
                >
                  <UserPlus size={16} /> Registar Novo
                </button>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
              {filteredBeneficiaries.map((b) => (
                <div key={b.id} className="group p-6 bg-slate-50 border border-transparent hover:bg-white hover:border-blue-100 hover:shadow-2xl rounded-[2.5rem] transition-all relative overflow-hidden">
                  <div className="flex items-start justify-between mb-4">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-blue-600 shadow-sm group-hover:bg-blue-600 group-hover:text-white transition-all duration-500">
                      <User size={24} />
                    </div>
                    <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button 
                        onClick={() => {
                          setEditingBeneficiaryId(b.id);
                          setBeneficiaryForm(b);
                          setShowBeneficiaryModal(true);
                        }}
                        className="p-2.5 bg-white text-slate-400 hover:text-blue-600 rounded-xl shadow-sm border border-slate-100 hover:scale-110 transition-all"
                        title="Editar Perfil"
                      >
                        <Edit3 size={14} />
                      </button>
                      <button 
                        onClick={() => handleDeleteBeneficiary(b.id)}
                        className="p-2.5 bg-white text-slate-400 hover:text-rose-600 rounded-xl shadow-sm border border-slate-100 hover:scale-110 transition-all"
                        title="Eliminar"
                      >
                        <Trash2 size={14} />
                      </button>
                    </div>
                  </div>
                  <h4 className="font-black text-slate-900 leading-tight mb-1 truncate">{b.name}</h4>
                  <span className="inline-block text-[8px] font-black bg-indigo-50 text-indigo-600 px-2.5 py-1 rounded-lg uppercase tracking-wider mb-5">{b.category}</span>
                  <div className="space-y-2 pt-4 border-t border-slate-200/60">
                    <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold">
                      <Phone size={12} className="text-blue-400" /> {b.phone || 'N/D'}
                    </div>
                    <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold truncate">
                      <Mail size={12} className="text-blue-400" /> {b.email || 'N/D'}
                    </div>
                  </div>
                </div>
              ))}
              {filteredBeneficiaries.length === 0 && (
                <div className="col-span-full py-20 text-center border-2 border-dashed border-slate-100 rounded-[3rem] bg-slate-50/30">
                  <User size={48} className="mx-auto text-slate-200 mb-4" />
                  <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">Nenhum beneficiário encontrado.</p>
                </div>
              )}
            </div>
          </div>

          <div className="bg-white rounded-[3.5rem] border border-slate-100 overflow-hidden shadow-sm">
            <div className="p-8 border-b border-slate-50 bg-slate-50/30">
              <h3 className="text-xl font-black text-slate-900 flex items-center gap-3">
                <TrendingUp size={20} className="text-emerald-600" /> Fluxo de Caixa Global
              </h3>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                    <th className="px-10 py-6">Descrição / Motivo</th>
                    <th className="px-10 py-6">Beneficiário</th>
                    <th className="px-10 py-6">Categoria</th>
                    <th className="px-10 py-6 text-right">Valor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {transactions.map((t) => (
                    <tr key={t.id} className="hover:bg-slate-50/50 transition-all group">
                      <td className="px-10 py-8">
                        <p className="font-bold text-slate-900">{t.description}</p>
                        <p className="text-[10px] text-slate-400 font-medium">{new Date(t.date).toLocaleDateString('pt-MZ')}</p>
                      </td>
                      <td className="px-10 py-8">
                        {t.beneficiary_name ? (
                          <div className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full w-fit border border-blue-100">
                            <User size={12} /> {t.beneficiary_name}
                          </div>
                        ) : (
                          <span className="text-[10px] text-slate-300 italic uppercase tracking-tighter">Fluxo Geral</span>
                        )}
                      </td>
                      <td className="px-10 py-8">
                        <span className="text-[9px] font-black bg-slate-100 text-slate-500 px-3 py-1.5 rounded-lg uppercase tracking-wider">{t.category}</span>
                      </td>
                      <td className={`px-10 py-8 text-right font-black text-lg tracking-tighter ${t.type === 'RECEITA' ? 'text-emerald-600' : 'text-rose-600'}`}>
                        {t.type === 'RECEITA' ? '+' : '-'} {t.amount.toLocaleString()} MT
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {/* Modal Lançamento Financeiro */}
      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-lg w-full shadow-2xl relative border-t-[12px] border-emerald-600">
            <button onClick={() => setShowModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900 transition-colors"><X size={28} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3"><DollarSign className="text-emerald-600" /> Movimento Financeiro</h2>

            <form onSubmit={handleLaunch} className="space-y-6">
              <div className="flex p-1.5 bg-slate-100 rounded-[1.5rem]">
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'RECEITA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Entrada</button>
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'DESPESA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Saída</button>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Beneficiário Responsável</label>
                <select 
                  value={newLaunch.beneficiary_id}
                  onChange={e => setNewLaunch({...newLaunch, beneficiary_id: e.target.value})}
                  className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold text-sm outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer"
                >
                  <option value="">Nenhum (Fluxo Interno)</option>
                  {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name} ({b.category})</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição do Lançamento</label>
                <input required placeholder="Ex: Pagamento de Subsídio Agente Macuti" value={newLaunch.description} onChange={e => setNewLaunch({...newLaunch, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                  <select value={newLaunch.category} onChange={e => setNewLaunch({...newLaunch, category: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer">
                    <option>Vendas</option><option>Operacional</option><option>Salários</option><option>Marketing</option><option>TI</option><option>Outros</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor (MT)</label>
                  <input required type="number" placeholder="0.00" value={newLaunch.amount} onChange={e => setNewLaunch({...newLaunch, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-black text-xl border-none outline-none focus:ring-2 focus:ring-emerald-500" />
                </div>
              </div>

              <button type="submit" className="w-full py-6 bg-emerald-600 text-white font-black rounded-[2rem] shadow-xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-3 mt-4 active:scale-95">
                <Plus size={20} /> Registar na Cloud Monte
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Modal CRUD Beneficiários */}
      {showBeneficiaryModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-lg w-full shadow-2xl relative border-t-[12px] border-blue-600">
            <button onClick={() => setShowBeneficiaryModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl p-2"><X size={28} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3 tracking-tight">
              <UserPlus className="text-blue-600" /> {editingBeneficiaryId ? 'Editar Perfil Beneficiário' : 'Novo Beneficiário'}
            </h2>

            <form onSubmit={handleSaveBeneficiary} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                <input 
                  required 
                  value={beneficiaryForm.name} 
                  onChange={e => setBeneficiaryForm({...beneficiaryForm, name: e.target.value})} 
                  className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all" 
                  placeholder="Ex: Carlos Beira"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria de Atividade</label>
                <select 
                  value={beneficiaryForm.category} 
                  onChange={e => setBeneficiaryForm({...beneficiaryForm, category: e.target.value as BeneficiaryCategory})}
                  className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all cursor-pointer"
                >
                  <option>Agente de Campo</option>
                  <option>Supervisor</option>
                  <option>Revisor</option>
                  <option>Digitador</option>
                  <option>Marketing</option>
                  <option>Criador de Conteúdo</option>
                  <option>Outros</option>
                </select>
              </div>

              <div className="grid grid-cols-1 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telemóvel (+258)</label>
                  <input 
                    value={beneficiaryForm.phone} 
                    onChange={e => setBeneficiaryForm({...beneficiaryForm, phone: e.target.value})} 
                    className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all" 
                    placeholder="84 / 82 / 87 / 86..."
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail (Para Notificações)</label>
                  <input 
                    type="email"
                    value={beneficiaryForm.email} 
                    onChange={e => setBeneficiaryForm({...beneficiaryForm, email: e.target.value})} 
                    className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-blue-100 transition-all" 
                    placeholder="exemplo@gmail.com"
                  />
                </div>
              </div>

              <button type="submit" className="w-full py-6 bg-blue-600 text-white font-black rounded-[2rem] shadow-xl hover:bg-slate-900 transition-all flex items-center justify-center gap-3 mt-4 active:scale-95">
                <Save size={20} /> Guardar na Base de Dados
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default FinanceView;

