<changes>
  <change>
    <file>views/TodoList.tsx</file>
    <description>Implementação de uma lista sempre expandida, focando na melhoria da visibilidade e edição de campos de descrição de tarefas, conforme feedback do usuário.</description>
    <content><![CDATA[
    import React, { useState } from 'react';
    import { CheckCircle, Circle, Edit2, MoreVertical, X } from 'react-feather';

    // Assuming you have a types.ts file with this definition
    interface Task {
      id: number;
      title: string;
      description: string;
      completed: boolean;
    }

    const TodoList = () => {
      const [tasks, setTasks] = useState<Task[]>([
        { id: 1, title: 'Learn React', description: '', completed: false },
        { id: 2, title: 'Build a Todo App', description: 'Make sure to handle edge cases.', completed: true },
        { id: 3, title: 'Deploy to Netlify', description: '', completed: false },
      ]);

      const [expandedIds, setExpandedIds] = useState<number[]>(tasks.map(task => task.id));

      const toggleTaskCompletion = (id: number) => {
        setTasks(tasks.map(task =>
          task.id === id ? { ...task, completed: !task.completed } : task
        ));
      };

      const handleDescriptionChange = (id: number, newDescription: string) => {
        setTasks(tasks.map(task =>
          task.id === id ? { ...task, description: newDescription } : task
        ));
      };

      const toggleTaskExpansion = (id: number) => {
          setExpandedIds(prevExpandedIds =>
          prevExpandedIds.includes(id)
            ? prevExpandedIds.filter(expandedId => expandedId !== id)
            : [...prevExpandedIds, id]
        );
      };

      return (
        <div className="w-full max-w-lg bg-white rounded-lg shadow-md p-6">
          <h1 className="text-2xl font-bold mb-4">Todo List</h1>
          {tasks.map(task => (
            <div key={task.id} className="mb-4 p-4 border rounded-md">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center">
                  <button
                    className="mr-2 focus:outline-none"
                    onClick={() => toggleTaskCompletion(task.id)}
                  >
                    {task.completed ? <CheckCircle className="text-green-500" /> : <Circle />}
                  </button>
                  <span className={`text-lg ${task.completed ? 'line-through text-gray-500' : ''}`}>
                    {task.title}
                  </span>
                </div>
                <div>
                  <button
                    className="focus:outline-none"
                    onClick={() => toggleTaskExpansion(task.id)}
                  >
                   <MoreVertical />
                  </button>
                </div>
              </div>

              {expandedIds.includes(task.id) && (
                <textarea
                  className="w-full p-2 border rounded-md"
                  placeholder="Adicione uma descrição mais detalhada para esta tarefa..."
                  value={task.description}
                  onChange={e => handleDescriptionChange(task.id, e.target.value)}
                />
              )}
            </div>
          ))}
        </div>
      );
    };

    export default TodoList;
    ]]></content>
  </change>
