        setRoles(fallbackRoles);
      }
    } catch (e) { 
      const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
      setRoles(fallbackRoles);
    } finally {
      setRolesLoading(false);
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) { console.warn("Error fetching users"); }
    finally { setLoading(false); }
  }

  async function fetchAuditLogs() {
    setLoadingLogs(true);
    try {
      const { data, error } = await supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);
      if (!error) setAuditLogs(data || []);
    } catch (e) { console.warn("Error fetching logs"); }
    finally { setLoadingLogs(false); }
  }

  const handleAddRole = async () => {
    if (!newRoleName.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase.from('roles').insert([{ name: newRoleName.trim(), is_deleted: false, permissions: [] }]);
      if (error) throw error;
      setNewRoleName('');
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao adicionar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateRole = async () => {
    if (!editingRoleName || !editingRoleName.new.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ name: editingRoleName.new.trim() })
        .eq('name', editingRoleName.old);
      if (error) throw error;
      setEditingRoleName(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao atualizar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleSaveRolePermissions = async () => {
    if (!editingRolePermissions) return;
    setSaving(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ permissions: editingRolePermissions.permissions })
        .eq('id', editingRolePermissions.id);
      if (error) throw error;

      if (currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_name: `Cargo: ${editingRolePermissions.name}`,
          action_type: 'CARGO_MATRIZ_SYNC',
          change_details: `Template de privilégios redefinido para o cargo: ${editingRolePermissions.name}. Total: ${editingRolePermissions.permissions.length} perms.`
        }]);
      }

      setEditingRolePermissions(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao salvar permissões do cargo: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteRole = async (name: string) => {
    if (!confirm(`Deseja desativar o cargo "${name}"? Ele será movido para a reciclagem.`)) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: true })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao desativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleReactivateRole = async (name: string) => {
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: false })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao reativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateUserPermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser || !originalUserState) return;
    setSaving(true);
    const changes = [];
    if (editingUser.role !== originalUserState.role) changes.push(`Cargo: [${originalUserState.role}] -> [${editingUser.role}]`);
    const oldPerms = originalUserState.permissions || [];
    const newPerms = editingUser.permissions || [];
    const added = newPerms.filter(p => !oldPerms.includes(p));
    const opponentRemoved = oldPerms.filter(p => !newPerms.includes(p));
    if (added.length > 0) changes.push(`+ Permissões: ${added.join(', ')}`);
    if (opponentRemoved.length > 0) changes.push(`- Permissões: ${opponentRemoved.join(', ')}`);

    try {
      const { error } = await supabase.from('employees').update({ role: editingUser.role, permissions: editingUser.permissions || [] }).eq('id', editingUser.id);
      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const toggleUserPermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleRolePermission = (permId: string) => {
    if (!editingRolePermissions) return;
    const current = editingRolePermissions.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[], target: 'user' | 'role') => {
    const idsInCategory = permsInCategory.map(p => p.id);

    if (target === 'user' && editingUser) {
      const currentPerms = editingUser.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingUser({ ...editingUser, permissions: newPerms });
    } else if (target === 'role' && editingRolePermissions) {
      const currentPerms = editingRolePermissions.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
    }
  };

  const applyRoleTemplateToUser = () => {
    if (!editingUser) return;
    const roleTemplate = roles.find(r => r.name === editingUser.role);
    if (roleTemplate) {
      setEditingUser({ ...editingUser, permissions: [...roleTemplate.permissions] });
    }
  };

  const getSecurityLevel = (permsCount: number) => {
    if (permsCount >= 12) return { label: 'Total', color: 'bg-rose-500', text: 'text-rose-600' };
    if (permsCount >= 8) return { label: 'Crítico', color: 'bg-rose-500', text: 'text-rose-600' };
    if (permsCount >= 5) return { label: 'Elevado', color: 'bg-amber-500', text: 'text-amber-600' };
    if (permsCount >= 3) return { label: 'Médio', color: 'bg-blue-500', text: 'text-blue-600' };
    return { label: 'Baixo', color: 'bg-emerald-500', text: 'text-emerald-600' };
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const filteredRoles = useMemo(() => {
    return roles.filter(r => r.is_deleted === showDeletedRoles);
  }, [roles, showDeletedRoles]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Governança estratégica de matrizes de privilégios.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { setRolesModalTab('roles'); setShowRolesModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <Settings2 size={16} className="text-blue-600" /> Configurar Matriz de Cargos
           </button>
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Histórico Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar colaborador ou cargo..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Permissões Específicas (Overrides)</th>
                <th className="px-10 py-6 text-right">Controlo</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase()) || u.role.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover ring-4 ring-slate-50" alt="" />
                      <div>
                        <p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p>
                        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap justify-center gap-1.5">
                      {user.permissions?.length ? user.permissions.map(p => (
                        <span key={p} className="text-[8px] font-black bg-white border border-slate-100 text-slate-400 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>
                      )) : <span className="text-[9px] font-black text-slate-300 italic uppercase tracking-tighter">Utilizando Matriz do Cargo</span>}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100 shadow-sm transition-all group-hover:scale-105">
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-[12px] border-indigo-600">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <div className="relative">
                 <img src={editingUser.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover shadow-2xl ring-4 ring-white" alt="" />
                 <div className="absolute -bottom-2 -right-2 p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><UserCog size={16}/></div>
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2>
                  <div className="flex items-center gap-3 mt-2">
                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-widest">Individual Cloud Sync</span>
                    <span className="text-slate-300">•</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{editingUser.email}</span>
                  </div>
               </div>
            </div>

            <form onSubmit={handleUpdateUserPermissions} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-end">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Award size={14} className="text-indigo-600" /> Atribuição de Cargo & Template
                  </label>
                  <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-indigo-600">
                    {roles.filter(r => !r.is_deleted).map(r => <option key={r.name} value={r.name}>{r.name}</option>)}
                  </select>
                </div>
                <button 
                  type="button" 
                  onClick={applyRoleTemplateToUser}
                  className="px-6 py-5 bg-indigo-50 text-indigo-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-3 border border-indigo-100 shadow-sm active:scale-95"
                >
                  <Zap size={16} /> Aplicar Permissões do Cargo
                </button>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2">
                        <h3 className="text-xs font-black uppercase text-slate-900 flex items-center gap-2">
                          <div className="w-1.5 h-4 bg-indigo-600 rounded-full"></div>
                          {category}
                        </h3>
                        <button type="button" onClick={() => toggleCategory(category, perms, 'user')} className="text-[9px] font-black uppercase text-indigo-600 bg-indigo-50 px-4 py-1.5 rounded-full hover:bg-indigo-100 transition-colors">Inverter Seleção</button>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        {perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (
                            <button key={p.id} type="button" onClick={() => toggleUserPermission(p.id)} className={`flex flex-col p-6 rounded-[2.5rem] border-2 text-left transition-all ${isActive ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-[1.02]' : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'}`}>
                              <div className="flex items-center justify-between mb-3">
                                <div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div>
                                {isActive && <CheckCircle2 size={16} className="text-indigo-200" />}
                              </div>
                              <span className="text-[11px] font-black uppercase mb-1">{p.label}</span>
                              <span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                ))}
              </div>
              <div className="flex gap-4 pt-8 border-t border-slate-100">
                <button disabled={saving} type="submit" className="flex-1 py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50">
                  {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Sincronizar Privilégios Individuais</>}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showRolesModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative flex flex-col max-h-[90vh] border-t-[12px] border-blue-600">
            <button onClick={() => { setShowRolesModal(false); setShowDeletedRoles(false); }} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center justify-between mb-6">
              <div className="flex items-center gap-4">
                <div className="p-4 bg-blue-600 text-white rounded-2xl shadow-xl shadow-blue-500/20"><Award size={28} /></div>
                <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Infraestrutura Cloud & Matrizes</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1 italic">Defina políticas mestre ou repare a integridade do banco.</p>
                </div>
              </div>
            </div>

            <div className="flex gap-4 mb-8 bg-slate-100 p-1 rounded-2xl border border-slate-200">
              <button 
                onClick={() => setRolesModalTab('roles')} 
                className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${rolesModalTab === 'roles' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-blue-400'}`}
              >
                <UsersIcon size={14} /> Gestão de Cargos
              </button>
              <button 
                onClick={() => setRolesModalTab('repair')} 
                className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${rolesModalTab === 'repair' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500 hover:text-rose-400'}`}
              >
                <Wrench size={14} /> Infraestrutura & Reparação
              </button>
            </div>

            {rolesModalTab === 'roles' ? (
              <>
                <div className="flex items-center justify-between mb-8">
                   <div className="flex-1 flex gap-3">
                     {!showDeletedRoles && (
                       <div className="flex-1 bg-slate-50 rounded-2xl flex gap-3 border border-slate-100 p-1">
                         <input 
                           value={newRoleName} 
                           onChange={e => setNewRoleName(e.target.value)}
                           placeholder="Nome do Novo Cargo Cloud..." 
                           className="flex-1 bg-transparent px-6 py-4 font-bold text-sm outline-none placeholder:text-slate-300"
                         />
                         <button 
                           onClick={handleAddRole}
                           disabled={rolesLoading || !newRoleName.trim()}
                           className="px-8 py-4 bg-blue-600 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-slate-900 disabled:opacity-50 transition-all flex items-center gap-2 shadow-xl shadow-blue-500/10"
                         >
                           {rolesLoading ? <Loader2 className="animate-spin" size={16} /> : <Plus size={16} />} Adicionar
                         </button>
                       </div>
                     )}
                   </div>
                   <button 
                    onClick={() => setShowDeletedRoles(!showDeletedRoles)}
                    className={`flex items-center gap-2 px-6 py-4 ml-4 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all border ${showDeletedRoles ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-200 text-slate-400 hover:bg-slate-50'}`}
                  >
                    {showDeletedRoles ? <Eye size={16} /> : <Trash2 size={16} />}
                    {showDeletedRoles ? 'Ver Ativos' : 'Reciclagem'}
                  </button>
                </div>

                <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
                  {rolesLoading ? (
                     <div className="py-20 flex justify-center"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
                  ) : filteredRoles.length === 0 ? (
                    <div className="py-24 text-center flex flex-col items-center gap-4 bg-slate-50 rounded-[3rem] border border-dashed border-slate-200">
                      <Award size={48} className="text-slate-200" />
                      <p className="text-xs font-black uppercase tracking-[0.2em] text-slate-400">Nenhum registo encontrado</p>
                    </div>
                  ) : filteredRoles.map((role) => {
                    const security = getSecurityLevel(role.permissions?.length || 0);
                    return (
                      <div key={role.id} className={`p-6 rounded-[2.5rem] border-2 flex flex-col md:flex-row md:items-center justify-between gap-6 group transition-all ${role.is_deleted ? 'bg-slate-50 border-slate-100 opacity-60' : 'bg-white border-slate-50 shadow-sm hover:border-blue-100 hover:shadow-xl'}`}>
                        {editingRoleName?.old === role.name ? (
                          <div className="flex-1 flex gap-3 animate-in slide-in-from-left-2">
                            <input 
                              autoFocus
                              value={editingRoleName.new}
                              onChange={e => setEditingRoleName({...editingRoleName, new: e.target.value})}
                              className="flex-1 bg-slate-50 rounded-2xl px-6 py-3 font-bold text-sm outline-none ring-2 ring-blue-500 shadow-inner"
                            />
                            <button onClick={handleUpdateRole} className="p-4 bg-emerald-500 text-white rounded-xl shadow-lg hover:bg-emerald-600"><Check size={20} /></button>
                            <button onClick={() => setEditingRoleName(null)} className="p-4 bg-slate-200 text-slate-500 rounded-xl hover:bg-slate-300"><X size={20} /></button>
                          </div>
                        ) : (
                          <>
                            <div className="flex items-center gap-5 flex-1">
                              <div className={`w-16 h-16 rounded-[1.75rem] flex items-center justify-center font-black text-xl transition-all duration-500 ${role.is_deleted ? 'bg-slate-200 text-slate-400' : 'bg-blue-50 text-blue-600 group-hover:bg-blue-600 group-hover:text-white shadow-inner group-hover:shadow-blue-500/20'}`}>
                                {role.name.charAt(0)}
                              </div>
                              <div>
                                <span className={`font-black text-lg block tracking-tight ${role.is_deleted ? 'text-slate-400' : 'text-slate-900'}`}>{role.name}</span>
                                <div className="flex flex-wrap items-center gap-3 mt-1.5">
                                   <div className={`px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-tighter border ${security.text} ${security.color.replace('bg-', 'border-')}`}>
