                                  <button onClick={() => setEditingRolePermissions({...role})} className="p-3.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm border border-blue-100/50" title="Editar Privilégios">
                                    <Shield size={18} />
                                  </button>
                                  <button onClick={() => setEditingRoleName({old: role.name, new: role.name})} className="p-3.5 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-xl transition-all border border-slate-100" title="Renomear">
                                    <Edit size={18} />
                                  </button>
                                  <button onClick={() => handleDeleteRole(role.name)} className="p-3.5 bg-rose-50 text-rose-400 hover:text-rose-600 rounded-xl transition-all border border-rose-100" title="Desativar">
                                    <Trash2 size={18} />
                                  </button>
                                </>
                              )}
