                        )}
                      </div>
                    );
                  })}
                </div>
              </>
            ) : (
              <div className="flex-1 flex flex-col overflow-hidden animate-in fade-in slide-in-from-right-4">
                 <div className="bg-rose-50 border-2 border-dashed border-rose-200 rounded-[2.5rem] p-8 mb-8 flex items-start gap-5">
                    <div className="p-4 bg-rose-100 text-rose-600 rounded-2xl"><AlertTriangle size={32} /></div>
                    <div>
                       <h4 className="text-lg font-black text-rose-900 uppercase tracking-tight mb-2">Reparação de Erros Críticos (Infraestrutura)</h4>
                       <p className="text-xs text-rose-700 font-bold leading-relaxed mb-4">Se você notar módulos inoperantes ou erros de tabela inexistente, execute o script abaixo no seu Editor SQL Supabase:</p>
                       <ol className="text-[10px] text-rose-800 font-black uppercase tracking-widest list-decimal pl-5 space-y-1">
                          <li>Copie o código SQL atualizado v11.0.</li>
