                 </div>

                 <div className="flex-1 bg-slate-900 rounded-[2rem] p-6 relative overflow-hidden group">
                    <div className="absolute top-4 right-4 flex gap-2">
                       <button 
                         onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }} 
                         className="flex items-center gap-2 px-4 py-2 bg-white/10 hover:bg-emerald-500 text-white rounded-lg font-black text-[10px] uppercase tracking-widest transition-all border border-white/5"
                       >
