          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-[12px] border-blue-600 animate-in zoom-in-95">
            <button onClick={() => setEditingRolePermissions(null)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-8 mb-12 border-b border-slate-100 pb-10">
              <div className="w-20 h-20 bg-blue-600 text-white rounded-[2rem] flex items-center justify-center shadow-2xl shadow-blue-500/40 relative overflow-hidden">
                 <Shield size={40} />
                 <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/10 to-transparent"></div>
              </div>
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight leading-none mb-2">Matriz: {editingRolePermissions.name}</h2>
                <div className="flex items-center gap-4">
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Configuração granular de privilégios</p>
                  <span className="text-slate-200">|</span>
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></span>
                    <p className="text-[11px] font-black text-blue-600 uppercase tracking-widest">{editingRolePermissions.permissions.length} Funcionalidades Ativas</p>
                  </div>
                </div>
