            <div className="space-y-16 mb-16">
              {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                  <div key={category} className="space-y-8">
                    <div className="flex items-center justify-between px-4 bg-slate-50 py-3 rounded-2xl border border-slate-100">
                      <h3 className="text-xs font-black uppercase text-slate-900 flex items-center gap-3">
                        <div className="p-1.5 bg-blue-100 text-blue-600 rounded-lg"><Lock size={12} /></div>
                        Módulo: {category}
                      </h3>
                      <button type="button" onClick={() => toggleCategory(category, perms, 'role')} className="text-[9px] font-black uppercase text-indigo-600 hover:text-indigo-900 transition-colors flex items-center gap-2">
                        <Zap size={12} /> Alternar Grupo Completo
