                            <div className="flex items-center justify-between mb-4 relative z-10">
                              <div className={`p-3 rounded-2xl transition-colors ${isActive ? 'bg-white/20' : 'bg-slate-50 text-blue-600 group-hover/btn:bg-white group-hover/btn:shadow-sm'}`}>
                                {p.icon}
                              </div>
                              {isActive && <div className="bg-white text-blue-600 p-1 rounded-full animate-in zoom-in"><Check size={12} strokeWidth={4} /></div>}
                            </div>
                            <span className="text-[12px] font-black uppercase mb-1.5 relative z-10 group-hover/btn:tracking-wider transition-all">{p.label}</span>
                            <span className={`text-[10px] font-medium leading-relaxed relative z-10 ${isActive ? 'text-blue-100' : 'text-slate-400'}`}>
                              {p.description}
                            </span>
                          </button>
                        );
                      })}
                    </div>
