export default AdminView;

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  AlertTriangle,
  RotateCcw,
  Loader2,
  X,
  RefreshCw,
  User,
  CheckSquare,
  Square,
  Zap,
  Check,
  AlignLeft,
  Filter
} from 'lucide-react';
import { Task, Beneficiary } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [beneficiaries, setBeneficiaries] = useState<Beneficiary[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskBeneficiary, setNewTaskBeneficiary] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'completed'>('all');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [lastSavedId, setLastSavedId] = useState<string | null>(null);
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
    fetchBeneficiaries();
  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada.', completed: false, priority: 'Alta', due_date: '2024-05-20' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico.', completed: true, priority: 'Média', due_date: '2024-06-15' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { 
      title: newTaskTitle, 
      description: '', 
      completed: false, 
      priority: 'Média' as const, 
      due_date: newTaskDueDate || null,
      beneficiary_id: newTaskBeneficiary || null
    };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const toggleSelectTask = (id: string) => {
    const next = new Set(selectedTaskIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedTaskIds(next);
  };

  const handleSelectAll = () => {
    const visibleTaskIds = filteredTasks.map(t => t.id);
    const allVisibleSelected = visibleTaskIds.every(id => selectedTaskIds.has(id));

    const next = new Set(selectedTaskIds);
    if (allVisibleSelected) {
      visibleTaskIds.forEach(id => next.delete(id));
    } else {
      visibleTaskIds.forEach(id => next.add(id));
    }
    setSelectedTaskIds(next);
  };

  const handleBulkPriorityUpdate = async (priority: 'Baixa' | 'Média' | 'Alta') => {
    const ids = Array.from(selectedTaskIds);
    if (ids.length === 0) return;

    setIsBulkUpdating(true);
    try {
      const { error } = await supabase.from('tasks').update({ priority }).in('id', ids);
      if (!error) {
        setTasks(tasks.map(t => ids.includes(t.id) ? { ...t, priority } : t));
        setSelectedTaskIds(new Set());
      }
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const updateTaskBeneficiary = async (taskId: string, beneficiaryId: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, beneficiary_id: beneficiaryId } : t));
    try { await supabase.from('tasks').update({ beneficiary_id: beneficiaryId }).eq('id', taskId); } catch (e) {}
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, dueDate: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: dueDate } : t));
    setIsSyncing(id);
    try { 
      await supabase.from('tasks').update({ due_date: dueDate }).eq('id', id); 
      setIsSyncing(null);
    } catch (e) { setIsSyncing(null); }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => {
          setLastSavedId(null);
        }, 2000);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId) return;
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) setTasks(tasks.filter(t => t.id !== deletingTaskId));
    } finally {
      setDeletingTaskId(null);
    }
  };

  const getPriorityColorClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const isOverdue = (date?: string) => {
    if (!date) return false;
    return new Date(date) < new Date(new Date().setHours(0,0,0,0));
  };

  const filteredTasks = tasks.filter(task => {
    const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesFilter = statusFilter === 'all' 
      ? true 
      : statusFilter === 'completed' 
        ? task.completed 
        : !task.completed;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      {/* Bulk Action Bar */}
      {selectedTaskIds.size > 0 && (
        <div className="absolute top-0 left-0 right-0 z-30 bg-slate-900 text-white p-4 flex items-center justify-between animate-in slide-in-from-top duration-300">
          <div className="flex items-center gap-4">
             <button onClick={() => setSelectedTaskIds(new Set())} className="p-2 hover:bg-white/10 rounded-xl transition-colors">
               <X size={20} />
             </button>
             <div>
                <p className="text-xs font-black uppercase tracking-widest">{selectedTaskIds.size} Selecionados</p>
                <p className="text-[8px] text-slate-400 font-bold uppercase">Definir Prioridade em Massa</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {isBulkUpdating ? (
               <Loader2 className="animate-spin text-blue-400 mr-4" size={20} />
             ) : (
               <>
                 <button onClick={() => handleBulkPriorityUpdate('Alta')} className="px-4 py-2 bg-red-500/20 text-red-400 rounded-xl text-[9px] font-black uppercase hover:bg-red-500 hover:text-white transition-all">Alta</button>
                 <button onClick={() => handleBulkPriorityUpdate('Média')} className="px-4 py-2 bg-blue-500/20 text-blue-400 rounded-xl text-[9px] font-black uppercase hover:bg-blue-500 hover:text-white transition-all">Média</button>
                 <button onClick={() => handleBulkPriorityUpdate('Baixa')} className="px-4 py-2 bg-slate-700 text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-50 hover:text-white transition-all">Baixa</button>
               </>
             )}
          </div>
        </div>
      )}

      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Afazeres Operacionais
        </h3>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleSelectAll} 
            title="Selecionar Todos"
            className={`p-2 rounded-xl transition-all ${filteredTasks.length > 0 && filteredTasks.every(t => selectedTaskIds.has(t.id)) ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
          >
            <CheckSquare size={18} />
          </button>
          <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
            <RotateCcw size={16} />
          </button>
        </div>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="space-y-3">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="Nova tarefa Monte..."
              className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none"
            />
            <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20"><Plus size={24} /></button>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <select 
              value={newTaskBeneficiary}
              onChange={e => setNewTaskBeneficiary(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600"
            >
              <option value="">Responsável</option>
              {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
            <input 
              type="date"
              value={newTaskDueDate}
              onChange={e => setNewTaskDueDate(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600"
            />
          </div>
        </form>
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Pesquisar..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 outline-none" />
          </div>
          <div className="flex items-center gap-1.5 p-1 bg-white rounded-2xl border border-slate-100 shadow-sm shrink-0">
             <button onClick={() => setStatusFilter('all')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'all' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>Todas</button>
             <button onClick={() => setStatusFilter('pending')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'pending' ? 'bg-amber-100 text-amber-600' : 'text-slate-400 hover:bg-slate-50'}`}>Pendentes</button>
             <button onClick={() => setStatusFilter('completed')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'completed' ? 'bg-emerald-100 text-emerald-600' : 'text-slate-400 hover:bg-slate-50'}`}>Feitas</button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {loading ? (
           <div className="flex justify-center py-10"><Loader2 className="animate-spin text-blue-600" /></div>
        ) : filteredTasks.map((task) => {
          const isExpanded = expandedId === task.id;
          const isSelected = selectedTaskIds.has(task.id);
          const assignedBeneficiary = beneficiaries.find(b => b.id === task.beneficiary_id);
          const overdue = isOverdue(task.due_date) && !task.completed;
          const priorityColor = getPriorityColorClass(task.priority, task.completed);

          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isSelected ? 'border-blue-500 bg-blue-50/30' : isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : 'border-slate-100 hover:border-blue-100'}`}>
              <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${priorityColor} transition-all duration-500 shadow-inner`}></div>

              <div className="p-5 pl-8 flex items-start gap-4">
                <div className="flex items-center gap-3 pt-1">
                  <button 
                    onClick={(e) => { e.stopPropagation(); toggleSelectTask(task.id); }} 
                    className={`transition-all ${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-blue-400'}`}
                  >
                    {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                  </button>
                  <div className="relative flex items-center">
                    <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : 'text-slate-300 hover:text-blue-500'}`}>
                      {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    {!task.completed && (
                      <div className={`absolute -right-1 -top-1 w-2.5 h-2.5 rounded-full border-2 border-white ${priorityColor} shadow-sm`}></div>
                    )}
                  </div>
                </div>

                <div className="flex-1 min-w-0">
                   <div className="flex items-center gap-2 mb-1 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                    <p className={`text-sm font-black truncate ${task.completed ? 'text-slate-400 line-through' : 'text-slate-900'}`}>{task.title}</p>
                    {task.due_date && (
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full flex items-center gap-1 border ${overdue ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                        <Calendar size={10} /> {new Date(task.due_date).toLocaleDateString('pt-MZ')}
                      </span>
                    )}
                   </div>

                   {/* Descrição Expandida por Defeito (Editável) */}
                   <div className="relative mb-2">
                     <textarea 
                        value={task.description} 
                        onChange={e => updateDescription(task.id, e.target.value)}
                        placeholder="Adicionar detalhes..."
                        rows={isExpanded ? 4 : 1}
                        className={`w-full bg-slate-50/50 hover:bg-slate-50 rounded-xl p-3 text-[11px] font-medium text-slate-600 border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none ${task.completed ? 'opacity-50 grayscale' : ''}`}
                     />
                     <div className="absolute right-3 bottom-2 flex items-center gap-1.5 h-4 pointer-events-none">
                        {isSyncing === task.id ? (
                           <RefreshCw size={10} className="animate-spin text-blue-400" />
                        ) : lastSavedId === task.id ? (
                           <Check size={10} strokeWidth={4} className="text-emerald-500 animate-in zoom-in duration-300" />
                        ) : null}
                     </div>
                   </div>

                   <div className="flex items-center justify-between">
                     {assignedBeneficiary ? (
                       <p className="text-[9px] font-black text-blue-500 uppercase flex items-center gap-1">
                         <User size={10} /> {assignedBeneficiary.name}
                       </p>
                     ) : (
                       <div />
                     )}
                     <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className="p-1 text-slate-400 hover:text-blue-600 flex items-center gap-1">
                        <span className="text-[8px] font-bold uppercase">{isExpanded ? 'Menos' : 'Configurações'}</span>
                        <ChevronDown className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} size={12} />
                     </button>
                   </div>
                </div>
              </div>

              {isExpanded && (
                <div className="px-14 pb-8 pt-4 border-t border-slate-50/50 animate-in slide-in-from-top-4 duration-500 space-y-6 bg-slate-50/20">
                   <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Responsável</label>
                        <select 
                          value={task.beneficiary_id || ''} 
                          onChange={e => updateTaskBeneficiary(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        >
                          <option value="">Não Atribuído</option>
                          {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Vencimento</label>
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={e => updateDueDate(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prioridade</label>
                        <div className="flex gap-2 bg-white border border-slate-100 p-1 rounded-xl shadow-sm">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button key={p} onClick={() => updatePriority(task.id, p)} className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}>{p}</button>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="flex justify-end gap-3 pt-2">
                     <button onClick={() => setDeletingTaskId(task.id)} className="px-4 py-2.5 bg-rose-50 text-rose-500 rounded-xl text-[9px] font-black uppercase hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center gap-2 border border-rose-100/50"><Trash2 size={12}/> Eliminar Tarefa</button>
                     <button onClick={() => setExpandedId(null)} className="px-4 py-2.5 bg-slate-100 text-slate-500 rounded-xl text-[9px] font-black uppercase hover:bg-slate-200 transition-all">Fechar</button>
                   </div>
                </div>
              )}
            </div>
          );
        })}
        {filteredTasks.length === 0 && !loading && (
          <div className="py-20 text-center flex flex-col items-center gap-4 animate-in fade-in">
             <div className="p-6 bg-slate-50 rounded-full text-slate-200">
               <LayoutList size={48} />
             </div>
             <div>
                <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Nenhuma tarefa encontrada</p>
                <p className="text-slate-300 text-[8px] font-bold uppercase mt-1">Experimente ajustar os filtros ou a pesquisa</p>
             </div>
          </div>
        )}
      </div>

      {deletingTaskId && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in">
           <div className="bg-white rounded-[3.5rem] p-10 max-sm w-full shadow-2xl text-center border-t-8 border-red-500">
              <AlertTriangle size={40} className="text-red-500 mx-auto mb-6" />
              <h4 className="text-xl font-black text-slate-900 mb-2">Eliminar Registo?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">Esta acção removerá a tarefa permanentemente da Cloud.</p>
              <div className="flex flex-col gap-3">
                 <button onClick={confirmDeletion} className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20">Sim, Eliminar Agora</button>
                 <button onClick={() => setDeletingTaskId(null)} className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Cancelar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  AlertTriangle,
  RotateCcw,
  Loader2,
  X,
  RefreshCw,
  User,
  CheckSquare,
  Square,
  Zap,
  Check,
  AlignLeft,
  Filter,
  CloudUpload
} from 'lucide-react';
import { Task, Beneficiary } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [beneficiaries, setBeneficiaries] = useState<Beneficiary[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskBeneficiary, setNewTaskBeneficiary] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'completed'>('all');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [lastSavedId, setLastSavedId] = useState<string | null>(null);
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
    fetchBeneficiaries();
  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada.', completed: false, priority: 'Alta', due_date: '2024-05-20' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico.', completed: true, priority: 'Média', due_date: '2024-06-15' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { 
      title: newTaskTitle, 
      description: '', 
      completed: false, 
      priority: 'Média' as const, 
      due_date: newTaskDueDate || null,
      beneficiary_id: newTaskBeneficiary || null
    };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const toggleSelectTask = (id: string) => {
    const next = new Set(selectedTaskIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedTaskIds(next);
  };

  const handleSelectAll = () => {
    const visibleTaskIds = filteredTasks.map(t => t.id);
    const allVisibleSelected = visibleTaskIds.every(id => selectedTaskIds.has(id));

    const next = new Set(selectedTaskIds);
    if (allVisibleSelected) {
      visibleTaskIds.forEach(id => next.delete(id));
    } else {
      visibleTaskIds.forEach(id => next.add(id));
    }
    setSelectedTaskIds(next);
  };

  const handleBulkPriorityUpdate = async (priority: 'Baixa' | 'Média' | 'Alta') => {
    const ids = Array.from(selectedTaskIds);
    if (ids.length === 0) return;

    setIsBulkUpdating(true);
    try {
      const { error } = await supabase.from('tasks').update({ priority }).in('id', ids);
      if (!error) {
        setTasks(tasks.map(t => ids.includes(t.id) ? { ...t, priority } : t));
        setSelectedTaskIds(new Set());
      }
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const updateTaskBeneficiary = async (taskId: string, beneficiaryId: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, beneficiary_id: beneficiaryId } : t));
    try { await supabase.from('tasks').update({ beneficiary_id: beneficiaryId }).eq('id', taskId); } catch (e) {}
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, dueDate: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: dueDate } : t));
    setIsSyncing(id);
    try { 
      await supabase.from('tasks').update({ due_date: dueDate }).eq('id', id); 
      setIsSyncing(null);
    } catch (e) { setIsSyncing(null); }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => {
          setLastSavedId(null);
        }, 2500);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId) return;
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) setTasks(tasks.filter(t => t.id !== deletingTaskId));
    } finally {
      setDeletingTaskId(null);
    }
  };

  const getPriorityColorClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const isOverdue = (date?: string) => {
    if (!date) return false;
    return new Date(date) < new Date(new Date().setHours(0,0,0,0));
  };

  const filteredTasks = tasks.filter(task => {
    const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesFilter = statusFilter === 'all' 
      ? true 
      : statusFilter === 'completed' 
        ? task.completed 
        : !task.completed;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      {/* Bulk Action Bar */}
      {selectedTaskIds.size > 0 && (
        <div className="absolute top-0 left-0 right-0 z-30 bg-slate-900 text-white p-4 flex items-center justify-between animate-in slide-in-from-top duration-300">
          <div className="flex items-center gap-4">
             <button onClick={() => setSelectedTaskIds(new Set())} className="p-2 hover:bg-white/10 rounded-xl transition-colors">
               <X size={20} />
             </button>
             <div>
                <p className="text-xs font-black uppercase tracking-widest">{selectedTaskIds.size} Selecionados</p>
                <p className="text-[8px] text-slate-400 font-bold uppercase">Definir Prioridade em Massa</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {isBulkUpdating ? (
               <Loader2 className="animate-spin text-blue-400 mr-4" size={20} />
             ) : (
               <>
                 <button onClick={() => handleBulkPriorityUpdate('Alta')} className="px-4 py-2 bg-red-500/20 text-red-400 rounded-xl text-[9px] font-black uppercase hover:bg-red-500 hover:text-white transition-all">Alta</button>
                 <button onClick={() => handleBulkPriorityUpdate('Média')} className="px-4 py-2 bg-blue-500/20 text-blue-400 rounded-xl text-[9px] font-black uppercase hover:bg-blue-500 hover:text-white transition-all">Média</button>
                 <button onClick={() => handleBulkPriorityUpdate('Baixa')} className="px-4 py-2 bg-slate-700 text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-50 hover:text-white transition-all">Baixa</button>
               </>
             )}
          </div>
        </div>
      )}

      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Afazeres Operacionais
        </h3>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleSelectAll} 
            title="Selecionar Todos"
            className={`p-2 rounded-xl transition-all ${filteredTasks.length > 0 && filteredTasks.every(t => selectedTaskIds.has(t.id)) ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
          >
            <CheckSquare size={18} />
          </button>
          <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
            <RotateCcw size={16} />
          </button>
        </div>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="space-y-3">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="Nova tarefa Monte..."
              className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none"
            />
            <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20"><Plus size={24} /></button>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <select 
              value={newTaskBeneficiary}
              onChange={e => setNewTaskBeneficiary(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600"
            >
              <option value="">Responsável</option>
              {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
            <input 
              type="date"
              value={newTaskDueDate}
              onChange={e => setNewTaskDueDate(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600"
            />
          </div>
        </form>
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Pesquisar..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 outline-none" />
          </div>
          <div className="flex items-center gap-1.5 p-1 bg-white rounded-2xl border border-slate-100 shadow-sm shrink-0">
             <button onClick={() => setStatusFilter('all')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'all' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>Todas</button>
             <button onClick={() => setStatusFilter('pending')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'pending' ? 'bg-amber-100 text-amber-600' : 'text-slate-400 hover:bg-slate-50'}`}>Pendentes</button>
             <button onClick={() => setStatusFilter('completed')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'completed' ? 'bg-emerald-100 text-emerald-600' : 'text-slate-400 hover:bg-slate-50'}`}>Feitas</button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {loading ? (
           <div className="flex justify-center py-10"><Loader2 className="animate-spin text-blue-600" /></div>
        ) : filteredTasks.map((task) => {
          const isExpanded = expandedId === task.id;
          const isSelected = selectedTaskIds.has(task.id);
          const assignedBeneficiary = beneficiaries.find(b => b.id === task.beneficiary_id);
          const overdue = isOverdue(task.due_date) && !task.completed;
          const priorityColor = getPriorityColorClass(task.priority, task.completed);

          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isSelected ? 'border-blue-500 bg-blue-50/30' : isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : 'border-slate-100 hover:border-blue-100'}`}>
              <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${priorityColor} transition-all duration-500 shadow-inner`}></div>

              <div className="p-5 pl-8 flex items-start gap-4">
                <div className="flex items-center gap-3 pt-1">
                  <button 
                    onClick={(e) => { e.stopPropagation(); toggleSelectTask(task.id); }} 
                    className={`transition-all ${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-blue-400'}`}
                  >
                    {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                  </button>
                  <div className="relative flex items-center">
                    <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : 'text-slate-300 hover:text-blue-500'}`}>
                      {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    {!task.completed && (
                      <div className={`absolute -right-1 -top-1 w-2.5 h-2.5 rounded-full border-2 border-white ${priorityColor} shadow-sm`}></div>
                    )}
                  </div>
                </div>

                <div className="flex-1 min-w-0">
                   <div className="flex items-center gap-2 mb-1 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                    <p className={`text-sm font-black truncate ${task.completed ? 'text-slate-400 line-through' : 'text-slate-900'}`}>{task.title}</p>
                    {task.due_date && (
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full flex items-center gap-1 border ${overdue ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                        <Calendar size={10} /> {new Date(task.due_date).toLocaleDateString('pt-MZ')}
                      </span>
                    )}
                   </div>

                   {/* Descrição Expandida por Defeito com Indicador Visual de Gravação */}
                   <div className="relative mb-2 group/desc">
                     <textarea 
                        value={task.description} 
                        onChange={e => updateDescription(task.id, e.target.value)}
                        placeholder="Adicionar detalhes estratégicos..."
                        rows={isExpanded ? 4 : 1}
                        className={`w-full bg-slate-50/50 hover:bg-slate-50 rounded-xl p-3 text-[11px] font-medium text-slate-600 border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none ${task.completed ? 'opacity-50 grayscale' : ''}`}
                     />

                     {/* Novo Indicador de Sincronização Detalhado */}
                     <div className="absolute top-2 right-3 flex items-center gap-1.5 h-5 pointer-events-none z-10">
                        {isSyncing === task.id ? (
                           <div className="flex items-center gap-1.5 bg-white/80 backdrop-blur-sm px-2 py-0.5 rounded-full border border-blue-50 shadow-sm animate-pulse">
                              <RefreshCw size={10} className="animate-spin text-blue-500" />
                              <span className="text-[7px] font-black text-blue-500 uppercase tracking-tighter">A guardar...</span>
                           </div>
                        ) : lastSavedId === task.id ? (
                           <div className="flex items-center gap-1.5 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-100 shadow-sm animate-in zoom-in duration-300">
                              <Check size={10} strokeWidth={4} className="text-emerald-600" />
                              <span className="text-[7px] font-black text-emerald-600 uppercase tracking-tighter">Sincronizado</span>
                           </div>
                        ) : null}
                     </div>
                   </div>

                   <div className="flex items-center justify-between">
                     {assignedBeneficiary ? (
                       <p className="text-[9px] font-black text-blue-500 uppercase flex items-center gap-1">
                         <User size={10} /> {assignedBeneficiary.name}
                       </p>
                     ) : (
                       <div />
                     )}
                     <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className="p-1 text-slate-400 hover:text-blue-600 flex items-center gap-1">
                        <span className="text-[8px] font-bold uppercase">{isExpanded ? 'Menos' : 'Configurações'}</span>
                        <ChevronDown className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} size={12} />
                     </button>
                   </div>
                </div>
              </div>

              {isExpanded && (
                <div className="px-14 pb-8 pt-4 border-t border-slate-50/50 animate-in slide-in-from-top-4 duration-500 space-y-6 bg-slate-50/20">
                   <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Responsável</label>
                        <select 
                          value={task.beneficiary_id || ''} 
                          onChange={e => updateTaskBeneficiary(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        >
                          <option value="">Não Atribuído</option>
                          {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Vencimento</label>
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={e => updateDueDate(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prioridade</label>
                        <div className="flex gap-2 bg-white border border-slate-100 p-1 rounded-xl shadow-sm">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button key={p} onClick={() => updatePriority(task.id, p)} className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}>{p}</button>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="flex justify-end gap-3 pt-2">
                     <button onClick={() => setDeletingTaskId(task.id)} className="px-4 py-2.5 bg-rose-50 text-rose-500 rounded-xl text-[9px] font-black uppercase hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center gap-2 border border-rose-100/50"><Trash2 size={12}/> Eliminar Tarefa</button>
                     <button onClick={() => setExpandedId(null)} className="px-4 py-2.5 bg-slate-100 text-slate-500 rounded-xl text-[9px] font-black uppercase hover:bg-slate-200 transition-all">Fechar</button>
                   </div>
                </div>
              )}
            </div>
          );
        })}
        {filteredTasks.length === 0 && !loading && (
          <div className="py-20 text-center flex flex-col items-center gap-4 animate-in fade-in">
             <div className="p-6 bg-slate-50 rounded-full text-slate-200">
               <LayoutList size={48} />
             </div>
             <div>
                <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Nenhuma tarefa encontrada</p>
                <p className="text-slate-300 text-[8px] font-bold uppercase mt-1">Experimente ajustar os filtros ou a pesquisa</p>
             </div>
          </div>
        )}
      </div>

      {deletingTaskId && (
        <div className="absolute inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in">
           <div className="bg-white rounded-[3.5rem] p-10 max-sm w-full shadow-2xl text-center border-t-8 border-red-500">
              <AlertTriangle size={40} className="text-red-500 mx-auto mb-6" />
              <h4 className="text-xl font-black text-slate-900 mb-2">Eliminar Registo?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">Esta acção removerá a tarefa permanentemente da Cloud.</p>
              <div className="flex flex-col gap-3">
                 <button onClick={confirmDeletion} className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20">Sim, Eliminar Agora</button>
                 <button onClick={() => setDeletingTaskId(null)} className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Cancelar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  AlertTriangle,
  RotateCcw,
  Loader2,
  X,
  RefreshCw,
  User,
  CheckSquare,
  Square,
  Zap,
  Check,
  AlignLeft,
  Filter,
  CloudUpload
} from 'lucide-react';
import { Task, Beneficiary } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [beneficiaries, setBeneficiaries] = useState<Beneficiary[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskBeneficiary, setNewTaskBeneficiary] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'completed'>('all');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [lastSavedId, setLastSavedId] = useState<string | null>(null);
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
    fetchBeneficiaries();
  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada.', completed: false, priority: 'Alta', due_date: '2024-05-20' },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico.', completed: true, priority: 'Média', due_date: '2024-06-15' }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { 
      title: newTaskTitle, 
      description: '', 
      completed: false, 
      priority: 'Média' as const, 
      due_date: newTaskDueDate || null,
      beneficiary_id: newTaskBeneficiary || null
    };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const toggleSelectTask = (id: string) => {
    const next = new Set(selectedTaskIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedTaskIds(next);
  };

  const handleSelectAll = () => {
    const visibleTaskIds = filteredTasks.map(t => t.id);
    const allVisibleSelected = visibleTaskIds.every(id => selectedTaskIds.has(id));

    const next = new Set(selectedTaskIds);
    if (allVisibleSelected) {
      visibleTaskIds.forEach(id => next.delete(id));
    } else {
      visibleTaskIds.forEach(id => next.add(id));
    }
    setSelectedTaskIds(next);
  };

  const handleBulkPriorityUpdate = async (priority: 'Baixa' | 'Média' | 'Alta') => {
    const ids = Array.from(selectedTaskIds);
    if (ids.length === 0) return;

    setIsBulkUpdating(true);
    try {
      const { error } = await supabase.from('tasks').update({ priority }).in('id', ids);
      if (!error) {
        setTasks(tasks.map(t => ids.includes(t.id) ? { ...t, priority } : t));
        setSelectedTaskIds(new Set());
      }
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const updateTaskBeneficiary = async (taskId: string, beneficiaryId: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, beneficiary_id: beneficiaryId } : t));
    try { await supabase.from('tasks').update({ beneficiary_id: beneficiaryId }).eq('id', taskId); } catch (e) {}
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, dueDate: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: dueDate } : t));
    setIsSyncing(id);
    try { 
      await supabase.from('tasks').update({ due_date: dueDate }).eq('id', id); 
      setIsSyncing(null);
    } catch (e) { setIsSyncing(null); }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => {
          setLastSavedId(null);
        }, 2500);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId || isDeleting) return;
    setIsDeleting(true);
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) {
        setTasks(tasks.filter(t => t.id !== deletingTaskId));
        setDeletingTaskId(null);
      }
    } catch (e) {
      console.error("Erro ao eliminar tarefa:", e);
    } finally {
      setIsDeleting(false);
    }
  };

  const getPriorityColorClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const isOverdue = (date?: string) => {
    if (!date) return false;
    return new Date(date) < new Date(new Date().setHours(0,0,0,0));
  };

  const filteredTasks = tasks.filter(task => {
    const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesFilter = statusFilter === 'all' 
      ? true 
      : statusFilter === 'completed' 
        ? task.completed 
        : !task.completed;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      {/* Bulk Action Bar */}
      {selectedTaskIds.size > 0 && (
        <div className="absolute top-0 left-0 right-0 z-30 bg-slate-900 text-white p-4 flex items-center justify-between animate-in slide-in-from-top duration-300">
          <div className="flex items-center gap-4">
             <button onClick={() => setSelectedTaskIds(new Set())} className="p-2 hover:bg-white/10 rounded-xl transition-colors">
               <X size={20} />
             </button>
             <div>
                <p className="text-xs font-black uppercase tracking-widest">{selectedTaskIds.size} Selecionados</p>
                <p className="text-[8px] text-slate-400 font-bold uppercase">Definir Prioridade em Massa</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {isBulkUpdating ? (
               <Loader2 className="animate-spin text-blue-400 mr-4" size={20} />
             ) : (
               <>
                 <button onClick={() => handleBulkPriorityUpdate('Alta')} className="px-4 py-2 bg-red-500/20 text-red-400 rounded-xl text-[9px] font-black uppercase hover:bg-red-500 hover:text-white transition-all">Alta</button>
                 <button onClick={() => handleBulkPriorityUpdate('Média')} className="px-4 py-2 bg-blue-500/20 text-blue-400 rounded-xl text-[9px] font-black uppercase hover:bg-blue-500 hover:text-white transition-all">Média</button>
                 <button onClick={() => handleBulkPriorityUpdate('Baixa')} className="px-4 py-2 bg-slate-700 text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-50 hover:text-white transition-all">Baixa</button>
               </>
             )}
          </div>
        </div>
      )}

      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Afazeres Operacionais
        </h3>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleSelectAll} 
            title="Selecionar Todos"
            className={`p-2 rounded-xl transition-all ${filteredTasks.length > 0 && filteredTasks.every(t => selectedTaskIds.has(t.id)) ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
          >
            <CheckSquare size={18} />
          </button>
          <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
            <RotateCcw size={16} />
          </button>
        </div>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="space-y-3">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="Nova tarefa Monte..."
              className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none"
            />
            <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20"><Plus size={24} /></button>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <select 
              value={newTaskBeneficiary}
              onChange={e => setNewTaskBeneficiary(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600"
            >
              <option value="">Responsável</option>
              {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
            <input 
              type="date"
              value={newTaskDueDate}
              onChange={e => setNewTaskDueDate(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600"
            />
          </div>
        </form>
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Pesquisar..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 outline-none" />
          </div>
          <div className="flex items-center gap-1.5 p-1 bg-white rounded-2xl border border-slate-100 shadow-sm shrink-0">
             <button onClick={() => setStatusFilter('all')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'all' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>Todas</button>
             <button onClick={() => setStatusFilter('pending')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'pending' ? 'bg-amber-100 text-amber-600' : 'text-slate-400 hover:bg-slate-50'}`}>Pendentes</button>
             <button onClick={() => setStatusFilter('completed')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'completed' ? 'bg-emerald-100 text-emerald-600' : 'text-slate-400 hover:bg-slate-50'}`}>Feitas</button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {loading ? (
           <div className="flex justify-center py-10"><Loader2 className="animate-spin text-blue-600" /></div>
        ) : filteredTasks.map((task) => {
          const isExpanded = expandedId === task.id;
          const isSelected = selectedTaskIds.has(task.id);
          const assignedBeneficiary = beneficiaries.find(b => b.id === task.beneficiary_id);
          const overdue = isOverdue(task.due_date) && !task.completed;
          const priorityColor = getPriorityColorClass(task.priority, task.completed);

          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isSelected ? 'border-blue-500 bg-blue-50/30' : isExpanded ? 'border-blue-300 shadow-2xl scale-[1.01] z-20' : 'border-slate-100 hover:border-blue-100'}`}>
              <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${priorityColor} transition-all duration-500 shadow-inner`}></div>

              <div className="p-5 pl-8 flex items-start gap-4">
                <div className="flex items-center gap-3 pt-1">
                  <button 
                    onClick={(e) => { e.stopPropagation(); toggleSelectTask(task.id); }} 
                    className={`transition-all ${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-blue-400'}`}
                  >
                    {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                  </button>
                  <div className="relative flex items-center">
                    <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : 'text-slate-300 hover:text-blue-500'}`}>
                      {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    {!task.completed && (
                      <div className={`absolute -right-1 -top-1 w-2.5 h-2.5 rounded-full border-2 border-white ${priorityColor} shadow-sm`}></div>
                    )}
                  </div>
                </div>

                <div className="flex-1 min-w-0">
                   <div className="flex items-center gap-2 mb-1 cursor-pointer" onClick={() => setExpandedId(isExpanded ? null : task.id)}>
                    <p className={`text-sm font-black truncate ${task.completed ? 'text-slate-400 line-through' : 'text-slate-900'}`}>{task.title}</p>
                    {task.due_date && (
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full flex items-center gap-1 border ${overdue ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                        <Calendar size={10} /> {new Date(task.due_date).toLocaleDateString('pt-MZ')}
                      </span>
                    )}
                   </div>

                   {/* Descrição Expandida por Defeito com Indicador Visual de Gravação */}
                   <div className="relative mb-2 group/desc">
                     <textarea 
                        value={task.description} 
                        onChange={e => updateDescription(task.id, e.target.value)}
                        placeholder="Adicionar detalhes estratégicos..."
                        rows={isExpanded ? 4 : 1}
                        className={`w-full bg-slate-50/50 hover:bg-slate-50 rounded-xl p-3 text-[11px] font-medium text-slate-600 border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none ${task.completed ? 'opacity-50 grayscale' : ''}`}
                     />

                     {/* Indicador de Sincronização Detalhado */}
                     <div className="absolute top-2 right-3 flex items-center gap-1.5 h-5 pointer-events-none z-10">
                        {isSyncing === task.id ? (
                           <div className="flex items-center gap-1.5 bg-white/80 backdrop-blur-sm px-2 py-0.5 rounded-full border border-blue-50 shadow-sm animate-pulse">
                              <RefreshCw size={10} className="animate-spin text-blue-500" />
                              <span className="text-[7px] font-black text-blue-500 uppercase tracking-tighter">A guardar...</span>
                           </div>
                        ) : lastSavedId === task.id ? (
                           <div className="flex items-center gap-1.5 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-100 shadow-sm animate-in zoom-in duration-300">
                              <Check size={10} strokeWidth={4} className="text-emerald-600" />
                              <span className="text-[7px] font-black text-emerald-600 uppercase tracking-tighter">Sincronizado</span>
                           </div>
                        ) : null}
                     </div>
                   </div>

                   <div className="flex items-center justify-between">
                     {assignedBeneficiary ? (
                       <p className="text-[9px] font-black text-blue-500 uppercase flex items-center gap-1">
                         <User size={10} /> {assignedBeneficiary.name}
                       </p>
                     ) : (
                       <div />
                     )}
                     <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className="p-1 text-slate-400 hover:text-blue-600 flex items-center gap-1">
                        <span className="text-[8px] font-bold uppercase">{isExpanded ? 'Menos' : 'Configurações'}</span>
                        <ChevronDown className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} size={12} />
                     </button>
                   </div>
                </div>
              </div>

              {isExpanded && (
                <div className="px-14 pb-8 pt-4 border-t border-slate-50/50 animate-in slide-in-from-top-4 duration-500 space-y-6 bg-slate-50/20">
                   <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Responsável</label>
                        <select 
                          value={task.beneficiary_id || ''} 
                          onChange={e => updateTaskBeneficiary(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        >
                          <option value="">Não Atribuído</option>
                          {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                        </select>
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Vencimento</label>
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={e => updateDueDate(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-100 rounded-xl px-4 py-3 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        />
                      </div>
                      <div className="space-y-2">
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Prioridade</label>
                        <div className="flex gap-2 bg-white border border-slate-100 p-1 rounded-xl shadow-sm">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button key={p} onClick={() => updatePriority(task.id, p)} className={`flex-1 py-2 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-blue-600 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}>{p}</button>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="flex justify-end gap-3 pt-2">
                     <button onClick={() => setDeletingTaskId(task.id)} className="px-4 py-2.5 bg-rose-50 text-rose-500 rounded-xl text-[9px] font-black uppercase hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center gap-2 border border-rose-100/50"><Trash2 size={12}/> Eliminar Tarefa</button>
                     <button onClick={() => setExpandedId(null)} className="px-4 py-2.5 bg-slate-100 text-slate-500 rounded-xl text-[9px] font-black uppercase hover:bg-slate-200 transition-all">Fechar</button>
                   </div>
                </div>
              )}
            </div>
          );
        })}
        {filteredTasks.length === 0 && !loading && (
          <div className="py-20 text-center flex flex-col items-center gap-4 animate-in fade-in">
             <div className="p-6 bg-slate-50 rounded-full text-slate-200">
               <LayoutList size={48} />
             </div>
             <div>
                <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Nenhuma tarefa encontrada</p>
                <p className="text-slate-300 text-[8px] font-bold uppercase mt-1">Experimente ajustar os filtros ou a pesquisa</p>
             </div>
          </div>
        )}
      </div>

      {/* Modal de Confirmação de Eliminação (Segurança Operacional) */}
      {deletingTaskId && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-10 max-w-sm w-full shadow-2xl text-center border-t-[10px] border-red-500 animate-in zoom-in-95 duration-300">
              <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={48} className="text-red-500 animate-pulse" />
              </div>
              <h4 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Confirmar Eliminação?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">
                Esta ação é irreversível. O registo da tarefa será permanentemente removido da Cloud da Monte Imobiliária.
              </p>
              <div className="flex flex-col gap-3">
                 <button 
                  onClick={confirmDeletion} 
                  disabled={isDeleting}
                  className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20 hover:bg-red-600 transition-all active:scale-95 flex items-center justify-center gap-2 disabled:opacity-70"
                 >
                   {isDeleting ? <Loader2 className="animate-spin" size={18} /> : <><Trash2 size={18} /> Sim, Eliminar Registo</>}
                 </button>
                 <button 
                  onClick={() => setDeletingTaskId(null)} 
                  disabled={isDeleting}
                  className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase hover:bg-slate-200 transition-all disabled:opacity-50"
                 >
                   Cancelar
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

