  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada e prazos de aviso prévio.', completed: false, priority: 'Alta', due_date: '2024-05-20', beneficiary_id: null },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza de filtros e verificação de gás nos blocos A e B.', completed: true, priority: 'Média', due_date: '2024-06-15', beneficiary_id: null }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { 
      title: newTaskTitle, 
      description: '', 
      completed: false, 
      priority: 'Média' as const, 
      due_date: newTaskDueDate || null,
      beneficiary_id: newTaskBeneficiary || null
    };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const toggleSelectTask = (id: string) => {
    const next = new Set(selectedTaskIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedTaskIds(next);
  };

  const handleSelectAll = () => {
    const visibleTaskIds = filteredTasks.map(t => t.id);
    const allVisibleSelected = visibleTaskIds.every(id => selectedTaskIds.has(id));

    const next = new Set(selectedTaskIds);
    if (allVisibleSelected) {
      visibleTaskIds.forEach(id => next.delete(id));
    } else {
      visibleTaskIds.forEach(id => next.add(id));
    }
    setSelectedTaskIds(next);
  };

  const handleBulkPriorityUpdate = async (priority: 'Baixa' | 'Média' | 'Alta') => {
    const ids = Array.from(selectedTaskIds);
    if (ids.length === 0) return;

    setIsBulkUpdating(true);
    try {
      const { error } = await supabase.from('tasks').update({ priority }).in('id', ids);
      if (!error) {
        setTasks(tasks.map(t => ids.includes(t.id) ? { ...t, priority } : t));
        setSelectedTaskIds(new Set());
      }
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const updateTaskBeneficiary = async (taskId: string, beneficiaryId: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, beneficiary_id: beneficiaryId } : t));
    try { await supabase.from('tasks').update({ beneficiary_id: beneficiaryId }).eq('id', taskId); } catch (e) {}
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, dueDate: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: dueDate } : t));
    setIsSyncing(id);
    try { 
      await supabase.from('tasks').update({ due_date: dueDate }).eq('id', id); 
      setIsSyncing(null);
    } catch (e) { setIsSyncing(null); }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => {
          setLastSavedId(null);
        }, 2500);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId || isDeleting) return;
    setIsDeleting(true);
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) {
        setTasks(tasks.filter(t => t.id !== deletingTaskId));
        setDeletingTaskId(null);
      }
    } catch (e) {
      console.error("Erro ao eliminar tarefa:", e);
    } finally {
      setIsDeleting(false);
    }
  };

  const getPriorityColorClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const isOverdue = (date?: string) => {
    if (!date) return false;
    return new Date(date) < new Date(new Date().setHours(0,0,0,0));
  };

  const filteredTasks = tasks.filter(task => {
    const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesFilter = statusFilter === 'all' 
      ? true 
      : statusFilter === 'completed' 
        ? task.completed 
        : !task.completed;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      {/* Bulk Action Bar */}
      {selectedTaskIds.size > 0 && (
        <div className="absolute top-0 left-0 right-0 z-30 bg-slate-900 text-white p-4 flex items-center justify-between animate-in slide-in-from-top duration-300">
          <div className="flex items-center gap-4">
             <button onClick={() => setSelectedTaskIds(new Set())} className="p-2 hover:bg-white/10 rounded-xl transition-colors">
               <X size={20} />
             </button>
             <div>
                <p className="text-xs font-black uppercase tracking-widest">{selectedTaskIds.size} Selecionados</p>
                <p className="text-[8px] text-slate-400 font-bold uppercase">Definir Prioridade em Massa</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {isBulkUpdating ? (
               <Loader2 className="animate-spin text-blue-400 mr-4" size={20} />
             ) : (
               <>
                 <button onClick={() => handleBulkPriorityUpdate('Alta')} className="px-4 py-2 bg-red-500/20 text-red-400 rounded-xl text-[9px] font-black uppercase hover:bg-red-500 hover:text-white transition-all">Alta</button>
                 <button onClick={() => handleBulkPriorityUpdate('Média')} className="px-4 py-2 bg-blue-500/20 text-blue-400 rounded-xl text-[9px] font-black uppercase hover:bg-blue-500 hover:text-white transition-all">Média</button>
                 <button onClick={() => handleBulkPriorityUpdate('Baixa')} className="px-4 py-2 bg-slate-700 text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-50 hover:text-white transition-all">Baixa</button>
               </>
             )}
          </div>
        </div>
      )}

      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Afazeres Operacionais
        </h3>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleSelectAll} 
            title="Selecionar Todos"
            className={`p-2 rounded-xl transition-all ${filteredTasks.length > 0 && filteredTasks.every(t => selectedTaskIds.has(t.id)) ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
          >
            <CheckSquare size={18} />
          </button>
          <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
            <RotateCcw size={16} />
          </button>
        </div>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="space-y-3">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="O que precisa ser feito hoje?"
              className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none placeholder:text-slate-400 transition-all shadow-sm"
            />
            <button type="submit" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20 active:scale-95 transition-all"><Plus size={24} /></button>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <select 
              value={newTaskBeneficiary}
              onChange={e => setNewTaskBeneficiary(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600 cursor-pointer shadow-sm"
            >
              <option value="">Atribuir Responsável</option>
              {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
            <input 
              type="date"
              value={newTaskDueDate}
              onChange={e => setNewTaskDueDate(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600 shadow-sm"
            />
          </div>
        </form>
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Localizar tarefa..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 outline-none" />
          </div>
          <div className="flex items-center gap-1.5 p-1 bg-white rounded-2xl border border-slate-100 shadow-sm shrink-0">
             <button onClick={() => setStatusFilter('all')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'all' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>Todas</button>
             <button onClick={() => setStatusFilter('pending')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'pending' ? 'bg-amber-100 text-amber-600' : 'text-slate-400 hover:bg-slate-50'}`}>Pendentes</button>
             <button onClick={() => setStatusFilter('completed')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'completed' ? 'bg-emerald-100 text-emerald-600' : 'text-slate-400 hover:bg-slate-50'}`}>Feitas</button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {loading ? (
           <div className="flex justify-center py-10"><Loader2 className="animate-spin text-blue-600" /></div>
        ) : filteredTasks.map((task) => {
          const isExpanded = expandedId === task.id;
          const isSelected = selectedTaskIds.has(task.id);
          const assignedBeneficiary = beneficiaries.find(b => b.id === task.beneficiary_id);
          const overdue = isOverdue(task.due_date) && !task.completed;
          const priorityColor = getPriorityColorClass(task.priority, task.completed);

          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isSelected ? 'border-blue-500 bg-blue-50/30' : isExpanded ? 'border-blue-200 shadow-xl scale-[1.005] z-20' : 'border-slate-100 hover:border-blue-100'}`}>
              <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${priorityColor} transition-all duration-500 shadow-inner`}></div>

              <div className="p-6 pl-8 flex items-start gap-4">
                <div className="flex items-center gap-3 pt-1">
                  <button 
                    onClick={(e) => { e.stopPropagation(); toggleSelectTask(task.id); }} 
                    className={`transition-all ${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-blue-400'}`}
                  >
                    {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                  </button>
                  <div className="relative flex items-center">
                    <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : 'text-slate-300 hover:text-blue-500'}`}>
                      {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    {!task.completed && (
                      <div className={`absolute -right-1 -top-1 w-2.5 h-2.5 rounded-full border-2 border-white ${priorityColor} shadow-sm`}></div>
                    )}
                  </div>
                </div>

                <div className="flex-1 min-w-0">
                   <div className="flex items-center gap-2 mb-2">
                    <p className={`text-base font-black truncate leading-tight ${task.completed ? 'text-slate-400 line-through' : 'text-slate-900'}`}>{task.title}</p>
                    {task.due_date && (
                      <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full flex items-center gap-1 border ${overdue ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
                        <Calendar size={10} /> {new Date(task.due_date).toLocaleDateString('pt-MZ')}
                      </span>
                    )}
                   </div>

                   {/* Descrição sempre visível e editável */}
                   <div className="relative group/desc mb-3">
                     <textarea 
                        value={task.description} 
                        onChange={e => updateDescription(task.id, e.target.value)}
                        placeholder="Adicionar detalhes técnicos ou notas de campo..."
                        rows={isExpanded ? 5 : 2}
                        className={`w-full bg-slate-50/50 hover:bg-slate-50 rounded-2xl p-4 text-[11px] font-bold text-slate-600 border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none shadow-inner scrollbar-hide leading-relaxed ${task.completed ? 'opacity-50 grayscale' : ''}`}
                     />

                     <div className="absolute top-3 right-4 flex items-center gap-1.5 h-5 pointer-events-none z-10">
                        {isSyncing === task.id ? (
                           <div className="flex items-center gap-1.5 bg-white/90 backdrop-blur-sm px-2.5 py-1 rounded-full border border-blue-100 shadow-sm animate-pulse">
                              <RefreshCw size={10} className="animate-spin text-blue-500" />
                              <span className="text-[7px] font-black text-blue-500 uppercase tracking-tighter">Gravação Cloud...</span>
                           </div>
                        ) : lastSavedId === task.id ? (
                           <div className="flex items-center gap-1.5 bg-emerald-50 px-2.5 py-1 rounded-full border border-emerald-100 shadow-sm animate-in zoom-in duration-300">
                              <Check size={10} strokeWidth={4} className="text-emerald-600" />
                              <span className="text-[7px] font-black text-emerald-600 uppercase tracking-tighter">Sincronizado</span>
                           </div>
                        ) : null}
                     </div>
                   </div>

                   <div className="flex items-center justify-between">
                     <div className="flex items-center gap-3">
                        {assignedBeneficiary ? (
                          <div className="flex items-center gap-1.5 text-[9px] font-black text-blue-600 bg-blue-50 px-2.5 py-1 rounded-lg border border-blue-100/50 uppercase tracking-tight">
                            <User size={10} /> {assignedBeneficiary.name}
                          </div>
                        ) : (
                          <div className="text-[9px] font-bold text-slate-300 uppercase italic">Sem atribuição</div>
                        )}
                        <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded border ${task.priority === 'Alta' ? 'text-rose-500 border-rose-100' : 'text-slate-400 border-slate-100'}`}>
                          {task.priority}
                        </span>
                     </div>
                     <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className={`px-3 py-1.5 rounded-xl transition-all flex items-center gap-2 border ${isExpanded ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-600'}`}>
                        <span className="text-[8px] font-black uppercase tracking-widest">{isExpanded ? 'Fechar' : 'Configurações'}</span>
                        <ChevronDown className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} size={12} />
                     </button>
                   </div>
                </div>
              </div>

              {/* Área de Configurações Expandida */}
              {isExpanded && (
                <div className="px-14 pb-10 pt-6 border-t border-slate-100 animate-in slide-in-from-top-2 duration-300 space-y-8 bg-slate-50/30">
                   <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 mb-1">
                          <User size={12} className="text-blue-600" />
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Responsável</label>
                        </div>
                        <select 
                          value={task.beneficiary_id || ''} 
                          onChange={e => updateTaskBeneficiary(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm cursor-pointer"
                        >
                          <option value="">Não Atribuído</option>
                          {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name} ({b.category})</option>)}
                        </select>
                      </div>

                      <div className="space-y-2">
                        <div className="flex items-center gap-2 mb-1">
                          <Calendar size={12} className="text-blue-600" />
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Limite: {task.due_date ? new Date(task.due_date).toLocaleDateString() : 'Indefinido'}</label>
                        </div>
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={e => updateDueDate(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        />
                      </div>

                      <div className="space-y-2">
                        <div className="flex items-center gap-2 mb-1">
                          <Zap size={12} className="text-blue-600" />
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Escalão de Prioridade</label>
                        </div>
                        <div className="flex gap-1.5 bg-white border border-slate-200 p-1 rounded-xl shadow-sm">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button 
                              key={p} 
                              onClick={() => updatePriority(task.id, p)} 
                              className={`flex-1 py-2.5 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-slate-900 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
                            >
                              {p}
                            </button>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="flex justify-between items-center pt-4 border-t border-slate-100/50">
                     <div className="flex items-center gap-2 text-[8px] font-bold text-slate-400 uppercase tracking-widest">
                        <FileText size={10} /> Criada em {task.created_at ? new Date(task.created_at).toLocaleDateString() : 'N/D'}
                     </div>
                     <div className="flex gap-3">
                       <button 
                        onClick={() => setDeletingTaskId(task.id)} 
                        className="px-5 py-2.5 bg-rose-50 text-rose-500 rounded-xl text-[9px] font-black uppercase hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center gap-2 border border-rose-100/50"
                       >
                         <Trash2 size={12}/> Eliminar Registo
                       </button>
                       <button 
                        onClick={() => setExpandedId(null)} 
                        className="px-5 py-2.5 bg-white text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-100 transition-all border border-slate-100"
                       >
                         Recolher
                       </button>
                     </div>
                   </div>
                </div>
              )}
            </div>
          );
        })}
        {filteredTasks.length === 0 && !loading && (
          <div className="py-20 text-center flex flex-col items-center gap-4 animate-in fade-in">
             <div className="p-6 bg-slate-50 rounded-full text-slate-200">
               <LayoutList size={48} />
             </div>
             <div>
                <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Nenhuma tarefa encontrada</p>
                <p className="text-slate-300 text-[8px] font-bold uppercase mt-1">Experimente ajustar os filtros ou a pesquisa</p>
             </div>
          </div>
        )}
      </div>

      {/* Modal de Confirmação de Eliminação (Segurança Operacional) */}
      {deletingTaskId && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-10 max-w-sm w-full shadow-2xl text-center border-t-[10px] border-red-500 animate-in zoom-in-95 duration-300">
              <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={48} className="text-red-500 animate-pulse" />
              </div>
              <h4 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Confirmar Eliminação?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">
                Esta ação é irreversível. O registo da tarefa será permanentemente removido da Cloud da Monte Imobiliária.
              </p>
              <div className="flex flex-col gap-3">
                 <button 
                  onClick={confirmDeletion} 
                  disabled={isDeleting}
                  className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20 hover:bg-red-600 transition-all active:scale-95 flex items-center justify-center gap-2 disabled:opacity-70"
                 >
                   {isDeleting ? <Loader2 className="animate-spin" size={18} /> : <><Trash2 size={18} /> Sim, Eliminar Registo</>}
                 </button>
                 <button 
                  onClick={() => setDeletingTaskId(null)} 
                  disabled={isDeleting}
                  className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase hover:bg-slate-200 transition-all disabled:opacity-50"
                 >
                   Cancelar
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect, useRef } from 'react';
import { 
  CheckCircle2, 
  Circle, 
  Plus, 
  Trash2, 
  ChevronDown, 
  AlertCircle,
  LayoutList,
  Search,
  Calendar,
  AlertTriangle,
  RotateCcw,
  Loader2,
  X,
  RefreshCw,
  User,
  CheckSquare,
  Square,
  Zap,
  Check,
  AlignLeft,
  Filter,
  CloudUpload,
  Settings2,
  FileText
} from 'lucide-react';
import { Task, Beneficiary } from '../types';
import { supabase } from '../supabaseClient';

const TodoList: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [beneficiaries, setBeneficiaries] = useState<Beneficiary[]>([]);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskBeneficiary, setNewTaskBeneficiary] = useState('');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'pending' | 'completed'>('all');
  const [loading, setLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState<string | null>(null);
  const [lastSavedId, setLastSavedId] = useState<string | null>(null);
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());
  const [deletingTaskId, setDeletingTaskId] = useState<string | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const [isBulkUpdating, setIsBulkUpdating] = useState(false);
  const syncTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    fetchTasks();
    fetchBeneficiaries();
  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTasks() {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('tasks')
        .select('*')
        .order('created_at', { ascending: false });
      if (!error && data) {
        setTasks(data);
      } else {
        setTasks([
          { id: '1', title: 'Rever contratos Macuti', description: 'Verificar cláusulas de rescisão antecipada e prazos de aviso prévio.', completed: false, priority: 'Alta', due_date: '2024-05-20', beneficiary_id: null },
          { id: '2', title: 'Manutenção AC Sede', description: 'Contactar técnico para limpeza de filtros e verificação de gás nos blocos A e B.', completed: true, priority: 'Média', due_date: '2024-06-15', beneficiary_id: null }
        ]);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  }

  const handleAddTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask = { 
      title: newTaskTitle, 
      description: '', 
      completed: false, 
      priority: 'Média' as const, 
      due_date: newTaskDueDate || null,
      beneficiary_id: newTaskBeneficiary || null
    };
    try {
      const { data, error } = await supabase.from('tasks').insert([newTask]).select();
      if (!error && data) {
        setTasks([data[0], ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(data[0].id);
      } else {
        const localTask: Task = { ...newTask, id: Date.now().toString() };
        setTasks([localTask, ...tasks]);
        setNewTaskTitle('');
        setNewTaskBeneficiary('');
        setNewTaskDueDate('');
        setExpandedId(localTask.id);
      }
    } catch (e) { console.error(e); }
  };

  const toggleComplete = async (task: Task) => {
    try {
      await supabase.from('tasks').update({ completed: !task.completed }).eq('id', task.id);
      setTasks(tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t));
    } catch (e) { console.error(e); }
  };

  const toggleSelectTask = (id: string) => {
    const next = new Set(selectedTaskIds);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setSelectedTaskIds(next);
  };

  const handleSelectAll = () => {
    const visibleTaskIds = filteredTasks.map(t => t.id);
    const allVisibleSelected = visibleTaskIds.every(id => selectedTaskIds.has(id));

    const next = new Set(selectedTaskIds);
    if (allVisibleSelected) {
      visibleTaskIds.forEach(id => next.delete(id));
    } else {
      visibleTaskIds.forEach(id => next.add(id));
    }
    setSelectedTaskIds(next);
  };

  const handleBulkPriorityUpdate = async (priority: 'Baixa' | 'Média' | 'Alta') => {
    const ids = Array.from(selectedTaskIds);
    if (ids.length === 0) return;

    setIsBulkUpdating(true);
    try {
      const { error } = await supabase.from('tasks').update({ priority }).in('id', ids);
      if (!error) {
        setTasks(tasks.map(t => ids.includes(t.id) ? { ...t, priority } : t));
        setSelectedTaskIds(new Set());
      }
    } finally {
      setIsBulkUpdating(false);
    }
  };

  const updateTaskBeneficiary = async (taskId: string, beneficiaryId: string) => {
    setTasks(tasks.map(t => t.id === taskId ? { ...t, beneficiary_id: beneficiaryId } : t));
    try { await supabase.from('tasks').update({ beneficiary_id: beneficiaryId }).eq('id', taskId); } catch (e) {}
  };

  const updatePriority = async (id: string, priority: 'Baixa' | 'Média' | 'Alta') => {
    setTasks(tasks.map(t => t.id === id ? { ...t, priority } : t));
    try { await supabase.from('tasks').update({ priority }).eq('id', id); } catch (e) {}
  };

  const updateDueDate = async (id: string, dueDate: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, due_date: dueDate } : t));
    setIsSyncing(id);
    try { 
      await supabase.from('tasks').update({ due_date: dueDate }).eq('id', id); 
      setIsSyncing(null);
      setLastSavedId(id);
      setTimeout(() => setLastSavedId(null), 2000);
    } catch (e) { setIsSyncing(null); }
  };

  const updateDescription = async (id: string, description: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, description } : t));
    setIsSyncing(id);
    setLastSavedId(null);

    if (syncTimeoutRef.current) clearTimeout(syncTimeoutRef.current);

    syncTimeoutRef.current = setTimeout(async () => {
      try { 
        await supabase.from('tasks').update({ description }).eq('id', id); 
        setIsSyncing(null);
        setLastSavedId(id);
        setTimeout(() => {
          setLastSavedId(null);
        }, 2500);
      } catch (e) { 
        setIsSyncing(null); 
      }
    }, 1000);
  };

  const confirmDeletion = async () => {
    if (!deletingTaskId || isDeleting) return;
    setIsDeleting(true);
    try {
      const { error } = await supabase.from('tasks').delete().eq('id', deletingTaskId);
      if (!error) {
        setTasks(tasks.filter(t => t.id !== deletingTaskId));
        setDeletingTaskId(null);
      }
    } catch (e) {
      console.error("Erro ao eliminar tarefa:", e);
    } finally {
      setIsDeleting(false);
    }
  };

  const getPriorityColorClass = (priority: string, completed: boolean) => {
    if (completed) return 'bg-emerald-500/20';
    switch (priority) {
      case 'Alta': return 'bg-red-500';
      case 'Média': return 'bg-blue-500';
      case 'Baixa': return 'bg-slate-400';
      default: return 'bg-blue-500';
    }
  };

  const isOverdue = (date?: string) => {
    if (!date) return false;
    return new Date(date) < new Date(new Date().setHours(0,0,0,0));
  };

  const filteredTasks = tasks.filter(task => {
    const matchesSearch = task.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesFilter = statusFilter === 'all' 
      ? true 
      : statusFilter === 'completed' 
        ? task.completed 
        : !task.completed;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col h-full relative">
      {/* Bulk Action Bar */}
      {selectedTaskIds.size > 0 && (
        <div className="absolute top-0 left-0 right-0 z-30 bg-slate-900 text-white p-4 flex items-center justify-between animate-in slide-in-from-top duration-300">
          <div className="flex items-center gap-4">
             <button onClick={() => setSelectedTaskIds(new Set())} className="p-2 hover:bg-white/10 rounded-xl transition-colors">
               <X size={20} />
             </button>
             <div>
                <p className="text-xs font-black uppercase tracking-widest">{selectedTaskIds.size} Selecionados</p>
                <p className="text-[8px] text-slate-400 font-bold uppercase">Definir Prioridade em Massa</p>
             </div>
          </div>
          <div className="flex items-center gap-2">
             {isBulkUpdating ? (
               <Loader2 className="animate-spin text-blue-400 mr-4" size={20} />
             ) : (
               <>
                 <button onClick={() => handleBulkPriorityUpdate('Alta')} className="px-4 py-2 bg-red-500/20 text-red-400 rounded-xl text-[9px] font-black uppercase hover:bg-red-500 hover:text-white transition-all">Alta</button>
                 <button onClick={() => handleBulkPriorityUpdate('Média')} className="px-4 py-2 bg-blue-500/20 text-blue-400 rounded-xl text-[9px] font-black uppercase hover:bg-blue-500 hover:text-white transition-all">Média</button>
                 <button onClick={() => handleBulkPriorityUpdate('Baixa')} className="px-4 py-2 bg-slate-700 text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-50 hover:text-white transition-all">Baixa</button>
               </>
             )}
          </div>
        </div>
      )}

      <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/20">
        <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
          <LayoutList className="text-blue-600" size={20} /> Afazeres Operacionais
        </h3>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleSelectAll} 
            title="Selecionar Todos"
            className={`p-2 rounded-xl transition-all ${filteredTasks.length > 0 && filteredTasks.every(t => selectedTaskIds.has(t.id)) ? 'text-blue-600 bg-blue-50' : 'text-slate-400 hover:bg-slate-100'}`}
          >
            <CheckSquare size={18} />
          </button>
          <button onClick={fetchTasks} className="p-2 text-slate-400 hover:text-blue-600 transition-colors">
            <RotateCcw size={16} />
          </button>
        </div>
      </div>

      <div className="p-6 border-b border-slate-50 bg-slate-50/40 space-y-4">
        <form onSubmit={handleAddTask} className="space-y-3">
          <div className="flex gap-2">
            <input 
              type="text" 
              value={newTaskTitle}
              onChange={(e) => setNewTaskTitle(e.target.value)}
              placeholder="O que precisa ser feito hoje?"
              className="flex-1 bg-white rounded-2xl px-5 py-4 text-sm font-bold border border-slate-200 focus:ring-2 focus:ring-blue-600 outline-none placeholder:text-slate-400 transition-all shadow-sm"
            />
            <button type="submit" title="Adicionar Nova Tarefa" className="p-4 bg-blue-600 text-white rounded-2xl hover:bg-blue-700 shadow-lg shadow-blue-500/20 active:scale-95 transition-all flex items-center gap-2">
              <Plus size={24} />
              <span className="hidden lg:inline text-[10px] font-black uppercase tracking-widest">Criar</span>
            </button>
          </div>
          <div className="grid grid-cols-2 gap-2">
            <select 
              value={newTaskBeneficiary}
              onChange={e => setNewTaskBeneficiary(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600 cursor-pointer shadow-sm"
            >
              <option value="">Atribuir Responsável</option>
              {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
            </select>
            <input 
              type="date"
              value={newTaskDueDate}
              onChange={e => setNewTaskDueDate(e.target.value)}
              className="bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-[10px] font-black uppercase tracking-widest outline-none focus:ring-2 focus:ring-blue-600 shadow-sm"
            />
          </div>
        </form>
        <div className="flex flex-col sm:flex-row gap-3">
          <div className="relative flex-1">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
            <input value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} placeholder="Localizar tarefa..." className="w-full pl-12 pr-4 py-3 text-xs font-bold bg-white rounded-2xl border border-slate-100 outline-none" />
          </div>
          <div className="flex items-center gap-1.5 p-1 bg-white rounded-2xl border border-slate-100 shadow-sm shrink-0">
             <button onClick={() => setStatusFilter('all')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'all' ? 'bg-blue-600 text-white' : 'text-slate-400 hover:bg-slate-50'}`}>Todas</button>
             <button onClick={() => setStatusFilter('pending')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'pending' ? 'bg-amber-100 text-amber-600' : 'text-slate-400 hover:bg-slate-50'}`}>Pendentes</button>
             <button onClick={() => setStatusFilter('completed')} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase transition-all ${statusFilter === 'completed' ? 'bg-emerald-100 text-emerald-600' : 'text-slate-400 hover:bg-slate-50'}`}>Feitas</button>
          </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar bg-white">
        {loading ? (
           <div className="flex justify-center py-10"><Loader2 className="animate-spin text-blue-600" /></div>
        ) : filteredTasks.map((task) => {
          const isExpanded = expandedId === task.id;
          const isSelected = selectedTaskIds.has(task.id);
          const assignedBeneficiary = beneficiaries.find(b => b.id === task.beneficiary_id);
          const overdue = isOverdue(task.due_date) && !task.completed;
          const priorityColor = getPriorityColorClass(task.priority, task.completed);

          return (
            <div key={task.id} className={`group bg-white border rounded-[2rem] transition-all duration-500 relative overflow-hidden ${isSelected ? 'border-blue-500 bg-blue-50/30' : isExpanded ? 'border-blue-200 shadow-xl scale-[1.005] z-20' : 'border-slate-100 hover:border-blue-100'}`}>
              <div className={`absolute left-0 top-0 bottom-0 w-1.5 ${priorityColor} transition-all duration-500 shadow-inner`}></div>

              <div className="p-6 pl-8 flex items-start gap-4">
                <div className="flex items-center gap-3 pt-1">
                  <button 
                    onClick={(e) => { e.stopPropagation(); toggleSelectTask(task.id); }} 
                    className={`transition-all ${isSelected ? 'text-blue-600' : 'text-slate-300 hover:text-blue-400'}`}
                  >
                    {isSelected ? <CheckSquare size={18} /> : <Square size={18} />}
                  </button>
                  <div className="relative flex items-center">
                    <button onClick={() => toggleComplete(task)} className={`transition-all transform active:scale-75 ${task.completed ? 'text-emerald-500' : 'text-slate-300 hover:text-blue-500'}`}>
                      {task.completed ? <CheckCircle2 size={24} /> : <Circle size={24} />}
                    </button>
                    {!task.completed && (
                      <div className={`absolute -right-1 -top-1 w-2.5 h-2.5 rounded-full border-2 border-white ${priorityColor} shadow-sm`}></div>
                    )}
                  </div>
                </div>

                <div className="flex-1 min-w-0">
                   <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2 mb-2">
                    <p className={`text-base font-black truncate leading-tight ${task.completed ? 'text-slate-400 line-through' : 'text-slate-900'}`}>{task.title}</p>

                    {/* Seletor de Data Direto e Editável */}
                    <div className="flex items-center gap-2 group/date relative">
                       <label className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full flex items-center gap-2 border transition-all cursor-pointer hover:scale-105 active:scale-95 ${overdue ? 'bg-rose-50 text-rose-600 border-rose-100 animate-pulse' : 'bg-slate-50 text-slate-400 border-slate-100 hover:bg-white hover:border-blue-300 hover:text-blue-600'}`}>
                          <Calendar size={10} /> 
                          {task.due_date ? new Date(task.due_date).toLocaleDateString('pt-MZ') : 'Definir Data'}
                          <input 
                            type="date" 
                            className="absolute inset-0 opacity-0 cursor-pointer"
                            value={task.due_date || ''}
                            onChange={(e) => updateDueDate(task.id, e.target.value)}
                          />
                       </label>
                       {isSyncing === task.id && <RefreshCw size={10} className="animate-spin text-blue-500" />}
                    </div>
                   </div>

                   {/* Descrição sempre visível e editável */}
                   <div className="relative group/desc mb-3">
                     <textarea 
                        value={task.description} 
                        onChange={e => updateDescription(task.id, e.target.value)}
                        placeholder="Adicionar detalhes técnicos ou notas de campo..."
                        rows={isExpanded ? 5 : 2}
                        className={`w-full bg-slate-50/50 hover:bg-slate-50 rounded-2xl p-4 text-[11px] font-bold text-slate-600 border-none outline-none focus:ring-2 focus:ring-blue-100 transition-all resize-none shadow-inner scrollbar-hide leading-relaxed ${task.completed ? 'opacity-50 grayscale' : ''}`}
                     />

                     <div className="absolute top-3 right-4 flex items-center gap-1.5 h-5 pointer-events-none z-10">
                        {isSyncing === task.id ? (
                           <div className="flex items-center gap-1.5 bg-white/90 backdrop-blur-sm px-2.5 py-1 rounded-full border border-blue-100 shadow-sm animate-pulse">
                              <RefreshCw size={10} className="animate-spin text-blue-500" />
                              <span className="text-[7px] font-black text-blue-500 uppercase tracking-tighter">Gravação Cloud...</span>
                           </div>
                        ) : lastSavedId === task.id ? (
                           <div className="flex items-center gap-1.5 bg-emerald-50 px-2.5 py-1 rounded-full border border-emerald-100 shadow-sm animate-in zoom-in duration-300">
                              <Check size={10} strokeWidth={4} className="text-emerald-600" />
                              <span className="text-[7px] font-black text-emerald-600 uppercase tracking-tighter">Sincronizado</span>
                           </div>
                        ) : null}
                     </div>
                   </div>

                   <div className="flex items-center justify-between">
                     <div className="flex items-center gap-3">
                        {assignedBeneficiary ? (
                          <div className="flex items-center gap-1.5 text-[9px] font-black text-blue-600 bg-blue-50 px-2.5 py-1 rounded-lg border border-blue-100/50 uppercase tracking-tight">
                            <User size={10} /> {assignedBeneficiary.name}
                          </div>
                        ) : (
                          <div className="text-[9px] font-bold text-slate-300 uppercase italic">Sem atribuição</div>
                        )}
                        <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded border ${task.priority === 'Alta' ? 'text-rose-500 border-rose-100' : 'text-slate-400 border-slate-100'}`}>
                          {task.priority}
                        </span>
                     </div>
                     <button onClick={() => setExpandedId(isExpanded ? null : task.id)} className={`px-3 py-1.5 rounded-xl transition-all flex items-center gap-2 border ${isExpanded ? 'bg-slate-900 text-white border-slate-900' : 'bg-white text-slate-500 border-slate-100 hover:border-blue-200 hover:text-blue-600'}`}>
                        <span className="text-[8px] font-black uppercase tracking-widest">{isExpanded ? 'Fechar' : 'Configurações'}</span>
                        <ChevronDown className={`transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`} size={12} />
                     </button>
                   </div>
                </div>
              </div>

              {/* Área de Configurações Expandida */}
              {isExpanded && (
                <div className="px-14 pb-10 pt-6 border-t border-slate-100 animate-in slide-in-from-top-2 duration-300 space-y-8 bg-slate-50/30">
                   <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      <div className="space-y-2">
                        <div className="flex items-center gap-2 mb-1">
                          <User size={12} className="text-blue-600" />
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Responsável</label>
                        </div>
                        <select 
                          value={task.beneficiary_id || ''} 
                          onChange={e => updateTaskBeneficiary(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm cursor-pointer"
                        >
                          <option value="">Não Atribuído</option>
                          {beneficiaries.map(b => <option key={b.id} value={b.id}>{b.name} ({b.category})</option>)}
                        </select>
                      </div>

                      <div className="space-y-2">
                        <div className="flex items-center gap-2 mb-1">
                          <Calendar size={12} className="text-blue-600" />
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Data de Vencimento</label>
                        </div>
                        <input 
                          type="date"
                          value={task.due_date || ''}
                          onChange={e => updateDueDate(task.id, e.target.value)}
                          className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3.5 text-[10px] font-black uppercase outline-none focus:ring-2 focus:ring-blue-100 transition-all shadow-sm"
                        />
                      </div>

                      <div className="space-y-2">
                        <div className="flex items-center gap-2 mb-1">
                          <Zap size={12} className="text-blue-600" />
                          <label className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em]">Escalão de Prioridade</label>
                        </div>
                        <div className="flex gap-1.5 bg-white border border-slate-200 p-1 rounded-xl shadow-sm">
                          {(['Baixa', 'Média', 'Alta'] as const).map(p => (
                            <button 
                              key={p} 
                              onClick={() => updatePriority(task.id, p)} 
                              className={`flex-1 py-2.5 text-[8px] font-black uppercase rounded-lg transition-all ${task.priority === p ? 'bg-slate-900 text-white shadow-md' : 'text-slate-400 hover:bg-slate-50'}`}
                            >
                              {p}
                            </button>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="flex justify-between items-center pt-4 border-t border-slate-100/50">
                     <div className="flex items-center gap-2 text-[8px] font-bold text-slate-400 uppercase tracking-widest">
                        <FileText size={10} /> Criada em {task.created_at ? new Date(task.created_at).toLocaleDateString() : 'N/D'}
                     </div>
                     <div className="flex gap-3">
                       <button 
                        onClick={() => setDeletingTaskId(task.id)} 
                        className="px-5 py-2.5 bg-rose-50 text-rose-500 rounded-xl text-[9px] font-black uppercase hover:bg-rose-500 hover:text-white transition-all flex items-center justify-center gap-2 border border-rose-100/50"
                       >
                         <Trash2 size={12}/> Eliminar Registo
                       </button>
                       <button 
                        onClick={() => setExpandedId(null)} 
                        className="px-5 py-2.5 bg-white text-slate-400 rounded-xl text-[9px] font-black uppercase hover:bg-slate-100 transition-all border border-slate-100"
                       >
                         Recolher
                       </button>
                     </div>
                   </div>
                </div>
              )}
            </div>
          );
        })}
        {filteredTasks.length === 0 && !loading && (
          <div className="py-20 text-center flex flex-col items-center gap-4 animate-in fade-in">
             <div className="p-6 bg-slate-50 rounded-full text-slate-200">
               <LayoutList size={48} />
             </div>
             <div>
                <p className="text-slate-400 font-black text-[10px] uppercase tracking-widest">Nenhuma tarefa encontrada</p>
                <p className="text-slate-300 text-[8px] font-bold uppercase mt-1">Experimente ajustar os filtros ou a pesquisa</p>
             </div>
          </div>
        )}
      </div>

      {/* Modal de Confirmação de Eliminação (Segurança Operacional) */}
      {deletingTaskId && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
           <div className="bg-white rounded-[3.5rem] p-10 max-w-sm w-full shadow-2xl text-center border-t-[10px] border-red-500 animate-in zoom-in-95 duration-300">
              <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertTriangle size={48} className="text-red-500 animate-pulse" />
              </div>
              <h4 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Confirmar Eliminação?</h4>
              <p className="text-sm font-medium text-slate-500 mb-10 leading-relaxed">
                Esta ação é irreversível. O registo da tarefa será permanentemente removido da Cloud da Monte Imobiliária.
              </p>
              <div className="flex flex-col gap-3">
                 <button 
                  onClick={confirmDeletion} 
                  disabled={isDeleting}
                  className="w-full py-5 bg-red-500 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl shadow-red-500/20 hover:bg-red-600 transition-all active:scale-95 flex items-center justify-center gap-2 disabled:opacity-70"
                 >
                   {isDeleting ? <Loader2 className="animate-spin" size={18} /> : <><Trash2 size={18} /> Sim, Eliminar Registo</>}
                 </button>
                 <button 
                  onClick={() => setDeletingTaskId(null)} 
                  disabled={isDeleting}
                  className="w-full py-5 bg-slate-100 text-slate-600 rounded-[2rem] font-black text-xs uppercase hover:bg-slate-200 transition-all disabled:opacity-50"
                 >
                   Cancelar
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default TodoList;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Shield, Key, UserCog, Save, 
  CheckCircle2, Loader2, Search,
  Fingerprint, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Users as UsersIcon, Terminal, Plus, Settings2,
  ChevronRight, History, Activity, Calendar, Award,
  RotateCcw, EyeOff, ShieldAlert, Lock, Zap,
  AlertTriangle,
  ArrowRight,
  Wrench,
  Code,
  LayoutDashboard,
  Wallet,
  Truck,
  Target,
  LayoutTemplate,
  CopyPlus
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee, User } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Geral' | 'Negócio' | 'Recursos' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

interface AuditLog {
  id: string;
  admin_name: string;
  target_user_name: string;
  action_type: string;
  change_details: string;
  created_at: string;
}

interface RoleRecord {
  id: string;
  name: string;
  is_deleted: boolean;
  permissions: string[];
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  // Categoria: Geral
  { id: 'dashboard.view', label: 'Ver Dashboard', category: 'Geral', description: 'Acesso à vista principal de estatísticas.', icon: <LayoutDashboard size={14} /> },
  { id: 'catalog.view', label: 'Consultar Catálogo', category: 'Geral', description: 'Visualizar imóveis e portfólio público.', icon: <LayoutTemplate size={14} /> },

  // Categoria: Negócio
  { id: 'catalog.manage', label: 'Gerir Catálogo', category: 'Negócio', description: 'Adicionar, editar e remover imóveis.', icon: <Edit size={14} /> },
  { id: 'finance.view', label: 'Ver Financeiro', category: 'Negócio', description: 'Consultar fluxos de caixa e balanços.', icon: <Wallet size={14} /> },
  { id: 'finance.manage', label: 'Operar Financeiro', category: 'Negócio', description: 'Registar receitas, despesas e beneficiários.', icon: <Plus size={14} /> },
  { id: 'projects.view', label: 'Ver Projetos', category: 'Negócio', description: 'Acompanhar progresso de obras e orçamentos.', icon: <Briefcase size={14} /> },
  { id: 'projects.manage', label: 'Gerir Projetos', category: 'Negócio', description: 'Criar novas obras e gerir equipas de projeto.', icon: <Wrench size={14} /> },

  // Categoria: Recursos
  { id: 'hr.view', label: 'Ver RH', category: 'Recursos', description: 'Visualizar lista de staff e candidaturas.', icon: <UsersIcon size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'Recursos', description: 'Contratar staff, editar contratos e gerir vagas.', icon: <UserCog size={14} /> },
  { id: 'fleet.view', label: 'Ver Frota', category: 'Recursos', description: 'Monitorizar estado e localização de veículos.', icon: <Truck size={14} /> },
  { id: 'fleet.manage', label: 'Gerir Frota', category: 'Recursos', description: 'Registar veículos, manutenções e motoristas.', icon: <Settings2 size={14} /> },
  { id: 'plans.view', label: 'Ver Estratégia', category: 'Recursos', description: 'Consultar metas e planos anuais.', icon: <Target size={14} /> },
  { id: 'plans.manage', label: 'Gerir Estratégia', category: 'Recursos', description: 'Definir e editar objetivos corporativos.', icon: <Zap size={14} /> },

  // Categoria: Sistema
  { id: 'admin.access', label: 'Administração TI', category: 'Sistema', description: 'Gestão de permissões, cargos e logs.', icon: <Shield size={14} /> },
  { id: 'system.repair', label: 'Reparação Cloud', category: 'Sistema', description: 'Acesso a scripts de reparação de base de dados.', icon: <Database size={14} /> },
];

interface AdminViewProps {
  currentUser: User | null;
}

const AdminView: React.FC<AdminViewProps> = ({ currentUser }) => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<RoleRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [originalUserState, setOriginalUserState] = useState<Employee | null>(null);
  const [showRolesModal, setShowRolesModal] = useState(false);
  const [rolesModalTab, setRolesModalTab] = useState<'roles' | 'repair'>('roles');
  const [showDeletedRoles, setShowDeletedRoles] = useState(false);
  const [newRoleName, setNewRoleName] = useState('');
  const [editingRoleName, setEditingRoleName] = useState<{old: string, new: string} | null>(null);
  const [editingRolePermissions, setEditingRolePermissions] = useState<RoleRecord | null>(null);
  const [rolesLoading, setRolesLoading] = useState(false);
  const [showAuditModal, setShowAuditModal] = useState(false);
  const [auditLogs, setAuditLogs] = useState<AuditLog[]>([]);
  const [loadingLogs, setLoadingLogs] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    setRolesLoading(true);
    try {
      const { data, error } = await supabase.from('roles').select('*').order('name');
      if (!error && data) {
        setRoles(data);
      } else {
        const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
        setRoles(fallbackRoles);
      }
    } catch (e) { 
      const fallbackRoles = Object.values(UserRole).map((r, i) => ({ id: i.toString(), name: r, is_deleted: false, permissions: [] }));
      setRoles(fallbackRoles);
    } finally {
      setRolesLoading(false);
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) { console.warn("Error fetching users"); }
    finally { setLoading(false); }
  }

  async function fetchAuditLogs() {
    setLoadingLogs(true);
    try {
      const { data, error } = await supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);
      if (!error) setAuditLogs(data || []);
    } catch (e) { console.warn("Error fetching logs"); }
    finally { setLoadingLogs(false); }
  }

  const handleAddRole = async () => {
    if (!newRoleName.trim()) return;
    setRolesLoading(true);
    try {
      const { data, error } = await supabase.from('roles').insert([{ name: newRoleName.trim(), is_deleted: false, permissions: [] }]).select();
      if (error) throw error;
      setNewRoleName('');
      fetchRoles();
      if (data && data[0]) {
        setEditingRolePermissions(data[0]);
      }
    } catch (err: any) {
      alert("Erro ao adicionar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleDuplicateRole = async (sourceRole: RoleRecord) => {
    const name = prompt("Nome para o novo cargo (cópia de " + sourceRole.name + "):");
    if (!name || !name.trim()) return;

    setRolesLoading(true);
    try {
      const { error } = await supabase.from('roles').insert([{ 
        name: name.trim(), 
        is_deleted: false, 
        permissions: sourceRole.permissions 
      }]);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao duplicar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateRole = async () => {
    if (!editingRoleName || !editingRoleName.new.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ name: editingRoleName.new.trim() })
        .eq('name', editingRoleName.old);
      if (error) throw error;
      setEditingRoleName(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao atualizar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleSaveRolePermissions = async () => {
    if (!editingRolePermissions) return;
    setSaving(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ permissions: editingRolePermissions.permissions })
        .eq('id', editingRolePermissions.id);
      if (error) throw error;

      if (currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_name: `Cargo: ${editingRolePermissions.name}`,
          action_type: 'CARGO_MATRIZ_SYNC',
          change_details: `Template de privilégios redefinido para o cargo: ${editingRolePermissions.name}. Total: ${editingRolePermissions.permissions.length} perms.`
        }]);
      }

      setEditingRolePermissions(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao salvar permissões do cargo: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteRole = async (name: string) => {
    if (!confirm(`Deseja desativar o cargo "${name}"? Ele será movido para a reciclagem.`)) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: true })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao desativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleReactivateRole = async (name: string) => {
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ is_deleted: false })
        .eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao reativar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateUserPermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser || !originalUserState) return;
    setSaving(true);
    const changes = [];
    if (editingUser.role !== originalUserState.role) changes.push(`Cargo: [${originalUserState.role}] -> [${editingUser.role}]`);
    const oldPerms = originalUserState.permissions || [];
    const newPerms = editingUser.permissions || [];
    const added = newPerms.filter(p => !oldPerms.includes(p));
    const opponentRemoved = oldPerms.filter(p => !newPerms.includes(p));
    if (added.length > 0) changes.push(`+ Permissões: ${added.join(', ')}`);
    if (opponentRemoved.length > 0) changes.push(`- Permissões: ${opponentRemoved.join(', ')}`);

    try {
      const { error } = await supabase.from('employees').update({ role: editingUser.role, permissions: editingUser.permissions || [] }).eq('id', editingUser.id);
      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const toggleUserPermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleRolePermission = (permId: string) => {
    if (!editingRolePermissions) return;
    const current = editingRolePermissions.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[], target: 'user' | 'role') => {
    const idsInCategory = permsInCategory.map(p => p.id);

    if (target === 'user' && editingUser) {
      const currentPerms = editingUser.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingUser({ ...editingUser, permissions: newPerms });
    } else if (target === 'role' && editingRolePermissions) {
      const currentPerms = editingRolePermissions.permissions || [];
      const allSelected = idsInCategory.every(id => currentPerms.includes(id));
      const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
      setEditingRolePermissions({ ...editingRolePermissions, permissions: newPerms });
    }
  };

  const applyRoleTemplateToUser = () => {
    if (!editingUser) return;
    const roleTemplate = roles.find(r => r.name === editingUser.role);
    if (roleTemplate) {
      setEditingUser({ ...editingUser, permissions: [...roleTemplate.permissions] });
    }
  };

  const getSecurityLevel = (permsCount: number) => {
    if (permsCount >= 14) return { label: 'Total', color: 'bg-rose-500', text: 'text-rose-600' };
    if (permsCount >= 9) return { label: 'Crítico', color: 'bg-rose-500', text: 'text-rose-600' };
    if (permsCount >= 6) return { label: 'Elevado', color: 'bg-amber-500', text: 'text-amber-600' };
    if (permsCount >= 3) return { label: 'Médio', color: 'bg-blue-500', text: 'text-blue-600' };
    return { label: 'Baixo', color: 'bg-emerald-500', text: 'text-emerald-600' };
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const filteredRoles = useMemo(() => {
    return roles.filter(r => r.is_deleted === showDeletedRoles);
  }, [roles, showDeletedRoles]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Monte & Chaisa Hub: Gestão de Matrizes de Privilégios.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { setRolesModalTab('roles'); setShowRolesModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <Settings2 size={16} className="text-blue-600" /> Matriz de Cargos
           </button>
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Logs de Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar colaborador ou cargo..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Colaborador / Perfil</th>
                <th className="px-10 py-6 text-center">Acessos Específicos (Overrides)</th>
                <th className="px-10 py-6 text-right">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase()) || u.role.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover ring-4 ring-slate-50" alt="" />
                      <div>
                        <p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p>
                        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap justify-center gap-1.5">
                      {user.permissions?.length ? user.permissions.map(p => (
                        <span key={p} className="text-[8px] font-black bg-white border border-slate-100 text-slate-400 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>
                      )) : <span className="text-[9px] font-black text-slate-300 italic uppercase tracking-tighter">Usando Matriz do Cargo</span>}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100 shadow-sm transition-all group-hover:scale-105">
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-[12px] border-indigo-600">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <div className="relative">
                 <img src={editingUser.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover shadow-2xl ring-4 ring-white" alt="" />
                 <div className="absolute -bottom-2 -right-2 p-2 bg-indigo-600 text-white rounded-xl shadow-lg"><UserCog size={16}/></div>
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2>
                  <div className="flex items-center gap-3 mt-2">
                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full uppercase tracking-widest">Override Privado Ativo</span>
                    <span className="text-slate-300">•</span>
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{editingUser.email}</span>
                  </div>
               </div>
            </div>

            <form onSubmit={handleUpdateUserPermissions} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-end">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <Award size={14} className="text-indigo-600" /> Mudar Cargo Principal
                  </label>
                  <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-indigo-600">
                    {roles.filter(r => !r.is_deleted).map(r => <option key={r.name} value={r.name}>{r.name}</option>)}
                  </select>
                </div>
                <button 
                  type="button" 
                  onClick={applyRoleTemplateToUser}
                  className="px-6 py-5 bg-indigo-50 text-indigo-600 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 hover:text-white transition-all flex items-center justify-center gap-3 border border-indigo-100 shadow-sm active:scale-95"
                >
                  <Zap size={16} /> Restaurar Padrão do Cargo
                </button>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2">
                        <h3 className="text-xs font-black uppercase text-slate-900 flex items-center gap-2">
