            <div className="p-4 bg-white/5 border-b border-white/5 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <CloudUpload size={16} className="text-blue-400" />
                <span className="text-[10px] font-black text-white uppercase tracking-widest">Cloud Sync Manager</span>
              </div>
              <span className="px-2 py-0.5 bg-blue-500 text-white text-[9px] font-black rounded-full animate-pulse">{pendingSyncs.length}</span>
            </div>
            <div className="max-h-60 overflow-y-auto custom-scrollbar p-3 space-y-2">
               {pendingSyncs.map(sync => (
                 <div key={sync.tempId} className={`p-3 rounded-xl border flex items-center justify-between gap-3 transition-all ${sync.status === 'error' ? 'bg-rose-500/10 border-rose-500/20' : 'bg-white/5 border-white/5'}`}>
                    <div className="min-w-0 flex-1">
                      <p className="text-[11px] font-bold text-white truncate leading-none mb-1">{sync.data.description}</p>
                      <p className="text-[9px] text-slate-400 font-medium">MT {sync.data.amount.toLocaleString()}</p>
                    </div>

                    <div className="flex items-center gap-1.5 shrink-0">
                      {sync.status === 'syncing' ? (
                        <Loader2 size={14} className="text-blue-400 animate-spin" />
                      ) : (
                        <div className="flex items-center gap-1">
                          <button onClick={() => retrySync(sync)} className="p-1.5 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-colors" title="Tentar Novamente">
                            <RefreshCw size={12} />
                          </button>
                          <button onClick={() => cancelSync(sync.tempId)} className="p-1.5 bg-white/10 text-slate-400 rounded-lg hover:bg-rose-500 hover:text-white transition-colors">
                            <X size={12} />
                          </button>
                        </div>
                      )}
                    </div>
                 </div>
               ))}
            </div>
            {pendingSyncs.some(s => s.status === 'error') && (
              <div className="p-3 bg-rose-500 text-white text-[9px] font-black uppercase text-center flex items-center justify-center gap-2">
                <AlertCircle size={10} /> Erro de Sincronização Detetado
              </div>
            )}
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-emerald-500/20">
            <BarChart3 size={24} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Fluxo Financeiro</h1>
