            <button onClick={() => { setError(null); setEditingVacancyId(null); setVacancyForm(initialVacancyState); setShowVacancyModal(true); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
