                <tbody className="divide-y divide-slate-50">
                  {applications.length === 0 ? (
                    <tr>
                      <td colSpan={5} className="px-10 py-24 text-center">
                         <MessageSquare size={48} className="mx-auto text-slate-100 mb-4" />
                         <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px]">Aguardando novas candidaturas Monte...</p>
                      </td>
                    </tr>
                  ) : applications.map((app) => {
                    const isNew = recentAppIds.has(app.id);
                    return (
                      <tr key={app.id} className={`hover:bg-slate-50/50 transition-all group relative ${isNew ? 'bg-emerald-50/30' : ''}`}>
