              <div className="flex items-center gap-4 mb-8">
                 <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl shadow-inner"><Code size={28} /></div>
                 <div>
                    <h2 className="text-3xl font-black text-slate-900 tracking-tight">Esquema: job_applications</h2>
