import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

/**
 * Função auxiliar para executar chamadas à API Gemini com lógica de re-tentativa (retry)
 * para lidar com erros transientes de RPC/XHR (Código 500/6).
 */
async function executeWithRetry(model: string, prompt: string, maxRetries = 3): Promise<string> {
  let lastError: any = null;

  for (let i = 0; i < maxRetries; i++) {
    try {
      // Sempre criar uma nova instância antes da chamada para garantir integridade da API Key
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const response: GenerateContentResponse = await ai.models.generateContent({
        model: model,
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          temperature: 0.7,
          topP: 0.95,
          topK: 40,
        }
      });

      if (!response.text) {
        throw new Error("Resposta da IA vazia ou malformada.");
      }

      return response.text;
    } catch (error: any) {
      lastError = error;
      const errorMsg = error?.message || String(error);

      console.warn(`Tentativa ${i + 1} falhou para o modelo ${model}:`, errorMsg);

      // Se for um erro transiente de rede ou erro 500/Rpc/xhr, tentamos novamente
      const isTransient = errorMsg.includes("500") || 
                        errorMsg.includes("xhr error") || 
                        errorMsg.includes("Rpc failed") ||
                        errorMsg.includes("fetch");

      if (isTransient && i < maxRetries - 1) {
        // Backoff exponencial: 1s, 2s, 4s...
        const delay = Math.pow(2, i) * 1000;
        await new Promise(resolve => setTimeout(resolve, delay));
        continue;
      }

      // Se não for transiente ou esgotou tentativas, interrompe
      break;
    }
  }

  console.error("Todas as tentativas de conexão com Gemini falharam:", lastError);
  throw lastError;
}

export const getStrategicInsight = async (context: string) => {
  try {
    const prompt = `Como um consultor empresarial experiente, analise estes dados e forneça uma sugestão curta e impactante para o negócio: ${context}. Responda em Português.`;
    return await executeWithRetry('gemini-3-pro-preview', prompt);
  } catch (error) {
    return "Não foi possível gerar insights estratégicos no momento devido a uma falha de conexão.";
  }
};

export const generateJobDescription = async (jobTitle: string, area: string, location: string) => {
  try {
    const prompt = `Gere uma descrição de vaga de emprego PROFISSIONAL e COMPLETA para o cargo de "${jobTitle}" na área de "${area}", em "${location}".

      REGRAS OBRIGATÓRIAS:
      1. NÃO inclua nenhuma introdução ou saudação (ex: "Aqui está...", "Com certeza...", "Olá").
      2. NÃO inclua comentários finais.
      3. Use Markdown para estruturar o texto: ## Resumo, ## Responsabilidades, ## Requisitos e ## Benefícios.
      4. Empresa: Monte Imobiliária (Beira, Moçambique).
      5. O texto deve começar DIRETAMENTE com o conteúdo da vaga e estar PRONTO para envio/publicação.`;

    return await executeWithRetry('gemini-3-flash-preview', prompt);
  } catch (error) {
    return "Não foi possível gerar a descrição via IA neste momento. Por favor, tente novamente em instantes.";
  }
};

