  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, 
  ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property, JobApplication } from '../types';
import { getStrategicInsight } from '../geminiService';
import TodoList from '../components/TodoList';

interface ContactRequest {
  id: string;
  name: string;
  email: string;
  subject: string;
  message: string;
  created_at: string;
}

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ revenue: 0, expenses: 0, employees: 0, properties: 0, contacts: 0 });
  const [recentMessages, setRecentMessages] = useState<ContactRequest[]>([]);
  const [recentApps, setRecentApps] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('Analisando pulso da empresa...');
  const [showQuickTransaction, setShowQuickTransaction] = useState(false);
  const [savingTx, setSavingTx] = useState(false);

  const [txForm, setTxForm] = useState({ description: '', amount: '', type: 'DESPESA' as 'RECEITA' | 'DESPESA' });

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    setDbError(null);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appListRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(4),
        supabase.from('job_applications').select('*').order('created_at', { ascending: false }).limit(3)
      ]);

      if (contactRes.error?.code === 'PGRST204' || contactRes.error?.code === 'PGRST205') {
        setDbError("Algumas tabelas do sistema (Inbox/Candidaturas) ainda não foram criadas. Vá em Administração TI e execute o Script de Reparação.");
      }

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        revenue: rev, expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0
      });

      setRecentMessages(msgListRes.data || []);
      setRecentApps(appListRes.data || []);

      const insight = await getStrategicInsight(`Receitas: ${rev}MT, Despesas: ${exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleQuickTx = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTx(true);
    try {
      const { error } = await supabase.from('transactions').insert([{
        description: txForm.description, amount: Number(txForm.amount), type: txForm.type, category: 'Geral',
        date: new Date().toISOString().split('T')[0]
      }]);
      if (!error) { setShowQuickTransaction(false); setTxForm({ description: '', amount: '', type: 'DESPESA' }); fetchGlobalStats(); }
    } finally { setSavingTx(false); }
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#10b981' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  const barData = useMemo(() => [{ name: 'Financeiro', receitas: stats.revenue, despesas: stats.expenses }], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <Loader2 className="animate-spin text-blue-600" size={56} />
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando com a Monte Imobiliária...</p>
    </div>
  );

  return (
