        <div className="bg-amber-50 border-l-4 border-amber-500 p-6 rounded-3xl flex items-center justify-between gap-6 shadow-sm">
           <div className="flex items-center gap-4 text-amber-800">
             <AlertTriangle size={24} className="shrink-0" />
             <p className="text-sm font-bold">{dbError}</p>
           </div>
           <button onClick={() => setDbError(null)}><CloseIcon size={18} className="text-amber-400" /></button>
        </div>
      )}

      <div className="flex items-center justify-between bg-white px-10 py-5 rounded-[4rem] border border-slate-100 shadow-sm">
        <div className="flex items-center gap-4">
           <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_12px_rgba(16,185,129,0.7)]"></div>
           <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
             <ShieldCheck size={18} className="text-blue-600" /> Monte Imobiliária Sync
           </span>
        </div>
        <div className="hidden md:flex items-center gap-8">
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Activity size={14} className="text-indigo-500" /> Latência Cloud: 18ms</div>
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Globe size={14} className="text-emerald-500" /> Rede Activa: Beira Node</div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
