                  <button type="button" onClick={() => setTxForm({...txForm, type: 'DESPESA'})} className={`flex-1 py-5 text-[11px] font-black uppercase tracking-widest rounded-[2.5rem] transition-all ${txForm.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Saída</button>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Motivo / Categoria</label>
                  <input required value={txForm.description} onChange={e => setTxForm({...txForm, description: e.target.value})} className="w-full bg-slate-50 p-6 rounded-3xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100 transition-all" placeholder="Ex: Manutenção Elétrica Sede" />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Valor (MZN)</label>
                  <input required type="number" value={txForm.amount} onChange={e => setTxForm({...txForm, amount: e.target.value})} className="w-full bg-slate-50 p-8 rounded-3xl font-black text-4xl border-none outline-none focus:ring-4 focus:ring-blue-100 shadow-inner" placeholder="0.00" />
               </div>
               <button disabled={savingTx} type="submit" className="w-full py-8 bg-blue-600 text-white font-black rounded-[3rem] hover:bg-slate-900 transition-all active:scale-95 flex items-center justify-center gap-4 shadow-2xl shadow-blue-600/20">
                  {savingTx ? <Loader2 className="animate-spin" /> : <><Plus size={24} /> Confirmar Registo</>}
               </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

