import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  ArrowUpCircle, 
  ArrowDownCircle, 
  Plus, 
  DollarSign, 
  X, 
  Loader2, 
  BarChart3, 
  TrendingUp, 
  User, 
  UserPlus, 
  Tag, 
  Edit3, 
  Trash2, 
  Phone, 
  Mail, 
  Users, 
  Check, 
  Save, 
  AlertTriangle,
  Search,
  Filter,
  Paperclip,
  FileUp,
  FileCheck,
  Eye,
  FileText,
  CloudUpload,
  RefreshCw,
  AlertCircle
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Beneficiary, BeneficiaryCategory } from '../types';

interface PendingSync {
  tempId: string;
  data: any;
  status: 'syncing' | 'error';
  errorMsg?: string;
  file?: File | null;
}

const FinanceView: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [beneficiaries, setBeneficiaries] = useState<Beneficiary[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [showBeneficiaryModal, setShowBeneficiaryModal] = useState(false);
  const [beneficiarySearch, setBeneficiarySearch] = useState('');
  const [isUploading, setIsUploading] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Fila de sincronização em segundo plano
  const [pendingSyncs, setPendingSyncs] = useState<PendingSync[]>([]);

  const [newLaunch, setNewLaunch] = useState({
    description: '',
    category: 'Vendas',
    amount: '',
    type: 'DESPESA' as 'RECEITA' | 'DESPESA',
    beneficiary_id: '',
    receipt_url: ''
  });

  const [beneficiaryForm, setBeneficiaryForm] = useState<Partial<Beneficiary>>({
    name: '',
    category: 'Agente de Campo',
    phone: '',
    email: ''
  });
  const [editingBeneficiaryId, setEditingBeneficiaryId] = useState<string | null>(null);

  useEffect(() => {
    fetchTransactions();
    fetchBeneficiaries();
  }, []);

  async function fetchBeneficiaries() {
    const { data } = await supabase.from('beneficiaries').select('*').order('name');
    if (data) setBeneficiaries(data);
  }

  async function fetchTransactions() {
    setLoading(true);
    const { data, error } = await supabase
      .from('transactions')
      .select(`
        *,
        beneficiary:beneficiaries(name)
      `)
      .order('date', { ascending: false });

    if (!error) {
      const formatted = (data || []).map((t: any) => ({
        ...t,
        beneficiary_name: t.beneficiary?.name
      }));
      setTransactions(formatted);
    }
    setLoading(false);
  }

  const handleSaveBeneficiary = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!beneficiaryForm.name?.trim()) return;

    try {
      if (editingBeneficiaryId) {
        const { error } = await supabase
          .from('beneficiaries')
          .update(beneficiaryForm)
          .eq('id', editingBeneficiaryId);
        if (!error) {
          setBeneficiaries(beneficiaries.map(b => b.id === editingBeneficiaryId ? { ...b, ...beneficiaryForm } : b));
        }
      } else {
        const { data, error } = await supabase
          .from('beneficiaries')
          .insert([beneficiaryForm])
          .select();
        if (!error && data) {
          setBeneficiaries([...beneficiaries, data[0]]);
        }
      }
      setShowBeneficiaryModal(false);
      setEditingBeneficiaryId(null);
      setBeneficiaryForm({ name: '', category: 'Agente de Campo', phone: '', email: '' });
    } catch (e) {}
  };

  const handleDeleteBeneficiary = async (id: string) => {
    if (!confirm('Eliminar este beneficiário permanentemente? Isso não removerá transações antigas, mas o nome pode não aparecer mais vinculado.')) return;
    try {
      const { error } = await supabase.from('beneficiaries').delete().eq('id', id);
      if (!error) {
        setBeneficiaries(beneficiaries.filter(b => b.id !== id));
      }
    } catch (e) {}
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  // Função principal de lançamento atualizada para ser assíncrona e não bloqueante
  const handleLaunch = async (e: React.FormEvent) => {
    e.preventDefault();

    const tempId = `temp_${Date.now()}`;
    const payload = {
      description: newLaunch.description,
      category: newLaunch.category,
      amount: Number(newLaunch.amount),
      type: newLaunch.type,
      beneficiary_id: newLaunch.beneficiary_id || null,
      date: new Date().toISOString().split('T')[0]
    };

    // 1. Fechar o modal imediatamente para não interromper o utilizador
    setShowModal(false);

    // 2. Adicionar à fila de sincronização (UI Optimística)
    const newPending: PendingSync = {
      tempId,
      data: payload,
      status: 'syncing',
      file: selectedFile
    };
    setPendingSyncs(prev => [...prev, newPending]);

    // Limpar formulário
    setNewLaunch({ description: '', category: 'Vendas', amount: '', type: 'DESPESA', beneficiary_id: '', receipt_url: '' });
    setSelectedFile(null);

    // 3. Processar o envio em background
    processBackgroundSync(newPending);
  };

  const processBackgroundSync = async (item: PendingSync) => {
    try {
      let receiptUrl = null;

      // Simulação de upload (O utilizador já está a fazer outras coisas)
      if (item.file) {
        // Simulação de latência de rede para upload
        await new Promise(r => setTimeout(r, 1500));
        receiptUrl = `https://storage.monte.mz/receipts/${Date.now()}_${item.file.name}`;
      }

      const finalPayload = {
        ...item.data,
        receipt_url: receiptUrl
      };

      const { error } = await supabase.from('transactions').insert([finalPayload]);

      if (error) throw error;

      // Sucesso: Remover da fila e atualizar tabela
      setPendingSyncs(prev => prev.filter(p => p.tempId !== item.tempId));
      fetchTransactions();
    } catch (err: any) {
      // Erro: Marcar como erro para que o utilizador possa retentar sem perder os dados
      setPendingSyncs(prev => prev.map(p => 
        p.tempId === item.tempId 
        ? { ...p, status: 'error', errorMsg: err.message } 
        : p
      ));
    }
  };

  const retrySync = (item: PendingSync) => {
    setPendingSyncs(prev => prev.map(p => 
      p.tempId === item.tempId ? { ...p, status: 'syncing', errorMsg: undefined } : p
    ));
    processBackgroundSync({ ...item, status: 'syncing' });
  };

  const cancelSync = (tempId: string) => {
    setPendingSyncs(prev => prev.filter(p => p.tempId !== tempId));
  };

  const totals = useMemo(() => {
    const base = transactions.reduce((acc, curr) => {
      if (curr.type === 'RECEITA') acc.receita += Number(curr.amount);
      else acc.despesa += Number(curr.amount);
      return acc;
    }, { receita: 0, despesa: 0 });

    // Somar também o que está a ser sincronizado (Optimistic Total)
    pendingSyncs.forEach(p => {
      if (p.data.type === 'RECEITA') base.receita += Number(p.data.amount);
      else base.despesa += Number(p.data.amount);
    });

    return base;
  }, [transactions, pendingSyncs]);

  const chartData = useMemo(() => {
    const months = [];
    const date = new Date();
    for (let i = 5; i >= 0; i--) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthName = d.toLocaleString('pt-BR', { month: 'short' });
      months.push({
        key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`,
        name: monthName.charAt(0).toUpperCase() + monthName.slice(1),
        receita: 0,
        despesa: 0
      });
    }
    transactions.forEach(t => {
      const tMonth = t.date.substring(0, 7);
      const monthObj = months.find(m => m.key === tMonth);
      if (monthObj) {
        if (t.type === 'RECEITA') monthObj.receita += Number(t.amount);
        else monthObj.despesa += Number(t.amount);
      }
    });
    return months;
  }, [transactions]);

  const filteredBeneficiaries = beneficiaries.filter(b => 
    b.name.toLowerCase().includes(beneficiarySearch.toLowerCase()) ||
    b.category.toLowerCase().includes(beneficiarySearch.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-24 relative">

      {/* Sync Manager Flutuante (Background Process Monitor) */}
      {pendingSyncs.length > 0 && (
        <div className="fixed bottom-6 right-6 z-[200] w-80 animate-in slide-in-from-bottom-4 duration-500">
          <div className="bg-slate-900/95 backdrop-blur-xl border border-white/10 rounded-[2rem] shadow-2xl overflow-hidden">
            <div className="p-4 bg-white/5 border-b border-white/5 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <CloudUpload size={16} className="text-blue-400" />
                <span className="text-[10px] font-black text-white uppercase tracking-widest">Cloud Sync Manager</span>
              </div>
              <span className="px-2 py-0.5 bg-blue-500 text-white text-[9px] font-black rounded-full animate-pulse">{pendingSyncs.length}</span>
            </div>
            <div className="max-h-60 overflow-y-auto custom-scrollbar p-3 space-y-2">
               {pendingSyncs.map(sync => (
                 <div key={sync.tempId} className={`p-3 rounded-xl border flex items-center justify-between gap-3 transition-all ${sync.status === 'error' ? 'bg-rose-500/10 border-rose-500/20' : 'bg-white/5 border-white/5'}`}>
                    <div className="min-w-0 flex-1">
                      <p className="text-[11px] font-bold text-white truncate leading-none mb-1">{sync.data.description}</p>
                      <p className="text-[9px] text-slate-400 font-medium">MT {sync.data.amount.toLocaleString()}</p>
                    </div>

                    <div className="flex items-center gap-1.5 shrink-0">
                      {sync.status === 'syncing' ? (
                        <Loader2 size={14} className="text-blue-400 animate-spin" />
                      ) : (
                        <div className="flex items-center gap-1">
                          <button onClick={() => retrySync(sync)} className="p-1.5 bg-amber-500 text-white rounded-lg hover:bg-amber-600 transition-colors" title="Tentar Novamente">
                            <RefreshCw size={12} />
                          </button>
                          <button onClick={() => cancelSync(sync.tempId)} className="p-1.5 bg-white/10 text-slate-400 rounded-lg hover:bg-rose-500 hover:text-white transition-colors">
                            <X size={12} />
                          </button>
                        </div>
                      )}
                    </div>
                 </div>
               ))}
            </div>
            {pendingSyncs.some(s => s.status === 'error') && (
              <div className="p-3 bg-rose-500 text-white text-[9px] font-black uppercase text-center flex items-center justify-center gap-2">
                <AlertCircle size={10} /> Erro de Sincronização Detetado
              </div>
            )}
          </div>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-emerald-500/20">
            <BarChart3 size={24} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Fluxo Financeiro</h1>
            <p className="text-slate-500 font-medium">Lançamentos instantâneos com sincronização em background.</p>
          </div>
        </div>
        <button onClick={() => { setShowModal(true); setSelectedFile(null); }} className="flex items-center gap-2 px-8 py-4 bg-emerald-600 text-white rounded-[2rem] font-black text-sm shadow-xl shadow-emerald-500/20 hover:scale-105 transition-all">
          <Plus size={20} /> Novo Lançamento
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-500/5 rounded-full -translate-y-1/2 translate-x-1/2"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Receitas Atuais</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-emerald-600">{totals.receita.toLocaleString()} MT</p>
                <ArrowUpCircle className="text-emerald-500" size={24} />
              </div>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 w-24 h-24 bg-rose-500/5 rounded-full -translate-y-1/2 translate-x-1/2"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Despesas Atuais</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-rose-600">{totals.despesa.toLocaleString()} MT</p>
                <ArrowDownCircle className="text-rose-500" size={24} />
              </div>
            </div>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl group-hover:bg-white/10 transition-all"></div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Saldo em Caixa Estimado</p>
