                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                  <select value={newLaunch.category} onChange={e => setNewLaunch({...newLaunch, category: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer shadow-inner">
                    <option>Vendas</option><option>Operacional</option><option>Salários</option><option>Marketing</option><option>TI</option><option>Outros</option>
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição do Lançamento</label>
                <input required placeholder="Ex: Pagamento de Subsídio Agente Macuti" value={newLaunch.description} onChange={e => setNewLaunch({...newLaunch, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 shadow-inner" />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor (MT)</label>
                <input required type="number" placeholder="0.00" value={newLaunch.amount} onChange={e => setNewLaunch({...newLaunch, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-6 font-black text-2xl border-none outline-none focus:ring-2 focus:ring-emerald-500 shadow-inner" />
              </div>

              <div className="space-y-3">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                   <Paperclip size={12} className="text-emerald-600" /> Anexo de Nota Fiscal / Comprovativo
                </label>

                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`group relative border-2 border-dashed rounded-[2rem] p-8 transition-all cursor-pointer flex flex-col items-center justify-center gap-3 ${selectedFile ? 'bg-emerald-50 border-emerald-200' : 'bg-slate-50 border-slate-200 hover:bg-white hover:border-emerald-300'}`}
                >
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    onChange={handleFileChange} 
                    className="hidden" 
                    accept="image/*,application/pdf"
                  />

                  {selectedFile ? (
                    <>
                      <div className="w-14 h-14 bg-emerald-100 text-emerald-600 rounded-2xl flex items-center justify-center shadow-inner animate-in zoom-in">
                        <FileCheck size={28} />
                      </div>
                      <div className="text-center">
                        <p className="text-xs font-black text-slate-900 truncate max-w-[250px]">{selectedFile.name}</p>
                        <p className="text-[9px] font-bold text-emerald-600 uppercase tracking-widest mt-1">Ficheiro Pronto para Sincronização</p>
                      </div>
                      <button 
                        type="button"
                        onClick={(e) => { e.stopPropagation(); setSelectedFile(null); }}
                        className="absolute top-4 right-4 p-2 bg-white text-slate-400 hover:text-rose-600 rounded-xl shadow-sm border border-slate-100 transition-all"
                      >
                        <Trash2 size={14} />
                      </button>
                    </>
                  ) : (
                    <>
                      <div className="w-14 h-14 bg-white text-slate-400 rounded-2xl flex items-center justify-center shadow-sm group-hover:bg-emerald-600 group-hover:text-white transition-all duration-500">
                        <FileUp size={28} />
                      </div>
                      <div className="text-center">
                        <p className="text-[11px] font-black text-slate-700 uppercase tracking-tight">Carregar Documento Digital</p>
                        <p className="text-[9px] font-medium text-slate-400 mt-1">PDF, JPG ou PNG (Máx. 5MB)</p>
                      </div>
                    </>
                  )}
                </div>
              </div>

              <button type="submit" className="w-full py-6 bg-emerald-600 text-white font-black rounded-[2rem] shadow-xl hover:bg-slate-900 transition-all flex items-center justify-center gap-3 mt-4 active:scale-95">
                <CloudUpload size={20} /> Sincronizar em Background
              </button>
              <p className="text-center text-[9px] font-black text-slate-400 uppercase tracking-widest leading-relaxed">
                 O sistema enviará os dados para a cloud enquanto continua o seu trabalho.
              </p>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

