import React, { useState, useEffect, useRef } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle, Briefcase, 
  Search, MapPin, DollarSign, LayoutList, Sparkles, AlignLeft, RefreshCcw,
  CheckCircle2, Camera, Link as LinkIcon, UserPlus, MessageSquare, ChevronRight, Fingerprint,
  BellRing,
  ExternalLink,
  Info,
  Calendar,
  CreditCard,
  Wrench,
  FileBadge,
  Building2,
  Trophy,
  UserCheck,
  ClipboardList,
  XCircle,
  Power,
  Code,
  Copy,
  Check
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole, JobVacancy, JobApplication } from '../types';
import { generateJobDescription } from '../geminiService';

const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies' | 'applications'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [viewingEmp, setViewingEmp] = useState<Employee | null>(null);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [realtimeNotification, setRealtimeNotification] = useState<{name: string, job: string} | null>(null);
  const [saving, setSaving] = useState(false);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const initialFormState: Partial<Employee> = {
    name: '', 
    role: UserRole.EMPLOYEE, 
    department: 'Geral', 
    salary: 0, 
    email: '', 
    phone: '+258 ',
    document_type: 'BI', 
    document_number: '', 
    document_expiry: '', 
    payment_method: 'M-Pesa', 
    contract_start: new Date().toISOString().split('T')[0],
    status: 'Ativo',
    join_date: new Date().toISOString().split('T')[0]
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchData();
    fetchVacancies();
    fetchApplications();

    const channel = supabase
      .channel('hr_realtime_dashboard')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, (payload) => {
        const newApp = payload.new as JobApplication;
        setApplications(prev => [newApp, ...prev]);
        if (audioRef.current) audioRef.current.play().catch(e => {});
        setRealtimeNotification({ name: newApp.applicant_name, job: newApp.job_title });
        setTimeout(() => setRealtimeNotification(null), 8000);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (data) setVacancies(data);
    } catch (err) {}
  }

  async function fetchApplications() {
    try {
      const { data } = await supabase.from('job_applications').select('*').order('created_at', { ascending: false });
      if (data) setApplications(data);
    } catch (err) {}
  }

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!formState.name || formState.name.trim().length < 3) { setError("Por favor, insira um nome completo válido."); return; }
    setSaving(true);
    try {
      const payload = { 
        ...formState, 
        salary: Number(formState.salary),
        avatar: formState.avatar || `https://picsum.photos/seed/${formState.name}/100` 
      };

      let res;
      if (editingEmpId) {
        res = await supabase.from('employees').update(payload).eq('id', editingEmpId);
      } else {
        res = await supabase.from('employees').insert([payload]);
      }

      if (res.error) throw res.error;

      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { 
      setError(err.message); 
    } finally { 
      setSaving(false); 
    }
  };

  const handleDeleteEmployee = async (id: string) => {
    if (!confirm('Eliminar este colaborador permanentemente do sistema?')) return;
    try {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (error) throw error;
      setShowViewModal(false);
      fetchData();
    } catch (err: any) {
      alert("Erro ao eliminar: " + err.message);
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} /> };
    const today = new Date();
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} /> };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} /> };
    return { label: 'Documento OK', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} /> };
  };

  const openViewModal = (emp: Employee) => {
    setViewingEmp(emp);
    setShowViewModal(true);
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-24 gap-4">
      <Loader2 className="animate-spin text-indigo-600" size={48} />
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando Staff Monte...</p>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20 relative">

      {/* Notificação em Tempo Real */}
      {realtimeNotification && (
        <div className="fixed top-24 right-8 z-[200] bg-slate-900 text-white p-6 rounded-[2.5rem] shadow-2xl flex items-center gap-5 animate-in slide-in-from-right-10 border border-emerald-500/30 backdrop-blur-xl">
           <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center animate-bounce">
             <BellRing size={24} />
           </div>
           <div>
              <p className="text-[9px] font-black text-emerald-400 uppercase tracking-widest mb-1">Nova Candidatura</p>
              <h4 className="text-sm font-bold truncate">{realtimeNotification.name}</h4>
           </div>
           <button onClick={() => setRealtimeNotification(null)} className="p-2 text-slate-500 hover:text-white"><X size={18} /></button>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Staff</h1>
             <p className="text-slate-500 font-medium italic">Controle de talentos e conformidade contratual da Monte Imobiliária.</p>
           </div>
        </div>
        <button onClick={() => { setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all flex items-center gap-2">
          <Plus size={20} /> Novo Colaborador
        </button>
      </div>

      <div className="flex p-1.5 bg-slate-100 rounded-[2.5rem] w-full max-w-lg mx-auto border border-slate-200 shadow-inner mb-10">
        <button onClick={() => setActiveTab('employees')} className={`flex-1 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500'}`}>Staff Activo</button>
        <button onClick={() => setActiveTab('vacancies')} className={`flex-1 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}>Recrutamento</button>
        <button onClick={() => setActiveTab('applications')} className={`flex-1 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'applications' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Candidatos</button>
      </div>

      {activeTab === 'employees' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.length === 0 ? (
            <div className="col-span-full py-20 text-center bg-white rounded-[3.5rem] border border-dashed border-slate-200">
               <Users size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Nenhum colaborador registado.</p>
            </div>
          ) : employees.map((emp, index) => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div 
                key={emp.id} 
                onClick={() => openViewModal(emp)}
                className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500 animate-in fade-in slide-in-from-bottom-4 cursor-pointer"
                style={{ animationDelay: `${index * 50}ms` }}
              >
                <div className={`absolute top-6 left-6 px-3 py-1 rounded-full border text-[8px] font-black uppercase tracking-widest flex items-center gap-1.5 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>

                <div className="mt-8 flex flex-col items-center">
                  <div className="relative mb-5">
                    <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-8 ring-slate-50 shadow-inner group-hover:scale-105 transition-transform" alt={emp.name} />
                    <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-4 border-white ${emp.status === 'Ativo' ? 'bg-green-500' : 'bg-amber-500'}`}></div>
                  </div>
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center truncate w-full">{emp.name}</h3>
