export default DashboardView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUp, TrendingDown, Users, Home, 
  Plus, MessageSquare, Briefcase, 
  Loader2, Wallet, ChevronRight,
  ArrowUpRight, ArrowDownRight, Activity,
  Sparkles, Star, Quote, Trash2, Edit3, Save, X as CloseIcon, 
  Cloud, ShieldCheck, Globe, Mail, Clock, UserCheck, AlertTriangle,
  UserPlus,
  ArrowRight,
  // Added missing RefreshCw icon
  RefreshCw
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, 
  ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property, JobApplication } from '../types';
import { getStrategicInsight } from '../geminiService';
import TodoList from '../components/TodoList';

interface ContactRequest {
  id: string;
  name: string;
  email: string;
  subject: string;
  message: string;
  created_at: string;
}

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ 
    revenue: 0, 
    expenses: 0, 
    employees: 0, 
    properties: 0, 
    contacts: 0,
    pendingApps: 0 
  });
  const [recentMessages, setRecentMessages] = useState<ContactRequest[]>([]);
  const [recentApps, setRecentApps] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [dbError, setDbError] = useState<string | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('Analisando pulso da empresa...');
  const [showQuickTransaction, setShowQuickTransaction] = useState(false);
  const [savingTx, setSavingTx] = useState(false);

  const [txForm, setTxForm] = useState({ description: '', amount: '', type: 'DESPESA' as 'RECEITA' | 'DESPESA' });

  useEffect(() => {
    fetchGlobalStats();

    // Listener Realtime para Candidaturas no Dashboard
    const channel = supabase
      .channel('dashboard_realtime')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, (payload) => {
        const newApp = payload.new as JobApplication;
        setRecentApps(prev => [newApp, ...prev].slice(0, 5));
        setStats(prev => ({ ...prev, pendingApps: prev.pendingApps + 1 }));
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    setDbError(null);
    try {
      const [txRes, empRes, propRes, contactRes, msgListRes, appListRes, appCountRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*', { count: 'exact', head: true }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false }).limit(4),
        supabase.from('job_applications').select('*').order('created_at', { ascending: false }).limit(5),
        supabase.from('job_applications').select('*', { count: 'exact', head: true }).eq('status', 'Pendente')
      ]);

      if (contactRes.error?.code === 'PGRST204' || contactRes.error?.code === 'PGRST205') {
        setDbError("Setup inicial pendente: As tabelas de Inbox/RH ainda não foram sincronizadas na Cloud.");
      }

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        revenue: rev, 
        expenses: exp,
        employees: empRes.count || 0,
        properties: propRes.count || 0, 
        contacts: contactRes.count || 0,
        pendingApps: appCountRes.count || 0
      });

      setRecentMessages(msgListRes.data || []);
      setRecentApps(appListRes.data || []);

      const insight = await getStrategicInsight(`Fluxo: ${rev-exp}MT, Imóveis: ${propRes.count}, Candidaturas: ${appCountRes.count}`);
      setAiInsight(insight);
    } catch (error: any) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleQuickTx = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTx(true);
    try {
      const { error } = await supabase.from('transactions').insert([{
        description: txForm.description, amount: Number(txForm.amount), type: txForm.type, category: 'Geral',
        date: new Date().toISOString().split('T')[0]
      }]);
      if (!error) { setShowQuickTransaction(false); setTxForm({ description: '', amount: '', type: 'DESPESA' }); fetchGlobalStats(); }
    } finally { setSavingTx(false); }
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#10b981' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  const barData = useMemo(() => [{ name: 'Financeiro', receitas: stats.revenue, despesas: stats.expenses }], [stats]);

  if (loading) return (
    <div className="h-full flex flex-col items-center justify-center py-32 gap-6 bg-slate-50">
      <div className="w-20 h-20 bg-blue-600 rounded-[2.5rem] flex items-center justify-center p-4 shadow-2xl animate-bounce">
         <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
      </div>
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.4em] animate-pulse">Sincronizando Ecossistema Monte...</p>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {dbError && (
        <div className="bg-amber-50 border-l-4 border-amber-500 p-6 rounded-[2.5rem] flex items-center justify-between gap-6 shadow-sm">
           <div className="flex items-center gap-4 text-amber-800">
             <AlertTriangle size={24} className="shrink-0" />
             <p className="text-sm font-bold">{dbError}</p>
           </div>
           <button onClick={() => setDbError(null)} className="p-2 hover:bg-amber-100 rounded-full transition-all"><CloseIcon size={18} className="text-amber-400" /></button>
        </div>
      )}

      {/* Barra de Status da Cloud */}
      <div className="flex flex-col md:flex-row items-center justify-between bg-white px-10 py-6 rounded-[3.5rem] border border-slate-100 shadow-sm gap-4">
        <div className="flex items-center gap-4">
           <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(16,185,129,0.8)]"></div>
           <span className="text-[10px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-3">
             <ShieldCheck size={18} className="text-blue-600" /> Sincronização Cloud Ativa
           </span>
        </div>

        {/* Insight da IA (Gemini) */}
        <div className="flex-1 max-w-2xl px-8 border-x border-slate-100 hidden lg:block">
           <div className="flex items-center gap-3 text-indigo-600 mb-1">
              <Sparkles size={14} className="animate-pulse" />
              <span className="text-[9px] font-black uppercase tracking-widest">Insight Estratégico IA</span>
           </div>
           <p className="text-xs font-bold text-slate-500 italic line-clamp-1">"{aiInsight}"</p>
        </div>

        <div className="flex items-center gap-8">
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Activity size={14} className="text-indigo-500" /> Latência Beira-Node: 12ms</div>
           <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-tighter"><Globe size={14} className="text-emerald-500" /> Rede Oficial Monte</div>
        </div>
      </div>

      {/* KPI Grid Aprimorado */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Fluxo Monte', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-blue-600" />, trend: 'Saldo Líquido Caixa', color: 'blue' },
          { label: 'Staff Ativo', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores Registados', color: 'emerald' },
          { label: 'Portfólio', value: stats.properties, icon: <Home className="text-indigo-600" />, trend: 'Imóveis no Catálogo', color: 'indigo' },
          { label: 'Candidaturas', value: stats.pendingApps, icon: <UserPlus className="text-rose-600" />, trend: 'Processos em Análise', color: 'rose' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all group overflow-hidden relative">
            <div className={`absolute top-0 right-0 w-32 h-32 bg-slate-50 rounded-full translate-x-12 -translate-y-12 group-hover:scale-125 transition-transform duration-700`}></div>
            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-6">
                <div className="p-4 bg-slate-50 rounded-[1.25rem] group-hover:bg-white group-hover:shadow-md transition-all">{kpi.icon}</div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{kpi.label}</span>
              </div>
              <h3 className="text-4xl font-black text-slate-900 tracking-tight mb-2">{kpi.value}</h3>
              <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{kpi.trend}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-10">
        <div className="xl:col-span-2 space-y-10">

          {/* Inbox de Mensagens */}
          <div className="bg-white rounded-[4rem] border border-slate-100 shadow-sm overflow-hidden">
             <div className="p-10 border-b border-slate-50 flex items-center justify-between bg-slate-50/30">
                <div className="flex items-center gap-4">
                   <div className="p-3 bg-blue-100 text-blue-600 rounded-2xl"><Mail size={24} /></div>
                   <div>
                      <h3 className="text-xl font-black text-slate-900 tracking-tight">Inbox de Mensagens</h3>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Interações via portal oficial</p>
                   </div>
                </div>
                <button onClick={fetchGlobalStats} className="p-3 text-blue-600 hover:rotate-180 transition-transform duration-700 bg-white rounded-xl border border-slate-100 shadow-sm"><RefreshCw size={20} /></button>
             </div>
             <div className="divide-y divide-slate-50">
                {recentMessages.length === 0 ? (
                  <div className="p-20 text-center flex flex-col items-center gap-4">
                    <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-200"><MessageSquare size={32} /></div>
                    <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Sem mensagens recentes.</p>
                  </div>
                ) : recentMessages.map((msg) => (
                  <div key={msg.id} className="p-8 hover:bg-slate-50/50 transition-all group">
                     <div className="flex justify-between items-start mb-3">
                        <div>
                           <p className="text-sm font-black text-slate-900">{msg.name}</p>
                           <p className="text-[10px] font-bold text-blue-600 uppercase tracking-wider">{msg.subject}</p>
                        </div>
                        <span className="text-[9px] font-black text-slate-300 uppercase flex items-center gap-1.5"><Clock size={12} /> {new Date(msg.created_at).toLocaleDateString()}</span>
                     </div>
                     <p className="text-xs text-slate-500 leading-relaxed bg-white border border-slate-100 p-5 rounded-[2rem] italic group-hover:border-blue-100 transition-all shadow-sm">"{msg.message}"</p>
                     <div className="mt-4 flex items-center gap-4">
                        <a href={`mailto:${msg.email}`} className="text-[10px] font-black text-indigo-500 uppercase tracking-widest flex items-center gap-1.5 hover:underline bg-indigo-50 px-4 py-2 rounded-lg"><Mail size={12} /> Responder Cliente</a>
                     </div>
                  </div>
                ))}
             </div>
          </div>

          {/* Gráfico Fiscal e TodoList */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
             <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm flex flex-col min-h-[450px]">
                <div className="flex items-center justify-between mb-12">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Performance Fiscal</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Balanço Cloud Monte</p>
                  </div>
                  <div className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl"><TrendingUp size={24} /></div>
                </div>
                <div className="h-[300px] w-full mt-auto">
                  <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
                    <BarChart data={barData}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" hide />
                      <YAxis hide />
                      <Tooltip 
                        contentStyle={{ borderRadius: '2rem', border: 'none', boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.1)', padding: '1.5rem' }} 
                        itemStyle={{ fontWeight: 900, textTransform: 'uppercase', fontSize: '10px' }}
                      />
                      <Bar dataKey="receitas" fill="#10b981" radius={[15, 15, 0, 0]} barSize={60} />
                      <Bar dataKey="despesas" fill="#f43f5e" radius={[15, 15, 0, 0]} barSize={60} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
             </div>
             <div className="h-[450px]"><TodoList /></div>
          </div>
        </div>

        {/* Sidebar Direita: Candidaturas e Balanço Pie */}
        <div className="space-y-10">

          {/* Widget de Recrutamento Redesenhado */}
          <div className="bg-slate-900 rounded-[4rem] p-10 text-white shadow-2xl relative overflow-hidden border border-white/5">
             <div className="relative z-10">
                <div className="flex items-center justify-between mb-10">
                   <div className="flex items-center gap-3">
                      <div className="w-10 h-10 bg-emerald-500/20 text-emerald-400 rounded-xl flex items-center justify-center"><UserCheck size={24} /></div>
                      <h3 className="text-lg font-black uppercase tracking-tight">Novos Talentos</h3>
                   </div>
                   {stats.pendingApps > 0 && (
                     <span className="px-3 py-1 bg-emerald-500 text-white text-[9px] font-black uppercase rounded-full animate-pulse">
                        {stats.pendingApps} Pendentes
                     </span>
                   )}
                </div>

                <div className="space-y-5">
                   {recentApps.length === 0 ? (
                     <div className="py-10 text-center opacity-40 italic flex flex-col items-center gap-3">
                        <Users size={32} />
                        <p className="text-xs">Nenhuma candidatura recente.</p>
                     </div>
                   ) : recentApps.map(app => (
                     <div key={app.id} className="flex items-center gap-4 group p-3 hover:bg-white/5 rounded-2xl transition-all border border-transparent hover:border-white/5">
                        <div className="w-12 h-12 bg-white/10 rounded-[1.25rem] flex items-center justify-center font-black text-emerald-400 text-lg shadow-inner group-hover:scale-110 transition-transform">
                          {app.applicant_name.charAt(0)}
                        </div>
                        <div className="flex-1 min-w-0">
                           <p className="text-sm font-black truncate">{app.applicant_name}</p>
                           <p className="text-[9px] text-slate-400 font-bold uppercase tracking-tighter truncate">{app.job_title}</p>
                        </div>
                        <div className="w-2 h-2 bg-emerald-500 rounded-full shadow-[0_0_10px_rgba(16,185,129,1)]"></div>
                     </div>
                   ))}
                </div>

                <button className="w-full mt-10 py-5 bg-white text-slate-900 hover:bg-emerald-500 hover:text-white rounded-[1.75rem] text-[10px] font-black uppercase tracking-[0.2em] transition-all flex items-center justify-center gap-3 shadow-xl active:scale-95">
                   Gerir Candidaturas <ArrowRight size={16} />
                </button>
             </div>
             {/* Efeitos de Fundo */}
             <div className="absolute top-0 right-0 w-48 h-48 bg-emerald-500/10 rounded-full blur-[80px] -translate-y-1/2 translate-x-1/2"></div>
             <div className="absolute bottom-0 left-0 w-32 h-32 bg-blue-500/10 rounded-full blur-[60px] translate-y-1/2 -translate-x-1/2"></div>
          </div>

          {/* Gráfico de Pizza do Balanço */}
          <div className="bg-white p-12 rounded-[4rem] border border-slate-100 shadow-sm">
            <h3 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-3 tracking-tight">
              <TrendingUp className="text-blue-600" size={24} /> Balanço Fiscal
            </h3>
            <div className="w-full mb-10 h-[300px]">
              <ResponsiveContainer width="100%" height="100%" minWidth={0} minHeight={0}>
                <PieChart>
                  <Pie data={chartData} cx="50%" cy="50%" innerRadius={85} outerRadius={115} paddingAngle={10} dataKey="value">
                    {chartData.map((entry, index) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                  </Pie>
                  <Tooltip 
                    contentStyle={{ borderRadius: '2rem', border: 'none', boxShadow: '0 20px 50px rgba(0,0,0,0.1)' }} 
                    formatter={(v: any) => `${Number(v).toLocaleString()} MT`} 
                  />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="space-y-4">
              <div className="p-8 bg-emerald-50 rounded-[2.5rem] flex justify-between items-center group transition-all shadow-sm border border-emerald-100 hover:bg-white hover:shadow-xl">
                <div><p className="text-[11px] font-black text-emerald-600 uppercase tracking-widest mb-1">Receitas</p><p className="text-2xl font-black text-slate-900 tracking-tighter">{stats.revenue.toLocaleString()} <span className="text-xs">MT</span></p></div>
                <div className="p-4 bg-white rounded-2xl shadow-sm text-emerald-600 group-hover:scale-110 transition-all"><ArrowUpRight size={24} /></div>
              </div>
              <div className="p-8 bg-rose-50 rounded-[2.5rem] flex justify-between items-center group transition-all shadow-sm border border-rose-100 hover:bg-white hover:shadow-xl">
                <div><p className="text-[11px] font-black text-rose-600 uppercase tracking-widest mb-1">Despesas</p><p className="text-2xl font-black text-slate-900 tracking-tighter">{stats.expenses.toLocaleString()} <span className="text-xs">MT</span></p></div>
                <div className="p-4 bg-white rounded-2xl shadow-sm text-rose-600 group-hover:scale-110 transition-all"><ArrowDownRight size={24} /></div>
              </div>
              <button onClick={() => setShowQuickTransaction(true)} className="w-full py-7 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] hover:border-blue-600 hover:text-blue-600 transition-all flex items-center justify-center gap-3 mt-4 active:scale-95">
                <Plus size={20} /> Lançamento Rápido
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Modal de Lançamento Rápido */}
      {showQuickTransaction && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-16 max-w-lg w-full shadow-2xl relative border-t-[12px] border-blue-600">
            <button onClick={() => setShowQuickTransaction(false)} className="absolute top-12 right-12 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><CloseIcon size={28} /></button>
            <div className="flex items-center gap-4 mb-12">
               <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-[1.5rem] flex items-center justify-center shadow-inner"><Wallet size={32} /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight leading-none">Registo de <br/>Movimento</h2>
            </div>
            <form onSubmit={handleQuickTx} className="space-y-10">
               <div className="flex p-2 bg-slate-100 rounded-[2rem] shadow-inner">
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'RECEITA'})} className={`flex-1 py-5 text-[11px] font-black uppercase tracking-widest rounded-[1.5rem] transition-all ${txForm.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Entrada</button>
                  <button type="button" onClick={() => setTxForm({...txForm, type: 'DESPESA'})} className={`flex-1 py-5 text-[11px] font-black uppercase tracking-widest rounded-[1.5rem] transition-all ${txForm.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Saída</button>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Motivo / Descrição</label>
                  <input required value={txForm.description} onChange={e => setTxForm({...txForm, description: e.target.value})} className="w-full bg-slate-50 p-6 rounded-3xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100 transition-all shadow-inner" placeholder="Ex: Manutenção Elétrica Sede" />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-4">Valor (MZN)</label>
                  <input required type="number" value={txForm.amount} onChange={e => setTxForm({...txForm, amount: e.target.value})} className="w-full bg-slate-50 p-8 rounded-3xl font-black text-4xl border-none outline-none focus:ring-4 focus:ring-blue-100 shadow-inner" placeholder="0.00" />
               </div>
               <button disabled={savingTx} type="submit" className="w-full py-8 bg-blue-600 text-white font-black rounded-[2.5rem] hover:bg-slate-900 transition-all active:scale-95 flex items-center justify-center gap-4 shadow-2xl shadow-blue-600/20">
                  {savingTx ? <Loader2 className="animate-spin" /> : <><Plus size={24} /> Confirmar Lançamento</>}
               </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;

