            <div className="space-y-4">
              <div className="p-8 bg-emerald-50 rounded-[2.5rem] flex justify-between items-center group transition-all shadow-sm border border-emerald-100 hover:bg-white hover:shadow-xl">
                <div><p className="text-[11px] font-black text-emerald-600 uppercase tracking-widest mb-1">Receitas</p><p className="text-2xl font-black text-slate-900 tracking-tighter">{stats.revenue.toLocaleString()} <span className="text-xs">MT</span></p></div>
                <div className="p-4 bg-white rounded-2xl shadow-sm text-emerald-600 group-hover:scale-110 transition-all"><ArrowUpRight size={24} /></div>
