                <div><p className="text-[11px] font-black text-rose-600 uppercase tracking-widest mb-1">Despesas</p><p className="text-2xl font-black text-slate-900 tracking-tighter">{stats.expenses.toLocaleString()} <span className="text-xs">MT</span></p></div>
                <div className="p-4 bg-white rounded-2xl shadow-sm text-rose-600 group-hover:scale-110 transition-all"><ArrowDownRight size={24} /></div>
              </div>
              <button onClick={() => setShowQuickTransaction(true)} className="w-full py-7 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] hover:border-blue-600 hover:text-blue-600 transition-all flex items-center justify-center gap-3 mt-4 active:scale-95">
                <Plus size={20} /> Lançamento Rápido
