                                 <div className="flex items-center gap-3 text-xs font-bold text-slate-700"><Mail size={16} className="text-blue-600" /> monteimobiliario@gmail.com</div>
                                 <div className="flex items-center gap-3 text-xs font-bold text-slate-700"><Phone size={16} className="text-blue-600" /> +258 87 501 8283</div>
