            {applyStatus === 'success' ? (
              <div className="py-20 text-center animate-in zoom-in">
                <div className="w-24 h-24 bg-emerald-100 text-emerald-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-inner"><CheckCircle2 size={64} /></div>
                <h2 className="text-3xl font-black text-slate-900 mb-2 tracking-tight">Candidatura Enviada!</h2>
                <p className="text-slate-500 font-medium mb-10 text-lg">Recebemos os seus dados. A equipa de RH da Monte Imobiliária entrará em contacto se o seu perfil for selecionado.</p>
                <button onClick={() => setShowApplyModal(false)} className="px-12 py-5 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all shadow-xl active:scale-95">Concluído</button>
