                <div className="mb-10">
                   <span className="bg-blue-50 text-blue-600 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest mb-3 inline-block">Portal de Recrutamento</span>
                   <h2 className="text-3xl font-black text-slate-900 tracking-tight leading-none">Candidatura: <br/><span className="text-blue-600">{selectedJob?.title}</span></h2>
