      {/* Modal Matriz de Permissões (Editar Cargo) */}
      {editingRolePermissions && (
        <div className="fixed inset-0 z-[170] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-[12px] border-blue-600 animate-in zoom-in-95">
            <button onClick={() => setEditingRolePermissions(null)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-8 mb-12 border-b border-slate-100 pb-10">
              <div className="w-20 h-20 bg-blue-600 text-white rounded-[2rem] flex items-center justify-center shadow-2xl shadow-blue-500/40 relative overflow-hidden">
                 <Shield size={40} />
                 <div className="absolute inset-0 bg-gradient-to-tr from-transparent via-white/10 to-transparent"></div>
              </div>
              <div>
                <h2 className="text-4xl font-black text-slate-900 tracking-tight leading-none mb-2">Cargo: {editingRolePermissions.name}</h2>
                <div className="flex items-center gap-4">
                  <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Editor de Matriz Granular</p>
                  <span className="text-slate-200">|</span>
                  <div className="flex items-center gap-2">
                    <span className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></span>
                    <p className="text-[11px] font-black text-blue-600 uppercase tracking-widest">{editingRolePermissions.permissions.length} Funcionalidades Permitidas</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-16 mb-16">
              {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                  <div key={category} className="space-y-8">
                    <div className="flex items-center justify-between px-4 bg-slate-50 py-3 rounded-2xl border border-slate-100">
                      <h3 className="text-xs font-black uppercase text-slate-900 flex items-center gap-3">
                        <div className="p-1.5 bg-blue-100 text-blue-600 rounded-lg"><Lock size={12} /></div>
                        Módulo: {category}
                      </h3>
                      <button type="button" onClick={() => toggleCategory(category, perms, 'role')} className="text-[9px] font-black uppercase text-indigo-600 hover:text-indigo-900 transition-colors flex items-center gap-2">
                        <Zap size={12} /> Selecionar Tudo
                      </button>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                      {perms.map(p => {
                        const isActive = editingRolePermissions.permissions?.includes(p.id);
                        return (
                          <button key={p.id} type="button" onClick={() => toggleRolePermission(p.id)} className={`flex flex-col p-8 rounded-[3rem] border-2 text-left transition-all duration-300 relative overflow-hidden group/btn ${isActive ? 'bg-blue-600 border-blue-600 text-white shadow-2xl scale-[1.03]' : 'bg-white border-slate-100 text-slate-600 hover:border-blue-200 hover:bg-blue-50/30'}`}>
                            <div className="flex items-center justify-between mb-4 relative z-10">
                              <div className={`p-3 rounded-2xl transition-colors ${isActive ? 'bg-white/20' : 'bg-slate-50 text-blue-600 group-hover/btn:bg-white group-hover/btn:shadow-sm'}`}>
                                {p.icon}
                              </div>
                              {isActive && <div className="bg-white text-blue-600 p-1 rounded-full animate-in zoom-in"><Check size={12} strokeWidth={4} /></div>}
                            </div>
                            <span className="text-[12px] font-black uppercase mb-1.5 relative z-10 group-hover/btn:tracking-wider transition-all">{p.label}</span>
                            <span className={`text-[10px] font-medium leading-relaxed relative z-10 ${isActive ? 'text-blue-100' : 'text-slate-400'}`}>
                              {p.description}
                            </span>
                          </button>
                        );
                      })}
                    </div>
                  </div>
              ))}
            </div>

            <div className="flex gap-6 pt-10 border-t border-slate-100">
              <button 
                onClick={handleSaveRolePermissions}
                disabled={saving}
                className="flex-1 py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-[0.3em] shadow-2xl shadow-blue-500/30 hover:bg-slate-900 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50"
              >
                {saving ? <Loader2 className="animate-spin" size={24} /> : <><Save size={24} /> Sincronizar Matriz de Cargo</>}
              </button>
              <button 
                onClick={() => setEditingRolePermissions(null)}
                className="px-12 py-8 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all active:scale-95"
              >
                Descartar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* NOVO: Modal de Auditoria de Segurança */}
      {showAuditModal && (
        <div className="fixed inset-0 z-[180] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
