import React from 'react';
import { ERP_NAVIGATION } from '../constants';
import { UserRole, User } from '../types';
import { X } from 'lucide-react';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  user: User; // Alterado de userRole para user completo para aceder às permissões
  isOpen: boolean;
  toggleSidebar: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPath, onNavigate, user, isOpen, toggleSidebar }) => {
  // Filtragem inteligente: O item deve satisfazer a role OU ter a permissão granular no array do utilizador
  const filteredNav = ERP_NAVIGATION.filter(item => {
    // Se o item não tem permissão definida, é visível para todos os staff (ex: Carreiras)
    if (!item.permission) return true;

    // Admins de sistema têm acesso total bypass
    if (user.role === UserRole.ADMIN) return true;

    // Verifica se a permissão granular está presente no array do utilizador
    return user.permissions?.includes(item.permission);
  });

  return (
