const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies' | 'applications'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [applications, setApplications] = useState<JobApplication[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [showViewModal, setShowViewModal] = useState(false);
  const [viewingEmp, setViewingEmp] = useState<Employee | null>(null);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [realtimeNotification, setRealtimeNotification] = useState<{name: string, job: string} | null>(null);
  const [saving, setSaving] = useState(false);
  const [isGeneratingIA, setIsGeneratingIA] = useState(false);

  // Estados de Filtro
  const [staffSearch, setStaffSearch] = useState('');
  const [deptFilter, setDeptFilter] = useState('Todos');
  const [statusFilter, setStatusFilter] = useState('Todos');

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, 
    email: '', phone: '+258 ', document_type: 'BI', document_number: '', 
    document_expiry: '', payment_method: 'M-Pesa', 
    contract_start: new Date().toISOString().split('T')[0],
    status: 'Ativo', join_date: new Date().toISOString().split('T')[0],
    nuit: '', niss: '', emergency_contact: '', gender: 'M', address: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Vendas', type: 'Full-time', location: 'Beira', salary: 'A negociar',
    description: '', status: 'Open'
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchData();
    fetchVacancies();
    fetchApplications();

    const channel = supabase
      .channel('hr_realtime_dashboard')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, (payload) => {
        const newApp = payload.new as JobApplication;
        setApplications(prev => [newApp, ...prev]);
        if (audioRef.current) audioRef.current.play().catch(e => {});
        setRealtimeNotification({ name: newApp.applicant_name, job: newApp.job_title });
        setTimeout(() => setRealtimeNotification(null), 8000);
      })
      .subscribe();

    return () => { supabase.removeChannel(channel); };
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (data) setVacancies(data);
    } catch (err) {}
  }

  async function fetchApplications() {
    try {
      const { data } = await supabase.from('job_applications').select('*').order('created_at', { ascending: false });
      if (data) setApplications(data);
    } catch (err) {}
  }

  // Estatísticas Calculadas
  const staffStats = useMemo(() => {
    const active = employees.filter(e => e.status === 'Ativo').length;
    const expiringDocs = employees.filter(e => {
      if (!e.document_expiry) return false;
      const today = new Date();
      const expiry = new Date(e.document_expiry);
      const diff = (expiry.getTime() - today.getTime()) / (1000 * 3600 * 24);
      return diff <= 30;
    }).length;
    const onVacation = employees.filter(e => e.status === 'Férias').length;
    return { active, expiringDocs, onVacation, total: employees.length };
  }, [employees]);

  // Lista Filtrada
  const filteredEmployees = useMemo(() => {
    return employees.filter(e => {
      const matchesSearch = e.name.toLowerCase().includes(staffSearch.toLowerCase()) || e.email.toLowerCase().includes(staffSearch.toLowerCase());
      const matchesDept = deptFilter === 'Todos' || e.department === deptFilter;
      const matchesStatus = statusFilter === 'Todos' || e.status === statusFilter;
      return matchesSearch && matchesDept && matchesStatus;
    });
  }, [employees, staffSearch, deptFilter, statusFilter]);

  const departments = ['Todos', 'Vendas', 'Administrativo', 'Engenharia', 'TI', 'Manutenção', 'Direcção', 'Geral'];

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if (!formState.name || formState.name.trim().length < 3) { setError("Por favor, insira um nome completo válido."); return; }
    setSaving(true);
    try {
      const payload = { 
        ...formState, 
        salary: Number(formState.salary),
        avatar: formState.avatar || `https://picsum.photos/seed/${formState.name}/100` 
      };

      let res;
      if (editingEmpId) {
        res = await supabase.from('employees').update(payload).eq('id', editingEmpId);
        // Log de Auditoria Manual (Simulação de sistema legado se o DB não tiver triggers)
        await supabase.from('audit_logs').insert([{
           admin_name: 'Sistema HR',
           target_user_name: formState.name,
           action_type: 'STAFF_ATUALIZADO',
           change_details: `Campos alterados no dossiê do colaborador ${formState.name}.`
        }]);
      } else {
        res = await supabase.from('employees').insert([payload]);
      }

      if (res.error) throw res.error;

      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { 
      setError(err.message); 
    } finally { 
      setSaving(false); 
    }
  };

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const { error: err } = await supabase.from('job_vacancies').insert([vacancyForm]);
      if (err) throw err;
      setShowVacancyModal(false);
      setVacancyForm(initialVacancyState);
      fetchVacancies();
    } catch (err: any) {
      alert(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleAIGenerateVacancy = async () => {
    if (!vacancyForm.title) return alert("Insira o título da vaga para a IA trabalhar.");
    setIsGeneratingIA(true);
    try {
      const desc = await generateJobDescription(vacancyForm.title, vacancyForm.area || 'Geral', vacancyForm.location || 'Beira');
      setVacancyForm(prev => ({ ...prev, description: desc }));
    } finally {
      setIsGeneratingIA(false);
    }
  };

  const handleDeleteEmployee = async (id: string) => {
    if (!confirm('Eliminar este colaborador permanentemente do sistema?')) return;
    try {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (error) throw error;
      setShowViewModal(false);
      fetchData();
    } catch (err: any) {
      alert("Erro ao eliminar: " + err.message);
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} /> };
    const today = new Date();
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} /> };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} /> };
    return { label: 'Documento OK', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} /> };
  };

  const openViewModal = (emp: Employee) => {
    setViewingEmp(emp);
    setShowViewModal(true);
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-24 gap-4">
      <Loader2 className="animate-spin text-indigo-600" size={48} />
      <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Sincronizando Staff Monte...</p>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-20 relative">

      {/* Notificação em Tempo Real */}
      {realtimeNotification && (
        <div className="fixed top-24 right-8 z-[200] bg-slate-900 text-white p-6 rounded-[2.5rem] shadow-2xl flex items-center gap-5 animate-in slide-in-from-right-10 border border-emerald-500/30 backdrop-blur-xl">
           <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center animate-bounce">
             <BellRing size={24} />
           </div>
           <div>
              <p className="text-[9px] font-black text-emerald-400 uppercase tracking-widest mb-1">Nova Candidatura</p>
              <h4 className="text-sm font-bold truncate">{realtimeNotification.name}</h4>
           </div>
           <button onClick={() => setRealtimeNotification(null)} className="p-2 text-slate-500 hover:text-white"><X size={18} /></button>
        </div>
      )}

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Staff</h1>
             <p className="text-slate-500 font-medium italic">Controle de talentos e conformidade contratual.</p>
           </div>
        </div>
        <div className="flex gap-3">
          <button onClick={() => setShowVacancyModal(true)} className="px-6 py-4 bg-white text-indigo-600 border border-indigo-100 rounded-[2rem] font-black text-xs uppercase tracking-widest hover:bg-indigo-50 transition-all shadow-sm flex items-center gap-2">
            <Plus size={18} /> Publicar Vaga
          </button>
          <button onClick={() => { setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl hover:bg-indigo-700 transition-all flex items-center gap-2">
            <UserPlus size={18} /> Novo Staff
          </button>
        </div>
      </div>

      {/* KPI Row - Melhoria Organizacional */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
         {[
           { label: 'Staff Total', value: staffStats.total, icon: <Users className="text-blue-600"/>, bg: 'bg-blue-50' },
           { label: 'Ativos Agora', value: staffStats.active, icon: <CheckCircle2 className="text-emerald-600"/>, bg: 'bg-emerald-50' },
           { label: 'Doc. Pendentes', value: staffStats.expiringDocs, icon: <AlertTriangle className="text-amber-600"/>, bg: 'bg-amber-50' },
           { label: 'Em Férias', value: staffStats.onVacation, icon: <Heart className="text-rose-600"/>, bg: 'bg-rose-50' },
         ].map((stat, i) => (
           <div key={i} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm flex items-center gap-5">
              <div className={`w-12 h-12 ${stat.bg} rounded-2xl flex items-center justify-center`}>{stat.icon}</div>
              <div>
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{stat.label}</p>
                 <p className="text-2xl font-black text-slate-900">{stat.value}</p>
              </div>
           </div>
         ))}
      </div>

      <div className="flex p-1.5 bg-slate-100 rounded-[2.5rem] w-full max-w-lg mx-auto border border-slate-200 shadow-inner mb-6">
        <button onClick={() => setActiveTab('employees')} className={`flex-1 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-50'}`}>Staff Activo</button>
        <button onClick={() => setActiveTab('vacancies')} className={`flex-1 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-md' : 'text-slate-500'}`}>Vagas</button>
        <button onClick={() => setActiveTab('applications')} className={`flex-1 py-3 rounded-[2rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'applications' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Candidatos</button>
      </div>

      {activeTab === 'employees' && (
        <div className="space-y-8">
          {/* Barra de Filtros */}
          <div className="bg-white p-6 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col md:flex-row gap-6">
             <div className="relative flex-1">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input value={staffSearch} onChange={e => setStaffSearch(e.target.value)} placeholder="Procurar por nome, email ou cargo..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none outline-none font-bold text-sm focus:ring-4 focus:ring-indigo-50" />
             </div>
             <div className="flex gap-4">
                <div className="flex items-center gap-3 bg-slate-50 px-4 rounded-2xl border border-slate-100">
                   <Building2 size={16} className="text-slate-400" />
                   <select value={deptFilter} onChange={e => setDeptFilter(e.target.value)} className="bg-transparent font-bold text-xs uppercase text-slate-600 outline-none py-4 cursor-pointer">
                      {departments.map(d => <option key={d} value={d}>{d}</option>)}
                   </select>
                </div>
                <div className="flex items-center gap-3 bg-slate-50 px-4 rounded-2xl border border-slate-100">
                   <Filter size={16} className="text-slate-400" />
                   <select value={statusFilter} onChange={e => setStatusFilter(e.target.value)} className="bg-transparent font-bold text-xs uppercase text-slate-600 outline-none py-4 cursor-pointer">
                      <option>Todos Estados</option><option>Ativo</option><option>Férias</option><option>Suspenso</option>
                   </select>
                </div>
             </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {filteredEmployees.length === 0 ? (
              <div className="col-span-full py-20 text-center bg-white rounded-[3.5rem] border border-dashed border-slate-200">
                 <Users size={48} className="mx-auto text-slate-200 mb-4" />
                 <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Nenhum colaborador encontrado com estes filtros.</p>
              </div>
            ) : filteredEmployees.map((emp, index) => {
              const docStatus = getExpiryStatus(emp.document_expiry);
              const isMissingData = !emp.nuit || !emp.niss;
              return (
                <div 
                  key={emp.id} 
                  onClick={() => openViewModal(emp)}
                  className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500 animate-in fade-in slide-in-from-bottom-4 cursor-pointer"
                  style={{ animationDelay: `${index * 50}ms` }}
                >
                  <div className={`absolute top-6 left-6 px-3 py-1 rounded-full border text-[8px] font-black uppercase tracking-widest flex items-center gap-1.5 z-10 ${docStatus.color}`}>
                    {docStatus.icon} {docStatus.label}
                  </div>
                  {isMissingData && (
                    <div className="absolute top-6 right-6 p-2 bg-amber-100 text-amber-600 rounded-xl" title="Dados Cadastrais Incompletos (NUIT/NISS)">
                      <AlertTriangle size={14} />
                    </div>
                  )}
                  <div className="mt-8 flex flex-col items-center">
                    <div className="relative mb-5">
                      <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-8 ring-slate-50 shadow-inner group-hover:scale-105 transition-transform" alt={emp.name} />
                      <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-4 border-white ${emp.status === 'Ativo' ? 'bg-green-500' : emp.status === 'Férias' ? 'bg-blue-400' : 'bg-amber-500'}`}></div>
                    </div>
                    <h3 className="text-xl font-black text-slate-900 mb-1 text-center truncate w-full">{emp.name}</h3>
                    <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-2 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter mb-4">{emp.department}</p>
                  </div>
                  <div className="pt-6 border-t border-slate-50 flex justify-between items-center text-[10px] font-bold text-slate-400">
                    <div className="flex items-center gap-1.5 truncate"><Mail size={12} className="shrink-0" /> {emp.email.split('@')[0]}...</div>
                    <div className="flex items-center gap-1.5"><Phone size={12} className="shrink-0" /> {emp.phone.slice(-4)}</div>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* MODAL ADICIONAR/EDITAR (Campos Melhorados) */}
      {showAddModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar border-t-[12px] border-indigo-600">
            {saving && (
              <div className="absolute top-0 left-0 right-0 h-2 bg-indigo-100 overflow-hidden">
                <div className="h-full bg-indigo-600 animate-progress-loop shadow-[0_0_10px_rgba(79,70,229,0.5)]"></div>
              </div>
            )}

            <button onClick={() => setShowAddModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10">
               <div className="w-14 h-14 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center shadow-inner"><UserPlus size={28} /></div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingEmpId ? 'Atualizar Dossiê Staff' : 'Registar Novo Staff'}</h2>
            </div>

            <form onSubmit={handleSaveEmployee} className="space-y-12">
              {/* Secção 1: Perfil Profissional */}
              <section className="space-y-8">
                <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center gap-3">
                  <Shield size={16} className="text-indigo-600" /> Perfil Corporativo
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo</label>
                    <input required value={formState.name} onChange={e => setFormState({...formState, name: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-indigo-100 shadow-inner" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cargo / Função</label>
                    <select value={formState.role} onChange={e => setFormState({...formState, role: e.target.value as UserRole})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-inner">
                      {Object.values(UserRole).map(role => <option key={role} value={role}>{role}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Departamento</label>
                    <select value={formState.department} onChange={e => setFormState({...formState, department: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-inner">
                      {departments.filter(d => d !== 'Todos').map(d => <option key={d} value={d}>{d}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Remuneração Base (MZN)</label>
                    <div className="relative">
                      <DollarSign className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-500" size={18} />
                      <input type="number" required value={formState.salary} onChange={e => setFormState({...formState, salary: Number(e.target.value)})} className="w-full bg-slate-50 border-none rounded-2xl p-5 pl-12 font-black text-xl outline-none focus:ring-4 focus:ring-indigo-100 shadow-inner" />
                    </div>
                  </div>
                </div>
              </section>

              {/* Secção 2: Identificação Fiscal (Conformidade Moçambique) */}
              <section className="space-y-8 p-10 bg-slate-50 rounded-[3rem] border border-slate-100 shadow-inner">
                <h3 className="text-[11px] font-black text-slate-500 uppercase tracking-[0.3em] flex items-center gap-3">
                  <FileBadge size={16} className="text-indigo-600" /> Identificação e Conformidade
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">NUIT</label>
                    <input value={formState.nuit} onChange={e => setFormState({...formState, nuit: e.target.value})} placeholder="9 dígitos" className="w-full bg-white border border-slate-200 rounded-xl p-4 font-bold outline-none focus:ring-4 focus:ring-indigo-100" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">NISS</label>
                    <input value={formState.niss} onChange={e => setFormState({...formState, niss: e.target.value})} placeholder="Segurança Social" className="w-full bg-white border border-slate-200 rounded-xl p-4 font-bold outline-none focus:ring-4 focus:ring-indigo-100" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Documento Validade</label>
                    <input type="date" value={formState.document_expiry} onChange={e => setFormState({...formState, document_expiry: e.target.value})} className="w-full bg-white border border-slate-200 rounded-xl p-4 font-bold outline-none focus:ring-4 focus:ring-indigo-100" />
                  </div>
                </div>
              </section>

              {/* Secção 3: Contactos e Emergência */}
              <section className="space-y-8">
                <h3 className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em] flex items-center gap-3">
                  <Phone size={16} className="text-indigo-600" /> Rede de Contactos
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telemóvel Corporativo</label>
                    <input required value={formState.phone} onChange={e => setFormState({...formState, phone: e.target.value})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none shadow-inner" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contacto de Emergência</label>
                    <div className="relative">
                      <Heart className="absolute left-5 top-1/2 -translate-y-1/2 text-rose-400" size={18} />
                      <input value={formState.emergency_contact} onChange={e => setFormState({...formState, emergency_contact: e.target.value})} placeholder="Nome e Telefone" className="w-full bg-slate-50 border-none rounded-2xl p-5 pl-12 font-bold outline-none shadow-inner" />
                    </div>
                  </div>
                </div>
              </section>

              <div className="pt-8 border-t border-slate-100 flex gap-4">
                 <button disabled={saving} type="submit" className="flex-1 py-7 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-2xl hover:bg-slate-900 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50">
                    {saving ? <><Loader2 className="animate-spin" /> Sincronizando Organizacional...</> : <><Save size={20} /> Guardar Dossiê Monte</>}
                 </button>
                 <button type="button" onClick={() => setShowAddModal(false)} className="px-10 py-7 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase hover:bg-slate-200 transition-all">Cancelar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Modal Visualização Dossiê (Melhorado) */}
      {showViewModal && viewingEmp && (
        <div className="fixed inset-0 z-[180] flex items-center justify-center p-4 bg-slate-900/95 backdrop-blur-2xl animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] max-w-5xl w-full shadow-2xl relative overflow-hidden flex flex-col md:flex-row h-[90vh] md:h-[85vh] animate-in zoom-in-95 duration-500 border-t-[12px] border-indigo-600">
            {/* Sidebar do Perfil */}
            <div className="w-full md:w-[35%] bg-slate-50 p-10 border-r border-slate-100 flex flex-col items-center text-center overflow-y-auto custom-scrollbar">
               <button onClick={() => setShowViewModal(false)} className="absolute top-8 left-8 md:static mb-8 p-3 bg-white text-slate-400 hover:text-slate-900 rounded-2xl shadow-sm transition-all md:self-start"><X size={24} /></button>
               <div className="relative mb-6">
                  <img src={viewingEmp.avatar} className="w-40 h-40 rounded-[3.5rem] object-cover ring-[12px] ring-white shadow-2xl" alt={viewingEmp.name} />
                  <div className={`absolute -bottom-2 -right-2 px-4 py-1 rounded-full border-4 border-white text-[10px] font-black uppercase text-white ${viewingEmp.status === 'Ativo' ? 'bg-emerald-500' : 'bg-amber-500'}`}>{viewingEmp.status}</div>
               </div>
               <h2 className="text-2xl font-black text-slate-900 tracking-tight mb-2 leading-tight">{viewingEmp.name}</h2>
               <p className="text-xs font-black text-indigo-600 uppercase tracking-[0.2em] bg-indigo-50 px-4 py-1.5 rounded-xl mb-8">{viewingEmp.role}</p>

               <div className="w-full space-y-4 text-left">
                  <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4">
                     <div className="p-3 bg-blue-50 text-blue-600 rounded-xl"><Mail size={20} /></div>
