                            </div>
                            <span className="text-[12px] font-black uppercase mb-1.5 relative z-10 group-hover/btn:tracking-wider transition-all">{p.label}</span>
                            <span className={`text-[10px] font-medium leading-relaxed relative z-10 ${isActive ? 'text-blue-100' : 'text-slate-400'}`}>
                              {p.description}
                            </span>
                          </button>
                        );
                      })}
                    </div>
                  </div>
              ))}
            </div>

            <div className="flex gap-6 pt-10 border-t border-slate-100">
              <button 
                onClick={handleSaveRolePermissions}
                disabled={saving}
                className="flex-1 py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-[0.3em] shadow-2xl shadow-blue-500/30 hover:bg-slate-900 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50"
              >
                {saving ? <Loader2 className="animate-spin" size={24} /> : <><Save size={24} /> Sincronizar Matriz de Cargo</>}
              </button>
              <button 
                onClick={() => setEditingRolePermissions(null)}
                className="px-12 py-8 bg-slate-100 text-slate-500 rounded-[2.5rem] font-black text-xs uppercase tracking-widest hover:bg-slate-200 transition-all active:scale-95"
              >
                Descartar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Auditoria de Segurança */}
      {showAuditModal && (
        <div className="fixed inset-0 z-[180] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-5xl w-full shadow-2xl relative flex flex-col max-h-[90vh] border-t-[12px] border-indigo-600">
            <button onClick={() => setShowAuditModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-5 mb-10">
               <div className="p-4 bg-indigo-600 text-white rounded-2xl shadow-xl shadow-indigo-500/20"><History size={28} /></div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Auditoria de Segurança Cloud</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Timeline integral de alterações críticas no ecossistema.</p>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
              {loadingLogs ? (
                <div className="py-24 flex flex-col items-center gap-4">
                  <Loader2 className="animate-spin text-indigo-600" size={48} />
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Consultando Sifre da Cloud...</p>
                </div>
              ) : auditLogs.length === 0 ? (
                <div className="py-24 text-center bg-slate-50 rounded-[3rem] border border-slate-200 flex flex-col items-center gap-4">
                  <ShieldAlert size={48} className="text-slate-200" />
                  <p className="text-xs font-black uppercase text-slate-400 tracking-widest">Nenhum registo de auditoria detetado.</p>
                </div>
              ) : auditLogs.map((log) => (
                <div key={log.id} className="p-8 bg-slate-50 rounded-[3rem] border border-slate-100 hover:bg-white hover:shadow-xl hover:border-indigo-100 transition-all group animate-in slide-in-from-bottom-2">
                   <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
                      <div className="flex items-center gap-4">
                         <div className={`px-4 py-1.5 ${getActionColor(log.action_type)} text-white rounded-full text-[9px] font-black uppercase tracking-widest shadow-md`}>
                            {log.action_type}
                         </div>
                         <div className="flex items-center gap-2 text-slate-900 font-bold text-sm">
                            <span className="flex items-center gap-1.5"><UserCog size={14} className="text-slate-400" /> {log.admin_name}</span>
                            <ArrowRight size={14} className="text-slate-300" />
                            <span className="text-indigo-600 font-black">{log.target_user_name}</span>
                         </div>
                      </div>
                      <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest bg-white px-3 py-1 rounded-full border border-slate-100">
                         <Calendar size={12} className="text-indigo-500" />
                         {new Date(log.created_at).toLocaleString('pt-MZ')}
                      </div>
                   </div>
                   <div className="relative">
                     <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-200 rounded-full"></div>
                     <div className="pl-6 py-4 bg-white/50 rounded-2xl border border-slate-100 text-[11px] text-slate-600 leading-relaxed font-medium italic group-hover:text-slate-900 transition-colors flex items-start gap-3">
                        <Terminal size={14} className="mt-0.5 text-indigo-400 shrink-0" />
                        <span className="font-mono">{log.change_details}</span>
                     </div>
                   </div>
                </div>
              ))}
            </div>

            <div className="mt-8 pt-8 border-t border-slate-100 text-center">
              <button onClick={() => setShowAuditModal(false)} className="px-10 py-5 bg-slate-900 text-white rounded-[2rem] font-black text-xs uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all shadow-2xl active:scale-95">Fechar Relatório</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;
